            let len_val = call.try_as_basic_value().basic().ok_or_else(|| {
                CodegenError::FailClosed("hew_hashset_len_layout returned void".into())
            })?;
            let (dest_ptr, _dest_ty) = place_pointer(fn_ctx, *dest_place)?;
            fn_ctx
