fn is_machine_step_symbol(callee: &str) -> bool {
    callee
        .strip_suffix("__step")
        .is_some_and(|prefix| !prefix.is_empty())
}

pub(crate) fn emit_trap_with_code(
    fn_ctx: &FnCtx<'_, '_>,
    code: u64,
    label: &str,
) -> CodegenResult<()> {
    let trap_with_code_fn = match fn_ctx.llvm_mod.get_function("hew_trap_with_code") {
        Some(fv) => fv,
        None => {
            let i32_ty = fn_ctx.ctx.i32_type();
            let fn_ty = fn_ctx.ctx.void_type().fn_type(&[i32_ty.into()], false);
            fn_ctx
                .llvm_mod
                .add_function("hew_trap_with_code", fn_ty, Some(Linkage::External))
        }
    };
    let code_val = fn_ctx.ctx.i32_type().const_int(code, false);
    fn_ctx
        .builder
        .build_call(trap_with_code_fn, &[code_val.into()], label)
        .llvm_ctx("hew_trap_with_code call")?;
    let trap_intrinsic = Intrinsic::find("llvm.trap")
        .ok_or_else(|| CodegenError::Llvm("llvm.trap intrinsic not found in LLVM build".into()))?;
    let trap_fn = trap_intrinsic
        .get_declaration(fn_ctx.llvm_mod, &[])
        .ok_or_else(|| CodegenError::Llvm("llvm.trap declaration failed".into()))?;
    fn_ctx
        .builder
        .build_call(trap_fn, &[], &format!("{label}_llvm_trap"))
        .llvm_ctx("llvm.trap call")?;
    fn_ctx.builder.build_unreachable().llvm_ctx("unreachable")?;
    Ok(())
}

/// Materialize the runtime `i32` send status into a user-visible
/// `Result<(), SendError>` stored at `dest`.
///
/// This is the single authority for the rc → `SendError` discriminant mapping
/// (plan decision D1). It runs for both `hew_lambda_actor_send` and
/// `hew_duplex_send`, whose status space is identical: `{0=Ok, 1=Closed,
/// 2=Full, 3=ActorStopped, 4=DoubleClose, 5=OrphanedAsk}`
/// (`hew-runtime/src/duplex.rs`, `hew-runtime/src/lambda_actor.rs`). The
/// user-visible `SendError` enum is `{Full=0, Closed=1, NodeRoutingNotWired=2}`
/// (`hew-types/src/builtin_enums.rs`). The mapping is:
///
/// * `rc == 0` → `Result::Ok(())`
/// * `rc == 2` (runtime Full) → `Result::Err(SendError::Full)`
/// * every other nonzero rc → `Result::Err(SendError::Closed)` — once a send
///   fails for any reason other than backpressure, no consumer can observe the
///   message, so `Closed` is the conservative in-process verdict.
///
/// `NodeRoutingNotWired` is never produced here: it is a *remote* routing
/// condition, not reachable for an in-process actor / duplex send.
///
/// Security invariant: the raw rc is NEVER stored as the discriminant. rc values
/// `3/4/5` are out of range for the 3-variant `SendError` enum and would be
/// undefined behaviour at the user's `match` (an out-of-range discriminant is a
/// security defect, not a cosmetic one). The `select` collapses the entire
/// nonzero rc space onto the two in-range variants `Full` / `Closed`, so no
/// out-of-range value can ever reach the tag slot.
///
/// Runs as an `Instr` (not a terminator), so it appends its own merge block and
/// leaves the builder positioned there for the instructions that follow.
pub(crate) fn emit_send_result_from_rc<'ctx>(
    fn_ctx: &FnCtx<'_, 'ctx>,
    status: IntValue<'ctx>,
    dest: Place,
    helper: &str,
) -> CodegenResult<()> {
    let dest_local = composite_dest_local(dest, helper)?;

    // The runtime decl returns i32 for both send symbols. Refuse to operate on
    // any other width rather than silently zext/trunc a security-sensitive
    // status (fail-closed: a width surprise means the decl drifted).
    let i32_ty = fn_ctx.ctx.i32_type();
    if status.get_type().get_bit_width() != 32 {
        return Err(CodegenError::FailClosed(format!(
            "{helper}: send status must be i32 (runtime ABI contract), got {}-bit",
            status.get_type().get_bit_width()
        )));
    }

    let zero_i32 = i32_ty.const_zero();
    let is_ok = fn_ctx
        .builder
        .build_int_compare(IntPredicate::EQ, status, zero_i32, "send_status_is_ok")
        .llvm_ctx_with(|| format!("{helper} status is_ok icmp"))?;

    let parent = fn_ctx
        .builder
        .get_insert_block()
        .and_then(|bb| bb.get_parent())
        .ok_or_else(|| CodegenError::FailClosed(format!("{helper}: no parent function")))?;
    let ok_bb = fn_ctx.ctx.append_basic_block(parent, "send_result_ok");
    let err_bb = fn_ctx.ctx.append_basic_block(parent, "send_result_err");
    let merge_bb = fn_ctx.ctx.append_basic_block(parent, "send_result_merge");
    fn_ctx
        .builder
        .build_conditional_branch(is_ok, ok_bb, err_bb)
        .llvm_ctx_with(|| format!("{helper} status cond br"))?;

    // ── Ok branch: Result tag = 0, payload = `()` (no field store). ──
    fn_ctx.builder.position_at_end(ok_bb);
    store_composite_tag(fn_ctx, dest_local, 0, helper)?;
    fn_ctx
        .builder
        .build_unconditional_branch(merge_bb)
        .llvm_ctx_with(|| format!("{helper} ok br merge"))?;

    // ── Err branch: Result tag = 1, payload = SendError::<mapped variant>. ──
    fn_ctx.builder.position_at_end(err_bb);
    store_composite_tag(fn_ctx, dest_local, 1, helper)?;

    // D1 mapping authority. We are on the Err branch, so rc != 0. `Full` is the
    // single backpressure variant (runtime rc == 2); everything else collapses
    // to `Closed`. The comparison is performed once, in i32; the per-slot
    // constants below only differ in width.
    let two_i32 = i32_ty.const_int(2, false);
    let is_full = fn_ctx
        .builder
        .build_int_compare(IntPredicate::EQ, status, two_i32, "send_status_is_full")
        .llvm_ctx_with(|| format!("{helper} status is_full icmp"))?;

    // Project the SendError payload slot: Result variant 1 (Err), field 0.
    let (send_err_ptr, send_err_ty) = place_pointer(
        fn_ctx,
        Place::MachineVariant {
            local: dest_local,
            variant_idx: 1,
            field_idx: 0,
        },
    )?;
    match send_err_ty {
        // Single-int representation: the SendError discriminant IS the slot.
        BasicTypeEnum::IntType(int_ty) => {
            let full_tag = int_ty.const_int(0, false); // SendError::Full
            let closed_tag = int_ty.const_int(1, false); // SendError::Closed
            let tag = fn_ctx
                .builder
                .build_select(is_full, full_tag, closed_tag, "send_err_tag")
                .llvm_ctx_with(|| format!("{helper} SendError tag select"))?
                .into_int_value();
            fn_ctx
                .builder
                .build_store(send_err_ptr, tag)
                .llvm_ctx_with(|| format!("{helper} store SendError discriminant"))?;
        }
        // Struct representation: zero-init the outer struct (defines any
        // payload padding), then patch field 0 (the discriminant tag).
        BasicTypeEnum::StructType(st) => {
            fn_ctx
                .builder
                .build_store(send_err_ptr, st.const_zero())
                .llvm_ctx_with(|| format!("{helper} zero SendError struct"))?;
            let tag_field_ptr = fn_ctx
                .builder
                .build_struct_gep(st, send_err_ptr, 0, "send_err_tag_ptr")
                .llvm_ctx_with(|| format!("{helper} SendError tag gep"))?;
            let tag_field_ty = st.get_field_type_at_index(0).ok_or_else(|| {
                CodegenError::FailClosed(format!("{helper}: SendError struct has no field 0 (tag)"))
            })?;
            let BasicTypeEnum::IntType(tag_int_ty) = tag_field_ty else {
                return Err(CodegenError::FailClosed(format!(
                    "{helper}: SendError tag field must be an integer, got {tag_field_ty:?}"
                )));
            };
            let full_tag = tag_int_ty.const_int(0, false); // SendError::Full
            let closed_tag = tag_int_ty.const_int(1, false); // SendError::Closed
            let tag = fn_ctx
                .builder
                .build_select(is_full, full_tag, closed_tag, "send_err_tag")
                .llvm_ctx_with(|| format!("{helper} SendError tag select"))?
                .into_int_value();
            fn_ctx
                .builder
                .build_store(tag_field_ptr, tag)
                .llvm_ctx_with(|| format!("{helper} store SendError tag"))?;
        }
        other => {
            return Err(CodegenError::FailClosed(format!(
                "{helper}: Err payload (SendError) must be a struct or int, got {other:?}"
            )));
        }
    }
    fn_ctx
        .builder
        .build_unconditional_branch(merge_bb)
        .llvm_ctx_with(|| format!("{helper} err br merge"))?;

    // ── Merge: subsequent instructions resume here. ──
    fn_ctx.builder.position_at_end(merge_bb);
    Ok(())
}

/// Resolve a target actor TYPE's dispatch global `__hew_actor_dispatch_<name>`
/// as a `ptr` value, for use as the `(dispatch, msg_type)` cross-node codec key
/// at an originating remote send / ask site. The trampoline is emitted by
/// `emit_actor_dispatch_trampoline` ahead of function-body lowering, so it is
/// present here; a missing symbol is wrong-code territory — fail closed rather
/// than pass a null key that would mis-route the codec lookup.
fn remote_actor_dispatch_ptr<'ctx>(
    fn_ctx: &FnCtx<'_, 'ctx>,
    actor_name: &str,
) -> CodegenResult<PointerValue<'ctx>> {
    let dispatch_name = format!("__hew_actor_dispatch_{}", mangle_dotted_name(actor_name));
    let dispatch_fn = fn_ctx
        .llvm_mod
        .get_function(&dispatch_name)
        .ok_or_else(|| {
            CodegenError::FailClosed(format!(
                "remote send/ask on `{actor_name}` requires dispatch trampoline \
             `{dispatch_name}` (the cross-node codec key); it was not declared"
            ))
        })?;
    Ok(dispatch_fn.as_global_value().as_pointer_value())
}

/// Resolve the target actor TYPE name `T` from a `RemotePid<T>` pid place, then
/// its dispatch global ptr (the `(dispatch, msg_type)` cross-node codec key for
/// the originating remote ask). Mirrors the `RemotePid<T>` unwrap in
/// `emit_remote_pid_tell_call`.
pub(crate) fn remote_ask_dispatch_ptr<'ctx>(
    fn_ctx: &FnCtx<'_, 'ctx>,
    pid_place: Place,
) -> CodegenResult<PointerValue<'ctx>> {
    let pid_ty = place_resolved_ty(fn_ctx, pid_place)?;
    let actor_name = match pid_ty {
        ResolvedTy::Named { name, args, .. } if name == "RemotePid" => match args.first() {
            Some(ResolvedTy::Named { name: t_name, .. }) => t_name.clone(),
            other => {
                return Err(CodegenError::FailClosed(format!(
                    "RemoteAsk pid `RemotePid<T>` inner T must be a named actor type, \
                     got {other:?}"
                )));
            }
        },
        other => {
            return Err(CodegenError::FailClosed(format!(
                "RemoteAsk pid must have resolved type RemotePid<T>, got {other:?}"
            )));
        }
    };
    remote_actor_dispatch_ptr(fn_ctx, &actor_name)
}

/// Emit the call sequence for `RemotePid<T>::tell(pid, msg) -> Result<(), SendError>`.
///
/// The checker rewrites `pid.tell(msg)` on a `RemotePid<T>` receiver into a
/// direct call to `hew_remote_pid_tell` (see hew-types::check::methods); the
/// HIR catalog entry (CompilerIntrinsic) satisfies fn_registry. This function
/// is the codegen interception that replaces the direct call with a
/// hew_actor_send_by_id call sequence plus user-visible Result construction.
///
/// Lowering:
///   * Load `args[0]` (the `RemotePid<T>` place) as a `u64` packed pid.
///   * Derive the msg_type i32: resolve T from `args[0]`'s `ResolvedTy`, look
///     up the matching `ActorLayout` in `fn_ctx.actor_layouts`, and find the
///     handler whose `param_tys[0]` equals `args[1]`'s resolved type. This
///     consumes checker-recorded types (no re-inference) — per
///     `checker-authority` and `codegen-abi-authority`.
///   * Extract `(payload_ptr, payload_size)` from `args[1]` via
///     `actor_payload_ptr_size`.
///   * Call `hew_actor_send_by_id(pid, msg_type, ptr, size) -> i32`.
///   * `rc == 0` → tag=0 (Ok), payload = `()` (no field store).
///   * `rc != 0` → tag=1 (Err), payload = `SendError::NodeRoutingNotWired`
///     (variant 2). The runtime currently collapses all failure modes into
///     a single `-1` rc, so any failure maps to the broadest "transport
///     unavailable" variant; narrowing requires a new runtime ABI.
///
/// Dispatch is by callee name (not a new `FnSymbol` variant), matching the
/// Node::lookup precedent (R82-era generalisation).
fn emit_remote_pid_tell_call<'ctx>(
    fn_ctx: &FnCtx<'_, 'ctx>,
    args: &[Place],
    dest: Option<&Place>,
    next: u32,
) -> CodegenResult<()> {
    let [pid_arg, msg_arg] = args else {
        return Err(CodegenError::FailClosed(format!(
            "hew_remote_pid_tell expects exactly 2 arguments (pid, msg), got {}",
            args.len()
        )));
    };
    let dest_place = dest.ok_or_else(|| {
        CodegenError::FailClosed(
            "hew_remote_pid_tell must carry a Terminator::Call dest \
             (Result<(), SendError> return value)"
                .into(),
        )
    })?;
    let dest_local = match dest_place {
        Place::Local(id) => *id,
        other => {
            return Err(CodegenError::FailClosed(format!(
                "hew_remote_pid_tell dest must be Place::Local(_), got {other:?}"
            )));
        }
    };

    // Resolve T from RemotePid<T> on the pid arg, then locate the matching
    // ActorLayout and the handler whose first param type equals the msg
    // arg's resolved type. The checker has already concretized both types
    // by the time we reach codegen.
    let pid_ty = place_resolved_ty(fn_ctx, *pid_arg)?;
    let actor_name = match pid_ty {
        ResolvedTy::Named { name, args, .. } if name == "RemotePid" => {
            let inner = args.first().ok_or_else(|| {
                CodegenError::FailClosed(
                    "hew_remote_pid_tell pid arg `RemotePid<T>` is missing its T type \
                     parameter"
                        .into(),
                )
            })?;
            match inner {
                ResolvedTy::Named { name: t_name, .. } => t_name.clone(),
                other => {
                    return Err(CodegenError::FailClosed(format!(
                        "hew_remote_pid_tell: RemotePid<T> inner T must be a named actor \
                         type, got {other:?}"
                    )));
                }
            }
        }
        other => {
            return Err(CodegenError::FailClosed(format!(
                "hew_remote_pid_tell pid arg must have resolved type \
                 ResolvedTy::Named {{ name: \"RemotePid\", .. }}, got {other:?}"
            )));
        }
    };
    let msg_ty = place_resolved_ty(fn_ctx, *msg_arg)?.clone();
    let actor_layout = fn_ctx
        .actor_layouts
        .iter()
        .find(|layout| layout.name == actor_name)
        .ok_or_else(|| {
            CodegenError::FailClosed(format!(
                "hew_remote_pid_tell: no ActorLayout for `{actor_name}` (RemotePid<T> \
                 receiver T)"
            ))
        })?;
    // Only single-parameter handlers are remote-dispatchable: the remote
    // wire carries exactly ONE message value, while a multi-arg handler's
    // local wire is the packed-args anonymous record. Matching a multi-arg
    // handler here would send a single-field payload to a body that unpacks
    // the full record — an out-of-bounds read on the receiving node. Fail
    // closed with the E_REMOTE_PAYLOAD_UNSUPPORTED marker
    // (`serializer-fail-closed`); the cross-node payload serialization lane
    // lands the positive path for packed-args shapes.
    let handler = actor_layout
        .handlers
        .iter()
        .find(|h| h.param_tys.len() == 1 && h.param_tys.first().is_some_and(|p| *p == msg_ty))
        .ok_or_else(|| {
            if let Some(multi) = actor_layout.handlers.iter().find(|h| {
                h.param_tys.len() > 1 && h.param_tys.first().is_some_and(|p| *p == msg_ty)
            }) {
                return CodegenError::FailClosed(format!(
                    "E_REMOTE_PAYLOAD_UNSUPPORTED: remote tell on `{actor_name}` would \
                     dispatch to multi-parameter receive fn `{}` ({} parameters); a \
                     remote send carries one message value and the cross-node codec is \
                     not seeded for packed multi-arg payloads. Declare a \
                     single-parameter handler (e.g. wrapping the fields in a record) \
                     for remote dispatch.",
                    multi.name,
                    multi.param_tys.len()
                ));
            }
            CodegenError::FailClosed(format!(
                "hew_remote_pid_tell: actor `{actor_name}` has no receive handler whose \
                 first param type matches the msg type `{msg_ty:?}` (handlers: {:?})",
                actor_layout
                    .handlers
                    .iter()
                    .map(|h| (h.name.as_str(), &h.param_tys))
                    .collect::<Vec<_>>()
            ))
        })?;
    let msg_type_const = fn_ctx
        .ctx
        .i32_type()
        .const_int(handler.msg_type as u64, true);

    // Load the packed u64 pid out of the RemotePid<T> alloca (which is an i64
    // slot per the `Named { name: "RemotePid" }` arm of `resolve_ty`).
    let (pid_slot, pid_slot_ty) = place_pointer(fn_ctx, *pid_arg)?;
    if !matches!(pid_slot_ty, BasicTypeEnum::IntType(t) if t.get_bit_width() == 64) {
        return Err(CodegenError::FailClosed(format!(
            "hew_remote_pid_tell: RemotePid<T> slot must be i64, got {pid_slot_ty:?}"
        )));
    }
    let pid_val = fn_ctx
        .builder
        .build_load(pid_slot_ty, pid_slot, "remote_tell_pid")
        .llvm_ctx("load RemotePid u64")?
        .into_int_value();

    // Extract the msg payload pointer and byte size from the msg arg's place.
    let (payload_ptr, payload_size) =
        actor_payload_ptr_size(fn_ctx, *msg_arg, "remote_tell_payload")?;

    // Resolve the TARGET actor type's dispatch global — the `(dispatch,
    // msg_type)` cross-node serialize codec key. The codec seeder registered
    // this actor's serializer under THIS module's same dispatch global, so the
    // remote-send encode selects the right codec even when another actor type's
    // `msg_type` SipHash-collides. Same symbol the spawn path uses
    // (`emit_spawn_actor`); fail closed if the trampoline is missing.
    let dispatch_ptr = remote_actor_dispatch_ptr(fn_ctx, &actor_name)?;

    // Call `hew_actor_send_by_id(pid, dispatch, msg_type, data, size) -> i32`.
    let send_fn = intern_runtime_decl(
        fn_ctx.ctx,
        fn_ctx.llvm_mod,
        &mut fn_ctx.runtime_decls.borrow_mut(),
        "hew_actor_send_by_id",
    )?;
    // `payload_size` is built as i64; the `size` param is `usize`/`size_t`
    // (i32 on wasm32). Reconcile to the target-correct width.
    let size_ty = runtime_size_ty(fn_ctx.ctx, fn_ctx.llvm_mod);
    let payload_size = reconcile_int_width_signed(
        fn_ctx,
        payload_size.into(),
        size_ty.into(),
        "send payload size",
    )?;
    let rc_basic = fn_ctx
        .builder
        .build_call(
            send_fn,
            &[
                pid_val.into(),
                dispatch_ptr.into(),
                msg_type_const.into(),
                payload_ptr.into(),
                payload_size.into(),
            ],
            "remote_tell_rc",
        )
        .llvm_ctx("hew_actor_send_by_id call")?
        .try_as_basic_value()
        .basic()
        .ok_or_else(|| {
            CodegenError::FailClosed("hew_actor_send_by_id returned void — expected i32 rc".into())
        })?;
    let rc = rc_basic.into_int_value();
    let i32_ty = fn_ctx.ctx.i32_type();
    let zero32 = i32_ty.const_zero();
    let is_ok = fn_ctx
        .builder
        .build_int_compare(IntPredicate::EQ, rc, zero32, "remote_tell_is_ok")
        .llvm_ctx("remote_tell icmp")?;

    let parent = fn_ctx
        .builder
        .get_insert_block()
        .and_then(|bb| bb.get_parent())
        .ok_or_else(|| {
            CodegenError::FailClosed("hew_remote_pid_tell call has no parent function".into())
        })?;
    let ok_bb = fn_ctx.ctx.append_basic_block(parent, "remote_tell_ok_bb");
    let err_bb = fn_ctx.ctx.append_basic_block(parent, "remote_tell_err_bb");
    fn_ctx
        .builder
        .build_conditional_branch(is_ok, ok_bb, err_bb)
        .llvm_ctx("remote_tell condbr")?;

    let next_bb = *fn_ctx.blocks.get(&next).ok_or_else(|| {
        CodegenError::FailClosed(format!("hew_remote_pid_tell next bb{next} missing"))
    })?;

    // --- Ok branch: tag=0, payload = `()` (no field store) -------------------
    fn_ctx.builder.position_at_end(ok_bb);
    let (tag_ptr_ok, tag_ty_ok) = place_pointer(fn_ctx, Place::MachineTag(dest_local))?;
    let tag_int_ty_ok = match tag_ty_ok {
        BasicTypeEnum::IntType(t) => t,
        other => {
            return Err(CodegenError::FailClosed(format!(
                "hew_remote_pid_tell dest Result tag type is not an integer: {other:?}"
            )));
        }
    };
    fn_ctx
        .builder
        .build_store(tag_ptr_ok, tag_int_ty_ok.const_zero())
        .llvm_ctx("store Ok tag")?;
    fn_ctx
        .builder
        .build_unconditional_branch(next_bb)
        .llvm_ctx("remote_tell ok br next")?;

    // --- Err branch: tag=1, payload = SendError::NodeRoutingNotWired ---------
    fn_ctx.builder.position_at_end(err_bb);
    let (tag_ptr_err, tag_ty_err) = place_pointer(fn_ctx, Place::MachineTag(dest_local))?;
    let tag_int_ty_err = match tag_ty_err {
        BasicTypeEnum::IntType(t) => t,
        other => {
            return Err(CodegenError::FailClosed(format!(
                "hew_remote_pid_tell dest Result tag type is not an integer: {other:?}"
            )));
        }
    };
    fn_ctx
        .builder
        .build_store(tag_ptr_err, tag_int_ty_err.const_int(1, false))
        .llvm_ctx("store Err tag")?;
    // Result<(), SendError>: variant 1 is the Err arm, field 0 is the
    // SendError outer struct.  SendError is a 3-variant payload-less enum
    // (Full=0, Closed=1, NodeRoutingNotWired=2); we write the SendError
    // tag into its first slot.
    let (send_err_ptr, send_err_ty) = place_pointer(
        fn_ctx,
        Place::MachineVariant {
            local: dest_local,
            variant_idx: 1,
            field_idx: 0,
        },
    )?;
    // The SendError outer struct's first integer slot is its discriminant
    // tag. Writing `2` (NodeRoutingNotWired) followed by a zero-init of any
    // padding is the same shape `LookupError::NotFound` writes via
    // `const_zero` in emit_node_lookup_call, except SendError carries a
    // non-zero discriminant.  We zero-initialise the outer struct (so any
    // payload field after the tag is well-defined) and then patch the tag
    // through a tag-slot projection equivalent.  Because SendError has no
    // payload, a const struct with tag=2 + zeroed padding is sufficient.
    let send_err_struct_ty = match send_err_ty {
        BasicTypeEnum::StructType(st) => st,
        BasicTypeEnum::IntType(_) => {
            // Single-int representation: write the discriminant directly.
            let int_ty = send_err_ty.into_int_type();
            fn_ctx
                .builder
                .build_store(send_err_ptr, int_ty.const_int(2, false))
                .llvm_ctx("store SendError discriminant")?;
            fn_ctx
                .builder
                .build_unconditional_branch(next_bb)
                .llvm_ctx("remote_tell err br next")?;
            return Ok(());
        }
        other => {
            return Err(CodegenError::FailClosed(format!(
                "hew_remote_pid_tell Err payload (SendError) must be a struct or int, \
                 got {other:?}"
            )));
        }
    };
    // Zero-initialise SendError struct, then overwrite the tag field with 2.
    fn_ctx
        .builder
        .build_store(send_err_ptr, send_err_struct_ty.const_zero())
        .llvm_ctx("zero SendError struct")?;
    // SendError's tag is at MachineTag of the dest's variant 1 field 0
    // local. For payload-less enums the layout is just a tag (no
    // MachineVariant projection needed), so we GEP into the struct's
    // first element.
    let tag_field_ptr = fn_ctx
        .builder
        .build_struct_gep(send_err_struct_ty, send_err_ptr, 0, "send_err_tag_ptr")
        .llvm_ctx("SendError tag gep")?;
    let tag_field_ty = send_err_struct_ty
        .get_field_type_at_index(0)
        .ok_or_else(|| CodegenError::FailClosed("SendError struct has no field 0 (tag)".into()))?;
    let tag_field_int_ty = match tag_field_ty {
        BasicTypeEnum::IntType(t) => t,
        other => {
            return Err(CodegenError::FailClosed(format!(
                "SendError tag field must be an integer, got {other:?}"
            )));
        }
    };
    fn_ctx
        .builder
        .build_store(tag_field_ptr, tag_field_int_ty.const_int(2, false))
        .llvm_ctx("store SendError tag")?;
    fn_ctx
        .builder
        .build_unconditional_branch(next_bb)
        .llvm_ctx("remote_tell err br next")?;

    Ok(())
}

/// Emit the call sequence for active-mode `conn.attach(handler)`.
///
/// The checker rewrites `conn.attach(handler)` on a `net.Connection` receiver
/// to a direct `hew_tcp_attach_local(conn, handler)` call (see
/// hew-types::check::methods); this is the codegen interception, mirroring
/// `emit_remote_pid_tell_call`.
///
/// Lowering:
///   * Resolve the concrete actor type `A` from `args[1]`'s recorded
///     `LocalPid<A>` type. The `LocalPid<ConcreteActor>` → `LocalPid<Handler>`
///     coercion in the checker deliberately does NOT rewrite the recorded
///     expr type, so the concrete actor survives to codegen here (per
///     `checker-authority`: codegen consumes recorded types, never re-infers).
///   * Look up `A`'s `ActorLayout` and read the `msg_type` (the SipHash-1-3
///     `msg_id`) of its `on_data` and `on_close` handlers. These are the same
///     ids the dispatch trampoline switches on, so a reactor-delivered message
///     routes to the right receive fn.
///   * Load `conn` (an i32 handle) and `handler` (the `LocalPid<A>` actor
///     pointer) and call the 4-arg runtime ABI
///     `hew_tcp_attach_local(conn, actor_ptr, on_data_id, on_close_id) -> i32`.
///   * `attach` returns Unit on the Hew surface; the runtime rc is discarded
///     (the runtime records the failure in last_error and the fail-closed
///     mailbox guard already rejected leak-prone mailboxes at type-check via
///     the runtime). Dispatch is by callee name (no new FnSymbol variant),
///     matching the `hew_remote_pid_tell` precedent.
fn emit_tcp_attach_local_call<'ctx>(fn_ctx: &FnCtx<'_, 'ctx>, args: &[Place]) -> CodegenResult<()> {
    let [conn_arg, handler_arg] = args else {
        return Err(CodegenError::FailClosed(format!(
            "hew_tcp_attach_local expects exactly 2 arguments (conn, handler), got {}",
            args.len()
        )));
    };

    // Resolve the concrete actor type behind the handler's `LocalPid<A>`.
    let handler_ty = place_resolved_ty(fn_ctx, *handler_arg)?;
    let actor_name = match handler_ty {
        ResolvedTy::Named { name, args, .. } if name == "LocalPid" => {
            let inner = args.first().ok_or_else(|| {
                CodegenError::FailClosed(
                    "hew_tcp_attach_local handler arg `LocalPid<A>` is missing its A type \
                     parameter"
                        .into(),
                )
            })?;
            match inner {
                ResolvedTy::Named { name: a_name, .. } => a_name.clone(),
                other => {
                    return Err(CodegenError::FailClosed(format!(
                        "hew_tcp_attach_local: LocalPid<A> inner A must be a named actor type, \
                         got {other:?}"
                    )));
                }
            }
        }
        other => {
            return Err(CodegenError::FailClosed(format!(
                "hew_tcp_attach_local handler arg must have resolved type \
                 ResolvedTy::Named {{ name: \"LocalPid\", .. }}, got {other:?}"
            )));
        }
    };

    let actor_layout = fn_ctx
        .actor_layouts
        .iter()
        .find(|layout| layout.name == actor_name)
        .ok_or_else(|| {
            CodegenError::FailClosed(format!(
                "hew_tcp_attach_local: no ActorLayout for `{actor_name}` (LocalPid<A> handler A); \
                 the actor must declare `on_data` / `on_close` receive fns to satisfy \
                 ConnectionHandler"
            ))
        })?;
    let handler_msg_id = |handler_name: &str| -> CodegenResult<i32> {
        actor_layout
            .handlers
            .iter()
            .find(|h| h.name == handler_name)
            .map(|h| h.msg_type)
            .ok_or_else(|| {
                CodegenError::FailClosed(format!(
                    "hew_tcp_attach_local: actor `{actor_name}` has no `{handler_name}` receive fn; \
                     a ConnectionHandler actor must declare both `on_data` and `on_close`"
                ))
            })
    };
    let on_data_id = handler_msg_id("on_data")?;
    let on_close_id = handler_msg_id("on_close")?;

    let i32_ty = fn_ctx.ctx.i32_type();
    let on_data_const = i32_ty.const_int(on_data_id as u64, true);
    let on_close_const = i32_ty.const_int(on_close_id as u64, true);

    // Load the conn handle (pointer-shaped opaque `Connection`) and the handler
    // actor pointer (ptr).
    let (conn_ptr, conn_slot_ty) = place_pointer(fn_ctx, *conn_arg)?;
    let conn_val = fn_ctx
        .builder
        .build_load(conn_slot_ty, conn_ptr, "attach_conn")
        .llvm_ctx("load attach conn")?;

    let (handler_ptr, handler_slot_ty) = place_pointer(fn_ctx, *handler_arg)?;
    let actor_ptr = fn_ctx
        .builder
        .build_load(handler_slot_ty, handler_ptr, "attach_actor_ptr")
        .llvm_ctx("load attach handler LocalPid ptr")?;

    // Call the 4-arg runtime ABI:
    //   hew_tcp_attach_local(conn: i32, actor: *mut HewActor, on_data: i32, on_close: i32) -> i32
    fn_ctx.call_runtime_void(
        "hew_tcp_attach_local",
        &[
            metadata_value_from_basic(conn_val),
            metadata_value_from_basic(actor_ptr),
            on_data_const.into(),
            on_close_const.into(),
        ],
        "attach_rc",
        "hew_tcp_attach_local call",
    )?;
    Ok(())
}

fn emit_math_builtin_intrinsic_call<'ctx>(
    fn_ctx: &FnCtx<'_, 'ctx>,
    callee: &str,
    intrinsic: MathBuiltinIntrinsic,
    args: &[Place],
    dest: Option<&Place>,
    next: u32,
) -> CodegenResult<()> {
    let dest_place = dest.ok_or_else(|| {
        CodegenError::FailClosed(format!(
            "math builtin `{callee}` must carry a Terminator::Call dest"
        ))
    })?;

    let f64_ty = fn_ctx.ctx.f64_type();
    let i64_ty = fn_ctx.ctx.i64_type();
    let i1_ty = fn_ctx.ctx.bool_type();

    // `UnaryF64` / `BinaryF64` float intrinsics are resolved via
    // `add_function`; they carry no integer-only attributes and their
    // `IntrNoMem` / `Speculatable` markers are preserved through the
    // external-linkage declaration.
    //
    // `AbsI64` and `BinaryI64` (abs / smin / smax / umin / umax) are
    // resolved via `Intrinsic::find` + `get_declaration` so LLVM
    // attaches the `IntrNoMem`, `Speculatable`, and `willreturn`
    // attributes that `add_function(..., External)` would strip.
    // These attributes enable InstCombine folding and LICM on
    // abs/min/max calls.
    match intrinsic {
        MathBuiltinIntrinsic::UnaryF64(name) => {
            let [arg] = args else {
                return Err(CodegenError::FailClosed(format!(
                    "math builtin `{callee}` expects 1 argument, got {}",
                    args.len()
                )));
            };
            let value = load_math_f64_arg(fn_ctx, *arg, &format!("{callee}_arg0"), callee)?;
            let fn_ty = f64_ty.fn_type(&[f64_ty.into()], false);
            let intrinsic_fn = fn_ctx.llvm_mod.get_function(name).unwrap_or_else(|| {
                fn_ctx
                    .llvm_mod
                    .add_function(name, fn_ty, Some(Linkage::External))
            });
            let call = fn_ctx
                .builder
                .build_call(
                    intrinsic_fn,
                    &[value.into()],
                    &format!("{callee}_intrinsic"),
                )
                .llvm_ctx_with(|| format!("{name} call"))?;
            let result = call.try_as_basic_value().basic().ok_or_else(|| {
                CodegenError::FailClosed(format!(
                    "math builtin `{callee}` intrinsic `{name}` returned void"
                ))
            })?;
            let (dest_ptr, dest_ty) = place_pointer(fn_ctx, *dest_place)?;
            if dest_ty != BasicTypeEnum::FloatType(f64_ty) {
                return Err(CodegenError::FailClosed(format!(
                    "math builtin `{callee}` dest type {dest_ty:?} does not match f64"
                )));
            }
            fn_ctx
                .builder
                .build_store(dest_ptr, result)
                .llvm_ctx_with(|| format!("{callee} intrinsic store"))?;
        }
        MathBuiltinIntrinsic::BinaryF64(name) => {
            let [lhs, rhs] = args else {
                return Err(CodegenError::FailClosed(format!(
                    "math builtin `{callee}` expects 2 arguments, got {}",
                    args.len()
                )));
            };
            let lhs = load_math_f64_arg(fn_ctx, *lhs, &format!("{callee}_lhs"), callee)?;
            let rhs = load_math_f64_arg(fn_ctx, *rhs, &format!("{callee}_rhs"), callee)?;
            let fn_ty = f64_ty.fn_type(&[f64_ty.into(), f64_ty.into()], false);
            let intrinsic_fn = fn_ctx.llvm_mod.get_function(name).unwrap_or_else(|| {
                fn_ctx
                    .llvm_mod
                    .add_function(name, fn_ty, Some(Linkage::External))
            });
            let call = fn_ctx
                .builder
                .build_call(
                    intrinsic_fn,
                    &[lhs.into(), rhs.into()],
                    &format!("{callee}_intrinsic"),
                )
                .llvm_ctx_with(|| format!("{name} call"))?;
            let result = call.try_as_basic_value().basic().ok_or_else(|| {
                CodegenError::FailClosed(format!(
                    "math builtin `{callee}` intrinsic `{name}` returned void"
                ))
            })?;
            let (dest_ptr, dest_ty) = place_pointer(fn_ctx, *dest_place)?;
            if dest_ty != BasicTypeEnum::FloatType(f64_ty) {
                return Err(CodegenError::FailClosed(format!(
                    "math builtin `{callee}` dest type {dest_ty:?} does not match f64"
                )));
            }
            fn_ctx
                .builder
                .build_store(dest_ptr, result)
                .llvm_ctx_with(|| format!("{callee} intrinsic store"))?;
        }
        MathBuiltinIntrinsic::AbsI64 => {
            let [arg] = args else {
                return Err(CodegenError::FailClosed(format!(
                    "math builtin `{callee}` expects 1 argument, got {}",
                    args.len()
                )));
            };
            let value = load_place_as_basic(fn_ctx, *arg, &format!("{callee}_arg0"))?;
            let BasicValueEnum::IntValue(value) = value else {
                return Err(CodegenError::FailClosed(format!(
                    "math builtin `{callee}` expected i64 argument, got {value:?}"
                )));
            };
            // Resolve via Intrinsic::find so LLVM preserves the IntrNoMem /
            // Speculatable / willreturn attributes that add_function strips.
            // llvm.abs is overloaded on the integer type; pass [i64] as the
            // type arg.  The second argument (is_int_min_poison) is i1 false —
            // conservative: INT_MIN.abs() == INT_MIN, no poison.
            let intrinsic_fn = Intrinsic::find("llvm.abs")
                .ok_or_else(|| CodegenError::FailClosed("llvm.abs not in LLVM build".into()))?
                .get_declaration(fn_ctx.llvm_mod, &[i64_ty.into()])
                .ok_or_else(|| {
                    CodegenError::FailClosed("llvm.abs.i64 declaration failed".into())
                })?;
            let call = fn_ctx
                .builder
                .build_call(
                    intrinsic_fn,
                    &[value.into(), i1_ty.const_zero().into()],
                    &format!("{callee}_intrinsic"),
                )
                .llvm_ctx_with(|| "llvm.abs.i64 call".to_owned())?;
            let result = call.try_as_basic_value().basic().ok_or_else(|| {
                CodegenError::FailClosed(
                    "math builtin `abs` intrinsic llvm.abs.i64 returned void".into(),
                )
            })?;
            let (dest_ptr, dest_ty) = place_pointer(fn_ctx, *dest_place)?;
            if dest_ty != BasicTypeEnum::IntType(i64_ty) {
                return Err(CodegenError::FailClosed(format!(
                    "math builtin `abs` dest type {dest_ty:?} does not match i64"
                )));
            }
            fn_ctx
                .builder
                .build_store(dest_ptr, result)
                .llvm_ctx_with(|| "abs intrinsic store".to_owned())?;
        }
        MathBuiltinIntrinsic::BinaryI64(name) => {
            let [lhs, rhs] = args else {
                return Err(CodegenError::FailClosed(format!(
                    "math builtin `{callee}` expects 2 arguments, got {}",
                    args.len()
                )));
            };
            let lhs = load_place_as_basic(fn_ctx, *lhs, &format!("{callee}_lhs"))?;
            let rhs = load_place_as_basic(fn_ctx, *rhs, &format!("{callee}_rhs"))?;
            let (BasicValueEnum::IntValue(lhs), BasicValueEnum::IntValue(rhs)) = (lhs, rhs) else {
                return Err(CodegenError::FailClosed(format!(
                    "math builtin `{callee}` expected i64 arguments"
                )));
            };
            // Resolve via Intrinsic::find so LLVM preserves IntrNoMem /
            // Speculatable / willreturn on llvm.smin / llvm.smax / llvm.umin /
            // llvm.umax.  These intrinsics are overloaded on the integer type;
            // the base name (without the .i64 suffix) is what Intrinsic::find
            // consumes; get_declaration produces the mangled form.
            let base_name = name.strip_suffix(".i64").unwrap_or(name);
            let intrinsic_fn = Intrinsic::find(base_name)
                .ok_or_else(|| CodegenError::FailClosed(format!("{base_name} not in LLVM build")))?
                .get_declaration(fn_ctx.llvm_mod, &[i64_ty.into()])
                .ok_or_else(|| CodegenError::FailClosed(format!("{name} declaration failed")))?;
            let call = fn_ctx
                .builder
                .build_call(
                    intrinsic_fn,
                    &[lhs.into(), rhs.into()],
                    &format!("{callee}_intrinsic"),
                )
                .llvm_ctx_with(|| format!("{name} call"))?;
            let result = call.try_as_basic_value().basic().ok_or_else(|| {
                CodegenError::FailClosed(format!(
                    "math builtin `{callee}` intrinsic `{name}` returned void"
                ))
            })?;
            let (dest_ptr, dest_ty) = place_pointer(fn_ctx, *dest_place)?;
            if dest_ty != BasicTypeEnum::IntType(i64_ty) {
                return Err(CodegenError::FailClosed(format!(
                    "math builtin `{callee}` dest type {dest_ty:?} does not match i64"
                )));
            }
            fn_ctx
                .builder
                .build_store(dest_ptr, result)
                .llvm_ctx_with(|| format!("{callee} intrinsic store"))?;
        }
    }

    let next_bb = *fn_ctx
        .blocks
        .get(&next)
        .ok_or_else(|| CodegenError::FailClosed(format!("{callee} next bb{next} missing")))?;
    fn_ctx
        .builder
        .build_unconditional_branch(next_bb)
        .llvm_ctx_with(|| format!("{callee} intrinsic br"))?;
    Ok(())
}

/// The element type of a recv dest local's checker-resolved `Option<T>` slot.
/// The blocking-recv `Terminator::Call` intercepts derive the layout witness
/// from this — the dest type is checker-authored (MIR allocates the dest from
/// the call's declared return type), never re-inferred from a symbol name.
fn recv_dest_option_elem_ty(
    fn_ctx: &FnCtx<'_, '_>,
    dest_local: u32,
    callee: &str,
) -> CodegenResult<ResolvedTy> {
    let dest_ty = fn_ctx.local_tys.get(&dest_local).ok_or_else(|| {
        CodegenError::FailClosed(format!(
            "{callee} dest local _{dest_local} has no registered type"
        ))
    })?;
    match dest_ty {
        ResolvedTy::Named { name, args, .. } if name == "Option" && args.len() == 1 => {
            Ok(args[0].clone())
        }
        other => Err(CodegenError::FailClosed(format!(
            "{callee} dest local _{dest_local} must be a checker-resolved Option<T> \
             slot; got {other:?}"
        ))),
    }
}

/// Materialise an `Option<T>` recv result into `dest_local` through a
/// layout-witness runtime entry (`i32 sym(handle, out, witness)` — one of
/// `hew_channel_recv_layout` / `hew_channel_try_recv_layout` /
/// `hew_stream_next_layout` / `hew_stream_pop_layout` /
/// `hew_stream_try_next_layout`). One emission path for EVERY element type the
/// witness can describe — the runtime decodes the element directly into the
/// Option's Some payload slot, so there is no per-element-kind branch here.
///
/// rc 1 → Some (tag 0; the payload slot holds the decoded element, ownership
/// transferred to the consumer — the MIR drop spine releases owned payloads).
/// rc 0 → None (tag 1; the payload slot is untouched and inert — a None-tagged
/// Option never reads or drops its payload).
pub(crate) fn store_recv_option_via_layout<'ctx>(
    fn_ctx: &FnCtx<'_, 'ctx>,
    handle_ptr: inkwell::values::PointerValue<'ctx>,
    dest_local: u32,
    recv_symbol: &str,
    elem_ty: &ResolvedTy,
) -> CodegenResult<()> {
    let witness = crate::layout::channel_elem_layout_witness_ptr(fn_ctx, elem_ty, recv_symbol)?;
    let (tag_ptr, tag_ty) = place_pointer(fn_ctx, Place::EnumTag(dest_local))?;
    let BasicTypeEnum::IntType(tag_int) = tag_ty else {
        return Err(CodegenError::FailClosed(format!(
            "{recv_symbol} dest Option tag must be integer-typed; got {tag_ty:?}"
        )));
    };
    let payload_place = Place::EnumVariant {
        local: dest_local,
        variant_idx: 0,
        field_idx: 0,
    };
    let (payload_ptr, _) = place_pointer(fn_ctx, payload_place)?;
    let recv_fn = intern_runtime_decl(
        fn_ctx.ctx,
        fn_ctx.llvm_mod,
        &mut fn_ctx.runtime_decls.borrow_mut(),
        recv_symbol,
    )?;
    let rc = fn_ctx
        .builder
        .build_call(
            recv_fn,
            &[handle_ptr.into(), payload_ptr.into(), witness.into()],
            &format!("{recv_symbol}_call"),
        )
        .llvm_ctx_with(|| format!("{recv_symbol} call"))?
        .try_as_basic_value()
        .basic()
        .ok_or_else(|| CodegenError::FailClosed(format!("{recv_symbol} returned void")))?
        .into_int_value();
    let is_some = fn_ctx
        .builder
        .build_int_compare(
            IntPredicate::EQ,
            rc,
            rc.get_type().const_int(1, false),
            &format!("{recv_symbol}_is_some"),
        )
        .llvm_ctx("layout recv rc compare")?;
    // tag: Some = 0, None = 1.
    let tag_val = fn_ctx
        .builder
        .build_select(
            is_some,
            tag_int.const_zero(),
            tag_int.const_int(1, false),
            &format!("{recv_symbol}_tag"),
        )
        .llvm_ctx("layout recv tag select")?;
    fn_ctx
        .builder
        .build_store(tag_ptr, tag_val)
        .llvm_ctx("layout recv tag store")?;
    Ok(())
}

/// Store an empty `bytes` value (null ptr, offset 0, len 0) into a bytes place.
/// Used by the SuspendingRead register-error edge (no read will arrive) — the
/// EOF/empty convention the blocking `hew_tcp_read` also returns on failure.
pub(crate) fn store_empty_bytes<'ctx>(fn_ctx: &FnCtx<'_, 'ctx>, dest: Place) -> CodegenResult<()> {
    let (dest_ptr, dest_ty) = place_pointer(fn_ctx, dest)?;
    let BasicTypeEnum::StructType(struct_ty) = dest_ty else {
        return Err(CodegenError::FailClosed(format!(
            "store_empty_bytes: dest must be a bytes struct slot, got {dest_ty:?}"
        )));
    };
    fn_ctx
        .builder
        .build_store(dest_ptr, struct_ty.const_zero())
        .llvm_ctx("store empty bytes")?;
    Ok(())
}

pub(crate) fn emit_read_deadline_timeout_err(
    fn_ctx: &FnCtx<'_, '_>,
    result_dest: Place,
    error_dest: Place,
) -> CodegenResult<()> {
    let error_local = composite_dest_local(error_dest, "SuspendingRead NetError")?;
    // `NetError::TimedOut` is variant index 3 in `std/net/net.hew`
    // (ConnectionRefused=0, AddressInUse=1, AddressNotAvailable=2, TimedOut=3).
    store_composite_tag(fn_ctx, error_local, 3, "SuspendingRead NetError::TimedOut")?;
    let (payload_ptr, payload_ty) = place_pointer(
        fn_ctx,
        Place::MachineVariant {
            local: error_local,
            variant_idx: 3,
            field_idx: 0,
        },
    )?;
    let payload_int_ty = match payload_ty {
        BasicTypeEnum::IntType(t) => t,
        other => {
            return Err(CodegenError::FailClosed(format!(
                "SuspendingRead NetError::TimedOut payload must be integer, got {other:?}"
            )));
        }
    };
    fn_ctx
        .builder
        .build_store(payload_ptr, payload_int_ty.const_zero())
        .llvm_ctx("store SuspendingRead NetError::TimedOut payload")?;
    emit_result_err(fn_ctx, result_dest, error_dest)
}

/// Emit `Err(TimeoutError::Timeout)` into `result_dest` for the
/// `await rx.recv() | after d` / `await stream.recv() | after d` timeout arm
/// (L4 phase 2). `TimeoutError::Timeout` is variant 0 with no payload.
pub(crate) fn emit_recv_deadline_timeout_err(
    fn_ctx: &FnCtx<'_, '_>,
    result_dest: Place,
    error_dest: Place,
) -> CodegenResult<()> {
    let error_local = composite_dest_local(error_dest, "SuspendingChannelRecv TimeoutError")?;
    // `TimeoutError::Timeout` is variant index 0 (the only variant), no payload.
    store_composite_tag(
        fn_ctx,
        error_local,
        0,
        "SuspendingChannelRecv TimeoutError::Timeout",
    )?;
    emit_result_err(fn_ctx, result_dest, error_dest)
}

/// Store an INVALID `Connection` (NEW-2) into a pointer-shaped opaque-handle
/// slot: the integer `-1` reinterpreted as a pointer, mirroring the blocking
/// `hew_tcp_accept` error return. The accept register-error edge binds this so
/// the resumed handler sees an invalid connection (`hew_connection_is_valid`
/// rejects it) rather than a deposited handle — fail-closed, never a panic.
pub(crate) fn store_invalid_connection<'ctx>(
    fn_ctx: &FnCtx<'_, 'ctx>,
    dest: Place,
) -> CodegenResult<()> {
    let (dest_ptr, dest_ty) = place_pointer(fn_ctx, dest)?;
    let BasicTypeEnum::PointerType(ptr_ty) = dest_ty else {
        return Err(CodegenError::FailClosed(format!(
            "store_invalid_connection: dest must be a pointer-shaped Connection slot, got {dest_ty:?}"
        )));
    };
    let invalid = fn_ctx.ctx.i64_type().const_all_ones();
    let invalid_ptr = fn_ctx
        .builder
        .build_int_to_ptr(invalid, ptr_ty, "invalid_connection")
        .llvm_ctx("store invalid connection inttoptr")?;
    fn_ctx
        .builder
        .build_store(dest_ptr, invalid_ptr)
        .llvm_ctx("store invalid connection")?;
    Ok(())
}

/// Emit the call sequence for `Node::lookup<T>(name) -> Result<RemotePid<T>, LookupError>`.
///
/// The runtime extern `hew_node_api_lookup(name: *const c_char) -> u64` returns a
/// packed pid (0 == not found); user-visible code sees a Result. Codegen
/// constructs the Result in-place from the raw u64:
///   * `rc != 0` → tag=0 (Ok), variant 0 field 0 = rc as `RemotePid<T>` (u64).
///   * `rc == 0` → tag=1 (Err), variant 1 field 0 = `LookupError::NotFound`
///     (a zero-initialised `LookupError` outer struct).
///
/// This bypasses the generic `FnSymbol::Real` `dest_ty == return_ty` check,
/// which would otherwise reject the Result-typed dest against the catalog's
/// `u64` return shape. The catalog deliberately advertises the C-ABI shape so
/// `predeclare_stdlib_catalog` declares the extern with the right LLVM type;
/// the Result construction lives here, not in a new `FnSymbol` variant
/// (mirrors `RemotePid::from_raw`'s precedent of catalog-return-as-u64 +
/// user-visible-type-via-codegen).
pub(crate) fn emit_node_lookup_call<'ctx>(
    fn_ctx: &FnCtx<'_, 'ctx>,
    fn_symbols: &FnSymbolMap<'ctx>,
    args: &[Place],
    dest: Option<&Place>,
    next: u32,
) -> CodegenResult<()> {
    let symbol_entry = *fn_symbols.get("Node::lookup").ok_or_else(|| {
        CodegenError::FailClosed(
            "Node::lookup has no declared FFI symbol — predeclare_stdlib_catalog must \
             register it before Terminator::Call lowering"
                .into(),
        )
    })?;
    let (lookup_fn, _ret_ty, _returns_unit) =
        symbol_entry.real("Node::lookup", "Terminator::Call(Node::lookup)")?;
    let [name_arg] = args else {
        return Err(CodegenError::FailClosed(format!(
            "Node::lookup expects exactly 1 argument (name), got {}",
            args.len()
        )));
    };
    let dest_place = dest.ok_or_else(|| {
        CodegenError::FailClosed(
            "Node::lookup must carry a Terminator::Call dest (Result return value)".into(),
        )
    })?;
    let dest_local = match dest_place {
        Place::Local(id) => *id,
        other => {
            return Err(CodegenError::FailClosed(format!(
                "Node::lookup dest must be Place::Local(_), got {other:?}"
            )));
        }
    };

    // Load the name string (a `ptr` value stored in the arg's alloca).
    let (name_ptr_slot, name_slot_ty) = place_pointer(fn_ctx, *name_arg)?;
    let name_val = fn_ctx
        .builder
        .build_load(name_slot_ty, name_ptr_slot, "lookup_name")
        .llvm_ctx("load lookup name")?;

    // Call the runtime extern.
    let call_site = fn_ctx
        .builder
        .build_call(
            lookup_fn,
            &[metadata_value_from_basic(name_val)],
            "lookup_rc",
        )
        .llvm_ctx("hew_node_api_lookup call")?;
    let rc_basic = call_site.try_as_basic_value().basic().ok_or_else(|| {
        CodegenError::FailClosed(
            "hew_node_api_lookup returned void — expected u64 packed pid".into(),
        )
    })?;
    let rc = rc_basic.into_int_value();
    let i64_ty = fn_ctx.ctx.i64_type();
    let zero64 = i64_ty.const_zero();
    let is_zero = fn_ctx
        .builder
        .build_int_compare(IntPredicate::EQ, rc, zero64, "lookup_is_zero")
        .llvm_ctx("lookup icmp")?;

    // Build target basic blocks for the Ok/Err arms; both join at `next`.
    let parent = fn_ctx
        .builder
        .get_insert_block()
        .and_then(|bb| bb.get_parent())
        .ok_or_else(|| {
            CodegenError::FailClosed("Node::lookup call has no parent function".into())
        })?;
    let err_bb = fn_ctx.ctx.append_basic_block(parent, "lookup_err_bb");
    let ok_bb = fn_ctx.ctx.append_basic_block(parent, "lookup_ok_bb");
    fn_ctx
        .builder
        .build_conditional_branch(is_zero, err_bb, ok_bb)
        .llvm_ctx("lookup condbr")?;

    let next_bb = *fn_ctx
        .blocks
        .get(&next)
        .ok_or_else(|| CodegenError::FailClosed(format!("Node::lookup next bb{next} missing")))?;

    // --- Err branch: tag=1, payload = LookupError::NotFound ---------------
    fn_ctx.builder.position_at_end(err_bb);
    let (tag_ptr_err, tag_ty_err) = place_pointer(fn_ctx, Place::MachineTag(dest_local))?;
    let tag_int_ty_err = match tag_ty_err {
        BasicTypeEnum::IntType(t) => t,
        other => {
            return Err(CodegenError::FailClosed(format!(
                "Node::lookup dest Result tag type is not an integer: {other:?}"
            )));
        }
    };
    let tag_one = tag_int_ty_err.const_int(1, false);
    fn_ctx
        .builder
        .build_store(tag_ptr_err, tag_one)
        .llvm_ctx("store Err tag")?;
    let (err_field_ptr, err_field_ty) = place_pointer(
        fn_ctx,
        Place::MachineVariant {
            local: dest_local,
            variant_idx: 1,
            field_idx: 0,
        },
    )?;
    // `LookupError::NotFound` is variant 0 of a single-variant enum with no
    // payload — the entire `LookupError` outer struct is zero-initialised.
    let zero_lookup_err = err_field_ty.const_zero();
    fn_ctx
        .builder
        .build_store(err_field_ptr, zero_lookup_err)
        .llvm_ctx("store LookupError::NotFound")?;
    fn_ctx
        .builder
        .build_unconditional_branch(next_bb)
        .llvm_ctx("lookup err br next")?;

    // --- Ok branch: tag=0, payload = RemotePid<T>(rc as u64) --------------
    fn_ctx.builder.position_at_end(ok_bb);
    let (tag_ptr_ok, tag_ty_ok) = place_pointer(fn_ctx, Place::MachineTag(dest_local))?;
    let tag_int_ty_ok = match tag_ty_ok {
        BasicTypeEnum::IntType(t) => t,
        other => {
            return Err(CodegenError::FailClosed(format!(
                "Node::lookup dest Result tag type is not an integer: {other:?}"
            )));
        }
    };
    let tag_zero = tag_int_ty_ok.const_zero();
    fn_ctx
        .builder
        .build_store(tag_ptr_ok, tag_zero)
        .llvm_ctx("store Ok tag")?;
    let (ok_field_ptr, ok_field_ty) = place_pointer(
        fn_ctx,
        Place::MachineVariant {
            local: dest_local,
            variant_idx: 0,
            field_idx: 0,
        },
    )?;
    if !matches!(ok_field_ty, BasicTypeEnum::IntType(t) if t.get_bit_width() == 64) {
        return Err(CodegenError::FailClosed(format!(
            "Node::lookup Ok payload (RemotePid<T>) must be i64, got {ok_field_ty:?}"
        )));
    }
    fn_ctx
        .builder
        .build_store(ok_field_ptr, rc)
        .llvm_ctx("store RemotePid<T> u64")?;
    fn_ctx
        .builder
        .build_unconditional_branch(next_bb)
        .llvm_ctx("lookup ok br next")?;

    Ok(())
}

// ============================================================================
// Composite-return spine — Lane W2.004 Stage 1
// ----------------------------------------------------------------------------
//
// Four substrate helpers that synthesize user-visible composite return values
// (`Result<T, E>`, struct literals, enum-variant literals) into a destination
// `Place`. Each helper resolves the destination's registered layout
// (`EnumLayout` via `machine_layouts`, `RecordLayout` via `record_layouts`)
// and stores the tag + per-field payload through the existing
// `Place::MachineTag` / `Place::MachineVariant` / record-field projection
// substrate — no new GEP plumbing.
//
// Precedents these helpers unify (per W2.004 Stage-0 audit §C):
//   - `emit_remote_pid_tell_call` Ok-arm `llvm.rs:~7533-7551` — `emit_result_ok`
//   - `emit_remote_pid_tell_call` Err-arm `llvm.rs:~7553-7641` — `emit_result_err`
//   - `emit_node_lookup_call`     Ok-arm `llvm.rs:~7783-7819` — `emit_result_ok`
//   - `emit_node_lookup_call`     Err-arm `llvm.rs:~7747-7781` — `emit_result_err`
//   - `Instr::RecordInit` `lower_record_init` — `emit_struct_literal`
//     (no in-scope refactor; helper is the substrate for future Cluster-2
//     consumers per audit §C.3)
//   - `emit_enum_variant_literal` — no precedent; new substrate for Stage 3
//     MIR producers (W2.005).
//
// Helper signatures (push-back per A259 #3(b) vs the plan):
//   - `emit_struct_literal` uses `&[(FieldOffset, Place)]` (the MIR
//     primitive used by `Instr::RecordInit`) rather than the plan's
//     `&[(FieldName, Place)]`. `FieldName` is not a type in the MIR model;
//     name → offset resolution happens at MIR-producer time per the
//     `RecordInit` docstring (`hew-mir/src/model.rs:1747`).
//   - `emit_struct_literal` does not take `struct_name`: the registered
//     record name is recovered from `place_resolved_ty(dest)`'s
//     `ResolvedTy::Named { name, .. }`, identically to `lower_record_init`.
//
// Constraints (CLAUDE.md customs):
//   - **#2 Fail-closed Codegen**: any missing layout / mismatched type /
//     out-of-range projection surfaces `CodegenError::FailClosed` with a
//     concrete diagnostic naming the offending Place + layout. No silent
//     zero-init.
//   - **#3 Type Inference Boundary**: helpers use `place_resolved_ty`; any
//     unresolved `Ty::Var` is rejected by that function before reaching
//     here.
//   - **#1 Drop Safety**: composites written by these helpers participate
//     in the same LIFO drop machinery as ordinary records/enums
//     (`build_lifo_drops` walks `owned_locals`); no new drop scheduling is
//     needed at the helper layer. Tag-aware payload-drop for heap-owning
//     Result variants (`Result<string, string>`) is inherited scope of
//     W2.005 per plan §9.2.
//
// LESSONS: boundary-fail-closed (P0), dedup-semantic-boundary (P2),
// no-silent-no-op-stubs (P0).
// ============================================================================

/// Resolve a destination `Place` to the backing local id whose alloca
/// holds the composite outer struct. The composite helpers below all
/// project through `Place::MachineTag(local)` / `Place::MachineVariant
/// { local, .. }` against this id.
///
/// Only `Place::Local(_)` is accepted today — the same constraint the
/// existing bespoke `emit_remote_pid_tell_call` / `emit_node_lookup_call`
/// precedents enforce (`llvm.rs:~7395, ~7700`). `Place::ReturnSlot`
/// composites are constructed via a temporary local + a final `Move`,
/// not directly — keeping the projection arithmetic uniform.
pub(crate) fn composite_dest_local(dest: Place, helper: &str) -> CodegenResult<u32> {
    match dest {
        Place::Local(id) => Ok(id),
        other => Err(CodegenError::FailClosed(format!(
            "{helper} dest must be Place::Local(_) (composites materialise into a \
             named local's alloca, then move to the final slot); got {other:?}"
        ))),
    }
}

/// Store an integer discriminant at `Place::MachineTag(dest_local)`.
/// The tag's LLVM integer type is recovered from the tagged-union layout
/// via `place_pointer`. Fail-closed if the tag projection does not
/// resolve to an integer type (a structural invariant of
/// `build_tagged_union_layout`).
pub(crate) fn store_composite_tag(
    fn_ctx: &FnCtx<'_, '_>,
    dest_local: u32,
    tag_value: u64,
    helper: &str,
) -> CodegenResult<()> {
    let (tag_ptr, tag_ty) = place_pointer(fn_ctx, Place::MachineTag(dest_local))?;
    let tag_int_ty = match tag_ty {
        BasicTypeEnum::IntType(t) => t,
        other => {
            return Err(CodegenError::FailClosed(format!(
                "{helper} dest local {dest_local} tag projection resolved to non-integer \
                 type {other:?} — tagged-union outer struct field 0 must be iN per \
                 build_tagged_union_layout"
            )));
        }
    };
    fn_ctx
        .builder
        .build_store(tag_ptr, tag_int_ty.const_int(tag_value, false))
        .llvm_ctx_with(|| format!("{helper} store tag={tag_value}"))?;
    Ok(())
}

/// Copy the full value at `src` into the variant-payload field at
/// `Place::MachineVariant { local: dest_local, variant_idx, field_idx }`.
/// Source and destination LLVM types must match exactly — composites are
/// not implicitly coerced (matching `lower_record_init`'s shape check).
fn copy_into_variant_field(
    fn_ctx: &FnCtx<'_, '_>,
    src: Place,
    dest_local: u32,
    variant_idx: u32,
    field_idx: u32,
    helper: &str,
) -> CodegenResult<()> {
    let (src_ptr, src_ty) = place_pointer(fn_ctx, src)?;
    let (dst_ptr, dst_ty) = place_pointer(
        fn_ctx,
        Place::MachineVariant {
            local: dest_local,
            variant_idx,
            field_idx,
        },
    )?;
    if src_ty != dst_ty {
        return Err(CodegenError::FailClosed(format!(
            "{helper}: variant {variant_idx} field {field_idx} type mismatch: \
             dest={dst_ty:?}, src={src_ty:?}. The MIR producer must allocate the \
             source local with the same ResolvedTy as the variant-layout field."
        )));
    }
    let src_val = fn_ctx
        .builder
        .build_load(
            src_ty,
            src_ptr,
            &format!("{helper}_v{variant_idx}_f{field_idx}_src"),
        )
        .llvm_ctx_with(|| format!("{helper} variant {variant_idx} field {field_idx} load"))?;
    fn_ctx
        .builder
        .build_store(dst_ptr, src_val)
        .llvm_ctx_with(|| format!("{helper} variant {variant_idx} field {field_idx} store"))?;
    Ok(())
}

/// Emit a `Result<T, E>::Ok(payload)` (or `Ok(())` when `payload = None`)
/// into the tagged-union slot at `dest`.
///
/// `dest` must be a `Place::Local(N)` whose registered layout is the
/// `Result` outer-struct (looked up by name through `machine_layouts`
/// via the existing `MachineTag` / `MachineVariant` projections). The
/// helper stores `tag = 0` (Ok arm) and copies `payload` (when present)
/// into the Ok-variant's field 0 — matching both the Stage-0 audit
/// precedents (`emit_remote_pid_tell_call` Ok-arm with `payload = None`,
/// `emit_node_lookup_call` Ok-arm with `payload = Some(rc_local)`).
///
/// Multi-field Ok-variant payloads are not in current scope: the Result
/// variant layout always has either zero fields (unit Ok) or a single
/// field (the user-visible `T`, which may itself be a record/struct
/// whose internal fields the caller has already populated before
/// passing the source local here). This matches the audit's enumeration
/// of every `Result<_, _>` shape registered at the base commit.
pub(crate) fn emit_result_ok(
    fn_ctx: &FnCtx<'_, '_>,
    dest: Place,
    payload: Option<Place>,
) -> CodegenResult<()> {
    let dest_local = composite_dest_local(dest, "emit_result_ok")?;
    store_composite_tag(fn_ctx, dest_local, 0, "emit_result_ok")?;
    if let Some(src) = payload {
        copy_into_variant_field(fn_ctx, src, dest_local, 0, 0, "emit_result_ok")?;
    }
    Ok(())
}

/// Emit a `Result<T, E>::Err(error_payload)` into the tagged-union slot
/// at `dest`.
///
/// `dest` must be a `Place::Local(N)` whose registered layout is the
/// `Result` outer-struct. The helper stores `tag = 1` (Err arm) and
/// copies `error_payload` into the Err-variant's field 0 — matching the
/// `emit_node_lookup_call` Err-arm precedent (`LookupError::NotFound`
/// pre-populated into a zero-initialised source local). For Err
/// payloads whose discriminant must be patched (e.g. `SendError::
/// NodeRoutingNotWired`), the caller constructs the source local with
/// the discriminant already set; this helper does not synthesise
/// variant tags for the payload type.
#[allow(dead_code)] // W2.004 Stage 1 substrate; consumers in Stage 2/3 + W2.005
pub(crate) fn emit_result_err(
    fn_ctx: &FnCtx<'_, '_>,
    dest: Place,
    error_payload: Place,
) -> CodegenResult<()> {
    let dest_local = composite_dest_local(dest, "emit_result_err")?;
    store_composite_tag(fn_ctx, dest_local, 1, "emit_result_err")?;
    copy_into_variant_field(fn_ctx, error_payload, dest_local, 1, 0, "emit_result_err")?;
    Ok(())
}

/// Emit a struct literal into a `Place::Local(N)` whose registered
/// layout is a `RecordLayout`. Each `(offset, src)` pair copies the
/// source field's loaded value into the destination's struct GEP at the
/// matching field index.
///
/// This helper is the substrate face of the existing `lower_record_init`
/// inlined codegen path (`llvm.rs:5052`); it intentionally mirrors that
/// shape so a later refactor can route the inline path through this helper.
///
/// It has NO production consumer today (only the unit test below). The
/// `monitor()` composite-return spine does NOT go through here: `monitor()`
/// builds `MonitorRef { ref_id }` via the MIR producer's `Instr::RecordInit`,
/// which codegen lowers through `lower_record_init` directly — the same
/// underlying path this helper delegates to, reached without this wrapper.
/// The `#[allow(dead_code)]` is therefore load-bearing until a consumer
/// adopts the wrapper.
///
/// `dest`'s resolved type must be `ResolvedTy::Named { name, .. }`
/// keyed to a registered `RecordLayout`; the struct's field order is
/// authoritative — `field_offset.0` indexes directly into the LLVM
/// struct.
#[allow(dead_code)] // substrate wrapper over lower_record_init; no production consumer yet
fn emit_struct_literal(
    fn_ctx: &FnCtx<'_, '_>,
    dest: Place,
    fields: &[(FieldOffset, Place)],
) -> CodegenResult<()> {
    let dest_ty = place_resolved_ty(fn_ctx, dest)?.clone();
    // Delegate to the established record-init path. Reusing
    // `lower_record_init` guarantees byte-identical IR shape for any
    // RecordLayout the helper consumes (the Stage 2 refactor target).
    // `lower_record_init` already enforces:
    //   - dest slot type matches the registered struct (fail-closed if
    //     producer/codegen disagree),
    //   - source slot type matches the field type at each offset,
    //   - field offsets are in-bounds.
    // No additional validation needed here — substrate-by-delegation.
    lower_record_init(fn_ctx, &dest_ty, fields, dest)
}

/// Emit an arbitrary-variant enum literal into a `Place::Local(N)`
/// whose registered layout is the named enum's tagged-union outer
/// struct.
///
/// Stores `tag = variant_idx` and copies each `payload[i]` into the
/// destination's `MachineVariant { variant_idx, field_idx: i }`. This
/// helper has no in-tree precedent (per W2.004 Stage-0 audit §C.4) —
/// existing enum-variant construction is open-coded at MIR-producer
/// call-sites. The substrate is anchored here for the M2-stage
/// consumers (Cluster-2 link/monitor surfaces, future `MonitorRef`-style
/// composites with non-unit variants).
///
/// `payload.len()` must equal the variant's `field_tys.len()` from the
/// registered `EnumLayout`; mismatched arities are caught downstream by
/// `place_pointer`'s `MachineVariant` field-index bounds check
/// (`llvm.rs:~2092`).
#[allow(dead_code)] // W2.004 Stage 1 substrate; consumers in Stage 2/3 + W2.005
fn emit_enum_variant_literal(
    fn_ctx: &FnCtx<'_, '_>,
    dest: Place,
    variant_idx: u32,
    payload: &[Place],
) -> CodegenResult<()> {
    let dest_local = composite_dest_local(dest, "emit_enum_variant_literal")?;
    store_composite_tag(
        fn_ctx,
        dest_local,
        u64::from(variant_idx),
        "emit_enum_variant_literal",
    )?;
    for (field_idx, src) in payload.iter().enumerate() {
        let field_idx_u32 = u32::try_from(field_idx).map_err(|_| {
            CodegenError::FailClosed(format!(
                "emit_enum_variant_literal: payload length {} exceeds u32::MAX — \
                 impossible variant arity",
                payload.len()
            ))
        })?;
        copy_into_variant_field(
            fn_ctx,
            *src,
            dest_local,
            variant_idx,
            field_idx_u32,
            "emit_enum_variant_literal",
        )?;
    }
    Ok(())
}

/// The companion struct field ordinals — kept in lock-step with the runtime
/// `hew_gen_coro_destroy` byte-offset reads (`hew-runtime/src/cont.rs`). The
/// three leading `ptr` fields (handle, env, out-drop thunk) and the two trailing
/// `i8` flags (started, pending) sit at fixed offsets the runtime computes from
/// the target pointer width; only `Y out_value` has a `Y`-dependent offset, and
/// the runtime never touches it directly (it dispatches through the thunk).
const GEN_COMPANION_HANDLE_FIELD: u32 = 0;
const GEN_COMPANION_ENV_FIELD: u32 = 1;
const GEN_COMPANION_OUT_DROP_THUNK_FIELD: u32 = 2;
const GEN_COMPANION_STARTED_FIELD: u32 = 3;
const GEN_COMPANION_PENDING_FIELD: u32 = 4;
const GEN_COMPANION_OUT_VALUE_FIELD: u32 = 5;

/// The yield type `Y` and the coro-companion struct
/// `{ ptr handle, ptr env, ptr out_drop_thunk, i8 started, i8 pending, Y out }`
/// for a `Generator<Y, R>` / `AsyncGenerator<Y>` place.
///
/// A generator value on the coro substrate is a heap **companion** the
/// `Generator<Y, R>` slot points at:
///
/// - field 0 `handle` — `ptr`, the `coro.begin` frame handle (`HewCont`),
/// - field 1 `env` — `ptr`, a HEAP copy of the capture-env record (null for a
///   capture-free generator). The body reads its free variables through this
///   pointer; it is heap-owned (not the caller's stack record) so it stays valid
///   across every suspend, when the constructing frame has long returned.
/// - field 2 `out_drop_thunk` — `ptr` to the per-`Y` `void(ptr companion)` typed
///   out-drop thunk, or null when `Y` is `BitCopy` (nothing to drop). The runtime
///   destroy calls it (passing this companion) IFF `pending != 0`; the thunk GEPs
///   to `out_value` and runs the typed drop for `Y` exactly once.
/// - field 3 `started` — `i8` lazy-resume gate (0 until the first value is
///   consumed; see below),
/// - field 4 `pending` — `i8` un-consumed-yield flag. 1 while `out_value` holds
///   an owned value the consumer has not yet moved out (a `yield` is a MOVE, so
///   the companion is that value's sole owner until a `.next()` reads it); 0 once
///   consumed, or when the body completed without leaving a value pending. The
///   runtime destroy drops `out_value` only when this is non-zero — dropping a
///   consumed (`pending == 0`) value would double-free the consumer's copy.
/// - field 5 `out_value` — `Y`, the value channel the body publishes each
///   yield into and the consumer reads.
///
/// `handle`, `env`, and `out_drop_thunk` are the first three `ptr` fields
/// (offsets 0, `ptr_width`, `2*ptr_width`) and `started` / `pending` follow at
/// `3*ptr_width` / `3*ptr_width+1`, so the runtime `hew_gen_coro_destroy` reads
/// them all at fixed offsets without knowing `Y`. Only `out_value`'s offset
/// depends on `Y`, and the runtime never reads it directly.
///
/// The companion is heap-allocated at `MakeGenerator` and freed at the
/// generator's drop (after `hew_cont_destroy`), so a `Generator` value is
/// self-contained: it survives moves, stores into records, and being passed
/// across function boundaries (the prior thread-runtime handle had the same
/// single-`ptr` shape).
///
/// ## The `started` gate (lazy per-resume interleaving)
///
/// Construction pre-runs the ramp to its FIRST `yield`, so the first value is
/// already published before any `.next()`. If `.next()` resumed eagerly after
/// reading, the body would advance to its NEXT yield (running that yield's side
/// effects) BEFORE the consumer observed the current value — collapsing the
/// lazy one-value-per-resume interleaving. The `started` flag defers the resume
/// to the TOP of each `.next()` EXCEPT the first: next #1 reads the
/// pre-positioned value and sets `started`; every later `.next()` resumes first
/// (advancing the body, firing exactly that yield's effects) then reads.
///
/// `Y` is the FIRST type argument of the `Generator<Y, R>` named type. Fails
/// closed if the place is not a generator builtin or carries no type args.
fn generator_coro_companion_ty<'ctx>(
    fn_ctx: &FnCtx<'_, 'ctx>,
    gen_place: Place,
) -> CodegenResult<(BasicTypeEnum<'ctx>, inkwell::types::StructType<'ctx>)> {
    let gen_ty = place_resolved_ty(fn_ctx, gen_place)?;
    let ResolvedTy::Named {
        builtin: Some(hew_types::BuiltinType::Generator | hew_types::BuiltinType::AsyncGenerator),
        args,
        ..
    } = gen_ty
    else {
        return Err(CodegenError::FailClosed(format!(
            "generator coro companion requested for non-generator place {gen_place:?} \
             (resolved {gen_ty:?})"
        )));
    };
    let yield_ty = args.first().ok_or_else(|| {
        CodegenError::FailClosed(
            "Generator<Y, R> type carries no yield type argument — the checker must \
             have populated the yield type by construction"
                .into(),
        )
    })?;
    // A `Generator<Never, R>` never yields (a no-yield gen body); `Never` has no
    // value representation, so the out-value channel is a zero-payload stand-in
    // (`i8`) that is never written or read. Resolving `Never` directly would fail
    // ("Never type cannot occur in a value-bearing position").
    let yield_llvm = if matches!(yield_ty, ResolvedTy::Never) {
        fn_ctx.ctx.i8_type().into()
    } else {
        resolve_ty(fn_ctx.ctx, yield_ty, fn_ctx.record_layouts)?
    };
    let ptr_ty = fn_ctx.ctx.ptr_type(AddressSpace::default());
    let i8_ty = fn_ctx.ctx.i8_type();
    // `{ ptr handle, ptr env, ptr out_drop_thunk, i8 started, i8 pending, Y out }`.
    // The three `ptr` fields lead so the runtime destroy reads them (and the two
    // trailing flag bytes) at pointer-width-derived offsets without knowing `Y`.
    // Unpacked (natural alignment) so the out-value's load/store honour `Y`'s
    // alignment; the two `i8` flags pack immediately after the three pointers
    // (offsets `3*ptr_width`, `3*ptr_width+1`), matching the runtime's reads.
    let companion = fn_ctx.ctx.struct_type(
        &[
            ptr_ty.into(),
            ptr_ty.into(),
            ptr_ty.into(),
            i8_ty.into(),
            i8_ty.into(),
            yield_llvm,
        ],
        false,
    );
    Ok((yield_llvm, companion))
}

/// Synthesise (or fetch) the per-`Y` typed out-drop thunk for a generator
/// companion, or `None` when `Y` is `BitCopy` (nothing to drop).
///
/// A `yield` is lowered as a MOVE — the body publishes its value into the
/// companion `out_value` slot and never drops it — so a generator dropped while
/// an owned yielded value is still un-consumed is that value's SOLE owner. The
/// generic runtime `hew_gen_coro_destroy` cannot type-drop `out_value` without
/// knowing `Y`, so codegen plants this `void(ptr companion)` thunk in the
/// companion; the runtime calls it (passing the companion) IFF the `pending`
/// flag is set. The thunk GEPs to the companion's `out_value` field and runs the
/// typed drop for `Y` exactly once (via [`emit_heap_slot_drop`], which the
/// scope-exit drop path uses for the same value type).
///
/// Returns:
/// - `None` when `Y` owns no heap (`BitCopy`: scalars, bitcopy records/enums) —
///   the companion stores a null thunk and the runtime skips the drop.
/// - `Some(thunk)` for an owned `Y` whose typed drop `emit_heap_slot_drop`
///   expresses (`String`, `Vec<_>`, `HashMap`, `HashSet`, owned tuples/arrays).
/// - Fails closed for an owned `Y` whose typed drop is not yet expressible as a
///   single slot-drop (e.g. a directly-yielded owned user record/enum) rather
///   than silently leaking it — the same fail-closed posture
///   `emit_heap_slot_drop` takes for an un-wired leaf.
///
/// Keyed on the generator body function name (`__hew_gen_body_*`, unique per
/// generator and already deterministic), so re-emitting the same body reuses
/// one thunk. The thunk uses internal linkage (module-private).
fn gen_companion_out_drop_thunk<'ctx>(
    fn_ctx: &FnCtx<'_, 'ctx>,
    gen_place: Place,
    body_fn: &str,
    companion_ty: inkwell::types::StructType<'ctx>,
) -> CodegenResult<Option<FunctionValue<'ctx>>> {
    let gen_ty = place_resolved_ty(fn_ctx, gen_place)?;
    let ResolvedTy::Named {
        builtin: Some(hew_types::BuiltinType::Generator | hew_types::BuiltinType::AsyncGenerator),
        args,
        ..
    } = gen_ty
    else {
        return Err(CodegenError::FailClosed(format!(
            "generator out-drop thunk requested for non-generator place {gen_place:?} \
             (resolved {gen_ty:?})"
        )));
    };
    let yield_ty = args
        .first()
        .ok_or_else(|| {
            CodegenError::FailClosed(
                "Generator<Y, R> type carries no yield type argument for the out-drop \
                 thunk — the checker must have populated the yield type"
                    .into(),
            )
        })?
        .clone();
    // A `Generator<Never, R>` never yields a value; its out-channel is the `i8`
    // stand-in (never written), so there is nothing to drop.
    if matches!(yield_ty, ResolvedTy::Never) {
        return Ok(None);
    }
    // BitCopy `Y` owns no heap → no thunk; the runtime skips the drop on null.
    if !resolved_ty_contains_heap_leaf(fn_ctx, &yield_ty, &mut HashSet::new()) {
        return Ok(None);
    }

    // Owned `Y`: synthesise (or reuse) the `void(ptr companion)` thunk keyed on
    // the body function name. Internal linkage — module-private.
    let thunk_name = format!("__hew_gen_out_drop_{body_fn}");
    if let Some(existing) = fn_ctx.llvm_mod.get_function(&thunk_name) {
        return Ok(Some(existing));
    }
    let void_ptr_fn_ty = fn_ctx.ctx.void_type().fn_type(
        &[fn_ctx.ctx.ptr_type(AddressSpace::default()).into()],
        false,
    );
    let thunk = fn_ctx
        .llvm_mod
        .add_function(&thunk_name, void_ptr_fn_ty, Some(Linkage::Internal));
    let entry = fn_ctx.ctx.append_basic_block(thunk, "entry");

    // Emit the thunk body with the shared module-level codegen state, saving and
    // restoring the builder's insertion point so the surrounding MakeGenerator
    // emission continues where it left off.
    let saved_block = fn_ctx.builder.get_insert_block();
    fn_ctx.builder.position_at_end(entry);
    let companion_param = thunk
        .get_nth_param(0)
        .ok_or_else(|| {
            CodegenError::FailClosed("gen out-drop thunk missing companion param".into())
        })?
        .into_pointer_value();
    let out_value_ptr = fn_ctx
        .builder
        .build_struct_gep(
            companion_ty,
            companion_param,
            GEN_COMPANION_OUT_VALUE_FIELD,
            "gen_out_drop_value_ptr",
        )
        .map_err(|e| {
            CodegenError::FailClosed(format!("gen out-drop thunk out-value GEP failed: {e:?}"))
        })?;
    // Drop the un-consumed owned value at the out-value slot by its type. Fails
    // closed for an owned `Y` whose typed drop is not yet wired. On error the
    // builder is restored before propagating so the caller's emission is sane.
    if let Err(e) = emit_heap_slot_drop(fn_ctx, out_value_ptr, &yield_ty, 0, "gen_out_drop") {
        if let Some(block) = saved_block {
            fn_ctx.builder.position_at_end(block);
        }
        return Err(e);
    }
    // Terminate the thunk (the builder is still positioned at `entry`, after the
    // drop's straight-line emission).
    fn_ctx
        .builder
        .build_return(None)
        .llvm_ctx("gen out-drop thunk ret")?;
    if let Some(block) = saved_block {
        fn_ctx.builder.position_at_end(block);
    }
    Ok(Some(thunk))
}

/// Emit a collapsed suspension carrier from its [`SuspendKind`] side-table
/// payload. The ten pure-`{resume, cleanup}` carriers fold onto a single bare
/// [`Terminator::Suspend`]; the carrier's distinguishing payload lives in the
/// side-table and is routed here to the SAME `emit_suspending_*` ramp the
/// dedicated carrier dispatched to. `resume` / `cleanup` come from the bare
/// `Suspend` terminator (they carry the original carrier's edges); `block_id`
/// keys the `await_deadline_ns` lookup the four deadline-bearing carriers
/// consume. By construction the emitted IR is byte-identical to the
/// dedicated-carrier shape (the ramps are unchanged).
fn dispatch_collapsed_suspend<'ctx>(
    fn_ctx: &FnCtx<'_, 'ctx>,
    kind: &SuspendKind,
    resume: u32,
    cleanup: u32,
    block_id: u32,
    await_deadlines: &std::collections::HashMap<u32, i64>,
) -> CodegenResult<()> {
    match kind {
        SuspendKind::Ask {
            actor,
            msg_type,
            value,
            result_dest,
            reply_dest,
            error_dest,
        } => crate::suspend::emit_suspending_ask_terminator(
            fn_ctx,
            crate::suspend::SuspendingAskEmit {
                actor: *actor,
                msg_type: *msg_type,
                value: *value,
                result_dest: *result_dest,
                reply_dest: *reply_dest,
                error_dest: *error_dest,
                resume,
                cleanup,
                deadline_ns: await_deadlines.get(&block_id).copied(),
            },
        ),
        SuspendKind::Read {
            conn,
            result_dest,
            deadline_result_dest,
            error_dest,
            to_string,
        } => crate::suspend::emit_suspending_read_terminator(
            fn_ctx,
            crate::suspend::SuspendingReadEmit {
                conn: *conn,
                result_dest: *result_dest,
                deadline_result_dest: *deadline_result_dest,
                error_dest: *error_dest,
                to_string: *to_string,
                resume,
                cleanup,
                deadline_ns: await_deadlines.get(&block_id).copied(),
            },
        ),
        SuspendKind::StreamNext {
            stream,
            result_dest,
            elem_ty,
            deadline_result_dest,
            error_dest,
        } => crate::suspend::emit_suspending_stream_next_terminator(
            fn_ctx,
            crate::suspend::SuspendingStreamNextEmit {
                stream: *stream,
                result_dest: *result_dest,
                elem_ty: elem_ty.clone(),
                deadline_result_dest: *deadline_result_dest,
                error_dest: *error_dest,
                deadline_ns: await_deadlines.get(&block_id).copied(),
                resume,
                cleanup,
            },
        ),
        SuspendKind::ChannelRecv {
            receiver,
            result_dest,
            elem_ty,
            deadline_result_dest,
            error_dest,
        } => crate::suspend::emit_suspending_channel_recv_terminator(
            fn_ctx,
            crate::suspend::SuspendingChannelRecvEmit {
                receiver: *receiver,
                result_dest: *result_dest,
                elem_ty: elem_ty.clone(),
                deadline_result_dest: *deadline_result_dest,
                error_dest: *error_dest,
                deadline_ns: await_deadlines.get(&block_id).copied(),
                resume,
                cleanup,
            },
        ),
        SuspendKind::StreamSend { sink, value } => {
            crate::suspend::emit_suspending_stream_send_terminator(
                fn_ctx,
                crate::suspend::SuspendingStreamSendEmit {
                    sink: *sink,
                    value: *value,
                    resume,
                    cleanup,
                },
            )
        }
        SuspendKind::Accept {
            listener,
            result_dest,
            deadline_result_dest,
            error_dest,
        } => crate::suspend::emit_suspending_accept_terminator(
            fn_ctx,
            crate::suspend::SuspendingAcceptEmit {
                listener: *listener,
                result_dest: *result_dest,
                deadline_result_dest: *deadline_result_dest,
                error_dest: *error_dest,
                deadline_ns: await_deadlines.get(&block_id).copied(),
                resume,
                cleanup,
            },
        ),
        SuspendKind::CallClosure {
            callee,
            args,
            ret_ty,
            result_dest,
        } => crate::suspend::emit_suspending_call_closure_terminator(
            fn_ctx,
            crate::suspend::SuspendingCallClosureEmit {
                callee: *callee,
                args: args.clone(),
                ret_ty,
                result_dest: *result_dest,
                resume,
                cleanup,
            },
        ),
        SuspendKind::RemoteAsk {
            actor,
            msg_type,
            value,
            timeout_ms,
            result_dest,
            reply_dest,
            error_dest,
            reply_ty,
        } => crate::suspend::emit_suspending_remote_actor_ask_terminator(
            fn_ctx,
            crate::suspend::SuspendingRemoteAskEmit {
                actor: *actor,
                msg_type: *msg_type,
                value: *value,
                timeout_ms: *timeout_ms,
                result_dest: *result_dest,
                reply_dest: *reply_dest,
                error_dest: *error_dest,
                reply_ty,
                resume,
                cleanup,
            },
        ),
        SuspendKind::TaskAwait {
            scope,
            task,
            result_dest,
        } => crate::suspend::emit_suspending_task_await_terminator(
            fn_ctx,
            crate::suspend::SuspendingTaskAwaitEmit {
                scope: *scope,
                task: *task,
                result_dest: *result_dest,
                resume,
                cleanup,
            },
        ),
        SuspendKind::RestartWait {
            sup_place,
            slot_index,
            result_dest,
            deadline_result_dest: _,
        } => crate::suspend::emit_suspending_restart_wait_terminator(
            fn_ctx,
            crate::suspend::SuspendingRestartWaitEmit {
                sup_place: *sup_place,
                slot_index: *slot_index,
                result_dest: *result_dest,
                resume,
                cleanup,
            },
        ),
        SuspendKind::Sleep { duration_ns } => crate::suspend::emit_suspending_sleep_terminator(
            fn_ctx,
            crate::suspend::SuspendingSleepEmit {
                duration_ns: *duration_ns,
                resume,
                cleanup,
            },
        ),
        SuspendKind::SleepUntil { instant_ns } => {
            crate::suspend::emit_suspending_sleep_until_terminator(
                fn_ctx,
                crate::suspend::SuspendingSleepUntilEmit {
                    instant_ns: *instant_ns,
                    resume,
                    cleanup,
                },
            )
        }
    }
}

fn lower_terminator<'ctx>(
    fn_ctx: &FnCtx<'_, 'ctx>,
    fn_symbols: &FnSymbolMap<'ctx>,
    term: &Terminator,
    block_id: u32,
    await_deadlines: &std::collections::HashMap<u32, i64>,
    suspend_kinds: &std::collections::HashMap<u32, SuspendKind>,
) -> CodegenResult<()> {
    match term {
        Terminator::Return => {
            // Implicit actor-drain floor: emit `hew_shutdown_initiate(0)` then
            // `hew_shutdown_wait()` before `main` returns. This ensures
            // fire-and-forget actor messages (spawned actors, pending handler
            // calls) are fully processed before the process exits. Without this,
            // `main` returning before scheduler workers drain causes the OS to
            // kill workers mid-dispatch, silently dropping messages.
            //
            // Scoped to native actor-using programs only (`emit_drain_epilogue`
            // is false for non-actor programs and for WASM targets).
            // WHY this is a codegen special-case and not a MIR Terminator: this
            // is the implicit safe floor; the companion change adds the explicit
            // `drain`/`join{}` language surface and emits a MIR-level
            // `Terminator::Drain`, at which point this codegen arm becomes dead.
            if fn_ctx.emit_drain_epilogue {
                let i64_ty = fn_ctx.ctx.i64_type();
                let shutdown_initiate = intern_runtime_decl(
                    fn_ctx.ctx,
                    fn_ctx.llvm_mod,
                    &mut fn_ctx.runtime_decls.borrow_mut(),
                    "hew_shutdown_initiate",
                )?;
                let shutdown_wait = intern_runtime_decl(
                    fn_ctx.ctx,
                    fn_ctx.llvm_mod,
                    &mut fn_ctx.runtime_decls.borrow_mut(),
                    "hew_shutdown_wait",
                )?;
                // 0 → use DEFAULT_DRAIN_TIMEOUT_MS (5 s). The orchestrator
                // polls `drain_is_idle()` and exits early once the scheduler
                // queue has been empty for two consecutive 10 ms intervals, so
                // typical actor programs complete in <100 ms; the 5 s ceiling
                // is reached only by deliberately-never-idle actors.
                fn_ctx
                    .builder
                    .build_call(
                        shutdown_initiate,
                        &[i64_ty.const_int(0, false).into()],
                        "hew_shutdown_initiate_call",
                    )
                    .llvm_ctx("hew_shutdown_initiate call")?;
                fn_ctx
                    .builder
                    .build_call(shutdown_wait, &[], "hew_shutdown_wait_call")
                    .llvm_ctx("hew_shutdown_wait call")?;
            }
            // wasm32 cooperative-scheduler normal exit: run all runnable actors
            // to completion, then shut down scheduler state and clean up tracked
            // actors before `main` returns. The standalone-WASM analogue of the
            // native drain+cleanup exit path; see `emit_wasm_runtime_exit`.
            if fn_ctx.emit_wasm_runtime_exit {
                fn_ctx.call_runtime_void(
                    "hew_wasm_runtime_exit",
                    &[],
                    "hew_wasm_runtime_exit_call",
                    "hew_wasm_runtime_exit call",
                )?;
            }
            // Lambda-actor drain: each lambda actor runs on its own OS
            // thread outside the work-stealing scheduler, so the
            // `hew_shutdown_wait` above does not cover them. Without this
            // drain a fire-and-forget `let log = actor |s|{...}; log("hi")`
            // races process termination and silently drops the body's
            // `println`. `hew_lambda_drain_all` blocks until every
            // dispatch thread has exited (or the 5 s default timeout
            // elapses), and is a no-op when no lambda actors were
            // spawned — so emitting unconditionally on every native
            // `main` is cheap.
            if fn_ctx.emit_lambda_drain_epilogue {
                let i64_ty = fn_ctx.ctx.i64_type();
                fn_ctx.call_runtime_void(
                    "hew_lambda_drain_all",
                    &[i64_ty.const_int(0, false).into()],
                    "hew_lambda_drain_all_call",
                    "hew_lambda_drain_all call",
                )?;
            }
            // Coroutine completion (W6.010 value routing): a suspendable handler
            // does NOT `ret` its Hew value — the ramp returns the `coro.begin`
            // handle. The body DEPOSITS its logical reply value directly onto its
            // caller's reply channel here (`hew_get_reply_channel` + `hew_reply`),
            // then emits its FINAL `coro.suspend(is_final=true)` so `coro.done`
            // becomes true and the executor reclaims the frame.
            //
            // WHY body-side deposit (not the trampoline's out-slot): a suspendable
            // handler completes EITHER on the trampoline's first poll OR — for an
            // async readiness source like an actor ask — inside the scheduler's
            // `resume_park` long after the trampoline frame (and its out-slot
            // alloca) has unwound. The body owns the deposit so the reply lands
            // wherever completion happens. The scheduler installs an execution
            // context carrying the caller's reply channel for BOTH the first
            // dispatch and every resume (`resume_suspended_activation`), so
            // `hew_get_reply_channel` resolves in either case.
            if let Some(coro) = fn_ctx.coro {
                // A coroutine that already carries an explicit final suspend (a
                // generator / the synthetic substrate fixture) reaches its
                // completion through THAT suspend; this `Return` just `ret`s the
                // handle (a second final suspend would make CoroSplit reject
                // "Only one suspend point can be marked as final"). The body-side
                // reply deposit + the synthesized final suspend below are for a
                // SuspendingAsk-driven coroutine, whose natural completion IS this
                // Return (no explicit final suspend in its MIR).
                if coro.has_explicit_final_suspend {
                    fn_ctx
                        .builder
                        .build_return(Some(&coro.handle))
                        .llvm_ctx("coro explicit-final return ret handle")?;
                    return Ok(());
                }
                // SuspendingAsk-driven coroutine: this `Return` is a natural
                // completion. EVERY `Return` block converges onto the single
                // shared `final_suspend_block` instead of inlining its own reply
                // deposit + `coro.suspend(is_final=true)`. The block's predecessor
                // has already stored this path's logical reply into `return_slot`
                // (a memory alloca, so no phi is needed); the shared block loads
                // it, deposits it, and emits the ONE final suspend (filled in the
                // coroutine epilogue). Inlining a per-`Return` final suspend is
                // exactly what made CoroSplit reject multi-return handlers with
                // "Only one suspend point can be marked as final".
                let final_suspend_block = coro.final_suspend_block.ok_or_else(|| {
                    CodegenError::Llvm(
                        "SuspendingAsk coroutine `Return` has no shared final-suspend block".into(),
                    )
                })?;
                fn_ctx
                    .builder
                    .build_unconditional_branch(final_suspend_block)
                    .llvm_ctx("coro Return -> shared final suspend")?;
                return Ok(());
            }
            if let Some(shape) = fn_ctx.lambda_actor_shape {
                // Lambda-actor body return epilogue. The runtime ABI return
                // is i32 (status code); the user reply value lives in
                // `return_slot`, and for Ask shape must be serialised into
                // a freshly-allocated reply buffer wired through the
                // `reply_out` / `reply_len_out` slots (`Local(3)` /
                // `Local(4)`).
                //
                // Tell: no reply. Return i32 0 unconditionally.
                // Ask: allocate `reply_width` bytes via
                //   `hew_lambda_body_alloc_reply_buf`, write the reply
                //   value, store (buf, width) into *reply_out /
                //   *reply_len_out, return i32 0.
                let i32_ty = fn_ctx.ctx.i32_type();
                let i64_ty = fn_ctx.ctx.i64_type();
                let ptr_ty = fn_ctx.ctx.ptr_type(AddressSpace::default());
                match shape {
                    hew_mir::LambdaActorShape::Tell => {
                        fn_ctx
                            .builder
                            .build_return(Some(&i32_ty.const_zero()))
                            .llvm_ctx("lambda_actor_body Tell ret 0")?;
                        return Ok(());
                    }
                    hew_mir::LambdaActorShape::Ask => {
                        let (reply_width, _reply_align) =
                            if matches!(fn_ctx.return_resolved_ty, ResolvedTy::Unit) {
                                (0, 1)
                            } else {
                                abi_size_align(fn_ctx.return_ty, Some(fn_ctx.target_data))?
                            };
                        let alloc_fn = intern_runtime_decl(
                            fn_ctx.ctx,
                            fn_ctx.llvm_mod,
                            &mut fn_ctx.runtime_decls.borrow_mut(),
                            "hew_lambda_body_alloc_reply_buf",
                        )?;
                        let buf_ptr = fn_ctx
                            .builder
                            .build_call(
                                alloc_fn,
                                &[i64_ty.const_int(reply_width, false).into()],
                                "lambda_body_reply_alloc",
                            )
                            .llvm_ctx("hew_lambda_body_alloc_reply_buf call")?
                            .try_as_basic_value()
                            .basic()
                            .ok_or_else(|| {
                                CodegenError::FailClosed(
                                    "hew_lambda_body_alloc_reply_buf returned void".into(),
                                )
                            })?
                            .into_pointer_value();
                        // Copy the user reply value's exact ABI bytes from
                        // the return slot into the freshly-allocated reply
                        // buffer. This mirrors ordinary by-value function
                        // returns at the storage boundary without assuming
                        // the reply is an i64.
                        if reply_width != 0 {
                            fn_ctx
                                .builder
                                .build_memcpy(
                                    buf_ptr,
                                    1,
                                    fn_ctx.return_slot,
                                    1,
                                    i64_ty.const_int(reply_width, false),
                                )
                                .llvm_ctx("lambda body reply memcpy")?;
                        }
                        // Store buf_ptr into *reply_out (Local(3)) and
                        // width into *reply_len_out (Local(4)).
                        let (reply_out_slot, _) = *fn_ctx.locals.get(&3u32).ok_or_else(|| {
                            CodegenError::FailClosed(
                                "lambda actor body Ask: missing Local(3) reply_out slot".into(),
                            )
                        })?;
                        let (reply_len_out_slot, _) =
                            *fn_ctx.locals.get(&4u32).ok_or_else(|| {
                                CodegenError::FailClosed(
                                    "lambda actor body Ask: missing Local(4) reply_len_out slot"
                                        .into(),
                                )
                            })?;
                        // Local(3) / Local(4) allocas hold the OUT-PARAM
                        // pointers (`*mut *mut u8` / `*mut usize`). Load
                        // them, then store buf_ptr / width through them.
                        let reply_out_ptr = fn_ctx
                            .builder
                            .build_load(ptr_ty, reply_out_slot, "lambda_body_reply_out_ptr_load")
                            .llvm_ctx("lambda body reply_out ptr load")?
                            .into_pointer_value();
                        let reply_len_out_ptr = fn_ctx
                            .builder
                            .build_load(
                                ptr_ty,
                                reply_len_out_slot,
                                "lambda_body_reply_len_out_ptr_load",
                            )
                            .llvm_ctx("lambda body reply_len_out ptr load")?
                            .into_pointer_value();
                        fn_ctx
                            .builder
                            .build_store(reply_out_ptr, buf_ptr)
                            .llvm_ctx("lambda body *reply_out = buf_ptr")?;
                        fn_ctx
                            .builder
                            .build_store(reply_len_out_ptr, i64_ty.const_int(reply_width, false))
                            .llvm_ctx("lambda body *reply_len_out = width")?;
                        fn_ctx
                            .builder
                            .build_return(Some(&i32_ty.const_zero()))
                            .llvm_ctx("lambda_actor_body Ask ret 0")?;
                        return Ok(());
                    }
                }
            }
            if matches!(fn_ctx.return_resolved_ty, ResolvedTy::Unit) {
                fn_ctx
                    .builder
                    .build_return(Some(&fn_ctx.ctx.i8_type().const_zero()))
                    .llvm_ctx("unit ret")?;
                return Ok(());
            }
            let loaded = fn_ctx
                .builder
                .build_load(fn_ctx.return_ty, fn_ctx.return_slot, "ret_val")
                .llvm_ctx("ret load")?;
            fn_ctx.builder.build_return(Some(&loaded)).llvm_ctx("ret")?;
        }
        Terminator::Goto { target } => {
            let bb = fn_ctx.blocks.get(target).ok_or_else(|| {
                CodegenError::FailClosed(format!("goto target bb{target} not found"))
            })?;
            fn_ctx
                .builder
                .build_unconditional_branch(*bb)
                .llvm_ctx("br")?;
        }
        Terminator::Branch {
            cond,
            then_target,
            else_target,
        } => {
            let (cond_ptr, cond_ty) = place_pointer(fn_ctx, *cond)?;
            let cond_int_ty = match cond_ty {
                BasicTypeEnum::IntType(t) => t,
                _ => {
                    return Err(CodegenError::FailClosed(
                        "Branch cond is not an integer".into(),
                    ));
                }
            };
            let cond_loaded = fn_ctx
                .builder
                .build_load(cond_int_ty, cond_ptr, "cond_load")
                .llvm_ctx("cond load")?
                .into_int_value();
            let zero = cond_int_ty.const_zero();
            let nonzero = fn_ctx
                .builder
                .build_int_compare(IntPredicate::NE, cond_loaded, zero, "cond_nz")
                .llvm_ctx("icmp ne")?;
            let then_bb = *fn_ctx
                .blocks
                .get(then_target)
                .ok_or_else(|| CodegenError::FailClosed(format!("then bb{then_target} missing")))?;
            let else_bb = *fn_ctx
                .blocks
                .get(else_target)
                .ok_or_else(|| CodegenError::FailClosed(format!("else bb{else_target} missing")))?;
            fn_ctx
                .builder
                .build_conditional_branch(nonzero, then_bb, else_bb)
                .llvm_ctx("condbr")?;
        }
        Terminator::Call {
            callee,
            builtin,
            args,
            dest,
            next,
        } => {
            use hew_types::runtime_call::RuntimeCallFamily as RtFamily;
            // `Node::lookup` constructs `Result<RemotePid<T>, LookupError>` in-place
            // from the runtime extern's raw `u64` packed-pid return. The generic
            // FnSymbol::Real arm's `dest_ty == return_ty` check rejects this shape
            // (Result outer struct vs. i64), so we handle it before the symbol
            // lookup. See `emit_node_lookup_call`.
            if *builtin == Some(RtFamily::NodeLookup) {
                emit_node_lookup_call(fn_ctx, fn_symbols, args, dest.as_ref(), *next)?;
                return Ok(());
            }
            // `hew_remote_pid_tell` is the checker's MethodCallRewrite target
            // for `pid.tell(msg)` on a `RemotePid<T>` receiver.  The catalog
            // entry uses `BuiltinLinkage::CalleeNameDispatchOnly` (a fieldless
            // variant — no `symbol` field) so no LLVM extern is declared.
            // Membership in MIR's `module_fn_names` comes from the
            // non-`CompilerIntrinsic` filter at `hew-mir/src/lower.rs:761-767`,
            // which inserts every catalog entry whose linkage is not
            // `CompilerIntrinsic { .. }`.  Codegen intercepts on the carried
            // `RuntimeCallFamily::RemotePidTell` here (in the
            // `Terminator::Call` lowering arm) and emits the real
            // `hew_actor_send_by_id` sequence plus the user-visible
            // `Result<(), SendError>` construction in-place.
            // Dispatch is family-keyed (no new `FnSymbol::*Pid*` variant),
            // matching the R82-era Node::lookup precedent.
            if *builtin == Some(RtFamily::RemotePidTell) {
                emit_remote_pid_tell_call(fn_ctx, args, dest.as_ref(), *next)?;
                return Ok(());
            }
            // `hew_tcp_attach_local` is the checker's MethodCallRewrite target
            // for `conn.attach(handler)` on a `net.Connection` receiver. Codegen
            // resolves the concrete actor from the handler's `LocalPid<A>`,
            // synthesises the `on_data` / `on_close` msg_ids, and emits the
            // 4-arg runtime attach ABI. Dispatch is on the carried family,
            // matching the `hew_remote_pid_tell` precedent. `attach` returns
            // Unit, so any `dest` would be a checker-boundary bug — fail
            // closed.
            if *builtin == Some(RtFamily::TcpAttachLocal) {
                if dest.is_some() {
                    return Err(CodegenError::FailClosed(
                        "hew_tcp_attach_local (conn.attach) returns Unit and must not carry a \
                         Terminator::Call dest"
                            .into(),
                    ));
                }
                emit_tcp_attach_local_call(fn_ctx, args)?;
                let next_bb = *fn_ctx.blocks.get(next).ok_or_else(|| {
                    CodegenError::FailClosed(format!("hew_tcp_attach_local next bb{next} missing"))
                })?;
                fn_ctx
                    .builder
                    .build_unconditional_branch(next_bb)
                    .llvm_ctx("hew_tcp_attach_local br next")?;
                return Ok(());
            }
            // `stream.recv()` / `stream.try_recv()` over a `Stream<T>` and
            // `rx.recv()` / `rx.try_recv()` over a `std::channel` `Receiver<T>`
            // route to the layout-witness recv entries
            // (`i32 sym(handle, out, witness)`). In a context-bearing caller
            // `recv` already flipped to `Terminator::SuspendingStreamNext` /
            // `Terminator::SuspendingChannelRecv` (the suspend ramps); a
            // `Terminator::Call` to these symbols is the NON-SUSPENDING path:
            // a default caller's blocking `recv` (`main`/free fn — a foreign
            // thread with no parkable continuation) or any `try_recv` (which
            // never suspends — only ever lowers as a direct call). The element
            // type comes from the dest local's checker-resolved `Option<T>`
            // payload — never from the symbol name; the runtime decodes the
            // element directly into the Option's Some payload slot and the
            // return code selects the tag. Dispatch on the carried family,
            // mirroring the `Node::lookup` / `hew_remote_pid_tell` precedent.
            if matches!(
                builtin,
                Some(
                    RtFamily::StreamNextLayout
                        | RtFamily::StreamTryNextLayout
                        | RtFamily::ChannelRecvLayout
                        | RtFamily::ChannelTryRecvLayout
                )
            ) {
                let [handle_arg] = args.as_slice() else {
                    return Err(CodegenError::FailClosed(format!(
                        "{callee} expects exactly 1 argument (the handle), got {}",
                        args.len()
                    )));
                };
                let dest_place = dest.as_ref().ok_or_else(|| {
                    CodegenError::FailClosed(format!(
                        "{callee} returns Option<T>; producer must supply a dest place"
                    ))
                })?;
                let Place::Local(dest_local) = dest_place else {
                    return Err(CodegenError::FailClosed(format!(
                        "{callee} dest must be Place::Local (Option<T> enum slot), got {dest_place:?}"
                    )));
                };
                let elem_ty = recv_dest_option_elem_ty(fn_ctx, *dest_local, callee)?;
                let handle_ptr =
                    load_duplex_handle(fn_ctx, *handle_arg, &format!("{callee} handle"))?;
                store_recv_option_via_layout(fn_ctx, handle_ptr, *dest_local, callee, &elem_ty)?;
                let next_bb = *fn_ctx.blocks.get(next).ok_or_else(|| {
                    CodegenError::FailClosed(format!("{callee} next bb{next} missing"))
                })?;
                fn_ctx
                    .builder
                    .build_unconditional_branch(next_bb)
                    .llvm_ctx_with(|| format!("{callee} br next"))?;
                return Ok(());
            }
            // `tx.send(x)` over a `Sender<T>` and `sink.send(x)` over a
            // `Sink<T>` (non-{string,bytes} elements) route to the typed-
            // serialise layout entries (`void sym(handle, data_ptr, witness)`).
            // The element is deep-copied INTO the queue envelope (`clone_fn`
            // for layout-managed elements) — the caller keeps its value and
            // its scope-exit drop; the queue owns an independent copy. The
            // witness comes from the value argument's checker-resolved static
            // type, and the value travels by SLOT ADDRESS (the local's alloca
            // holds exactly the per-kind slot shape the runtime expects:
            // a string slot, a BytesTriple, raw Plain bytes, or the owned
            // representation).
            if matches!(
                builtin,
                Some(RtFamily::ChannelSendLayout | RtFamily::StreamSendLayout)
            ) {
                let [handle_arg, value_arg] = args.as_slice() else {
                    return Err(CodegenError::FailClosed(format!(
                        "{callee} expects exactly 2 arguments (handle, value), got {}",
                        args.len()
                    )));
                };
                if dest.is_some() {
                    return Err(CodegenError::FailClosed(format!(
                        "{callee} returns Unit and must not carry a Terminator::Call dest"
                    )));
                }
                let value_local = match value_arg {
                    Place::Local(local) => *local,
                    other => {
                        return Err(CodegenError::FailClosed(format!(
                            "{callee} value argument must be a Place::Local element slot, \
                             got {other:?}"
                        )));
                    }
                };
                let elem_ty = fn_ctx.local_tys.get(&value_local).cloned().ok_or_else(|| {
                    CodegenError::FailClosed(format!(
                        "{callee} value local _{value_local} has no registered type"
                    ))
                })?;
                let witness =
                    crate::layout::channel_elem_layout_witness_ptr(fn_ctx, &elem_ty, callee)?;
                let handle_ptr =
                    load_duplex_handle(fn_ctx, *handle_arg, &format!("{callee} handle"))?;
                let (value_ptr, _) = place_pointer(fn_ctx, *value_arg)?;
                let send_fn = intern_runtime_decl(
                    fn_ctx.ctx,
                    fn_ctx.llvm_mod,
                    &mut fn_ctx.runtime_decls.borrow_mut(),
                    callee,
                )?;
                fn_ctx
                    .builder
                    .build_call(
                        send_fn,
                        &[handle_ptr.into(), value_ptr.into(), witness.into()],
                        &format!("{callee}_call"),
                    )
                    .llvm_ctx_with(|| format!("{callee} call"))?;
                let next_bb = *fn_ctx.blocks.get(next).ok_or_else(|| {
                    CodegenError::FailClosed(format!("{callee} next bb{next} missing"))
                })?;
                fn_ctx
                    .builder
                    .build_unconditional_branch(next_bb)
                    .llvm_ctx_with(|| format!("{callee} br next"))?;
                return Ok(());
            }
            // Producer-gap backstop (fail-closed): the five intercepts above
            // dispatch on the carried `builtin` family. A callee whose NAME
            // is one of those intercept identities but which arrived with
            // `builtin: None` means a MIR producer minted the call without
            // threading the checker-resolved family — refuse loudly here
            // with the gap named, instead of falling through to the generic
            // symbol path (which would fail closed too, but with an
            // unrelated "no declared symbol" / dest-shape message that
            // hides the real defect). LESSONS `boundary-fail-closed`.
            if builtin.is_none() {
                if let Some(family) = RtFamily::from_c_symbol(callee) {
                    if matches!(
                        family,
                        RtFamily::NodeLookup
                            | RtFamily::RemotePidTell
                            | RtFamily::TcpAttachLocal
                            | RtFamily::StreamNextLayout
                            | RtFamily::StreamTryNextLayout
                            | RtFamily::ChannelRecvLayout
                            | RtFamily::ChannelTryRecvLayout
                            | RtFamily::ChannelSendLayout
                            | RtFamily::StreamSendLayout
                    ) {
                        return Err(CodegenError::FailClosed(format!(
                            "Terminator::Call to intercept callee `{callee}` arrived without \
                             its typed builtin family ({family:?}); the MIR producer must \
                             carry the checker-resolved RuntimeCallFamily on the call"
                        )));
                    }
                }
            }
            if let Some(intrinsic) = math_builtin_intrinsic(callee) {
                if !fn_symbols.contains_key(callee) {
                    emit_math_builtin_intrinsic_call(
                        fn_ctx,
                        callee,
                        intrinsic,
                        args,
                        dest.as_ref(),
                        *next,
                    )?;
                    return Ok(());
                }
            }
            // Closure-pair Vec element marshalling: a `Vec<fn(...)>` rides
            // the pointer-element runtime ABI with each slot holding a
            // `hew_dyn_box_alloc(16, 8)` copy of the closure pair. Detected
            // structurally by the pair-typed operand/dest (so pointer-handle
            // vecs — `Vec<LocalPid<T>>`, nested vecs — keep the generic
            // path). push/set box the pair on ingress; get borrows the pair
            // out of the slot's box; pop transfers ownership (copies the
            // pair out, frees the element box; the popped pair keeps the
            // env, whose free obligation the consumer's `let` admission
            // tracks). The scope-exit release walk is
            // `hew_vec_free_closure_pairs`.
            if is_closure_pair_vec_call(fn_ctx, callee, args, dest.as_ref())? {
                lower_closure_pair_vec_call(fn_ctx, callee, args, dest.as_ref(), *next)?;
                return Ok(());
            }
            if is_bool_vec_runtime_symbol(callee) {
                lower_bool_vec_direct_call(fn_ctx, callee, args, dest.as_ref(), *next)?;
                return Ok(());
            }
            if is_vec_constructor_symbol(callee) {
                lower_vec_constructor_call(fn_ctx, callee, args, dest.as_ref(), *next)?;
                return Ok(());
            }
            if crate::layout::is_layout_vec_runtime_symbol(callee) {
                lower_layout_vec_direct_call(fn_ctx, callee, args, dest.as_ref(), *next)?;
                return Ok(());
            }
            if is_owned_vec_runtime_symbol(callee) {
                lower_owned_vec_direct_call(fn_ctx, callee, args, dest.as_ref(), *next)?;
                return Ok(());
            }
            if is_vec_i32_get_set_symbol(callee) {
                lower_vec_i32_get_set(fn_ctx, fn_symbols, callee, args, dest.as_ref(), *next)?;
                return Ok(());
            }
            if is_hashmap_layout_probe_symbol(callee) {
                lower_hashmap_layout_probe(fn_ctx, callee, args, dest.as_ref(), *next)?;
                return Ok(());
            }
            if is_hashmap_layout_runtime_symbol(callee) {
                lower_hashmap_layout_direct_call(fn_ctx, callee, args, dest.as_ref(), *next)?;
                return Ok(());
            }
            if is_hashmap_layout_get_symbol(callee) {
                lower_hashmap_get_layout_call(fn_ctx, args, dest.as_ref(), *next)?;
                return Ok(());
            }
            if callee == "hew_vec_get_clone" {
                lower_vec_get_clone_call(fn_ctx, args, dest.as_ref(), *next)?;
                return Ok(());
            }
            if callee == "hew_bytes_get" {
                lower_bytes_get_option_call(fn_ctx, args, dest.as_ref(), *next)?;
                return Ok(());
            }
            if callee == "hew_string_get" {
                lower_string_get_option_call(fn_ctx, args, dest.as_ref(), *next)?;
                return Ok(());
            }
            if callee == "hew_hashmap_get_clone_layout" {
                lower_hashmap_index_trap_call(fn_ctx, args, dest.as_ref(), *next)?;
                return Ok(());
            }
            if is_hashmap_constructor_symbol(callee) {
                lower_hashmap_constructor_call(fn_ctx, callee, args, dest.as_ref(), *next)?;
                return Ok(());
            }
            if is_bytes_constructor_symbol(callee) {
                lower_bytes_constructor_call(fn_ctx, callee, args, dest.as_ref(), *next)?;
                return Ok(());
            }
            let callee_symbol_entry = *fn_symbols.get(callee).ok_or_else(|| {
                CodegenError::FailClosed(format!(
                    "Call to `{callee}` with no declared symbol (coroutine targets are not callable yet)"
                ))
            })?;
            match callee_symbol_entry {
                FnSymbol::PrintIntercept {
                    runtime_symbol,
                    kind,
                    newline,
                } => {
                    if dest.is_some() {
                        return Err(CodegenError::FailClosed(format!(
                            "print intercept `{callee}` must not carry a Terminator::Call dest"
                        )));
                    }
                    let [arg] = args.as_slice() else {
                        return Err(CodegenError::FailClosed(format!(
                            "print intercept `{callee}` expects exactly one argument, got {}",
                            args.len()
                        )));
                    };
                    emit_print_value_call(fn_ctx, runtime_symbol, *arg, kind, newline, callee)?;
                }
                FnSymbol::Real {
                    value,
                    return_ty,
                    returns_unit,
                } => {
                    let machine_step_queue = if is_machine_step_symbol(callee) {
                        let queue = fn_ctx.ctx.ptr_type(AddressSpace::default()).const_null();
                        emit_machine_step_enter_call(fn_ctx, queue)?;
                        Some(queue)
                    } else {
                        None
                    };
                    // ── Bytes-triple `_raw` path ─────────────────────────────────────────
                    // [2 x i64] return_ty sentinel means stored value is {callee}_raw:
                    // void(params..., out_ptr). Detect early to append dest_ptr and skip store.
                    let bytes_raw_dest_ptr = if return_ty.is_array_type() {
                        if let Some(dest_place) = dest.as_ref() {
                            let (dest_ptr, dest_ty) = place_pointer(fn_ctx, *dest_place)?;
                            if matches!(dest_ty, BasicTypeEnum::StructType(_))
                                && matches!(
                                    place_resolved_ty(fn_ctx, *dest_place)?,
                                    ResolvedTy::Bytes
                                )
                            {
                                Some(dest_ptr)
                            } else {
                                None
                            }
                        } else {
                            None
                        }
                    } else {
                        None
                    };
                    // Reconcile each loaded argument against the callee's
                    // *declared* LLVM parameter type. The Hew place may hold a
                    // wider integer (e.g. an i64 local or the i64 result of a
                    // dropped `as i32` cast after inlining) than the runtime
                    // C function declares (e.g. `hew_char_to_string(i32)` /
                    // `hew_string_char_at(.., i32)`). Without this, codegen
                    // hands an i64 to an i32 param and LLVM verification
                    // rejects the module. Signed narrow/widen keeps negative
                    // values correct for signed operands; unsigned operands
                    // must zero-extend at this boundary.
                    // NOTE: for _raw, declared_param_tys has trailing ptr; loop
                    // uses args.len() indices so it never misclassifies it.
                    let declared_param_tys = value.get_type().get_param_types();
                    let mut arg_vals: Vec<inkwell::values::BasicMetadataValueEnum> =
                        Vec::with_capacity(args.len() + usize::from(bytes_raw_dest_ptr.is_some()));
                    for (idx, arg) in args.iter().enumerate() {
                        let (arg_ptr, arg_ty) = place_pointer(fn_ctx, *arg)?;
                        // By-pointer bytes consumer: the callee declares this
                        // parameter as `ptr` while the Hew argument is a `bytes`
                        // value (a `{ptr, i32, i32}` alloca). Pass the alloca
                        // ADDRESS so the runtime reads the triple through the
                        // pointer — sidesteps the non-first by-value small-struct
                        // ABI coercion gap. See `is_bytes_by_pointer_consumer`.
                        if matches!(
                            declared_param_tys.get(idx),
                            Some(BasicMetadataTypeEnum::PointerType(_))
                        ) && matches!(arg_ty, BasicTypeEnum::StructType(_))
                            && matches!(place_resolved_ty(fn_ctx, *arg)?, ResolvedTy::Bytes)
                        {
                            arg_vals.push(metadata_value_from_basic(arg_ptr.into()));
                            continue;
                        }
                        let loaded = fn_ctx
                            .builder
                            .build_load(arg_ty, arg_ptr, "call_arg")
                            .llvm_ctx("call arg load")?;
                        let reconciled = match declared_param_tys.get(idx) {
                            Some(BasicMetadataTypeEnum::IntType(param_int)) => {
                                let arg_resolved_ty = place_resolved_ty(fn_ctx, *arg)?;
                                reconcile_int_width(
                                    fn_ctx,
                                    loaded,
                                    (*param_int).into(),
                                    !is_unsigned_integer_ty(arg_resolved_ty),
                                    "argument",
                                )?
                            }
                            _ => loaded,
                        };
                        arg_vals.push(metadata_value_from_basic(reconciled));
                    }
                    // Bytes-triple _raw: append dest_ptr as final out-param.
                    if let Some(dest_ptr) = bytes_raw_dest_ptr {
                        arg_vals.push(metadata_value_from_basic(dest_ptr.into()));
                    }
                    let call_site = fn_ctx
                        .builder
                        .build_call(value, &arg_vals, "call_result")
                        .llvm_ctx("build_call")?;
                    if bytes_raw_dest_ptr.is_some() {
                        // `_raw` wrote directly to dest_ptr; no further store needed.
                    } else if let Some(dest_place) = dest {
                        if returns_unit {
                            return Err(CodegenError::FailClosed(format!(
                                "Call to unit-returning fn `{callee}` must not carry a Terminator::Call dest"
                            )));
                        }
                        let (dest_ptr, dest_ty) = place_pointer(fn_ctx, *dest_place)?;
                        let ret_val = call_site.try_as_basic_value().basic().ok_or_else(|| {
                            CodegenError::FailClosed(
                                "Call to void-returning fn is not usable with Terminator::Call dest"
                                    .into(),
                            )
                        })?;
                        // Reconcile C-ABI return width against Hew dest width.
                        let stored = if dest_ty == return_ty {
                            // Reconcile the runtime C-ABI return width against the
                            // Hew dest width. A runtime function declared `-> i32`
                            // (e.g. `hew_string_find` / `hew_string_index_of_start`,
                            // returning the `-1` not-found sentinel) must
                            // sign-extend its result up to the Hew-facing i64 dest,
                            // so `-1` stays `-1` rather than `4294967295`. Equal
                            // widths and matching types pass through; genuinely
                            // incompatible shapes (int vs struct) still fail closed.
                            ret_val
                        } else if dest_ty.is_int_type() && return_ty.is_int_type() {
                            reconcile_int_width(fn_ctx, ret_val, dest_ty, true, "return")?
                        } else {
                            return Err(CodegenError::FailClosed(format!(
                                "Call dest type {dest_ty:?} does not match callee return {:?}",
                                return_ty
                            )));
                        };
                        fn_ctx
                            .builder
                            .build_store(dest_ptr, stored)
                            .llvm_ctx("call store")?;
                    } else if !returns_unit {
                        // `dest == None` with `!returns_unit`: the call site is
                        // in statement position and the return value is
                        // intentionally discarded (e.g. `conn.close()`,
                        // `ln.close()` → `hew_tcp_close: i32`).
                        //
                        // Allow the discard ONLY for scalar (integer/float)
                        // return types. These are BitCopy/status values with no
                        // owned heap; silently dropping the i32 is correct.
                        //
                        // For pointer or aggregate (struct) returns — which are
                        // potentially owned/heap — fail closed. The cross-crate
                        // invariant is that `hew-mir` always assigns a tracked
                        // `dest = Some` for owned/heap returns, so this arm
                        // should never be reached for those types today. This
                        // guard is the codegen-side backstop: if a future
                        // `hew-mir` regression routes an owned/pointer/aggregate
                        // return into `dest = None`, we fail loudly rather than
                        // silently leaking.
                        match return_ty {
                            BasicTypeEnum::IntType(_) | BasicTypeEnum::FloatType(_) => {
                                // Scalar status discard — intentional, safe.
                            }
                            _ => {
                                return Err(CodegenError::FailClosed(format!(
                                    "Call to value-returning fn `{callee}` must carry a \
                                     Terminator::Call dest (return type {return_ty:?} is a \
                                     pointer or aggregate; only scalar discards are allowed)"
                                )));
                            }
                        }
                    }
                    if let Some(queue) = machine_step_queue {
                        emit_machine_step_exit_call(fn_ctx, queue)?;
                    }
                }
                FnSymbol::NodeRegisterPid {
                    register_fn,
                    pid_fn,
                } => {
                    // Two-step lowering per R81:
                    //   step 1: pid_u64 = hew_actor_pid(actor_ptr)
                    //   step 2: result  = hew_node_api_register_by_pid(name_ptr, pid_u64)
                    //
                    // The `LocalPid<T>` alloca is a `ptr` (not u64); we must
                    // load it as a pointer value and pass it to `hew_actor_pid`
                    // before passing the numeric PID to the register extern.
                    let [name_arg, pid_arg] = args.as_slice() else {
                        return Err(CodegenError::FailClosed(format!(
                            "Node::register expects exactly 2 arguments (name, pid), got {}",
                            args.len()
                        )));
                    };
                    let dest_place = dest.as_ref().ok_or_else(|| {
                        CodegenError::FailClosed(
                            "Node::register (i32-returning) must carry a Terminator::Call dest"
                                .into(),
                        )
                    })?;

                    // Load the name string pointer (ptr-typed alloca).
                    let (name_ptr, name_ty) = place_pointer(fn_ctx, *name_arg)?;
                    let name_val = fn_ctx
                        .builder
                        .build_load(name_ty, name_ptr, "reg_name")
                        .llvm_ctx("load reg name")?;

                    // Load the LocalPid<T> alloca as a raw pointer.
                    let (actor_alloca_ptr, actor_alloca_ty) = place_pointer(fn_ctx, *pid_arg)?;
                    let actor_ptr = fn_ctx
                        .builder
                        .build_load(actor_alloca_ty, actor_alloca_ptr, "reg_actor_ptr")
                        .llvm_ctx("load LocalPid<T> ptr")?;

                    // Step 1: extract the u64 PID from the actor pointer.
                    let pid_call = fn_ctx
                        .builder
                        .build_call(pid_fn, &[metadata_value_from_basic(actor_ptr)], "actor_pid")
                        .llvm_ctx("hew_actor_pid call")?;
                    let pid_u64 = pid_call.try_as_basic_value().basic().ok_or_else(|| {
                        CodegenError::FailClosed(
                            "hew_actor_pid returned void — expected u64".into(),
                        )
                    })?;

                    // Step 2: register by PID.
                    let reg_call = fn_ctx
                        .builder
                        .build_call(
                            register_fn,
                            &[
                                metadata_value_from_basic(name_val),
                                metadata_value_from_basic(pid_u64),
                            ],
                            "reg_result",
                        )
                        .llvm_ctx("hew_node_api_register_by_pid call")?;
                    let reg_i32 = reg_call.try_as_basic_value().basic().ok_or_else(|| {
                        CodegenError::FailClosed(
                            "hew_node_api_register_by_pid returned void — expected i32".into(),
                        )
                    })?;

                    // Store the i32 return value into the destination.
                    let (dest_ptr, dest_ty) = place_pointer(fn_ctx, *dest_place)?;
                    let i32_ty = fn_ctx.ctx.i32_type();
                    if dest_ty != BasicTypeEnum::IntType(i32_ty) {
                        return Err(CodegenError::FailClosed(format!(
                            "Node::register dest type {dest_ty:?} does not match i32"
                        )));
                    }
                    fn_ctx
                        .builder
                        .build_store(dest_ptr, reg_i32)
                        .llvm_ctx("store reg result")?;
                }
            }
            let next_bb = *fn_ctx
                .blocks
                .get(next)
                .ok_or_else(|| CodegenError::FailClosed(format!("Call next bb{next} missing")))?;
            fn_ctx
                .builder
                .build_unconditional_branch(next_bb)
                .llvm_ctx("call br")?;
        }
        Terminator::Trap { kind } => {
            if matches!(*kind, TrapKind::MachineDispatchUnreachable) {
                // Machine step dispatch is HIR-exhaustive. The residual
                // fallthrough block is therefore impossible in well-typed
                // programs and must not surface as a user-visible trap code.
                fn_ctx
                    .builder
                    .build_unreachable()
                    .llvm_ctx("machine dispatch unreachable")?;
                return Ok(());
            }
            // The exit-code constants here are single-sourced from the runtime
            // (`hew-runtime/src/internal/types.rs`) via the module-level
            // `HEW_TRAP_*` import, so a renumber on either side is a build
            // error rather than a silently-desynced literal. The runtime
            // constants are `i32`; `emit_trap_with_code` takes `u64`.
            let code: u64 = match *kind {
                TrapKind::IntegerOverflow => HEW_TRAP_INTEGER_OVERFLOW as u64,
                TrapKind::DivideByZero => HEW_TRAP_DIVIDE_BY_ZERO as u64,
                TrapKind::SignedMinDivNegOne => HEW_TRAP_SIGNED_MIN_DIV_NEG_ONE as u64,
                TrapKind::ShiftOutOfRange => HEW_TRAP_SHIFT_OUT_OF_RANGE as u64,
                TrapKind::IndexOutOfBounds => HEW_TRAP_INDEX_OUT_OF_BOUNDS as u64,
                TrapKind::SupervisorChildUnavailable => HEW_TRAP_ACTOR_SEND_FAILED as u64,
                TrapKind::MachineDispatchUnreachable => {
                    HEW_TRAP_MACHINE_DISPATCH_UNREACHABLE as u64
                }
                TrapKind::ExhaustivenessFallthrough => HEW_TRAP_EXHAUSTIVENESS_FALLTHROUGH as u64,
            };
            emit_trap_with_code(fn_ctx, code, "trap")?;
        }
        Terminator::Yield { value, next } => {
            // Generator suspension on the `llvm.coro.*` continuation substrate.
            //
            // Producer contract (`lower_gen_block`): the gen-body function is a
            // coroutine ramp whose `Local(0)` is the out-pointer `*mut Y` — the
            // value channel. Each `yield` publishes its value there then suspends:
            //   1. Load `out = Local(0)` (the consumer's companion out-slot).
            //   2. Store `value` into `*out` (the yielded value rides the frame
            //      out-pointer — NOT `hew_cont_poll`'s out_value arg, which the
            //      runtime accepts and ignores; the body owns the publish).
            //   3. `coro.suspend(resume = next, cleanup, suspend_return,
            //      is_final = false)` via `CoroContext::emit_suspend`. Control
            //      returns to the executor (consumer); a `hew_cont_resume` lands
            //      on `next` (case 0); a `hew_cont_destroy` tears the frame down
            //      through the shared cleanup epilogue (case 1).
            //
            // The yielded value is COPIED into `*out` (a value store), never a
            // pointer to a body-local slot that is dead across the suspend.
            // CoroSplit spills the body's cross-suspend-live locals into the heap
            // frame automatically; the out-slot lives in the consumer's companion
            // (heap), reachable after every resume.
            let coro = fn_ctx.coro.ok_or_else(|| {
                CodegenError::FailClosed(
                    "Terminator::Yield reached codegen but the function carries no \
                     coro prologue state — lower_function must detect the Yield \
                     carrier (has_suspend) and emit the coro prologue before the body"
                        .into(),
                )
            })?;
            // The out-pointer parameter slot (Local(0)). Loaded as an opaque
            // `ptr`; its pointee is the yield type `Y`.
            let (out_slot, _out_slot_ty) = fn_ctx.locals.get(&0).copied().ok_or_else(|| {
                CodegenError::FailClosed(
                    "Terminator::Yield: gen-body coroutine ramp has no Local(0) \
                     out-pointer parameter — `lower_gen_block` must prepend the \
                     out-pointer `*mut Y` as the ramp's first parameter"
                        .to_string(),
                )
            })?;
            let ptr_ty = fn_ctx.ctx.ptr_type(AddressSpace::default());
            let out_ptr = fn_ctx
                .builder
                .build_load(ptr_ty, out_slot, "gen_out_ptr")
                .llvm_ctx("gen out-pointer load")?
                .into_pointer_value();
            // Publish the yielded value to `*out`. `place_load_value` reads the
            // value out of `value`'s slot at its resolved LLVM type; the store
            // copies it into the consumer-owned out-slot.
            let (value_ptr, value_ty) = place_pointer(fn_ctx, *value)?;
            let yielded = fn_ctx
                .builder
                .build_load(value_ty, value_ptr, "gen_yield_value")
                .llvm_ctx("gen yield value load")?;
            fn_ctx
                .builder
                .build_store(out_ptr, yielded)
                .llvm_ctx("gen yield value publish")?;
            // Suspend (non-final). The resume edge is the MIR `next` block; the
            // destroy edge routes to the shared single-teardown cleanup epilogue.
            let resume_bb = *fn_ctx
                .blocks
                .get(next)
                .ok_or_else(|| CodegenError::FailClosed(format!("Yield next bb{next} missing")))?;
            let cc = crate::coro::CoroContext {
                ctx: fn_ctx.ctx,
                llvm_mod: fn_ctx.llvm_mod,
                builder: &fn_ctx.builder,
                function: fn_ctx
                    .builder
                    .get_insert_block()
                    .and_then(|bb| bb.get_parent())
                    .ok_or_else(|| {
                        CodegenError::Llvm("yield block has no parent function".into())
                    })?,
                handle: coro.handle,
                id_token: coro.id_token,
            };
            cc.emit_suspend(
                resume_bb,
                coro.cleanup_block,
                coro.suspend_return_block,
                false,
                "gen_yield",
            )?;
        }
        Terminator::MakeGenerator {
            dest,
            body_fn,
            next,
            env,
        } => {
            // Generator construction on the `llvm.coro.*` continuation
            // substrate. The MIR producer (`lower_gen_block`) emitted this
            // terminator with the deterministic `__hew_gen_body_*` body-fn name;
            // that body is an `llvm.coro` ramp (it carries `Terminator::Yield`,
            // detected by `is_coroutine` in `declare_function`, so its LLVM
            // return type is the `coro.begin` handle `ptr` and its leading param
            // is the out-pointer `*mut Y`, optionally followed by the env ptr).
            //
            // Construction shape (mirrors the proven `coro_emission_exec`
            // driver):
            //   1. Heap-allocate the companion `{ ptr handle, ptr env,
            //      ptr out_drop_thunk, i8 started, i8 pending, Y out_value }` via
            //      `hew_cont_frame_alloc` — the `Generator<Y, R>` value points at
            //      it. Plant the per-`Y` out-drop thunk (null for BitCopy `Y`).
            //   2. Call `__hew_gen_body(&companion.out_value, env_ptr?)`. The
            //      ramp runs the body to its FIRST `coro.suspend` (the first
            //      `yield`, with the first value already published to
            //      `*out_value`) and returns the `coro.begin` handle.
            //   3. Store the returned handle into `companion.handle` and set
            //      `pending` from the post-ramp done state (a suspended body has a
            //      live un-consumed yield in `out_value`).
            //   4. Store the companion pointer into the `Generator<Y, R>` slot.
            //
            // The env (capture record) is passed by ADDRESS into the ramp's
            // env param: the coro frame is single-owner (no body thread), so the
            // body reads the caller's env record directly while constructing the
            // frame — no deep-copy/thread-boundary protocol is needed. Captures
            // are plain-copyable only (`gen_env_capture_admissible` fail-closes
            // owned and opaque captures), so the body's env reads are read-only
            // views and there is no per-field clone or env-field drop.
            let body_function = fn_ctx.llvm_mod.get_function(body_fn).ok_or_else(|| {
                CodegenError::FailClosed(format!(
                    "Terminator::MakeGenerator: generator body fn `{body_fn}` was not \
                     declared before its construction site — `lower_gen_block` must \
                     register the `__hew_gen_body_*` function in the pipeline"
                ))
            })?;
            let ptr_ty = fn_ctx.ctx.ptr_type(AddressSpace::default());

            // The body must be a coroutine RAMP — it returns the `coro.begin`
            // handle (`ptr`). A body with no `yield` (a `Generator<Never, R>`
            // no-yield gen) is NOT a coroutine (no suspend carrier), so its LLVM
            // return is its logical type, not a handle. Such a generator never
            // suspends or yields and is not iterable (`for x in g` over a `Never`
            // yield is rejected by the checker); lowering its construction is not
            // yet supported. Fail closed with a precise diagnostic rather than
            // mis-driving a non-ramp call as a coro handle.
            if !matches!(
                body_function.get_type().get_return_type(),
                Some(BasicTypeEnum::PointerType(_))
            ) {
                return Err(CodegenError::Unsupported(
                    "a generator body with no `yield` (a never-yielding \
                     `Generator<Never, R>`) is not lowerable: it is not a \
                     coroutine and cannot be iterated. Add at least one `yield`, \
                     or use a plain function for a value-returning computation",
                ));
            }

            // ── 1. Heap-allocate the companion via `hew_cont_frame_alloc`. ──
            // The companion `{ ptr handle, ptr env, ptr out_drop_thunk, i8 started,
            // i8 pending, Y out_value }` is allocated through the SAME
            // size-headered allocator the coro frame uses, so its scope-exit drop
            // (`hew_gen_coro_destroy` → `hew_cont_frame_free`) is symmetric without
            // separate size bookkeeping. `hew_cont_frame_alloc` 16-byte-aligns
            // every block, which covers `Y`'s alignment for every Hew scalar /
            // pointer / aggregate (the same invariant the coro frame itself relies
            // on, `cont.rs` FRAME_ALIGN).
            let (_yield_llvm, companion_ty) = generator_coro_companion_ty(fn_ctx, *dest)?;
            let companion_size = companion_ty.size_of().ok_or_else(|| {
                CodegenError::FailClosed(
                    "generator coro companion struct has no static size".into(),
                )
            })?;
            let companion = fn_ctx.call_runtime_ptr(
                "hew_cont_frame_alloc",
                &[companion_size.into()],
                "gen_companion_alloc",
                "gen companion hew_cont_frame_alloc call",
            )?;

            // ── 2. Init the `started` gate (field 3) to 0: the consumer's first
            // `.next()` reads the pre-positioned first value WITHOUT resuming.
            let started_ptr = fn_ctx
                .builder
                .build_struct_gep(
                    companion_ty,
                    companion,
                    GEN_COMPANION_STARTED_FIELD,
                    "gen_companion_started_ptr",
                )
                .map_err(|e| {
                    CodegenError::FailClosed(format!("gen companion started GEP failed: {e:?}"))
                })?;
            fn_ctx
                .builder
                .build_store(started_ptr, fn_ctx.ctx.i8_type().const_zero())
                .llvm_ctx("gen companion started init")?;

            // ── 2b. Plant the per-`Y` typed out-drop thunk (field 2). Null when
            // `Y` is `BitCopy` (nothing to drop). The runtime destroy calls it
            // (passing this companion) IFF `pending != 0`, so a generator dropped
            // while an owned yielded value is still un-consumed releases it
            // exactly once instead of leaking. Fails closed for an owned `Y`
            // whose typed drop is not yet expressible as a single thunk. ──
            let out_drop_thunk =
                gen_companion_out_drop_thunk(fn_ctx, *dest, body_fn, companion_ty)?;
            let thunk_ptr = fn_ctx
                .builder
                .build_struct_gep(
                    companion_ty,
                    companion,
                    GEN_COMPANION_OUT_DROP_THUNK_FIELD,
                    "gen_companion_out_drop_thunk_ptr",
                )
                .map_err(|e| {
                    CodegenError::FailClosed(format!(
                        "gen companion out-drop-thunk GEP failed: {e:?}"
                    ))
                })?;
            let thunk_value: BasicValueEnum = match out_drop_thunk {
                Some(thunk_fn) => thunk_fn.as_global_value().as_pointer_value().into(),
                None => fn_ctx
                    .ctx
                    .ptr_type(AddressSpace::default())
                    .const_null()
                    .into(),
            };
            fn_ctx
                .builder
                .build_store(thunk_ptr, thunk_value)
                .llvm_ctx("gen companion out-drop-thunk store")?;

            // ── 3. Heap-copy the capture env (field 1) and assemble ramp args. ──
            // The body reads its free variables through the env pointer ACROSS
            // suspends, long after this constructing frame has returned — so the
            // env MUST be heap-owned, not the caller's stack record. Heap-copy the
            // env into a fresh block now (the caller's record is live HERE), store
            // its pointer in the companion (freed by `hew_gen_coro_destroy`), and
            // pass THAT to the ramp. Captures are plain-copyable only
            // (`gen_env_capture_admissible` rejects owned/opaque), so a flat
            // memcpy + flat free is sound — no per-field clone or drop.
            let env_field_ptr = fn_ctx
                .builder
                .build_struct_gep(
                    companion_ty,
                    companion,
                    GEN_COMPANION_ENV_FIELD,
                    "gen_companion_env_ptr",
                )
                .map_err(|e| {
                    CodegenError::FailClosed(format!("gen companion env GEP failed: {e:?}"))
                })?;
            let out_value_ptr = fn_ctx
                .builder
                .build_struct_gep(
                    companion_ty,
                    companion,
                    GEN_COMPANION_OUT_VALUE_FIELD,
                    "gen_companion_out_ptr",
                )
                .map_err(|e| {
                    CodegenError::FailClosed(format!("gen companion out-value GEP failed: {e:?}"))
                })?;
            let mut ramp_args: Vec<BasicMetadataValueEnum> = vec![out_value_ptr.into()];
            match env {
                None => {
                    // Capture-free: no env. Null the companion env field so the
                    // destroy's `hew_dealloc(null)` is a no-op.
                    fn_ctx
                        .builder
                        .build_store(env_field_ptr, ptr_ty.const_null())
                        .llvm_ctx("gen companion env null")?;
                }
                Some(env_place) => {
                    let (env_slot, env_slot_ty) = place_pointer(fn_ctx, *env_place)?;
                    let BasicTypeEnum::StructType(env_struct) = env_slot_ty else {
                        return Err(CodegenError::FailClosed(format!(
                            "MakeGenerator env place {env_place:?} is not struct-typed \
                             (got {env_slot_ty:?}); the capture env must be the \
                             RecordInit'd env record"
                        )));
                    };
                    let env_size = env_struct.size_of().ok_or_else(|| {
                        CodegenError::FailClosed(
                            "MakeGenerator env struct has no static size".into(),
                        )
                    })?;
                    // Allocate the heap env through the size-headered
                    // `hew_cont_frame_alloc`, so `hew_gen_coro_destroy` frees it
                    // via the symmetric `hew_cont_frame_free` without separate
                    // (size, align) bookkeeping. 16-byte aligned — covers the env
                    // record's alignment (plain-copyable fields only).
                    let env_alloc_fn = intern_runtime_decl(
                        fn_ctx.ctx,
                        fn_ctx.llvm_mod,
                        &mut fn_ctx.runtime_decls.borrow_mut(),
                        "hew_cont_frame_alloc",
                    )?;
                    let heap_env = fn_ctx
                        .builder
                        .build_call(env_alloc_fn, &[env_size.into()], "gen_env_alloc")
                        .llvm_ctx("gen env hew_cont_frame_alloc call")?
                        .try_as_basic_value()
                        .basic()
                        .ok_or_else(|| {
                            CodegenError::FailClosed("hew_cont_frame_alloc returned void".into())
                        })?
                        .into_pointer_value();
                    fn_ctx
                        .builder
                        .build_memcpy(heap_env, 1, env_slot, 1, env_size)
                        .map_err(|e| {
                            CodegenError::FailClosed(format!(
                                "MakeGenerator env memcpy failed: {e:?}"
                            ))
                        })?;
                    fn_ctx
                        .builder
                        .build_store(env_field_ptr, heap_env)
                        .llvm_ctx("gen companion env store")?;
                    ramp_args.push(heap_env.into());
                }
            }
            let gen_handle = fn_ctx
                .builder
                .build_call(body_function, &ramp_args, "gen_body_ramp_call")
                .llvm_ctx("generator coro ramp call")?
                .try_as_basic_value()
                .basic()
                .ok_or_else(|| {
                    CodegenError::FailClosed(
                        "generator coro ramp returned void; a coroutine ramp must return \
                         its coro.begin handle (ptr)"
                            .into(),
                    )
                })?
                .into_pointer_value();

            // ── 3. Store the handle into `companion.handle` (field 0). ──
            let handle_ptr = fn_ctx
                .builder
                .build_struct_gep(
                    companion_ty,
                    companion,
                    GEN_COMPANION_HANDLE_FIELD,
                    "gen_companion_handle_ptr",
                )
                .map_err(|e| {
                    CodegenError::FailClosed(format!("gen companion handle GEP failed: {e:?}"))
                })?;
            fn_ctx
                .builder
                .build_store(handle_ptr, gen_handle)
                .llvm_ctx("gen companion handle store")?;

            // ── 3b. Init the `pending` flag (field 4). The ramp pre-ran the body
            // to its first `yield` (or to completion). If the body suspended at a
            // yield (`!hew_cont_done(handle)`), the value it published into
            // `out_value` is a live, un-consumed owned value the companion now
            // SOLELY owns (a `yield` is a MOVE; the body never drops it). Set
            // `pending = 1` so a drop before the first `.next()` releases it via
            // the typed thunk instead of leaking. A body that ran to completion
            // without yielding leaves nothing pending (`pending = 0`); the
            // checker rejects a truly no-yield generator, so in practice the
            // pre-run always suspends at the first yield, but deriving `pending`
            // from `done` keeps the flag honest for any body shape. ──
            let done_fn = intern_runtime_decl(
                fn_ctx.ctx,
                fn_ctx.llvm_mod,
                &mut fn_ctx.runtime_decls.borrow_mut(),
                "hew_cont_done",
            )?;
            let done_after_ramp = fn_ctx
                .builder
                .build_call(done_fn, &[gen_handle.into()], "gen_companion_ramp_done")
                .llvm_ctx("gen companion post-ramp hew_cont_done call")?
                .try_as_basic_value()
                .basic()
                .ok_or_else(|| CodegenError::FailClosed("hew_cont_done returned void".into()))?
                .into_int_value();
            // pending = (done == 0) ? 1 : 0, narrowed to i8.
            let i8_ty = fn_ctx.ctx.i8_type();
            let not_done = fn_ctx
                .builder
                .build_int_compare(
                    inkwell::IntPredicate::EQ,
                    done_after_ramp,
                    done_after_ramp.get_type().const_zero(),
                    "gen_companion_pending_bit",
                )
                .llvm_ctx("gen companion pending compare")?;
            let pending_init = fn_ctx
                .builder
                .build_int_z_extend_or_bit_cast(not_done, i8_ty, "gen_companion_pending_i8")
                .llvm_ctx("gen companion pending zext")?;
            let pending_ptr = fn_ctx
                .builder
                .build_struct_gep(
                    companion_ty,
                    companion,
                    GEN_COMPANION_PENDING_FIELD,
                    "gen_companion_pending_ptr",
                )
                .map_err(|e| {
                    CodegenError::FailClosed(format!("gen companion pending GEP failed: {e:?}"))
                })?;
            fn_ctx
                .builder
                .build_store(pending_ptr, pending_init)
                .llvm_ctx("gen companion pending init")?;

            // ── 4. Store the companion ptr into the `Generator<Y, R>` slot. ──
            let (dest_slot, _dest_ty) = place_pointer(fn_ctx, *dest)?;
            fn_ctx
                .builder
                .build_store(dest_slot, companion)
                .llvm_ctx("generator companion ptr store")?;
            let _ = ptr_ty;
            let next_bb = *fn_ctx.blocks.get(next).ok_or_else(|| {
                CodegenError::FailClosed(format!("MakeGenerator next bb{next} missing"))
            })?;
            fn_ctx
                .builder
                .build_unconditional_branch(next_bb)
                .llvm_ctx("MakeGenerator br next")?;
        }
        Terminator::MakeLambdaActor {
            dest,
            body_fn,
            state_drop_fn,
            shape,
            mailbox_capacity,
            next,
            env,
            env_field_drops,
        } => {
            // Lambda-actor construction (`hew-runtime/src/lambda_actor.rs`).
            // The MIR producer (`lower_spawn_lambda_actor`) emitted this
            // terminator with the deterministic `__hew_lambda_body_*` body-fn
            // name and the state-drop name; codegen resolves the body
            // function's address and calls `hew_lambda_actor_new(mailbox_cap,
            // shape, body_fn, state, state_drop_fn)`, storing the returned
            // `*mut HewLambdaActorHandle` into `dest`. The constructed
            // handle's drop (`hew_lambda_actor_release`) is scheduled at
            // scope exit by the enclosing function's LIFO drop plan via
            // `place_aware_drop_fn`.
            //
            // The state arg is null for a capture-free lambda. With captures
            // (`env` is Some) this site owns the WHOLE env heap protocol:
            //   1. malloc(sizeof(env_struct)) and memcpy the stack record in.
            //   2. String fields: replace the copied alias with an
            //      independent `hew_string_clone` — the env owns its copy,
            //      the caller's binding keeps the original.
            //   3. Weak self fields: store null (the handle does not exist
            //      yet) — back-filled with the DOWNGRADED weak handle after
            //      construction, before any message can be dispatched (the
            //      first send happens-after this block in program order and
            //      the mailbox channel publishes the write).
            //   4. Synthesize the per-env `state_drop_fn`: field drops
            //      (`hew_string_drop` / `hew_lambda_actor_weak_drop`) then
            //      `free(env)`. The runtime calls it exactly once after the
            //      dispatch loop stops (`lifecycle-symmetry`); body-side
            //      capture reads are non-owning views
            //      (`ffi-ownership-contracts`).
            let body_function = fn_ctx.llvm_mod.get_function(body_fn).ok_or_else(|| {
                CodegenError::FailClosed(format!(
                    "Terminator::MakeLambdaActor: body fn `{body_fn}` was not declared \
                     before its construction site — `lower_spawn_lambda_actor` must \
                     register the `__hew_lambda_body_*` function in the pipeline"
                ))
            })?;
            let ptr_ty = fn_ctx.ctx.ptr_type(AddressSpace::default());
            let i64_ty = fn_ctx.ctx.i64_type();
            let i32_ty = fn_ctx.ctx.i32_type();

            // ── Env boxing (steps 1-3) ──
            let env_struct_and_heap: Option<(StructType, PointerValue)> = match env {
                None => None,
                Some(env_place) => {
                    let (env_slot, env_slot_ty) = place_pointer(fn_ctx, *env_place)?;
                    let BasicTypeEnum::StructType(env_struct) = env_slot_ty else {
                        return Err(CodegenError::FailClosed(format!(
                            "MakeLambdaActor env place {env_place:?} is not struct-typed \
                             (got {env_slot_ty:?}); the capture env must be the \
                             RecordInit'd anonymous env record"
                        )));
                    };
                    if env_field_drops.len() != env_struct.get_field_types().len() {
                        return Err(CodegenError::FailClosed(format!(
                            "MakeLambdaActor env drop-class count {} does not match env \
                             field count {} — producer and layout drifted",
                            env_field_drops.len(),
                            env_struct.get_field_types().len()
                        )));
                    }
                    let env_size = env_struct.size_of().ok_or_else(|| {
                        CodegenError::FailClosed(
                            "MakeLambdaActor env struct has no static size".into(),
                        )
                    })?;
                    let size_ty = runtime_size_ty(fn_ctx.ctx, fn_ctx.llvm_mod);
                    let env_size_arg = reconcile_int_width_signed(
                        fn_ctx,
                        env_size.into(),
                        size_ty.into(),
                        "lambda env malloc size",
                    )?;
                    let malloc_fn = get_or_declare_libc_malloc(fn_ctx.ctx, fn_ctx.llvm_mod);
                    let heap_env = fn_ctx
                        .builder
                        .build_call(malloc_fn, &[env_size_arg.into()], "lambda_env_malloc")
                        .llvm_ctx("lambda env malloc call")?
                        .try_as_basic_value()
                        .basic()
                        .ok_or_else(|| CodegenError::FailClosed("malloc returned void".into()))?
                        .into_pointer_value();
                    fn_ctx
                        .builder
                        .build_memcpy(heap_env, 1, env_slot, 1, env_size)
                        .map_err(|e| {
                            CodegenError::FailClosed(format!(
                                "MakeLambdaActor env memcpy failed: {e:?}"
                            ))
                        })?;
                    for (idx, drop_class) in env_field_drops.iter().enumerate() {
                        let field_idx = u32::try_from(idx).map_err(|_| {
                            CodegenError::FailClosed(
                                "lambda env field count exceeds u32::MAX".into(),
                            )
                        })?;
                        match drop_class {
                            LambdaEnvFieldDrop::None => {}
                            LambdaEnvFieldDrop::String => {
                                let field_ptr = fn_ctx
                                    .builder
                                    .build_struct_gep(
                                        env_struct,
                                        heap_env,
                                        field_idx,
                                        &format!("lambda_env_str_{idx}_ptr"),
                                    )
                                    .llvm_ctx("lambda env string field gep")?;
                                let alias = fn_ctx
                                    .builder
                                    .build_load(
                                        ptr_ty,
                                        field_ptr,
                                        &format!("lambda_env_str_{idx}_alias"),
                                    )
                                    .llvm_ctx("lambda env string alias load")?;
                                let clone_fn = fn_ctx
                                    .llvm_mod
                                    .get_function("hew_string_clone")
                                    .unwrap_or_else(|| {
                                        fn_ctx.llvm_mod.add_function(
                                            "hew_string_clone",
                                            ptr_ty.fn_type(&[ptr_ty.into()], false),
                                            Some(Linkage::External),
                                        )
                                    });
                                let owned = fn_ctx
                                    .builder
                                    .build_call(
                                        clone_fn,
                                        &[alias.into()],
                                        &format!("lambda_env_str_{idx}_clone"),
                                    )
                                    .llvm_ctx("lambda env string clone call")?
                                    .try_as_basic_value()
                                    .basic()
                                    .ok_or_else(|| {
                                        CodegenError::FailClosed(
                                            "hew_string_clone returned void".into(),
                                        )
                                    })?;
                                fn_ctx
                                    .builder
                                    .build_store(field_ptr, owned)
                                    .llvm_ctx("lambda env string clone store")?;
                            }
                            LambdaEnvFieldDrop::WeakSelfHandle => {
                                let field_ptr = fn_ctx
                                    .builder
                                    .build_struct_gep(
                                        env_struct,
                                        heap_env,
                                        field_idx,
                                        &format!("lambda_env_weak_{idx}_ptr"),
                                    )
                                    .llvm_ctx("lambda env weak field gep")?;
                                fn_ctx
                                    .builder
                                    .build_store(field_ptr, ptr_ty.const_null())
                                    .llvm_ctx("lambda env weak field null store")?;
                            }
                        }
                    }
                    Some((env_struct, heap_env))
                }
            };

            // ── State-drop function (step 4) ──
            let drop_function = match fn_ctx.llvm_mod.get_function(state_drop_fn) {
                Some(f) => f,
                None if state_drop_fn == "__hew_lambda_state_drop_noop" => {
                    let void_ty = fn_ctx.ctx.void_type();
                    let fn_ty = void_ty.fn_type(&[ptr_ty.into()], false);
                    let func = fn_ctx.llvm_mod.add_function(
                        "__hew_lambda_state_drop_noop",
                        fn_ty,
                        Some(inkwell::module::Linkage::Internal),
                    );
                    let entry_bb = fn_ctx.ctx.append_basic_block(func, "entry");
                    let nested_builder = fn_ctx.ctx.create_builder();
                    nested_builder.position_at_end(entry_bb);
                    nested_builder
                        .build_return(None)
                        .llvm_ctx("lambda state-drop noop ret void")?;
                    func
                }
                None if env_struct_and_heap.is_some() => {
                    let (env_struct, _) = env_struct_and_heap
                        .as_ref()
                        .expect("guarded by match arm condition");
                    crate::thunks::emit_lambda_env_dropper(
                        fn_ctx.ctx,
                        fn_ctx.llvm_mod,
                        state_drop_fn,
                        *env_struct,
                        env_field_drops,
                    )?
                }
                None => {
                    return Err(CodegenError::FailClosed(format!(
                        "Terminator::MakeLambdaActor: state-drop fn `{state_drop_fn}` was \
                         not declared before its construction site and the terminator \
                         carries no env to synthesize it from — producer and codegen \
                         drifted on the state-drop contract"
                    )));
                }
            };
            let body_fn_ptr = body_function.as_global_value().as_pointer_value();
            let drop_fn_ptr = drop_function.as_global_value().as_pointer_value();
            let state_arg: PointerValue = env_struct_and_heap
                .as_ref()
                .map_or_else(|| ptr_ty.const_null(), |(_, heap)| *heap);
            let mailbox_const = i64_ty.const_int(u64::from(*mailbox_capacity), false);
            // i32 shape — sign-extended widening matches the cabi i32 ABI.
            // JUSTIFIED: MIR's lambda-actor producer emits only 0 (Tell) or 1 (Ask);
            // fail closed here if that invariant drifts instead of defaulting to Tell.
            let shape_u32 = u32::try_from(*shape).map_err(|_| {
                CodegenError::FailClosed(format!(
                    "Terminator::MakeLambdaActor: lambda-actor shape must be 0 or 1, got {shape}"
                ))
            })?;
            if !matches!(shape_u32, 0 | 1) {
                return Err(CodegenError::FailClosed(format!(
                    "Terminator::MakeLambdaActor: lambda-actor shape must be 0 or 1, got {shape}"
                )));
            }
            let shape_const = i32_ty.const_int(u64::from(shape_u32), false);
            let handle = fn_ctx.call_runtime_basic(
                "hew_lambda_actor_new",
                &[
                    mailbox_const.into(),
                    shape_const.into(),
                    body_fn_ptr.into(),
                    state_arg.into(),
                    drop_fn_ptr.into(),
                ],
                "hew_lambda_actor_new_call",
                "hew_lambda_actor_new call",
            )?;
            let (dest_slot, _dest_ty) = place_pointer(fn_ctx, *dest)?;
            fn_ctx
                .builder
                .build_store(dest_slot, handle)
                .llvm_ctx("hew_lambda_actor_new handle store")?;

            // ── Weak self back-fill (step 3, second half) ──
            if let Some((env_struct, heap_env)) = &env_struct_and_heap {
                for (idx, drop_class) in env_field_drops.iter().enumerate() {
                    if !matches!(drop_class, LambdaEnvFieldDrop::WeakSelfHandle) {
                        continue;
                    }
                    let field_idx = u32::try_from(idx).map_err(|_| {
                        CodegenError::FailClosed("lambda env field count exceeds u32::MAX".into())
                    })?;
                    let weak = fn_ctx.call_runtime_basic(
                        "hew_lambda_actor_downgrade",
                        &[handle.into()],
                        &format!("lambda_env_weak_{idx}_downgrade"),
                        "hew_lambda_actor_downgrade call",
                    )?;
                    let field_ptr = fn_ctx
                        .builder
                        .build_struct_gep(
                            *env_struct,
                            *heap_env,
                            field_idx,
                            &format!("lambda_env_weak_{idx}_fill_ptr"),
                        )
                        .llvm_ctx("lambda env weak back-fill gep")?;
                    fn_ctx
                        .builder
                        .build_store(field_ptr, weak)
                        .llvm_ctx("lambda env weak back-fill store")?;
                }
            }

            let next_bb = *fn_ctx.blocks.get(next).ok_or_else(|| {
                CodegenError::FailClosed(format!("MakeLambdaActor next bb{next} missing"))
            })?;
            fn_ctx
                .builder
                .build_unconditional_branch(next_bb)
                .llvm_ctx("MakeLambdaActor br next")?;
        }
        Terminator::Send {
            actor,
            msg_type,
            value,
            next,
            // `alias_mode` is deliberately UNCONSUMED by codegen today. It is
            // the checker-authoritative alias-vs-copy classification stamped
            // by MIR lowering (P5.1 threading; contract pinned by
            // `hew-mir/tests/send_alias_mode.rs`), reserved for the
            // retain-on-share send spine (P5.2) — which will retain the
            // payload's heap reference on an `Alias` send instead of the
            // plain mailbox memcpy below. Every send today lowers to
            // `hew_actor_send_by_id` regardless of this field: the only
            // payload special-case is the `send_gated_string` borrow retain
            // below, which rides the SEPARATE `borrow_mode`/`borrow_tainted`
            // mechanism (string-only roots in `compute_borrow_taint`; bytes
            // never enter that branch). `--explain-cow` renders from the
            // checker's `actor_send_aliasing` map (`hew-cli/src/explain_cow.rs`),
            // not from this field, so ignoring it here changes no diagnostic
            // output. Consuming it without wiring the retain would either be
            // a no-op or an unbalanced refcount — bind it `_` until P5.2
            // lands (LESSONS: checker-authority / codegen-abi-authority).
            alias_mode: _,
        } => {
            let actor_ptr = load_duplex_handle(fn_ctx, *actor, "actor_send receiver")?;
            let actor_id = load_actor_id(fn_ctx, actor_ptr)?;
            // P5-RX Stage 2a (A625): a borrowed-String receive view that
            // escapes into a re-send must take its OWN owner — the new envelope
            // the runtime builds from this payload releases its buffer, which
            // would double-free the original envelope-owned buffer. Under
            // `borrow_mode != 0` retain via `hew_string_clone` into a scratch
            // slot and send that; under `borrow_mode == 0` (copy mode) send the
            // handler's private handle exactly as before.
            let send_gated_string = matches!(
                fn_ctx.borrow_mode.zip(place_base_local(value)),
                Some((_, base)) if fn_ctx.borrow_tainted.contains(&base)
            );
            let (payload_ptr, payload_size) = if send_gated_string {
                let borrow_mode = fn_ctx
                    .borrow_mode
                    .expect("send_gated_string implies borrow_mode is Some");
                let (src_ptr, src_ty) = place_pointer(fn_ctx, *value)?;
                let handle = fn_ctx
                    .builder
                    .build_load(src_ty, src_ptr, "actor_send_payload_load")
                    .llvm_ctx("actor send payload load")?;
                let owner =
                    emit_borrow_gated_string_clone(fn_ctx, borrow_mode, handle, "send_payload")?;
                let ptr_ty = fn_ctx.ctx.ptr_type(AddressSpace::default());
                let scratch =
                    build_entry_alloca(fn_ctx, ptr_ty.into(), "actor_send_payload_scratch")?;
                fn_ctx
                    .builder
                    .build_store(scratch, owner)
                    .llvm_ctx("actor send scratch store")?;
                let size = ptr_ty.size_of();
                (scratch, size)
            } else {
                actor_payload_ptr_size(fn_ctx, *value, "actor_send_payload")?
            };
            let send = intern_runtime_decl(
                fn_ctx.ctx,
                fn_ctx.llvm_mod,
                &mut fn_ctx.runtime_decls.borrow_mut(),
                "hew_actor_send_by_id",
            )?;
            // `payload_size` is built as i64; the `size` param is `usize`/
            // `size_t` (i32 on wasm32). Reconcile to the target-correct width.
            let size_ty = runtime_size_ty(fn_ctx.ctx, fn_ctx.llvm_mod);
            let payload_size = reconcile_int_width_signed(
                fn_ctx,
                payload_size.into(),
                size_ty.into(),
                "actor send payload size",
            )?;
            let msg_type = fn_ctx.ctx.i32_type().const_int(*msg_type as u64, false);
            // Bind the i32 return value. A nonzero status means the recipient
            // was gone, the mailbox was full, or the remote partition rejected
            // the message. We must not silently proceed — that could leave the
            // caller operating on stale state or attempting a follow-up ask
            // on a dead actor.
            // `Terminator::Send` targets a LOCAL actor handle (`ActorRef`/`Pid`);
            // it delivers into a local mailbox and never reaches the cross-node
            // serialize path (that is the `RemotePid<T>` `emit_remote_pid_tell_call`
            // spine). So the `(dispatch, msg_type)` codec key is irrelevant here —
            // pass a null dispatch, which the local send path ignores.
            let null_dispatch = fn_ctx.ctx.ptr_type(AddressSpace::default()).const_null();
            let send_status = fn_ctx
                .builder
                .build_call(
                    send,
                    &[
                        actor_id.into(),
                        null_dispatch.into(),
                        msg_type.into(),
                        payload_ptr.into(),
                        payload_size.into(),
                    ],
                    "hew_actor_send_by_id_call",
                )
                .llvm_ctx("hew_actor_send_by_id call")?
                .try_as_basic_value()
                .basic()
                .ok_or_else(|| {
                    CodegenError::FailClosed("hew_actor_send_by_id returned void".into())
                })?
                .into_int_value();

            // Branch: status == 0 → next_bb; status != 0 → send_fail_bb.
            let send_fail_bb = fn_ctx
                .builder
                .get_insert_block()
                .and_then(|bb| bb.get_parent())
                .map(|f| fn_ctx.ctx.append_basic_block(f, "actor_send_fail"))
                .ok_or_else(|| CodegenError::Llvm("send block has no parent function".into()))?;
            let zero = fn_ctx.ctx.i32_type().const_zero();
            let send_failed = fn_ctx
                .builder
                .build_int_compare(
                    inkwell::IntPredicate::NE,
                    send_status,
                    zero,
                    "actor_send_failed",
                )
                .llvm_ctx("send status cmp")?;

            let next_bb = *fn_ctx
                .blocks
                .get(next)
                .ok_or_else(|| CodegenError::FailClosed(format!("Send next bb{next} missing")))?;
            fn_ctx
                .builder
                .build_conditional_branch(send_failed, send_fail_bb, next_bb)
                .llvm_ctx("send status branch")?;

            fn_ctx.builder.position_at_end(send_fail_bb);
            emit_trap_with_code(fn_ctx, HEW_TRAP_ACTOR_SEND_FAILED as u64, "actor_send_fail")?;
        }
        Terminator::Ask {
            actor,
            msg_type,
            value,
            result_dest,
            reply_dest,
            error_dest,
            next,
        } => {
            let actor_ptr = load_duplex_handle(fn_ctx, *actor, "actor_ask receiver")?;
            let (payload_ptr, payload_size) =
                actor_payload_ptr_size(fn_ctx, *value, "actor_ask_payload")?;
            let ask = intern_runtime_decl(
                fn_ctx.ctx,
                fn_ctx.llvm_mod,
                &mut fn_ctx.runtime_decls.borrow_mut(),
                "hew_actor_ask",
            )?;
            let msg_type_val = fn_ctx.ctx.i32_type().const_int(*msg_type as u64, false);
            // `payload_size` is built as i64; the `size` param is `usize`/
            // `size_t` (i32 on wasm32). Reconcile to the target-correct width.
            let ask_size_ty = runtime_size_ty(fn_ctx.ctx, fn_ctx.llvm_mod);
            let payload_size = reconcile_int_width_signed(
                fn_ctx,
                payload_size.into(),
                ask_size_ty.into(),
                "actor ask payload size",
            )?;
            let reply_ptr = fn_ctx
                .builder
                .build_call(
                    ask,
                    &[
                        actor_ptr.into(),
                        msg_type_val.into(),
                        payload_ptr.into(),
                        payload_size.into(),
                    ],
                    "hew_actor_ask_call",
                )
                .llvm_ctx("hew_actor_ask call")?
                .try_as_basic_value()
                .basic()
                .ok_or_else(|| CodegenError::FailClosed("hew_actor_ask returned void".into()))?
                .into_pointer_value();
            let parent = fn_ctx
                .builder
                .get_insert_block()
                .and_then(|bb| bb.get_parent())
                .ok_or_else(|| CodegenError::Llvm("ask block has no parent function".into()))?;
            let ok_bb = fn_ctx.ctx.append_basic_block(parent, "actor_ask_reply_ok");
            let err_bb = fn_ctx.ctx.append_basic_block(parent, "actor_ask_reply_err");
            let is_null = fn_ctx
                .builder
                .build_is_null(reply_ptr, "actor_ask_reply_is_null")
                .llvm_ctx("ask null compare")?;
            fn_ctx
                .builder
                .build_conditional_branch(is_null, err_bb, ok_bb)
                .llvm_ctx("ask result branch")?;

            let next_bb = *fn_ctx
                .blocks
                .get(next)
                .ok_or_else(|| CodegenError::FailClosed(format!("Ask next bb{next} missing")))?;

            // Ok path: load reply value → store into reply_dest → emit Result::Ok.
            fn_ctx.builder.position_at_end(ok_bb);
            let (dest_ptr, dest_ty) = place_pointer(fn_ctx, *reply_dest)?;
            let reply_val = fn_ctx
                .builder
                .build_load(dest_ty, reply_ptr, "actor_ask_reply_value")
                .llvm_ctx("ask reply load")?;
            fn_ctx
                .builder
                .build_store(dest_ptr, reply_val)
                .llvm_ctx("ask reply store")?;
            emit_result_ok(fn_ctx, *result_dest, Some(*reply_dest))?;
            let free = get_or_declare_free(fn_ctx);
            fn_ctx
                .builder
                .build_call(free, &[reply_ptr.into()], "actor_ask_reply_free")
                .llvm_ctx("free ask reply")?;
            fn_ctx
                .builder
                .build_unconditional_branch(next_bb)
                .llvm_ctx("ask ok br")?;

            // Err path: call hew_actor_ask_take_last_error → store tag into
            // error_dest → emit Result::Err(error_dest).
            fn_ctx.builder.position_at_end(err_bb);
            let err_fn = intern_runtime_decl(
                fn_ctx.ctx,
                fn_ctx.llvm_mod,
                &mut fn_ctx.runtime_decls.borrow_mut(),
                "hew_actor_ask_take_last_error",
            )?;
            let err_code = fn_ctx
                .builder
                .build_call(err_fn, &[], "hew_actor_ask_take_last_error_call")
                .llvm_ctx("hew_actor_ask_take_last_error call")?
                .try_as_basic_value()
                .basic()
                .ok_or_else(|| {
                    CodegenError::FailClosed("hew_actor_ask_take_last_error returned void".into())
                })?
                .into_int_value();
            let error_local = composite_dest_local(*error_dest, "Ask AskError")?;
            let (error_tag_ptr, error_tag_ty) =
                place_pointer(fn_ctx, Place::MachineTag(error_local))?;
            let error_tag_int_ty = match error_tag_ty {
                BasicTypeEnum::IntType(t) => t,
                other => {
                    return Err(CodegenError::FailClosed(format!(
                        "Ask AskError tag projection must be integer, got {other:?}"
                    )));
                }
            };
            let err_code = match err_code
                .get_type()
                .get_bit_width()
                .cmp(&error_tag_int_ty.get_bit_width())
            {
                std::cmp::Ordering::Equal => err_code,
                std::cmp::Ordering::Less => fn_ctx
                    .builder
                    .build_int_z_extend(err_code, error_tag_int_ty, "ask_err_zext")
                    .llvm_ctx("ask err zext")?,
                std::cmp::Ordering::Greater => fn_ctx
                    .builder
                    .build_int_truncate(err_code, error_tag_int_ty, "ask_err_trunc")
                    .llvm_ctx("ask err trunc")?,
            };
            fn_ctx
                .builder
                .build_store(error_tag_ptr, err_code)
                .llvm_ctx("store Ask AskError tag")?;
            emit_result_err(fn_ctx, *result_dest, *error_dest)?;
            fn_ctx
                .builder
                .build_unconditional_branch(next_bb)
                .llvm_ctx("ask err br")?;
        }
        // The ten pure-{resume,cleanup} suspension carriers collapsed onto the
        // bare `Terminator::Suspend` arm below, which reads the `SuspendKind`
        // side-table and routes to the SAME `emit_suspending_*` ramp via
        // `dispatch_collapsed_suspend`.
        Terminator::RemoteAsk {
            actor,
            msg_type,
            value,
            timeout_ms,
            result_dest,
            reply_dest,
            error_dest,
            reply_ty,
            next,
        } => crate::suspend::emit_remote_actor_ask_terminator(
            fn_ctx,
            crate::suspend::RemoteAskEmit {
                actor: *actor,
                msg_type: *msg_type,
                value: *value,
                timeout_ms: *timeout_ms,
                result_dest: *result_dest,
                reply_dest: *reply_dest,
                error_dest: *error_dest,
                reply_ty,
                next: *next,
            },
        )?,
        Terminator::Select { arms, .. } => {
            emit_select_terminator(fn_ctx, arms)?;
        }
        Terminator::SuspendingSelect {
            arms,
            resume,
            cleanup,
        } => {
            emit_suspending_select_terminator(fn_ctx, arms, *resume, *cleanup)?;
        }
        Terminator::Join {
            branches,
            result,
            next,
        } => {
            emit_join_terminator(fn_ctx, branches, *result, *next)?;
        }
        Terminator::Suspend {
            resume,
            cleanup,
            is_final,
        } => {
            // A collapsed suspension carrier: its distinguishing payload lives in
            // the `suspend_kinds` side-table keyed by this block. Route it to the
            // SAME `emit_suspending_*` ramp the dedicated carrier dispatched to —
            // byte-identical emission by construction (the ramps are unchanged).
            // A bare `Suspend` with NO side-table entry is a generator / synthetic
            // substrate suspend, handled by the direct `coro.suspend` path below.
            if let Some(kind) = suspend_kinds.get(&block_id) {
                dispatch_collapsed_suspend(
                    fn_ctx,
                    kind,
                    *resume,
                    *cleanup,
                    block_id,
                    await_deadlines,
                )?;
                return Ok(());
            }
            // Stackless suspend point (R326/R327). Emit `coro.suspend` + the
            // 3-way switch. The function's coro prologue (emitted in
            // `lower_function` when the MIR carries this terminator) must have
            // populated `fn_ctx.coro`; a `Suspend` without it is a producer that
            // ran ahead of the prologue — fail closed rather than emit a dangling
            // suspend (boundary-fail-closed; the R2 silent-no-op guard).
            let coro = fn_ctx.coro.ok_or_else(|| {
                CodegenError::FailClosed(
                    "Terminator::Suspend reached codegen but the function carries \
                     no coro prologue state — lower_function must detect the \
                     suspend carrier and emit the prologue before the body"
                        .into(),
                )
            })?;
            let resume_bb = *fn_ctx.blocks.get(resume).ok_or_else(|| {
                CodegenError::FailClosed(format!("suspend resume target bb{resume} not found"))
            })?;
            // Validate the MIR `cleanup` target exists (carrier well-formedness)
            // even though the case-1 destroy edge routes to the single-teardown
            // epilogue below. The MIR `cleanup` block is the drop-elaboration
            // block (frame-owned-value drops); it is lowered as a normal block
            // and is the seam the source-driven suspend (NEW-3) routes its
            // pre-teardown drops through. The single teardown OWNER — the only
            // place that emits `coro.free`+`coro.end` — is the codegen
            // `coro.cleanup_block` epilogue (single-owner discipline,
            // `cont.rs`); routing case-1 straight there keeps exactly one
            // teardown edge per frame.
            if !fn_ctx.blocks.contains_key(cleanup) {
                return Err(CodegenError::FailClosed(format!(
                    "suspend cleanup target bb{cleanup} not found"
                )));
            }
            let cc = crate::coro::CoroContext {
                ctx: fn_ctx.ctx,
                llvm_mod: fn_ctx.llvm_mod,
                builder: &fn_ctx.builder,
                function: fn_ctx
                    .builder
                    .get_insert_block()
                    .and_then(|bb| bb.get_parent())
                    .ok_or_else(|| {
                        CodegenError::Llvm("suspend block has no parent function".into())
                    })?,
                handle: coro.handle,
                id_token: coro.id_token,
            };
            cc.emit_suspend(
                resume_bb,
                coro.cleanup_block,
                coro.suspend_return_block,
                *is_final,
                "coro",
            )?;
        }
        Terminator::SuspendingScopeDeadline {
            scope,
            duration_ms,
            timeout_body_block,
            resume,
            cleanup,
        } => crate::suspend::emit_suspending_scope_deadline_terminator(
            fn_ctx,
            crate::suspend::SuspendingScopeDeadlineEmit {
                scope: *scope,
                duration_ms: *duration_ms,
                timeout_body_block: *timeout_body_block,
                resume: *resume,
                cleanup: *cleanup,
            },
        )?,
    }
    Ok(())
}

/// Emit the LLVM IR for `Terminator::Select` with `ActorAsk` +
/// optional `AfterTimer` arms.
///
/// Producer contract (`Terminator::Select { arms, next }`):
/// - Every arm carries `body_block` (the block reached on win) and
///   `binding` (the per-arm reply slot for `ActorAsk` arms; `None`
///   for `AfterTimer`).
/// - At most one `AfterTimer` arm is present (HIR enforces).
/// - `StreamNext` / `TaskAwait` arms are not in scope for this change
///   and remain fail-closed below (defence-in-depth — the MIR
///   producer rejects them before this codegen runs).
///
/// Emitted shape (per slice 3 plan §6 + runtime ABI). For each
/// `ActorAsk` arm: allocate `ch = hew_reply_channel_new()`, store
/// into a stack array slot, then call `hew_actor_ask_with_channel`.
/// If that call returns non-zero, branch to a mid-setup error
/// recovery block that frees every channel allocated so far and
/// traps (Risk R3). Read the AfterTimer arm's duration if present,
/// convert ns → ms, saturate to `i32::MAX`; otherwise use -1
/// (wait indefinitely). Call `hew_select_first(arr, n_asks, timeout_ms)`
/// to get the winner index. Dispatch via switch: an ActorAsk arm
/// index routes to that arm's winner block; the default routes to
/// the AfterTimer winner block (when present) or a trap. In each
/// winner block, `hew_reply_wait(ch[winner])` reads the reply, the
/// value is stored into `arm.binding`'s slot, `libc::free(reply_ptr)`
/// releases the buffer, and `hew_reply_channel_free(ch[winner])`
/// releases the channel. For every loser j, `hew_reply_channel_cancel(ch[j])`
/// runs BEFORE `hew_reply_channel_free(ch[j])` — Risk R4: cancel
/// before free prevents UAF when a reply races our free.
/// Finally each winner block branches to the arm's MIR-allocated
/// `body_block`.
fn stream_callback_type_suffix(item_ty: BasicTypeEnum<'_>) -> String {
    let mut hash = 0xcbf29ce484222325_u64;
    for byte in item_ty.print_to_string().to_string().bytes() {
        hash ^= u64::from(byte);
        hash = hash.wrapping_mul(0x100000001b3);
    }
    format!("{hash:016x}")
}

fn get_or_create_select_stream_callback<'ctx>(
    fn_ctx: &FnCtx<'_, 'ctx>,
    item_ty: BasicTypeEnum<'ctx>,
) -> CodegenResult<FunctionValue<'ctx>> {
    let callback_name = format!(
        "hew_select_stream_reply_ready_{}",
        stream_callback_type_suffix(item_ty)
    );
    if let Some(fv) = fn_ctx.llvm_mod.get_function(&callback_name) {
        return Ok(fv);
    }

    let ctx = fn_ctx.ctx;
    let ptr_ty = ctx.ptr_type(AddressSpace::default());
    let i64_ty = ctx.i64_type();
    // Target-correct `usize`/`size_t`: i32 on wasm32, i64 on native.
    // Used to reconcile the `size` parameter of `hew_reply` to its actual ABI width.
    let reply_size_ty = runtime_size_ty(ctx, fn_ctx.llvm_mod);
    let item_size = item_ty.size_of().ok_or_else(|| {
        CodegenError::FailClosed(format!(
            "stream callback item type has no static size: {item_ty:?}"
        ))
    })?;
    let fn_ty = ctx
        .void_type()
        .fn_type(&[ptr_ty.into(), ptr_ty.into()], false);
    let callback = fn_ctx
        .llvm_mod
        .add_function(&callback_name, fn_ty, Some(Linkage::Private));
    let entry = ctx.append_basic_block(callback, "entry");
    let null_item_bb = ctx.append_basic_block(callback, "null_item");
    let non_null_bb = ctx.append_basic_block(callback, "non_null");
    let delivered_bb = ctx.append_basic_block(callback, "delivered");
    let not_delivered_bb = ctx.append_basic_block(callback, "not_delivered");
    let free_item_bb = ctx.append_basic_block(callback, "free_item");
    let return_bb = ctx.append_basic_block(callback, "return");

    let builder = ctx.create_builder();
    builder.position_at_end(entry);
    let ch = callback
        .get_nth_param(0)
        .ok_or_else(|| CodegenError::Llvm("stream callback missing channel param".into()))?
        .into_pointer_value();
    let item = callback
        .get_nth_param(1)
        .ok_or_else(|| CodegenError::Llvm("stream callback missing item param".into()))?
        .into_pointer_value();
    let item_is_null = builder
        .build_is_null(item, "stream_item_is_null")
        .llvm_ctx("stream callback item null cmp")?;
    builder
        .build_conditional_branch(item_is_null, null_item_bb, non_null_bb)
        .llvm_ctx("stream callback item null branch")?;

    let reply = intern_runtime_decl(
        ctx,
        fn_ctx.llvm_mod,
        &mut fn_ctx.runtime_decls.borrow_mut(),
        "hew_reply",
    )?;

    builder.position_at_end(null_item_bb);
    builder
        .build_call(
            reply,
            &[
                ch.into(),
                ptr_ty.const_null().into(),
                // null-item path: size is zero; use the target-correct zero width.
                reply_size_ty.const_zero().into(),
            ],
            "stream_reply_null_item",
        )
        .llvm_ctx("stream callback null hew_reply call")?;
    builder
        .build_unconditional_branch(return_bb)
        .llvm_ctx("stream callback null return")?;

    builder.position_at_end(non_null_bb);
    let item_value = builder
        .build_load(item_ty, item, "stream_item_value")
        .llvm_ctx("stream callback item load")?;
    let item_slot = builder
        .build_alloca(item_ty, "stream_item_slot")
        .llvm_ctx("stream callback item slot alloca")?;
    builder
        .build_store(item_slot, item_value)
        .llvm_ctx("stream callback item store")?;
    // Reconcile item_size (always i64 from LLVM size_of) to the target-correct
    // `usize`/`size_t` width required by `hew_reply`'s `size` parameter.
    let item_size = if item_size.get_type() == reply_size_ty {
        item_size
    } else if reply_size_ty.get_bit_width() < i64_ty.get_bit_width() {
        builder
            .build_int_truncate(item_size, reply_size_ty, "stream_item_size_trunc")
            .llvm_ctx("stream callback item size trunc")?
    } else {
        builder
            .build_int_z_extend(item_size, reply_size_ty, "stream_item_size_zext")
            .llvm_ctx("stream callback item size zext")?
    };
    let delivered = builder
        .build_call(
            reply,
            &[ch.into(), item_slot.into(), item_size.into()],
            "stream_reply_delivered",
        )
        .llvm_ctx("stream callback hew_reply call")?
        .try_as_basic_value()
        .basic()
        .ok_or_else(|| CodegenError::FailClosed("hew_reply returned void".into()))?
        .into_int_value();
    builder
        .build_conditional_branch(delivered, delivered_bb, not_delivered_bb)
        .llvm_ctx("stream callback delivered branch")?;

    builder.position_at_end(delivered_bb);
    builder
        .build_unconditional_branch(free_item_bb)
        .llvm_ctx("stream callback delivered return")?;

    builder.position_at_end(not_delivered_bb);
    builder
        .build_unconditional_branch(free_item_bb)
        .llvm_ctx("stream callback item free branch")?;

    builder.position_at_end(free_item_bb);
    let free_fn = match fn_ctx.llvm_mod.get_function("free") {
        Some(fv) => fv,
        None => fn_ctx.llvm_mod.add_function(
            "free",
            ctx.void_type().fn_type(&[ptr_ty.into()], false),
            Some(Linkage::External),
        ),
    };
    builder
        .build_call(free_fn, &[item.into()], "stream_item_free")
        .llvm_ctx("stream callback item free")?;
    builder
        .build_unconditional_branch(return_bb)
        .llvm_ctx("stream callback free return")?;

    builder.position_at_end(return_bb);
    builder
        .build_return(None)
        .llvm_ctx("stream callback return")?;
    Ok(callback)
}

fn load_current_task_scope<'ctx>(fn_ctx: &FnCtx<'_, 'ctx>) -> CodegenResult<PointerValue<'ctx>> {
    let ctx_ptr = fn_ctx.execution_context.ok_or_else(|| {
        CodegenError::FailClosed("select{} TaskAwait arm requires an execution context".into())
    })?;
    let offset = fn_ctx
        .ctx
        .i64_type()
        .const_int(HEW_CTX_OFFSET_TASK_SCOPE as u64, false);
    // W6.010: a `select` TaskAwait after a suspend must read the task scope from
    // the resume-installed thread-local context, not the unwound spilled `ctx`
    // param (same coro-aware routing as `current_actor_ptr`/`lower_context_field`).
    let read_ctx = live_execution_context_ptr(fn_ctx, ctx_ptr)?;
    let field_ptr = unsafe {
        fn_ctx
            .builder
            .build_gep(
                fn_ctx.ctx.i8_type(),
                read_ctx,
                &[offset],
                "select_task_scope_ptr",
            )
            .llvm_ctx("select task scope gep")?
    };
    Ok(fn_ctx
        .builder
        .build_load(
            fn_ctx.ctx.ptr_type(AddressSpace::default()),
            field_ptr,
            "select_task_scope",
        )
        .llvm_ctx("select task scope load")?
        .into_pointer_value())
}

fn emit_select_terminator<'ctx>(
    fn_ctx: &FnCtx<'_, 'ctx>,
    arms: &[hew_mir::SelectArm],
) -> CodegenResult<()> {
    use hew_mir::SelectArmKind;

    if arms.is_empty() {
        // HIR rejects empty selects with SelectNoArms; defence-in-depth.
        return Err(CodegenError::FailClosed(
            "select{} terminator carries zero arms (HIR should have rejected with SelectNoArms)"
                .to_string(),
        ));
    }

    // Partition arms by kind, preserving original arm indices for the
    // body-block dispatch. ActorAsk arms feed the `hew_select_first`
    // channel array; the AfterTimer arm (at most one — HIR enforces)
    // supplies the deadline.
    let mut wait_arm_indices: Vec<usize> = Vec::with_capacity(arms.len());
    let mut after_arm_index: Option<usize> = None;
    for (i, arm) in arms.iter().enumerate() {
        match &arm.kind {
            SelectArmKind::ActorAsk { .. }
            | SelectArmKind::StreamNext { .. }
            | SelectArmKind::TaskAwait { .. }
            | SelectArmKind::ChannelRecv { .. } => wait_arm_indices.push(i),
            SelectArmKind::AfterTimer { .. } => {
                if after_arm_index.is_some() {
                    return Err(CodegenError::FailClosed(
                        "select{} carries more than one AfterTimer arm \
                         (HIR should have rejected)"
                            .to_string(),
                    ));
                }
                after_arm_index = Some(i);
            }
        }
    }

    if wait_arm_indices.is_empty() {
        // A select with only an `after` arm is structurally valid but
        // has no race to dispatch: we'd reduce to "wait then run the
        // after-arm body". The HIR forbids select{} composed only of
        // an `after` arm (a sealed-shape invariant); fail closed.
        return Err(CodegenError::FailClosed(
            "select{} carries no value-producing arms (only AfterTimer): \
             HIR should have rejected as a sealed-shape violation"
                .to_string(),
        ));
    }

    let n_waits: usize = wait_arm_indices.len();
    let n_waits_i32 = i32::try_from(n_waits).map_err(|_| {
        CodegenError::FailClosed(format!(
            "select{{}} arm count {n_waits} exceeds i32::MAX — runtime ABI is i32-bound"
        ))
    })?;

    let ctx = fn_ctx.ctx;
    let i32_ty = ctx.i32_type();
    let i64_ty = ctx.i64_type();
    let ptr_ty = ctx.ptr_type(AddressSpace::default());

    // Allocate the channel array on the stack: [N x ptr]. Per-ActorAsk
    // arm index i stores the freshly-allocated `*mut HewReplyChannel`
    // at `channel_array[i]`. The array is referenced by the winner
    // dispatch (free/cancel) and by `hew_select_first`.
    let arr_ty = ptr_ty.array_type(n_waits_i32 as u32);
    let arr_ptr = fn_ctx
        .builder
        .build_alloca(arr_ty, "select_channels")
        .llvm_ctx("select channel array alloca")?;
    let pending_id_arr_ty = i64_ty.array_type(n_waits_i32 as u32);
    let pending_id_arr_ptr = fn_ctx
        .builder
        .build_alloca(pending_id_arr_ty, "select_pending_read_ids")
        .llvm_ctx("select pending-read array alloca")?;

    // Resolve the parent function once for block allocation.
    let parent_fn = fn_ctx
        .builder
        .get_insert_block()
        .and_then(|bb| bb.get_parent())
        .ok_or_else(|| CodegenError::Llvm("select block has no parent function".into()))?;

    // The keep path needs only the blocking wait entry; the per-arm channel /
    // observer decls and the winner/loser dispatch decls are interned inside the
    // shared `emit_select_arm_setup` / `emit_select_winner_dispatch` helpers.
    let select_first = intern_runtime_decl(
        ctx,
        fn_ctx.llvm_mod,
        &mut fn_ctx.runtime_decls.borrow_mut(),
        "hew_select_first",
    )?;

    // Per-arm readiness setup (channel alloc + ask/poll/observe + setup-fail
    // recovery). Shared with the suspending select path, which passes its shared
    // await-cancel arbiter so each arm's channel re-enqueues the parked
    // continuation on readiness; the blocking path passes `None`.
    emit_select_arm_setup(
        fn_ctx,
        arms,
        &wait_arm_indices,
        arr_ty,
        arr_ptr,
        pending_id_arr_ty,
        pending_id_arr_ptr,
        parent_fn,
        None,
    )?;

    // Determine the deadline. If the select carries an AfterTimer arm,
    // load its duration (i64 ns), convert to i32 ms (saturating). With
    // no AfterTimer arm, use -1 (wait indefinitely).
    let timeout_ms_val = if let Some(idx) = after_arm_index {
        let duration_place = match &arms[idx].kind {
            SelectArmKind::AfterTimer { duration } => *duration,
            _ => unreachable!("after_arm_index only set for AfterTimer arms"),
        };
        let (dur_ptr, dur_ty) = place_pointer(fn_ctx, duration_place)?;
        let dur_ns = fn_ctx
            .builder
            .build_load(dur_ty, dur_ptr, "select_after_dur_ns")
            .llvm_ctx("select after dur load")?
            .into_int_value();
        // ns → ms = dur_ns / 1_000_000.
        let ms_per_ns = i64_ty.const_int(1_000_000, false);
        let dur_ms_i64 = fn_ctx
            .builder
            .build_int_signed_div(dur_ns, ms_per_ns, "select_after_dur_ms_i64")
            .llvm_ctx("select after dur sdiv")?;
        // Saturate to i32::MAX (the runtime ABI is i32; a duration
        // > ~24.8 days clamps to "effectively wait forever" but stays
        // non-negative so `hew_select_first` doesn't interpret it as
        // -1 = infinite).
        let i32_max_as_i64 = i64_ty.const_int(i64::from(i32::MAX) as u64, true);
        let too_big = fn_ctx
            .builder
            .build_int_compare(
                inkwell::IntPredicate::SGT,
                dur_ms_i64,
                i32_max_as_i64,
                "select_after_dur_too_big",
            )
            .llvm_ctx("select after dur cmp")?;
        let clamped = fn_ctx
            .builder
            .build_select(
                too_big,
                i32_max_as_i64,
                dur_ms_i64,
                "select_after_dur_clamped",
            )
            .llvm_ctx("select after dur select")?
            .into_int_value();
        // Negative durations clamp to 0 (immediate timeout) so we
        // never accidentally collide with the -1 wait-forever
        // sentinel.
        let zero_i64 = i64_ty.const_zero();
        let neg = fn_ctx
            .builder
            .build_int_compare(
                inkwell::IntPredicate::SLT,
                clamped,
                zero_i64,
                "select_after_dur_neg",
            )
            .llvm_ctx("select after dur neg cmp")?;
        let clamped_nonneg = fn_ctx
            .builder
            .build_select(neg, zero_i64, clamped, "select_after_dur_nonneg")
            .llvm_ctx("select after dur nonneg select")?
            .into_int_value();
        fn_ctx
            .builder
            .build_int_truncate(clamped_nonneg, i32_ty, "select_after_dur_ms")
            .llvm_ctx("select after dur trunc")?
    } else {
        // No AfterTimer arm: wait indefinitely.
        i32_ty.const_int(u64::from(u32::MAX), true) // -1 in two's complement
    };

    // GEP the array down to a `*mut *mut HewReplyChannel` for the call.
    let idx0 = i32_ty.const_zero();
    let arr_first_ptr = unsafe {
        fn_ctx
            .builder
            .build_gep(arr_ty, arr_ptr, &[idx0, idx0], "select_channels_first")
            .llvm_ctx("select arr first gep")?
    };
    let count_val = i32_ty.const_int(n_waits_i32 as u64, true);
    let winner = fn_ctx
        .builder
        .build_call(
            select_first,
            &[
                arr_first_ptr.into(),
                count_val.into(),
                timeout_ms_val.into(),
            ],
            "select_winner_idx",
        )
        .llvm_ctx("hew_select_first call")?
        .try_as_basic_value()
        .basic()
        .ok_or_else(|| CodegenError::FailClosed("hew_select_first returned void".into()))?
        .into_int_value();

    // The winner switch + per-arm winner/loser dispatch is identical to the
    // suspending-select resume edge (the only difference is HOW `winner` is
    // produced: a blocking `hew_select_first` here vs a non-blocking
    // `hew_select_ready_index` after the coro suspend). Share it.
    emit_select_winner_dispatch(
        fn_ctx,
        arms,
        &wait_arm_indices,
        after_arm_index,
        arr_ty,
        arr_ptr,
        pending_id_arr_ty,
        pending_id_arr_ptr,
        parent_fn,
        winner,
        None,
    )
}

/// Emit the winner switch + per-arm winner/loser dispatch shared by
/// [`emit_select_terminator`] (blocking) and
/// [`emit_suspending_select_terminator`] (coro-suspend). `winner` is the
/// first-ready arm index (or -1 → the AfterTimer winner / no-winner trap). When
/// `teardown` is `Some`, each terminal edge (every winner block AND the
/// AfterTimer winner block) calls it BEFORE branching into the arm body, so the
/// suspending path can cancel + free its shared await-cancel arbiter on every
/// resume edge exactly once. The blocking path passes `None`.
#[allow(
    clippy::too_many_arguments,
    reason = "the winner dispatch threads the channel + pending-id arrays, the \
              arm partition, the parent function, the winner value, and the \
              optional arbiter-teardown hook — all are needed in one place so \
              the per-arm loser cancel + free runs against the same array view \
              both select paths built"
)]
fn emit_select_winner_dispatch<'ctx>(
    fn_ctx: &FnCtx<'_, 'ctx>,
    arms: &[hew_mir::SelectArm],
    wait_arm_indices: &[usize],
    after_arm_index: Option<usize>,
    arr_ty: inkwell::types::ArrayType<'ctx>,
    arr_ptr: PointerValue<'ctx>,
    pending_id_arr_ty: inkwell::types::ArrayType<'ctx>,
    pending_id_arr_ptr: PointerValue<'ctx>,
    parent_fn: FunctionValue<'ctx>,
    winner: IntValue<'ctx>,
    teardown: Option<&dyn Fn() -> CodegenResult<()>>,
) -> CodegenResult<()> {
    use hew_mir::SelectArmKind;

    let ctx = fn_ctx.ctx;
    let i32_ty = ctx.i32_type();
    let i64_ty = ctx.i64_type();
    let ptr_ty = ctx.ptr_type(AddressSpace::default());

    let channel_cancel = intern_runtime_decl(
        ctx,
        fn_ctx.llvm_mod,
        &mut fn_ctx.runtime_decls.borrow_mut(),
        "hew_reply_channel_cancel",
    )?;
    let channel_free = intern_runtime_decl(
        ctx,
        fn_ctx.llvm_mod,
        &mut fn_ctx.runtime_decls.borrow_mut(),
        "hew_reply_channel_free",
    )?;
    let reply_wait = intern_runtime_decl(
        ctx,
        fn_ctx.llvm_mod,
        &mut fn_ctx.runtime_decls.borrow_mut(),
        "hew_reply_wait",
    )?;
    let stream_cancel = intern_runtime_decl(
        ctx,
        fn_ctx.llvm_mod,
        &mut fn_ctx.runtime_decls.borrow_mut(),
        "hew_stream_cancel_pending_read",
    )?;
    let channel_poll_cancel = intern_runtime_decl(
        ctx,
        fn_ctx.llvm_mod,
        &mut fn_ctx.runtime_decls.borrow_mut(),
        "hew_channel_cancel_pending_read",
    )?;
    let signal_ready = intern_runtime_decl(
        ctx,
        fn_ctx.llvm_mod,
        &mut fn_ctx.runtime_decls.borrow_mut(),
        "hew_reply_channel_signal_ready",
    )?;
    let task_completion_unobserve = intern_runtime_decl(
        ctx,
        fn_ctx.llvm_mod,
        &mut fn_ctx.runtime_decls.borrow_mut(),
        "hew_task_completion_unobserve",
    )?;
    let task_get_result = intern_runtime_decl(
        ctx,
        fn_ctx.llvm_mod,
        &mut fn_ctx.runtime_decls.borrow_mut(),
        "hew_task_get_result",
    )?;
    let libc_free = get_or_declare_free(fn_ctx);

    // Channel-array-slot GEP helper: `&channel_array[i]` — reconstructed here so
    // the dispatch can run as a free function shared by both select paths.
    let slot_ptr = |i: usize| -> CodegenResult<PointerValue<'ctx>> {
        let i_u32 = u32::try_from(i).map_err(|_| {
            CodegenError::FailClosed(format!("select arm index {i} exceeds u32::MAX"))
        })?;
        let idx0 = i32_ty.const_zero();
        let idx1 = i32_ty.const_int(u64::from(i_u32), false);
        let gep = unsafe {
            fn_ctx
                .builder
                .build_gep(arr_ty, arr_ptr, &[idx0, idx1], &format!("ch_slot_{i}"))
                .llvm_ctx("ch slot gep")?
        };
        Ok(gep)
    };
    let pending_id_slot_ptr = |i: usize| -> CodegenResult<PointerValue<'ctx>> {
        let i_u32 = u32::try_from(i).map_err(|_| {
            CodegenError::FailClosed(format!("select arm index {i} exceeds u32::MAX"))
        })?;
        let idx0 = i32_ty.const_zero();
        let idx1 = i32_ty.const_int(u64::from(i_u32), false);
        let gep = unsafe {
            fn_ctx
                .builder
                .build_gep(
                    pending_id_arr_ty,
                    pending_id_arr_ptr,
                    &[idx0, idx1],
                    &format!("pending_read_slot_{i}"),
                )
                .llvm_ctx("pending-read slot gep")?
        };
        Ok(gep)
    };

    // Allocate per-arm winner blocks and an AfterTimer-winner block
    // (if applicable). Each winner block handles its own loser
    // cleanup, reply read, and branch to the MIR-allocated body block.
    let mut winner_bbs: Vec<inkwell::basic_block::BasicBlock<'_>> =
        Vec::with_capacity(wait_arm_indices.len());
    for slot_idx in 0..wait_arm_indices.len() {
        winner_bbs.push(ctx.append_basic_block(parent_fn, &format!("select_win_ask_{slot_idx}")));
    }
    let after_winner_bb =
        after_arm_index.map(|_| ctx.append_basic_block(parent_fn, "select_win_after"));
    // Fallback "unreachable" block: -1 with no AfterTimer arm should
    // never happen because we passed -1 timeout, but defence-in-depth.
    let no_winner_bb = ctx.append_basic_block(parent_fn, "select_no_winner_trap");

    // Build the switch on `winner`:
    //   case 0 → winner_bbs[0]
    //   case 1 → winner_bbs[1]
    //   ...
    //   default → after_winner_bb (if present) else no_winner_bb
    let default_bb = after_winner_bb.unwrap_or(no_winner_bb);
    let cases: Vec<(IntValue<'_>, inkwell::basic_block::BasicBlock<'_>)> = winner_bbs
        .iter()
        .enumerate()
        .map(|(slot_idx, bb)| (i32_ty.const_int(slot_idx as u64, true), *bb))
        .collect();
    fn_ctx
        .builder
        .build_switch(winner, default_bb, &cases)
        .llvm_ctx("select winner switch")?;

    // No-winner fallback: trap. (Reachable only if the runtime
    // contract is violated — `hew_select_first` returned a value
    // outside `0..n_asks` and there was no AfterTimer arm.)
    fn_ctx.builder.position_at_end(no_winner_bb);
    emit_select_no_winner_trap(fn_ctx)?;

    // For each ActorAsk winner block: read the reply, cancel+free
    // every loser, branch to the arm body block.
    for (winner_slot, &arm_idx) in wait_arm_indices.iter().enumerate() {
        let arm = &arms[arm_idx];
        let binding_place = arm.binding.ok_or_else(|| {
            CodegenError::FailClosed(format!(
                 "select{{}} value-producing arm {arm_idx} carries no binding Place (the producer must \
                 populate `SelectArm.binding` with the per-arm reply slot)"
            ))
        })?;
        let body_block_id = arm.body_block;

        fn_ctx.builder.position_at_end(winner_bbs[winner_slot]);

        // Load the winning channel from the array.
        let win_slot_ptr = slot_ptr(winner_slot)?;
        let win_ch = fn_ctx
            .builder
            .build_load(
                ptr_ty,
                win_slot_ptr,
                &format!("select_win_ch_load_{winner_slot}"),
            )
            .llvm_ctx("select winner load")?
            .into_pointer_value();

        let (dest_ptr, dest_ty) = place_pointer(fn_ctx, binding_place)?;
        if let SelectArmKind::ChannelRecv { receiver, elem_ty } = &arm.kind {
            // The poll fired `signal_ready` on readiness WITHOUT consuming; the
            // winning consumer pops the queued item itself on its own edge via
            // the non-blocking try_recv and materialises `Option<T>` (close →
            // `None`). The owned `Some(string)` pointer is balanced by the MIR
            // drop spine — it never crosses the park thread, so a losing arm
            // (left queued + cancelled) cannot leak it.
            let Place::Local(dest_local) = binding_place else {
                return Err(CodegenError::FailClosed(format!(
                    "select{{}} ChannelRecv arm {arm_idx} binding must be Place::Local, got {binding_place:?}"
                )));
            };
            let rx_ptr = load_duplex_handle(fn_ctx, *receiver, "select_channel_winner")?;
            store_recv_option_via_layout(
                fn_ctx,
                rx_ptr,
                dest_local,
                "hew_channel_try_recv_layout",
                elem_ty,
            )?;
            let _ = dest_ptr;
            let _ = dest_ty;
            // Free the winning channel's caller-side ref (its poll already
            // cleared its own pending_read; no cancel needed).
            fn_ctx
                .builder
                .build_call(
                    channel_free,
                    &[win_ch.into()],
                    &format!("select_win_chan_ch_free_{winner_slot}"),
                )
                .llvm_ctx("select channel winner ch free")?;
        } else {
            let task_result_ptr = if matches!(arm.kind, SelectArmKind::TaskAwait { .. }) {
                let task_place = match &arm.kind {
                    SelectArmKind::TaskAwait { task } => *task,
                    _ => unreachable!("checked above"),
                };
                let task_ptr = load_duplex_handle(fn_ctx, task_place, "select_task_winner")?;
                Some(
                    fn_ctx
                        .builder
                        .build_call(
                            task_get_result,
                            &[task_ptr.into()],
                            &format!("select_task_get_result_{winner_slot}"),
                        )
                        .llvm_ctx("hew_task_get_result call")?
                        .try_as_basic_value()
                        .basic()
                        .ok_or_else(|| {
                            CodegenError::FailClosed("hew_task_get_result returned void".into())
                        })?
                        .into_pointer_value(),
                )
            } else {
                None
            };
            let reply_ptr = if let Some(result_ptr) = task_result_ptr {
                result_ptr
            } else {
                fn_ctx
                    .builder
                    .build_call(
                        reply_wait,
                        &[win_ch.into()],
                        &format!("select_reply_wait_{winner_slot}"),
                    )
                    .llvm_ctx("hew_reply_wait call")?
                    .try_as_basic_value()
                    .basic()
                    .ok_or_else(|| CodegenError::FailClosed("hew_reply_wait returned void".into()))?
                    .into_pointer_value()
            };

            // Defensive null check on the reply pointer. `hew_reply_wait`
            // returns null when the published value pointer was null —
            // which happens on the allocation-failure-during-publish path
            // (`take_ready_reply` at `hew-runtime/src/reply_channel.rs:164`
            // returns null after `hew_reply_channel_mark_allocation_failed`
            // toggled the flag). `hew_select_first` will route us here
            // because the channel reached `ready=true` with a null value;
            // dereferencing would SIGSEGV. Mirrors `Terminator::Ask`'s
            // null-trap shape (`llvm.rs:4831-4854`).
            let null_bb =
                ctx.append_basic_block(parent_fn, &format!("select_reply_null_trap_{winner_slot}"));
            let ok_bb =
                ctx.append_basic_block(parent_fn, &format!("select_reply_ok_{winner_slot}"));
            let is_null = fn_ctx
                .builder
                .build_is_null(reply_ptr, &format!("select_reply_is_null_{winner_slot}"))
                .llvm_ctx("select reply null cmp")?;
            fn_ctx
                .builder
                .build_conditional_branch(is_null, null_bb, ok_bb)
                .llvm_ctx("select reply null branch")?;
            // Null-reply trap branch.
            fn_ctx.builder.position_at_end(null_bb);
            let trap_intrinsic = Intrinsic::find("llvm.trap").ok_or_else(|| {
                CodegenError::Llvm("llvm.trap intrinsic not found in LLVM build".into())
            })?;
            let trap_fn = trap_intrinsic
                .get_declaration(fn_ctx.llvm_mod, &[])
                .ok_or_else(|| CodegenError::Llvm("llvm.trap declaration failed".into()))?;
            fn_ctx
                .builder
                .build_call(
                    trap_fn,
                    &[],
                    &format!("select_reply_null_trap_call_{winner_slot}"),
                )
                .llvm_ctx("select reply null trap")?;
            fn_ctx
                .builder
                .build_unreachable()
                .llvm_ctx("select reply null unreachable")?;
            // Ok branch: load + store + frees.
            fn_ctx.builder.position_at_end(ok_bb);
            let reply_val = fn_ctx
                .builder
                .build_load(
                    dest_ty,
                    reply_ptr,
                    &format!("select_reply_value_{winner_slot}"),
                )
                .llvm_ctx("select reply load")?;
            fn_ctx
                .builder
                .build_store(dest_ptr, reply_val)
                .llvm_ctx("select reply store")?;

            if task_result_ptr.is_none() {
                fn_ctx
                    .builder
                    .build_call(
                        libc_free,
                        &[reply_ptr.into()],
                        &format!("select_reply_free_{winner_slot}"),
                    )
                    .llvm_ctx("select reply free")?;
            }

            // Free the winning channel's caller-side ref (no cancel — we
            // consumed its reply, the channel is not abandoned).
            fn_ctx
                .builder
                .build_call(
                    channel_free,
                    &[win_ch.into()],
                    &format!("select_win_ch_free_{winner_slot}"),
                )
                .llvm_ctx("select winner ch free")?;
        }

        // Loser cleanup: every OTHER ActorAsk arm gets cancel + free,
        // in that order (Risk R4 — cancel BEFORE free is the UAF
        // mitigation for late-reply races on cancelled channels).
        for (loser_slot, &loser_arm_idx) in wait_arm_indices.iter().enumerate() {
            if loser_slot == winner_slot {
                continue;
            }
            let loser_slot_ptr = slot_ptr(loser_slot)?;
            let loser_ch = fn_ctx
                .builder
                .build_load(
                    ptr_ty,
                    loser_slot_ptr,
                    &format!("select_loser_load_w{winner_slot}_l{loser_slot}"),
                )
                .llvm_ctx("select loser load")?
                .into_pointer_value();
            match &arms[loser_arm_idx].kind {
                SelectArmKind::StreamNext { stream } => {
                    let stream_ptr = load_duplex_handle(fn_ctx, *stream, "select_loser_stream")?;
                    let pending_slot = pending_id_slot_ptr(loser_slot)?;
                    let pending_id = fn_ctx
                        .builder
                        .build_load(
                            i64_ty,
                            pending_slot,
                            &format!("select_loser_pending_id_w{winner_slot}_l{loser_slot}"),
                        )
                        .llvm_ctx("select loser pending id load")?
                        .into_int_value();
                    fn_ctx
                        .builder
                        .build_call(
                            stream_cancel,
                            &[stream_ptr.into(), pending_id.into()],
                            &format!("select_loser_stream_cancel_w{winner_slot}_l{loser_slot}"),
                        )
                        .llvm_ctx("select loser stream cancel")?;
                }
                SelectArmKind::TaskAwait { task } => {
                    fn_ctx
                        .builder
                        .build_call(
                            channel_cancel,
                            &[loser_ch.into()],
                            &format!("select_loser_cancel_w{winner_slot}_l{loser_slot}"),
                        )
                        .llvm_ctx("select loser cancel")?;
                    let scope_ptr = load_current_task_scope(fn_ctx)?;
                    let task_ptr = load_duplex_handle(fn_ctx, *task, "select_loser_task")?;
                    fn_ctx
                        .builder
                        .build_call(
                            task_completion_unobserve,
                            &[
                                scope_ptr.into(),
                                task_ptr.into(),
                                signal_ready.as_global_value().as_pointer_value().into(),
                                loser_ch.into(),
                            ],
                            &format!("select_loser_task_unobserve_w{winner_slot}_l{loser_slot}"),
                        )
                        .llvm_ctx("select loser task unobserve")?;
                }
                SelectArmKind::ActorAsk { .. } => {
                    fn_ctx
                        .builder
                        .build_call(
                            channel_cancel,
                            &[loser_ch.into()],
                            &format!("select_loser_cancel_w{winner_slot}_l{loser_slot}"),
                        )
                        .llvm_ctx("select loser cancel")?;
                }
                SelectArmKind::ChannelRecv { receiver, .. } => {
                    let rx_ptr = load_duplex_handle(fn_ctx, *receiver, "select_loser_channel")?;
                    let pending_slot = pending_id_slot_ptr(loser_slot)?;
                    let pending_id = fn_ctx
                        .builder
                        .build_load(
                            i64_ty,
                            pending_slot,
                            &format!("select_loser_chan_pending_id_w{winner_slot}_l{loser_slot}"),
                        )
                        .llvm_ctx("select loser channel pending id load")?
                        .into_int_value();
                    fn_ctx
                        .builder
                        .build_call(
                            channel_poll_cancel,
                            &[rx_ptr.into(), pending_id.into()],
                            &format!("select_loser_channel_cancel_w{winner_slot}_l{loser_slot}"),
                        )
                        .llvm_ctx("select loser channel cancel")?;
                }
                SelectArmKind::AfterTimer { .. } => {
                    unreachable!("wait_arm_indices excludes AfterTimer")
                }
            }
            fn_ctx
                .builder
                .build_call(
                    channel_free,
                    &[loser_ch.into()],
                    &format!("select_loser_free_w{winner_slot}_l{loser_slot}"),
                )
                .llvm_ctx("select loser free")?;
        }

        // Suspending path: the won + all losers are deregistered; tear down the
        // shared await-cancel arbiter (cancel-no-wake + free) on this resume
        // edge before continuing — exactly once per winning arm. The blocking
        // path passes no teardown.
        if let Some(teardown) = teardown {
            teardown()?;
        }

        // Branch into the arm body block.
        let body_bb = *fn_ctx.blocks.get(&body_block_id).ok_or_else(|| {
            CodegenError::FailClosed(format!(
                "select{{}} ActorAsk arm {arm_idx} body block {body_block_id} \
                 missing from FnCtx.blocks"
            ))
        })?;
        fn_ctx
            .builder
            .build_unconditional_branch(body_bb)
            .llvm_ctx("select win br")?;
    }

    // AfterTimer winner: every ActorAsk arm is a loser; cancel + free
    // each, then branch to the AfterTimer arm's body block.
    if let (Some(after_idx), Some(after_bb)) = (after_arm_index, after_winner_bb) {
        let after_arm = &arms[after_idx];
        let body_block_id = after_arm.body_block;
        fn_ctx.builder.position_at_end(after_bb);
        for (loser_slot, &loser_arm_idx) in wait_arm_indices.iter().enumerate() {
            let loser_slot_ptr = slot_ptr(loser_slot)?;
            let loser_ch = fn_ctx
                .builder
                .build_load(
                    ptr_ty,
                    loser_slot_ptr,
                    &format!("select_after_loser_load_{loser_slot}"),
                )
                .llvm_ctx("select after loser load")?
                .into_pointer_value();
            match &arms[loser_arm_idx].kind {
                SelectArmKind::StreamNext { stream } => {
                    let stream_ptr =
                        load_duplex_handle(fn_ctx, *stream, "select_after_loser_stream")?;
                    let pending_slot = pending_id_slot_ptr(loser_slot)?;
                    let pending_id = fn_ctx
                        .builder
                        .build_load(
                            i64_ty,
                            pending_slot,
                            &format!("select_after_loser_pending_id_{loser_slot}"),
                        )
                        .llvm_ctx("select after loser pending id load")?
                        .into_int_value();
                    fn_ctx
                        .builder
                        .build_call(
                            stream_cancel,
                            &[stream_ptr.into(), pending_id.into()],
                            &format!("select_after_loser_stream_cancel_{loser_slot}"),
                        )
                        .llvm_ctx("select after loser stream cancel")?;
                }
                SelectArmKind::TaskAwait { task } => {
                    fn_ctx
                        .builder
                        .build_call(
                            channel_cancel,
                            &[loser_ch.into()],
                            &format!("select_after_loser_cancel_{loser_slot}"),
                        )
                        .llvm_ctx("select after loser cancel")?;
                    let scope_ptr = load_current_task_scope(fn_ctx)?;
                    let task_ptr = load_duplex_handle(fn_ctx, *task, "select_after_loser_task")?;
                    fn_ctx
                        .builder
                        .build_call(
                            task_completion_unobserve,
                            &[
                                scope_ptr.into(),
                                task_ptr.into(),
                                signal_ready.as_global_value().as_pointer_value().into(),
                                loser_ch.into(),
                            ],
                            &format!("select_after_loser_task_unobserve_{loser_slot}"),
                        )
                        .llvm_ctx("select after loser task unobserve")?;
                }
                SelectArmKind::ActorAsk { .. } => {
                    fn_ctx
                        .builder
                        .build_call(
                            channel_cancel,
                            &[loser_ch.into()],
                            &format!("select_after_loser_cancel_{loser_slot}"),
                        )
                        .llvm_ctx("select after loser cancel")?;
                }
                SelectArmKind::ChannelRecv { receiver, .. } => {
                    let rx_ptr =
                        load_duplex_handle(fn_ctx, *receiver, "select_after_loser_channel")?;
                    let pending_slot = pending_id_slot_ptr(loser_slot)?;
                    let pending_id = fn_ctx
                        .builder
                        .build_load(
                            i64_ty,
                            pending_slot,
                            &format!("select_after_loser_chan_pending_id_{loser_slot}"),
                        )
                        .llvm_ctx("select after loser channel pending id load")?
                        .into_int_value();
                    fn_ctx
                        .builder
                        .build_call(
                            channel_poll_cancel,
                            &[rx_ptr.into(), pending_id.into()],
                            &format!("select_after_loser_channel_cancel_{loser_slot}"),
                        )
                        .llvm_ctx("select after loser channel cancel")?;
                }
                SelectArmKind::AfterTimer { .. } => {
                    unreachable!("wait_arm_indices excludes AfterTimer")
                }
            }
            fn_ctx
                .builder
                .build_call(
                    channel_free,
                    &[loser_ch.into()],
                    &format!("select_after_loser_free_{loser_slot}"),
                )
                .llvm_ctx("select after loser free")?;
        }
        // Suspending path: tear down the shared arbiter on the deadline-won
        // resume edge before running the timeout body (exactly once).
        if let Some(teardown) = teardown {
            teardown()?;
        }
        let body_bb = *fn_ctx.blocks.get(&body_block_id).ok_or_else(|| {
            CodegenError::FailClosed(format!(
                "select{{}} AfterTimer arm {after_idx} body block {body_block_id} \
                 missing from FnCtx.blocks"
            ))
        })?;
        fn_ctx
            .builder
            .build_unconditional_branch(body_bb)
            .llvm_ctx("select after br")?;
    }

    Ok(())
}

/// Emit the per-arm readiness setup shared by [`emit_select_terminator`]
/// (blocking) and [`emit_suspending_select_terminator`] (coro-suspend): for each
/// wait arm allocate its reply channel, store it into `channel_array[slot]`,
/// register the arm's readiness observer (ActorAsk → `hew_actor_ask_with_channel`,
/// StreamNext → `hew_stream_poll`, TaskAwait → `hew_task_completion_observe`,
/// ChannelRecv → `hew_channel_poll`) so the source fires `signal_ready(ch)` on
/// readiness, and on any setup failure free every channel allocated so far and
/// trap (Risk R3). When `arbiter` is `Some((reg, self_actor))`, each
/// successfully-set-up channel additionally attaches the shared await-cancel
/// arbiter (`hew_reply_channel_set_await_cancel`) + the parked actor
/// (`hew_reply_channel_set_parked_waiter`), so the FIRST arm to fire wins the
/// arbiter's one-shot CAS and re-enqueues the parked continuation; the setup-fail
/// path then also cancels (no wake) + frees the arbiter so a partially-built
/// waitset leaks nothing. The blocking path passes `None`.
#[allow(
    clippy::too_many_arguments,
    reason = "the arm setup threads the channel + pending-id arrays, the arm \
              partition, the parent function, and the optional shared arbiter — \
              all needed in one place so the setup-fail recovery frees against \
              the same array view it built"
)]
fn emit_select_arm_setup<'ctx>(
    fn_ctx: &FnCtx<'_, 'ctx>,
    arms: &[hew_mir::SelectArm],
    wait_arm_indices: &[usize],
    arr_ty: inkwell::types::ArrayType<'ctx>,
    arr_ptr: PointerValue<'ctx>,
    pending_id_arr_ty: inkwell::types::ArrayType<'ctx>,
    pending_id_arr_ptr: PointerValue<'ctx>,
    parent_fn: FunctionValue<'ctx>,
    arbiter: Option<(PointerValue<'ctx>, PointerValue<'ctx>)>,
) -> CodegenResult<()> {
    use hew_mir::SelectArmKind;

    let ctx = fn_ctx.ctx;
    let i32_ty = ctx.i32_type();
    let i64_ty = ctx.i64_type();
    let ptr_ty = ctx.ptr_type(AddressSpace::default());

    let channel_new = intern_runtime_decl(
        ctx,
        fn_ctx.llvm_mod,
        &mut fn_ctx.runtime_decls.borrow_mut(),
        "hew_reply_channel_new",
    )?;
    let ask_with_channel = intern_runtime_decl(
        ctx,
        fn_ctx.llvm_mod,
        &mut fn_ctx.runtime_decls.borrow_mut(),
        "hew_actor_ask_with_channel",
    )?;
    let channel_cancel = intern_runtime_decl(
        ctx,
        fn_ctx.llvm_mod,
        &mut fn_ctx.runtime_decls.borrow_mut(),
        "hew_reply_channel_cancel",
    )?;
    let channel_free = intern_runtime_decl(
        ctx,
        fn_ctx.llvm_mod,
        &mut fn_ctx.runtime_decls.borrow_mut(),
        "hew_reply_channel_free",
    )?;
    let channel_retain = intern_runtime_decl(
        ctx,
        fn_ctx.llvm_mod,
        &mut fn_ctx.runtime_decls.borrow_mut(),
        "hew_reply_channel_retain",
    )?;
    let signal_ready = intern_runtime_decl(
        ctx,
        fn_ctx.llvm_mod,
        &mut fn_ctx.runtime_decls.borrow_mut(),
        "hew_reply_channel_signal_ready",
    )?;
    let stream_poll = intern_runtime_decl(
        ctx,
        fn_ctx.llvm_mod,
        &mut fn_ctx.runtime_decls.borrow_mut(),
        "hew_stream_poll",
    )?;
    let stream_cancel = intern_runtime_decl(
        ctx,
        fn_ctx.llvm_mod,
        &mut fn_ctx.runtime_decls.borrow_mut(),
        "hew_stream_cancel_pending_read",
    )?;
    let channel_poll = intern_runtime_decl(
        ctx,
        fn_ctx.llvm_mod,
        &mut fn_ctx.runtime_decls.borrow_mut(),
        "hew_channel_poll",
    )?;
    let channel_poll_cancel = intern_runtime_decl(
        ctx,
        fn_ctx.llvm_mod,
        &mut fn_ctx.runtime_decls.borrow_mut(),
        "hew_channel_cancel_pending_read",
    )?;
    let task_completion_observe = intern_runtime_decl(
        ctx,
        fn_ctx.llvm_mod,
        &mut fn_ctx.runtime_decls.borrow_mut(),
        "hew_task_completion_observe",
    )?;
    let task_completion_unobserve = intern_runtime_decl(
        ctx,
        fn_ctx.llvm_mod,
        &mut fn_ctx.runtime_decls.borrow_mut(),
        "hew_task_completion_unobserve",
    )?;
    let set_await_cancel = intern_runtime_decl(
        ctx,
        fn_ctx.llvm_mod,
        &mut fn_ctx.runtime_decls.borrow_mut(),
        "hew_reply_channel_set_await_cancel",
    )?;
    let set_parked_waiter = intern_runtime_decl(
        ctx,
        fn_ctx.llvm_mod,
        &mut fn_ctx.runtime_decls.borrow_mut(),
        "hew_reply_channel_set_parked_waiter",
    )?;
    let cancel_arbiter = intern_runtime_decl(
        ctx,
        fn_ctx.llvm_mod,
        &mut fn_ctx.runtime_decls.borrow_mut(),
        "hew_await_cancel_cancel",
    )?;
    let free_arbiter = intern_runtime_decl(
        ctx,
        fn_ctx.llvm_mod,
        &mut fn_ctx.runtime_decls.borrow_mut(),
        "hew_await_cancel_free",
    )?;

    let slot_ptr = |i: usize| -> CodegenResult<PointerValue<'ctx>> {
        let i_u32 = u32::try_from(i).map_err(|_| {
            CodegenError::FailClosed(format!("select arm index {i} exceeds u32::MAX"))
        })?;
        let idx0 = i32_ty.const_zero();
        let idx1 = i32_ty.const_int(u64::from(i_u32), false);
        let gep = unsafe {
            fn_ctx
                .builder
                .build_gep(arr_ty, arr_ptr, &[idx0, idx1], &format!("ch_slot_{i}"))
                .llvm_ctx("ch slot gep")?
        };
        Ok(gep)
    };
    let pending_id_slot_ptr = |i: usize| -> CodegenResult<PointerValue<'ctx>> {
        let i_u32 = u32::try_from(i).map_err(|_| {
            CodegenError::FailClosed(format!("select arm index {i} exceeds u32::MAX"))
        })?;
        let idx0 = i32_ty.const_zero();
        let idx1 = i32_ty.const_int(u64::from(i_u32), false);
        let gep = unsafe {
            fn_ctx
                .builder
                .build_gep(
                    pending_id_arr_ty,
                    pending_id_arr_ptr,
                    &[idx0, idx1],
                    &format!("pending_read_slot_{i}"),
                )
                .llvm_ctx("pending-read slot gep")?
        };
        Ok(gep)
    };

    for (slot_idx, &arm_idx) in wait_arm_indices.iter().enumerate() {
        // Allocate the channel.
        let ch_val = fn_ctx
            .builder
            .build_call(channel_new, &[], &format!("select_ch_new_{slot_idx}"))
            .llvm_ctx("hew_reply_channel_new call")?
            .try_as_basic_value()
            .basic()
            .ok_or_else(|| CodegenError::FailClosed("hew_reply_channel_new returned void".into()))?
            .into_pointer_value();

        // Store into channel_array[slot_idx]. We perform the store
        // BEFORE issuing the ask so the recovery block sees a
        // consistent array view if the ask issue fails.
        let slot = slot_ptr(slot_idx)?;
        fn_ctx
            .builder
            .build_store(slot, ch_val)
            .llvm_ctx("ch slot store")?;

        // Suspending path: attach the shared arbiter + parked actor to this
        // arm's channel BEFORE arming its readiness source (the ask / poll /
        // observe below). The readiness arms (`hew_channel_poll`,
        // `hew_stream_poll`) wait on a foreign park thread that fires
        // `signal_ready` the instant the source is already readable — for a
        // channel whose item was queued + sink closed before the select, that
        // fire happens synchronously inside the arming call. If `caller_actor`
        // were still null at that fire (the attach done afterward, as it was),
        // `publish_reply_from_sender_ref` takes the condvar wake path
        // (`cond.notify_one()`) — but the suspending caller parks on the
        // coroutine, never on the condvar, so the wake is silently lost and the
        // actor parks forever (empty output, clean exit). macOS schedules the
        // park thread fast enough to win that race the vast majority of the
        // time; Linux usually loses it, hence the platform-specific flake.
        // Setting the parked waiter first routes any immediate fire through
        // `enqueue_resume` (recorded as `pending_wake` while still Running and
        // drained by the suspend edge — the FG3 two-phase park), so the wake is
        // never lost regardless of park-thread timing.
        if let Some((reg, self_actor)) = arbiter {
            fn_ctx
                .builder
                .build_call(
                    set_await_cancel,
                    &[ch_val.into(), reg.into()],
                    &format!("select_set_await_cancel_{slot_idx}"),
                )
                .llvm_ctx("hew_reply_channel_set_await_cancel call")?;
            fn_ctx
                .builder
                .build_call(
                    set_parked_waiter,
                    &[ch_val.into(), self_actor.into()],
                    &format!("select_set_parked_waiter_{slot_idx}"),
                )
                .llvm_ctx("hew_reply_channel_set_parked_waiter call")?;
        }

        // `recoverable` marks an arm whose non-zero setup status is a
        // FAIL-CLOSED send failure (the receiver was unreachable — e.g. a
        // FUNGIBLE supervisor-child ref resolved to a dead/null child), NOT an
        // internal setup error. A recoverable failure retires THIS arm (frees
        // its channel, nulls its array slot so the dispatch + teardown skip it)
        // and continues setting up the remaining arms, mirroring the single-shot
        // `hew_actor_ask` path which binds `Err(AskError::*)` on any non-zero
        // send status instead of trapping. Only ActorAsk is a send surface;
        // stream/task/channel poll failures stay process-fatal (genuine
        // registration failures, not a send the program can recover from).
        let (status, current_has_retained_observer, recoverable) = match &arms[arm_idx].kind {
            SelectArmKind::ActorAsk {
                actor,
                msg_type,
                value,
                ..
            } => {
                // #1739: register R's destructor on this arm's channel BEFORE
                // the ask issues. In a select, at most one arm wins; a reply
                // delivered to a LOSING ask arm (another arm won, or the timer
                // fired) is never consumed, and the loser-cleanup `cancel+free`
                // below reaches the channel free leg with `value` still set.
                // Without this the free leg would `libc::free` the buffer alone
                // and leak the reply's embedded heap. R is the arm's reply
                // binding type (the slot the winner edge loads the reply into).
                let arm_reply_binding = arms[arm_idx].binding.ok_or_else(|| {
                    CodegenError::FailClosed(format!(
                        "select{{}} ActorAsk arm {arm_idx} carries no binding Place \
                         (the per-arm reply slot whose type is R)"
                    ))
                })?;
                let arm_reply_ty = ask_reply_ty(fn_ctx, arm_reply_binding)?.clone();
                wire_reply_drop_fn(fn_ctx, ch_val, &arm_reply_ty)?;
                let actor_ptr = load_duplex_handle(fn_ctx, *actor, "select_actor_handle")?;
                let (payload_ptr, payload_size) =
                    actor_payload_ptr_size(fn_ctx, *value, "select_ask_payload")?;
                let msg_type_val = i32_ty.const_int(*msg_type as u64, false);
                // `payload_size` is built as i64; the `size` param is `usize`/
                // `size_t` (i32 on wasm32). Reconcile to the target-correct width.
                let select_ask_size_ty = runtime_size_ty(fn_ctx.ctx, fn_ctx.llvm_mod);
                let payload_size = reconcile_int_width_signed(
                    fn_ctx,
                    payload_size.into(),
                    select_ask_size_ty.into(),
                    "select ask payload size",
                )?;
                let status = fn_ctx
                    .builder
                    .build_call(
                        ask_with_channel,
                        &[
                            actor_ptr.into(),
                            msg_type_val.into(),
                            payload_ptr.into(),
                            payload_size.into(),
                            ch_val.into(),
                        ],
                        &format!("select_ask_issue_{slot_idx}"),
                    )
                    .llvm_ctx("hew_actor_ask_with_channel call")?
                    .try_as_basic_value()
                    .basic()
                    .ok_or_else(|| {
                        CodegenError::FailClosed("hew_actor_ask_with_channel returned void".into())
                    })?
                    .into_int_value();
                (status, false, true)
            }
            SelectArmKind::StreamNext { stream } => {
                let binding_place = arms[arm_idx].binding.ok_or_else(|| {
                    CodegenError::FailClosed(format!(
                        "select{{}} StreamNext arm {arm_idx} carries no binding Place (the producer must \
                         populate `SelectArm.binding` with the stream item slot)"
                    ))
                })?;
                let (_, item_ty) = place_pointer(fn_ctx, binding_place)?;
                let stream_callback = get_or_create_select_stream_callback(fn_ctx, item_ty)?;
                fn_ctx
                    .builder
                    .build_call(
                        channel_retain,
                        &[ch_val.into()],
                        &format!("select_stream_ch_retain_{slot_idx}"),
                    )
                    .llvm_ctx("stream channel retain")?;
                let stream_ptr = load_duplex_handle(fn_ctx, *stream, "select_stream_handle")?;
                let pending_id = fn_ctx
                    .builder
                    .build_call(
                        stream_poll,
                        &[
                            stream_ptr.into(),
                            stream_callback.as_global_value().as_pointer_value().into(),
                            ch_val.into(),
                        ],
                        &format!("select_stream_poll_{slot_idx}"),
                    )
                    .llvm_ctx("hew_stream_poll call")?
                    .try_as_basic_value()
                    .basic()
                    .ok_or_else(|| {
                        CodegenError::FailClosed("hew_stream_poll returned void".into())
                    })?
                    .into_int_value();
                let pending_slot = pending_id_slot_ptr(slot_idx)?;
                fn_ctx
                    .builder
                    .build_store(pending_slot, pending_id)
                    .llvm_ctx("pending-read id store")?;
                let failed = fn_ctx
                    .builder
                    .build_int_compare(
                        inkwell::IntPredicate::EQ,
                        pending_id,
                        i64_ty.const_zero(),
                        &format!("select_stream_poll_failed_{slot_idx}"),
                    )
                    .llvm_ctx("stream poll cmp")?;
                let status = fn_ctx
                    .builder
                    .build_int_z_extend(failed, i32_ty, &format!("select_stream_status_{slot_idx}"))
                    .llvm_ctx("stream poll status zext")?;
                (status, true, false)
            }
            SelectArmKind::TaskAwait { task } => {
                fn_ctx
                    .builder
                    .build_call(
                        channel_retain,
                        &[ch_val.into()],
                        &format!("select_task_ch_retain_{slot_idx}"),
                    )
                    .llvm_ctx("task channel retain")?;
                let scope_ptr = load_current_task_scope(fn_ctx)?;
                let task_ptr = load_duplex_handle(fn_ctx, *task, "select_task_handle")?;
                let status = fn_ctx
                    .builder
                    .build_call(
                        task_completion_observe,
                        &[
                            scope_ptr.into(),
                            task_ptr.into(),
                            signal_ready.as_global_value().as_pointer_value().into(),
                            ch_val.into(),
                        ],
                        &format!("select_task_observe_{slot_idx}"),
                    )
                    .llvm_ctx("hew_task_completion_observe call")?
                    .try_as_basic_value()
                    .basic()
                    .ok_or_else(|| {
                        CodegenError::FailClosed("hew_task_completion_observe returned void".into())
                    })?
                    .into_int_value();
                (status, true, false)
            }
            SelectArmKind::ChannelRecv { receiver, .. } => {
                // Signal-only readiness poll (mirrors TaskAwait's observe +
                // StreamNext's pending-id): register a poll on the channel that
                // fires `signal_ready(ch)` when readable. The winner edge pops
                // the item itself via try_recv, so nothing is consumed here.
                fn_ctx
                    .builder
                    .build_call(
                        channel_retain,
                        &[ch_val.into()],
                        &format!("select_channel_ch_retain_{slot_idx}"),
                    )
                    .llvm_ctx("channel poll channel retain")?;
                let rx_ptr = load_duplex_handle(fn_ctx, *receiver, "select_channel_handle")?;
                let pending_id = fn_ctx
                    .builder
                    .build_call(
                        channel_poll,
                        &[
                            rx_ptr.into(),
                            signal_ready.as_global_value().as_pointer_value().into(),
                            ch_val.into(),
                            // Cancel-path release for the retained observer ref:
                            // a withdrawn poll frees exactly one reference of
                            // `ch_val` WITHOUT firing the readiness callback,
                            // matching `signal_ready`'s consume on the fire path
                            // (exactly-once ownership handoff — H1).
                            channel_free.as_global_value().as_pointer_value().into(),
                        ],
                        &format!("select_channel_poll_{slot_idx}"),
                    )
                    .llvm_ctx("hew_channel_poll call")?
                    .try_as_basic_value()
                    .basic()
                    .ok_or_else(|| {
                        CodegenError::FailClosed("hew_channel_poll returned void".into())
                    })?
                    .into_int_value();
                let pending_slot = pending_id_slot_ptr(slot_idx)?;
                fn_ctx
                    .builder
                    .build_store(pending_slot, pending_id)
                    .llvm_ctx("channel poll pending-id store")?;
                let failed = fn_ctx
                    .builder
                    .build_int_compare(
                        inkwell::IntPredicate::EQ,
                        pending_id,
                        i64_ty.const_zero(),
                        &format!("select_channel_poll_failed_{slot_idx}"),
                    )
                    .llvm_ctx("channel poll cmp")?;
                let status = fn_ctx
                    .builder
                    .build_int_z_extend(
                        failed,
                        i32_ty,
                        &format!("select_channel_status_{slot_idx}"),
                    )
                    .llvm_ctx("channel poll status zext")?;
                (status, true, false)
            }
            SelectArmKind::AfterTimer { .. } => {
                unreachable!("wait_arm_indices excludes AfterTimer")
            }
        };

        // Branch on status: 0 → next ask setup or the wait dispatch; non-zero
        // → setup recovery. For a RECOVERABLE arm (fungible ActorAsk send to a
        // dead/unreachable child) the recovery retires this single arm and
        // continues (see `setup_recover_bb` below); for a non-recoverable arm
        // (stream/task/channel poll registration failure) it frees every channel
        // allocated through `slot_idx` inclusive, then traps.
        let zero = i32_ty.const_zero();
        let failed = fn_ctx
            .builder
            .build_int_compare(
                inkwell::IntPredicate::NE,
                status,
                zero,
                &format!("select_ask_failed_{slot_idx}"),
            )
            .llvm_ctx("select ask cmp")?;
        let setup_ok_bb = ctx.append_basic_block(parent_fn, &format!("select_setup_ok_{slot_idx}"));

        if recoverable {
            // FAIL-CLOSED recoverable arm: a fungible ActorAsk whose send found
            // an unreachable receiver (dead/null child) returns a non-zero
            // status from `hew_actor_ask_with_channel`, exactly as the
            // single-shot ask does before it binds `Err(AskError::*)`. Rather
            // than abandon the whole select with a process-fatal trap, retire
            // ONLY this arm and continue: free its channel and NULL its array
            // slot so `hew_select_first`/`hew_select_ready_index` skip it
            // (both `continue` on a null slot) and every loser/teardown leg
            // (all null-guarded `cancel`/`free`) treats it as absent. The arm
            // never becomes ready, so the select races the remaining ready
            // arms (or falls through to the `after` deadline if it is the only
            // / last live arm) — never traps.
            let setup_recover_bb =
                ctx.append_basic_block(parent_fn, &format!("select_setup_recover_{slot_idx}"));
            fn_ctx
                .builder
                .build_conditional_branch(failed, setup_recover_bb, setup_ok_bb)
                .llvm_ctx("select setup recoverable br")?;

            fn_ctx.builder.position_at_end(setup_recover_bb);
            // Release the caller-side reference the runtime kept on send failure
            // (`KeepCreatorRef`): `hew_reply_channel_free` runs the channel's
            // attached await-cancel teardown too, dropping this arm's ref on the
            // shared suspending-select arbiter (no-op on the blocking path).
            fn_ctx
                .builder
                .build_call(
                    channel_free,
                    &[ch_val.into()],
                    &format!("select_recover_free_{slot_idx}"),
                )
                .llvm_ctx("setup-recover free")?;
            // NULL the slot so the dispatch + every teardown leg skip this arm.
            let recover_slot = slot_ptr(slot_idx)?;
            fn_ctx
                .builder
                .build_store(recover_slot, ptr_ty.const_null())
                .llvm_ctx("setup-recover null slot store")?;
            fn_ctx
                .builder
                .build_unconditional_branch(setup_ok_bb)
                .llvm_ctx("setup-recover continue br")?;

            // Continue emitting the remaining arms in the OK block.
            fn_ctx.builder.position_at_end(setup_ok_bb);
            continue;
        }

        let setup_fail_bb =
            ctx.append_basic_block(parent_fn, &format!("select_setup_fail_{slot_idx}"));
        fn_ctx
            .builder
            .build_conditional_branch(failed, setup_fail_bb, setup_ok_bb)
            .llvm_ctx("select setup br")?;

        // Recovery block: free channels [0..=slot_idx] (each was
        // allocated and stored; the ask-issue failure also released
        // the queued sender ref on the failing channel inside the
        // runtime, but the caller-side ref is still live — see
        // `submit_ask_with_reply_channel`'s KeepCreatorRef behaviour).
        // Cancel before free for any channel where an ask was
        // successfully submitted (i < slot_idx); the failing channel
        // (slot_idx) only needs `free`.
        fn_ctx.builder.position_at_end(setup_fail_bb);
        for (j, &prev_arm_idx) in wait_arm_indices.iter().enumerate().take(slot_idx) {
            let cleanup_slot = slot_ptr(j)?;
            let cleanup_ch = fn_ctx
                .builder
                .build_load(ptr_ty, cleanup_slot, &format!("select_cleanup_load_{j}"))
                .llvm_ctx("setup-fail load")?
                .into_pointer_value();
            match &arms[prev_arm_idx].kind {
                SelectArmKind::StreamNext { stream } => {
                    let stream_ptr = load_duplex_handle(fn_ctx, *stream, "select_cleanup_stream")?;
                    let pending_slot = pending_id_slot_ptr(j)?;
                    let pending_id = fn_ctx
                        .builder
                        .build_load(
                            i64_ty,
                            pending_slot,
                            &format!("select_cleanup_pending_id_{j}"),
                        )
                        .llvm_ctx("setup-fail pending id load")?
                        .into_int_value();
                    fn_ctx
                        .builder
                        .build_call(
                            stream_cancel,
                            &[stream_ptr.into(), pending_id.into()],
                            &format!("select_cleanup_stream_cancel_{j}"),
                        )
                        .llvm_ctx("setup-fail stream cancel")?;
                }
                SelectArmKind::TaskAwait { task } => {
                    fn_ctx
                        .builder
                        .build_call(
                            channel_cancel,
                            &[cleanup_ch.into()],
                            &format!("select_cleanup_cancel_{j}"),
                        )
                        .llvm_ctx("setup-fail cancel")?;
                    let scope_ptr = load_current_task_scope(fn_ctx)?;
                    let task_ptr = load_duplex_handle(fn_ctx, *task, "select_cleanup_task")?;
                    fn_ctx
                        .builder
                        .build_call(
                            task_completion_unobserve,
                            &[
                                scope_ptr.into(),
                                task_ptr.into(),
                                signal_ready.as_global_value().as_pointer_value().into(),
                                cleanup_ch.into(),
                            ],
                            &format!("select_cleanup_task_unobserve_{j}"),
                        )
                        .llvm_ctx("setup-fail task unobserve")?;
                }
                SelectArmKind::ActorAsk { .. } => {
                    fn_ctx
                        .builder
                        .build_call(
                            channel_cancel,
                            &[cleanup_ch.into()],
                            &format!("select_cleanup_cancel_{j}"),
                        )
                        .llvm_ctx("setup-fail cancel")?;
                }
                SelectArmKind::ChannelRecv { receiver, .. } => {
                    let rx_ptr = load_duplex_handle(fn_ctx, *receiver, "select_cleanup_channel")?;
                    let pending_slot = pending_id_slot_ptr(j)?;
                    let pending_id = fn_ctx
                        .builder
                        .build_load(
                            i64_ty,
                            pending_slot,
                            &format!("select_cleanup_chan_pending_id_{j}"),
                        )
                        .llvm_ctx("setup-fail channel pending id load")?
                        .into_int_value();
                    fn_ctx
                        .builder
                        .build_call(
                            channel_poll_cancel,
                            &[rx_ptr.into(), pending_id.into()],
                            &format!("select_cleanup_channel_cancel_{j}"),
                        )
                        .llvm_ctx("setup-fail channel cancel")?;
                }
                SelectArmKind::AfterTimer { .. } => {
                    unreachable!("wait_arm_indices excludes AfterTimer")
                }
            }
            fn_ctx
                .builder
                .build_call(
                    channel_free,
                    &[cleanup_ch.into()],
                    &format!("select_cleanup_free_{j}"),
                )
                .llvm_ctx("setup-fail free")?;
        }
        // Failing channel: free the caller-side ref (no cancel — no
        // ask was successfully submitted, so no late replier exists).
        fn_ctx
            .builder
            .build_call(
                channel_free,
                &[ch_val.into()],
                &format!("select_setup_fail_free_self_{slot_idx}"),
            )
            .llvm_ctx("setup-fail self free")?;
        if current_has_retained_observer {
            fn_ctx
                .builder
                .build_call(
                    channel_free,
                    &[ch_val.into()],
                    &format!("select_setup_fail_free_observer_{slot_idx}"),
                )
                .llvm_ctx("setup-fail observer free")?;
        }

        // Suspending path: a partially-built waitset is being abandoned by the
        // trap; cancel (no wake) + free the shared arbiter so its registration
        // and any retained timer ref are reclaimed before the trap. The
        // per-channel frees above already released the arbiter refs the
        // successfully-set-up channels took; this drops the codegen-held ref.
        // (The trap aborts the process, but freeing keeps ASan/LSan clean and
        // matches the abandon-edge teardown.)
        if let Some((reg, _self_actor)) = arbiter {
            let cancelled_status = i32_ty.const_int(2, false); // Cancelled
            let no_wake = i32_ty.const_zero();
            fn_ctx
                .builder
                .build_call(
                    cancel_arbiter,
                    &[reg.into(), cancelled_status.into(), no_wake.into()],
                    &format!("select_setup_fail_arbiter_cancel_{slot_idx}"),
                )
                .llvm_ctx("setup-fail arbiter cancel")?;
            fn_ctx
                .builder
                .build_call(
                    free_arbiter,
                    &[reg.into()],
                    &format!("select_setup_fail_arbiter_free_{slot_idx}"),
                )
                .llvm_ctx("setup-fail arbiter free")?;
        }

        // Trap with HEW_TRAP_ACTOR_SEND_FAILED (the same diagnostic
        // code `Terminator::Send` uses on send-status failure — the
        // ask submission failed because the receiver mailbox was
        // unreachable, which is the same supervisor-visible failure).
        emit_select_setup_failure_trap(fn_ctx)?;

        // Setup OK: this arm's channel is live + observing. The shared arbiter +
        // parked actor were attached BEFORE the readiness source was armed
        // (above), so the FIRST arm to fire — including a synchronous fire
        // during the arming call for an already-ready source — wins the
        // one-shot CAS and re-enqueues the parked continuation through
        // `enqueue_resume` (the N-source generalisation of the `await x |
        // after d` waker). Nothing left to do here but fall through to the next
        // arm's setup.
        fn_ctx.builder.position_at_end(setup_ok_bb);
    }

    Ok(())
}

/// Emit the LLVM IR for `Terminator::SuspendingSelect` — the coro-suspend
/// sibling of [`emit_select_terminator`].
///
/// Shape (the suspending select ramp):
/// ```text
///   self = hew_actor_self()                       ; the parked-cont actor
///   <build channel_array + pending_id_array>      ; identical to the keep path
///   reg  = hew_await_cancel_new(self, null, null) ; ONE shared first-ready arbiter
///   <per arm: channel_new + ask/poll/observe>     ; emit_select_arm_setup, arbiter
///   <          set_await_cancel(ch, reg)>         ;   attached per channel so the
///   <          set_parked_waiter(ch, self)>       ;   first-ready arm wins + wakes
///   [AfterTimer] hew_await_cancel_schedule_deadline_ms(reg, global_wheel, ms)
///   br (no AfterTimer || armed) -> do_suspend, immediate
/// immediate:                                       ; deadline arm failed to arm —
///   <ready_index scan; if none, deadline fail-safe wins>
/// do_suspend:                                       ; coro.suspend (non-final)
///   switch coro.suspend [default -> return handle, 0 -> resume, 1 -> abandon]
/// abandon:                                          ; parked cont destroyed
///   cancel(reg, Cancelled, no_wake)
///   <per arm: cancel + free its channel / detach observer>
///   free(reg); br shared cleanup
/// resume:                                           ; first-ready (or deadline) woke us
///   winner = hew_select_ready_index(arr, count)    ; -1 => deadline won
///   switch winner -> per-arm winner blocks / AfterTimer winner block
///   (each winner block: bind value, cancel losers, cancel+free reg, -> body)
/// ```
/// The shared `HewAwaitCancel` arbiter is the N-source generalisation of the
/// single-source `await x | after d` waker: each arm's channel carries the SAME
/// arbiter, so the first arm to fire wins the one-shot CAS (`hew_await_cancel_complete`
/// inside `publish_reply_from_sender_ref`) and re-enqueues the parked actor exactly
/// once; the AfterTimer deadline rides the SAME arbiter on the global timer wheel.
/// The losers are cancelled on the resume edge by the shared winner dispatch.
fn emit_suspending_select_terminator<'ctx>(
    fn_ctx: &FnCtx<'_, 'ctx>,
    arms: &[hew_mir::SelectArm],
    resume: u32,
    cleanup: u32,
) -> CodegenResult<()> {
    use hew_mir::SelectArmKind;

    let coro = fn_ctx.coro.ok_or_else(|| {
        CodegenError::FailClosed(
            "Terminator::SuspendingSelect reached codegen but the function carries \
             no coro prologue state — lower_function must detect the suspend \
             carrier (has_suspend) and emit the prologue before the body"
                .into(),
        )
    })?;
    if !fn_ctx.blocks.contains_key(&resume) {
        return Err(CodegenError::FailClosed(format!(
            "SuspendingSelect resume target bb{resume} not found"
        )));
    }
    if !fn_ctx.blocks.contains_key(&cleanup) {
        return Err(CodegenError::FailClosed(format!(
            "SuspendingSelect cleanup target bb{cleanup} not found"
        )));
    }

    if arms.is_empty() {
        return Err(CodegenError::FailClosed(
            "select{} terminator carries zero arms (HIR should have rejected with SelectNoArms)"
                .to_string(),
        ));
    }

    // Partition arms (identical to the blocking path).
    let mut wait_arm_indices: Vec<usize> = Vec::with_capacity(arms.len());
    let mut after_arm_index: Option<usize> = None;
    for (i, arm) in arms.iter().enumerate() {
        match &arm.kind {
            SelectArmKind::ActorAsk { .. }
            | SelectArmKind::StreamNext { .. }
            | SelectArmKind::TaskAwait { .. }
            | SelectArmKind::ChannelRecv { .. } => wait_arm_indices.push(i),
            SelectArmKind::AfterTimer { .. } => {
                if after_arm_index.is_some() {
                    return Err(CodegenError::FailClosed(
                        "select{} carries more than one AfterTimer arm (HIR should have rejected)"
                            .to_string(),
                    ));
                }
                after_arm_index = Some(i);
            }
        }
    }
    if wait_arm_indices.is_empty() {
        return Err(CodegenError::FailClosed(
            "select{} carries no value-producing arms (only AfterTimer): \
             HIR should have rejected as a sealed-shape violation"
                .to_string(),
        ));
    }

    let n_waits = wait_arm_indices.len();
    let n_waits_i32 = i32::try_from(n_waits).map_err(|_| {
        CodegenError::FailClosed(format!(
            "select{{}} arm count {n_waits} exceeds i32::MAX — runtime ABI is i32-bound"
        ))
    })?;

    let ctx = fn_ctx.ctx;
    let i32_ty = ctx.i32_type();
    let i64_ty = ctx.i64_type();
    let ptr_ty = ctx.ptr_type(AddressSpace::default());

    // Allocate the channel + pending-id arrays (identical to the blocking path).
    let arr_ty = ptr_ty.array_type(n_waits_i32 as u32);
    let arr_ptr = fn_ctx
        .builder
        .build_alloca(arr_ty, "select_channels")
        .llvm_ctx("select channel array alloca")?;
    let pending_id_arr_ty = i64_ty.array_type(n_waits_i32 as u32);
    let pending_id_arr_ptr = fn_ctx
        .builder
        .build_alloca(pending_id_arr_ty, "select_pending_read_ids")
        .llvm_ctx("select pending-read array alloca")?;

    let parent_fn = fn_ctx
        .builder
        .get_insert_block()
        .and_then(|bb| bb.get_parent())
        .ok_or_else(|| {
            CodegenError::Llvm("suspending select block has no parent function".into())
        })?;

    // self = the parked-continuation actor the readiness/timer wake re-enqueues.
    // MUST come from hew_actor_self() (the live thread-local context), NOT a
    // spilled param: across a suspend the per-dispatch context the spilled param
    // pointed to is freed; on RESUME the scheduler installs a fresh context, so
    // the thread-local read returns the live actor (the FIX-THE-CLASS accessor
    // the ask/read/sleep ramps use).
    let actor_self_fn = intern_runtime_decl(
        ctx,
        fn_ctx.llvm_mod,
        &mut fn_ctx.runtime_decls.borrow_mut(),
        "hew_actor_self",
    )?;
    let self_actor = fn_ctx
        .builder
        .build_call(actor_self_fn, &[], "suspending_select_self")
        .llvm_ctx("hew_actor_self call")?
        .try_as_basic_value()
        .basic()
        .ok_or_else(|| CodegenError::FailClosed("hew_actor_self returned void".into()))?
        .into_pointer_value();

    // ONE shared first-ready arbiter. No source cleanup callback (the resume +
    // abandon edges do the per-arm loser cancel / observer detach with full
    // pointer context, like the sleep ramp's null-cleanup arbiter).
    let null_ptr = ptr_ty.const_null();
    let cancel_new = intern_runtime_decl(
        ctx,
        fn_ctx.llvm_mod,
        &mut fn_ctx.runtime_decls.borrow_mut(),
        "hew_await_cancel_new",
    )?;
    let reg = fn_ctx
        .builder
        .build_call(
            cancel_new,
            &[self_actor.into(), null_ptr.into(), null_ptr.into()],
            "suspending_select_reg",
        )
        .llvm_ctx("hew_await_cancel_new call")?
        .try_as_basic_value()
        .basic()
        .ok_or_else(|| CodegenError::FailClosed("hew_await_cancel_new returned void".into()))?
        .into_pointer_value();

    // Per-arm readiness setup + arbiter attachment.
    emit_select_arm_setup(
        fn_ctx,
        arms,
        &wait_arm_indices,
        arr_ty,
        arr_ptr,
        pending_id_arr_ty,
        pending_id_arr_ptr,
        parent_fn,
        Some((reg, self_actor)),
    )?;

    // AfterTimer arm: arm the deadline on the SAME arbiter via the global timer
    // wheel (the shared wheel cut-task-sleep uses). The timer-fired finish wakes
    // the actor; a non-timer arm winning cancels the timer through the arbiter's
    // one-shot complete. With no AfterTimer arm the select waits indefinitely on
    // the readiness arms.
    if let Some(idx) = after_arm_index {
        let duration_place = match &arms[idx].kind {
            SelectArmKind::AfterTimer { duration } => *duration,
            _ => unreachable!("after_arm_index only set for AfterTimer arms"),
        };
        let (dur_ptr, dur_ty) = place_pointer(fn_ctx, duration_place)?;
        let dur_ns = fn_ctx
            .builder
            .build_load(dur_ty, dur_ptr, "suspending_select_after_dur_ns")
            .llvm_ctx("select after dur load")?
            .into_int_value();
        // ns → ms, clamped non-negative (a negative duration is an immediate
        // deadline). The schedule takes u64 ms.
        let ms_per_ns = i64_ty.const_int(1_000_000, false);
        let dur_ms = fn_ctx
            .builder
            .build_int_signed_div(dur_ns, ms_per_ns, "suspending_select_after_dur_ms")
            .llvm_ctx("select after dur sdiv")?;
        let zero_i64 = i64_ty.const_zero();
        let neg = fn_ctx
            .builder
            .build_int_compare(
                inkwell::IntPredicate::SLT,
                dur_ms,
                zero_i64,
                "suspending_select_after_neg",
            )
            .llvm_ctx("select after neg cmp")?;
        let dur_ms_nonneg = fn_ctx
            .builder
            .build_select(neg, zero_i64, dur_ms, "suspending_select_after_nonneg")
            .llvm_ctx("select after nonneg select")?
            .into_int_value();
        let tw_fn = intern_runtime_decl(
            ctx,
            fn_ctx.llvm_mod,
            &mut fn_ctx.runtime_decls.borrow_mut(),
            "hew_global_timer_wheel",
        )?;
        let tw = fn_ctx
            .builder
            .build_call(tw_fn, &[], "suspending_select_tw")
            .llvm_ctx("hew_global_timer_wheel call")?
            .try_as_basic_value()
            .basic()
            .ok_or_else(|| CodegenError::FailClosed("hew_global_timer_wheel returned void".into()))?
            .into_pointer_value();
        let schedule = intern_runtime_decl(
            ctx,
            fn_ctx.llvm_mod,
            &mut fn_ctx.runtime_decls.borrow_mut(),
            "hew_await_cancel_schedule_deadline_ms",
        )?;
        // The deadline arm cannot fail-safe to "immediate" the way sleep does
        // (a select still has live readiness arms to wait on if the wheel is
        // unavailable), so we ignore the schedule rc: a failed arm simply means
        // no deadline fires and the readiness arms decide the winner. This never
        // hangs the timer subsystem.
        fn_ctx
            .builder
            .build_call(
                schedule,
                &[reg.into(), tw.into(), dur_ms_nonneg.into()],
                "suspending_select_schedule",
            )
            .llvm_ctx("hew_await_cancel_schedule_deadline_ms call")?;
    }

    // Suspend the continuation. The abandon arm cancels the arbiter (no wake),
    // deregisters every observer + cancels the timer, and frees the arbiter; the
    // resume arm scans for the winner and dispatches.
    let resume_bb = *fn_ctx.blocks.get(&resume).ok_or_else(|| {
        CodegenError::FailClosed(format!(
            "SuspendingSelect resume target bb{resume} not found"
        ))
    })?;
    let parent = parent_fn;
    let do_suspend_bb = ctx.append_basic_block(parent, "suspending_select_suspend");
    fn_ctx
        .builder
        .build_unconditional_branch(do_suspend_bb)
        .llvm_ctx("suspending select -> suspend br")?;
    let scan_bb = ctx.append_basic_block(parent, "suspending_select_scan");

    fn_ctx.builder.position_at_end(do_suspend_bb);
    let cancel_arbiter = intern_runtime_decl(
        ctx,
        fn_ctx.llvm_mod,
        &mut fn_ctx.runtime_decls.borrow_mut(),
        "hew_await_cancel_cancel",
    )?;
    let free_arbiter = intern_runtime_decl(
        ctx,
        fn_ctx.llvm_mod,
        &mut fn_ctx.runtime_decls.borrow_mut(),
        "hew_await_cancel_free",
    )?;
    let channel_cancel = intern_runtime_decl(
        ctx,
        fn_ctx.llvm_mod,
        &mut fn_ctx.runtime_decls.borrow_mut(),
        "hew_reply_channel_cancel",
    )?;
    let channel_free = intern_runtime_decl(
        ctx,
        fn_ctx.llvm_mod,
        &mut fn_ctx.runtime_decls.borrow_mut(),
        "hew_reply_channel_free",
    )?;
    let stream_cancel = intern_runtime_decl(
        ctx,
        fn_ctx.llvm_mod,
        &mut fn_ctx.runtime_decls.borrow_mut(),
        "hew_stream_cancel_pending_read",
    )?;
    let channel_poll_cancel = intern_runtime_decl(
        ctx,
        fn_ctx.llvm_mod,
        &mut fn_ctx.runtime_decls.borrow_mut(),
        "hew_channel_cancel_pending_read",
    )?;
    let task_completion_unobserve = intern_runtime_decl(
        ctx,
        fn_ctx.llvm_mod,
        &mut fn_ctx.runtime_decls.borrow_mut(),
        "hew_task_completion_unobserve",
    )?;
    let signal_ready = intern_runtime_decl(
        ctx,
        fn_ctx.llvm_mod,
        &mut fn_ctx.runtime_decls.borrow_mut(),
        "hew_reply_channel_signal_ready",
    )?;

    // GEP helpers for the abandon-edge per-arm deregister.
    let slot_ptr = |i: usize| -> CodegenResult<PointerValue<'ctx>> {
        let idx0 = i32_ty.const_zero();
        let idx1 = i32_ty.const_int(i as u64, false);
        Ok(unsafe {
            fn_ctx
                .builder
                .build_gep(
                    arr_ty,
                    arr_ptr,
                    &[idx0, idx1],
                    &format!("abandon_ch_slot_{i}"),
                )
                .llvm_ctx("abandon ch slot gep")?
        })
    };
    let pending_id_slot_ptr = |i: usize| -> CodegenResult<PointerValue<'ctx>> {
        let idx0 = i32_ty.const_zero();
        let idx1 = i32_ty.const_int(i as u64, false);
        Ok(unsafe {
            fn_ctx
                .builder
                .build_gep(
                    pending_id_arr_ty,
                    pending_id_arr_ptr,
                    &[idx0, idx1],
                    &format!("abandon_pending_slot_{i}"),
                )
                .llvm_ctx("abandon pending slot gep")?
        })
    };

    crate::suspend::emit_suspend_point(
        fn_ctx,
        coro,
        parent,
        scan_bb,
        "suspending_select",
        "suspending_select_abandon_cleanup",
        "suspending select abandon -> shared cleanup br",
        || {
            // Abandon: the parked continuation is being destroyed. Cancel the
            // arbiter WITHOUT waking (cancels the armed deadline so a racing fire
            // drops its wake), then deregister + free EVERY arm's channel
            // (cancel before free — UAF mitigation R4), then free the arbiter.
            // Each call runs exactly once on this single abandon edge.
            let cancelled_status = i32_ty.const_int(2, false); // Cancelled
            let no_wake = i32_ty.const_zero();
            fn_ctx
                .builder
                .build_call(
                    cancel_arbiter,
                    &[reg.into(), cancelled_status.into(), no_wake.into()],
                    "suspending_select_abandon_arbiter_cancel",
                )
                .llvm_ctx("abandon arbiter cancel")?;
            for (slot_idx, &arm_idx) in wait_arm_indices.iter().enumerate() {
                let ch = fn_ctx
                    .builder
                    .build_load(
                        ptr_ty,
                        slot_ptr(slot_idx)?,
                        &format!("abandon_ch_load_{slot_idx}"),
                    )
                    .llvm_ctx("abandon ch load")?
                    .into_pointer_value();
                match &arms[arm_idx].kind {
                    SelectArmKind::StreamNext { stream } => {
                        let stream_ptr = load_duplex_handle(fn_ctx, *stream, "abandon_stream")?;
                        let pending_id = fn_ctx
                            .builder
                            .build_load(
                                i64_ty,
                                pending_id_slot_ptr(slot_idx)?,
                                &format!("abandon_stream_pending_{slot_idx}"),
                            )
                            .llvm_ctx("abandon stream pending load")?
                            .into_int_value();
                        fn_ctx
                            .builder
                            .build_call(
                                stream_cancel,
                                &[stream_ptr.into(), pending_id.into()],
                                &format!("abandon_stream_cancel_{slot_idx}"),
                            )
                            .llvm_ctx("abandon stream cancel")?;
                    }
                    SelectArmKind::TaskAwait { task } => {
                        fn_ctx
                            .builder
                            .build_call(
                                channel_cancel,
                                &[ch.into()],
                                &format!("abandon_task_cancel_{slot_idx}"),
                            )
                            .llvm_ctx("abandon task cancel")?;
                        let scope_ptr = load_current_task_scope(fn_ctx)?;
                        let task_ptr = load_duplex_handle(fn_ctx, *task, "abandon_task")?;
                        fn_ctx
                            .builder
                            .build_call(
                                task_completion_unobserve,
                                &[
                                    scope_ptr.into(),
                                    task_ptr.into(),
                                    signal_ready.as_global_value().as_pointer_value().into(),
                                    ch.into(),
                                ],
                                &format!("abandon_task_unobserve_{slot_idx}"),
                            )
                            .llvm_ctx("abandon task unobserve")?;
                    }
                    SelectArmKind::ActorAsk { .. } => {
                        fn_ctx
                            .builder
                            .build_call(
                                channel_cancel,
                                &[ch.into()],
                                &format!("abandon_ask_cancel_{slot_idx}"),
                            )
                            .llvm_ctx("abandon ask cancel")?;
                    }
                    SelectArmKind::ChannelRecv { receiver, .. } => {
                        let rx_ptr = load_duplex_handle(fn_ctx, *receiver, "abandon_channel")?;
                        let pending_id = fn_ctx
                            .builder
                            .build_load(
                                i64_ty,
                                pending_id_slot_ptr(slot_idx)?,
                                &format!("abandon_chan_pending_{slot_idx}"),
                            )
                            .llvm_ctx("abandon channel pending load")?
                            .into_int_value();
                        fn_ctx
                            .builder
                            .build_call(
                                channel_poll_cancel,
                                &[rx_ptr.into(), pending_id.into()],
                                &format!("abandon_channel_cancel_{slot_idx}"),
                            )
                            .llvm_ctx("abandon channel cancel")?;
                    }
                    SelectArmKind::AfterTimer { .. } => {
                        unreachable!("wait_arm_indices excludes AfterTimer")
                    }
                }
                fn_ctx
                    .builder
                    .build_call(
                        channel_free,
                        &[ch.into()],
                        &format!("abandon_ch_free_{slot_idx}"),
                    )
                    .llvm_ctx("abandon ch free")?;
            }
            fn_ctx
                .builder
                .build_call(
                    free_arbiter,
                    &[reg.into()],
                    "suspending_select_abandon_arbiter_free",
                )
                .llvm_ctx("abandon arbiter free")?;
            Ok(())
        },
        || {
            // Resume: a readiness arm fired (or the deadline). Scan the readiness
            // flags once (non-blocking) to find the winner; -1 means the deadline
            // won (no channel ready). Then dispatch through the shared winner
            // blocks, which bind the winner, cancel the losers, and tear down the
            // arbiter (cancel-no-wake + free) on every resume edge exactly once.
            let idx0 = i32_ty.const_zero();
            let arr_first = unsafe {
                fn_ctx
                    .builder
                    .build_gep(
                        arr_ty,
                        arr_ptr,
                        &[idx0, idx0],
                        "suspending_select_arr_first",
                    )
                    .llvm_ctx("suspending select arr first gep")?
            };
            let ready_index = intern_runtime_decl(
                ctx,
                fn_ctx.llvm_mod,
                &mut fn_ctx.runtime_decls.borrow_mut(),
                "hew_select_ready_index",
            )?;
            let count_val = i32_ty.const_int(n_waits_i32 as u64, true);
            let winner = fn_ctx
                .builder
                .build_call(
                    ready_index,
                    &[arr_first.into(), count_val.into()],
                    "suspending_select_winner_idx",
                )
                .llvm_ctx("hew_select_ready_index call")?
                .try_as_basic_value()
                .basic()
                .ok_or_else(|| {
                    CodegenError::FailClosed("hew_select_ready_index returned void".into())
                })?
                .into_int_value();

            // Tear down the shared arbiter once per resume edge (cancel-no-wake
            // settles the one-shot if the deadline won; the timer is already
            // cancelled by the winning fire's complete), then free it. This runs
            // BEFORE the arm body so the body sees no live registration.
            let teardown = || -> CodegenResult<()> {
                let cancelled_status = i32_ty.const_int(2, false); // Cancelled
                let no_wake = i32_ty.const_zero();
                fn_ctx
                    .builder
                    .build_call(
                        cancel_arbiter,
                        &[reg.into(), cancelled_status.into(), no_wake.into()],
                        "suspending_select_resume_arbiter_cancel",
                    )
                    .llvm_ctx("resume arbiter cancel")?;
                fn_ctx
                    .builder
                    .build_call(
                        free_arbiter,
                        &[reg.into()],
                        "suspending_select_resume_arbiter_free",
                    )
                    .llvm_ctx("resume arbiter free")?;
                Ok(())
            };

            emit_select_winner_dispatch(
                fn_ctx,
                arms,
                &wait_arm_indices,
                after_arm_index,
                arr_ty,
                arr_ptr,
                pending_id_arr_ty,
                pending_id_arr_ptr,
                parent,
                winner,
                Some(&teardown),
            )
        },
    )?;
    let _ = resume_bb;
    Ok(())
}

/// Emit the LLVM IR for `Terminator::Join` — the wait-ALL sibling of
/// [`emit_select_terminator`].
///
/// Every branch is an actor-ask. The setup PREAMBLE is identical to the
/// `select` ActorAsk path: allocate one reply channel per branch, store
/// it into a stack `[N x ptr]` array, and issue the ask; any ask-issue
/// failure frees the channels allocated so far and traps
/// (`emit_select_setup_failure_trap`). The back half differs: instead of
/// a `hew_select_first` winner race, we WAIT on EVERY channel in
/// declaration order (`hew_reply_wait`), materialise each reply into the
/// `result` tuple's matching element, and free each channel exactly once.
///
/// Per HEW-SPEC-2026 §4.11.2, a branch error cancels the remaining
/// branches and the trap propagates. The substrate surfaces a branch
/// failure as a null reply (`hew_reply_wait` returns null when the
/// published value pointer was null — the allocation-failure /
/// unreachable-mailbox path); on a null reply we cancel + free every
/// not-yet-consumed channel (cancel-rest) and trap (propagate).
fn emit_join_terminator<'ctx>(
    fn_ctx: &FnCtx<'_, 'ctx>,
    branches: &[hew_mir::JoinBranch],
    result: Place,
    next: u32,
) -> CodegenResult<()> {
    if branches.is_empty() {
        // HIR rejects empty joins with JoinNoBranches; defence-in-depth.
        return Err(CodegenError::FailClosed(
            "join{} terminator carries zero branches (HIR should have rejected with JoinNoBranches)"
                .to_string(),
        ));
    }

    let n = branches.len();
    let n_i32 = i32::try_from(n).map_err(|_| {
        CodegenError::FailClosed(format!(
            "join{{}} branch count {n} exceeds i32::MAX — runtime ABI is i32-bound"
        ))
    })?;

    let ctx = fn_ctx.ctx;
    let i32_ty = ctx.i32_type();
    let ptr_ty = ctx.ptr_type(AddressSpace::default());

    // Channel array on the stack: [N x ptr]. Branch i stores its freshly
    // allocated `*mut HewReplyChannel` at `channel_array[i]`.
    let arr_ty = ptr_ty.array_type(n_i32 as u32);
    let arr_ptr = fn_ctx
        .builder
        .build_alloca(arr_ty, "join_channels")
        .llvm_ctx("join channel array alloca")?;

    let parent_fn = fn_ctx
        .builder
        .get_insert_block()
        .and_then(|bb| bb.get_parent())
        .ok_or_else(|| CodegenError::Llvm("join block has no parent function".into()))?;

    let channel_new = intern_runtime_decl(
        ctx,
        fn_ctx.llvm_mod,
        &mut fn_ctx.runtime_decls.borrow_mut(),
        "hew_reply_channel_new",
    )?;
    let ask_with_channel = intern_runtime_decl(
        ctx,
        fn_ctx.llvm_mod,
        &mut fn_ctx.runtime_decls.borrow_mut(),
        "hew_actor_ask_with_channel",
    )?;
    let channel_cancel = intern_runtime_decl(
        ctx,
        fn_ctx.llvm_mod,
        &mut fn_ctx.runtime_decls.borrow_mut(),
        "hew_reply_channel_cancel",
    )?;
    let channel_free = intern_runtime_decl(
        ctx,
        fn_ctx.llvm_mod,
        &mut fn_ctx.runtime_decls.borrow_mut(),
        "hew_reply_channel_free",
    )?;
    let reply_wait = intern_runtime_decl(
        ctx,
        fn_ctx.llvm_mod,
        &mut fn_ctx.runtime_decls.borrow_mut(),
        "hew_reply_wait",
    )?;
    let libc_free = get_or_declare_free(fn_ctx);

    // `&channel_array[i]` helper.
    let slot_ptr = |i: usize| -> CodegenResult<PointerValue<'ctx>> {
        let i_u32 = u32::try_from(i).map_err(|_| {
            CodegenError::FailClosed(format!("join branch index {i} exceeds u32::MAX"))
        })?;
        let idx0 = i32_ty.const_zero();
        let idx1 = i32_ty.const_int(u64::from(i_u32), false);
        let gep = unsafe {
            fn_ctx
                .builder
                .build_gep(arr_ty, arr_ptr, &[idx0, idx1], &format!("join_ch_slot_{i}"))
                .llvm_ctx("join ch slot gep")?
        };
        Ok(gep)
    };

    // ── Setup PREAMBLE: allocate channel + issue ask per branch ──────
    for (i, branch) in branches.iter().enumerate() {
        let ch_val = fn_ctx
            .builder
            .build_call(channel_new, &[], &format!("join_ch_new_{i}"))
            .llvm_ctx("hew_reply_channel_new call")?
            .try_as_basic_value()
            .basic()
            .ok_or_else(|| CodegenError::FailClosed("hew_reply_channel_new returned void".into()))?
            .into_pointer_value();

        // Store BEFORE issuing the ask so the recovery path sees a
        // consistent array view if the ask issue fails.
        let slot = slot_ptr(i)?;
        fn_ctx
            .builder
            .build_store(slot, ch_val)
            .llvm_ctx("join ch slot store")?;

        // #1739: register this branch's reply destructor on its channel BEFORE
        // the ask issues. `join` awaits every branch, but if the join is
        // abandoned (coro destroy / actor shutdown) after a branch deposited
        // its reply yet before `hew_reply_wait` consumed it, the abandon/cancel
        // teardown reaches this channel's free leg with `value` still set.
        // Without the destructor the free leg would `libc::free` the buffer
        // alone and leak R's embedded heap. R is the branch's reply type.
        wire_reply_drop_fn(fn_ctx, ch_val, &branch.reply_ty)?;

        let actor_ptr = load_duplex_handle(fn_ctx, branch.actor, "join_actor_handle")?;
        let (payload_ptr, payload_size) =
            actor_payload_ptr_size(fn_ctx, branch.value, "join_ask_payload")?;
        let msg_type_val = i32_ty.const_int(branch.msg_type as u64, false);
        // `payload_size` is built as i64; the `size` param of
        // `hew_actor_ask_with_channel` is `usize`/`size_t` (i32 on wasm32).
        // Reconcile to the target-correct width, matching every sibling emitter.
        let join_ask_size_ty = runtime_size_ty(fn_ctx.ctx, fn_ctx.llvm_mod);
        let payload_size = reconcile_int_width_signed(
            fn_ctx,
            payload_size.into(),
            join_ask_size_ty.into(),
            "join ask payload size",
        )?;
        let status = fn_ctx
            .builder
            .build_call(
                ask_with_channel,
                &[
                    actor_ptr.into(),
                    msg_type_val.into(),
                    payload_ptr.into(),
                    payload_size.into(),
                    ch_val.into(),
                ],
                &format!("join_ask_issue_{i}"),
            )
            .llvm_ctx("hew_actor_ask_with_channel call")?
            .try_as_basic_value()
            .basic()
            .ok_or_else(|| {
                CodegenError::FailClosed("hew_actor_ask_with_channel returned void".into())
            })?
            .into_int_value();

        // Branch on status: 0 → next ask; non-zero → mid-setup recovery
        // (free every channel allocated through `i` inclusive, then trap).
        let zero = i32_ty.const_zero();
        let failed = fn_ctx
            .builder
            .build_int_compare(
                inkwell::IntPredicate::NE,
                status,
                zero,
                &format!("join_ask_failed_{i}"),
            )
            .llvm_ctx("join ask cmp")?;
        let setup_ok_bb = ctx.append_basic_block(parent_fn, &format!("join_setup_ok_{i}"));
        let setup_fail_bb = ctx.append_basic_block(parent_fn, &format!("join_setup_fail_{i}"));
        fn_ctx
            .builder
            .build_conditional_branch(failed, setup_fail_bb, setup_ok_bb)
            .llvm_ctx("join setup br")?;

        // Recovery block: cancel + free channels [0..i] (each had an ask
        // successfully submitted), then free the failing channel `i`
        // (no cancel — no ask was submitted), then trap.
        fn_ctx.builder.position_at_end(setup_fail_bb);
        for j in 0..i {
            let cleanup_slot = slot_ptr(j)?;
            let cleanup_ch = fn_ctx
                .builder
                .build_load(ptr_ty, cleanup_slot, &format!("join_cleanup_load_{j}"))
                .llvm_ctx("join setup-fail load")?
                .into_pointer_value();
            fn_ctx
                .builder
                .build_call(
                    channel_cancel,
                    &[cleanup_ch.into()],
                    &format!("join_cleanup_cancel_{j}"),
                )
                .llvm_ctx("join setup-fail cancel")?;
            fn_ctx
                .builder
                .build_call(
                    channel_free,
                    &[cleanup_ch.into()],
                    &format!("join_cleanup_free_{j}"),
                )
                .llvm_ctx("join setup-fail free")?;
        }
        fn_ctx
            .builder
            .build_call(
                channel_free,
                &[ch_val.into()],
                &format!("join_setup_fail_free_self_{i}"),
            )
            .llvm_ctx("join setup-fail self free")?;
        emit_select_setup_failure_trap(fn_ctx)?;

        fn_ctx.builder.position_at_end(setup_ok_bb);
    }

    // ── WAIT-ALL back half: wait every channel, materialise the tuple ─
    let (result_ptr, result_ty) = place_pointer(fn_ctx, result)?;
    // A multi-branch join binds a tuple struct; a single-branch join
    // binds the lone reply type directly (the checker's `Expr::Join`
    // rule). Resolve the per-branch element type accordingly.
    let result_struct_ty = match result_ty {
        BasicTypeEnum::StructType(st) => Some(st),
        _ => {
            if n != 1 {
                return Err(CodegenError::FailClosed(format!(
                    "join{{}} with {n} branches must bind a tuple struct result, got {result_ty:?}"
                )));
            }
            None
        }
    };

    for (i, branch) in branches.iter().enumerate() {
        let win_slot_ptr = slot_ptr(i)?;
        let win_ch = fn_ctx
            .builder
            .build_load(ptr_ty, win_slot_ptr, &format!("join_ch_load_{i}"))
            .llvm_ctx("join channel load")?
            .into_pointer_value();

        let reply_ptr = fn_ctx
            .builder
            .build_call(
                reply_wait,
                &[win_ch.into()],
                &format!("join_reply_wait_{i}"),
            )
            .llvm_ctx("hew_reply_wait call")?
            .try_as_basic_value()
            .basic()
            .ok_or_else(|| CodegenError::FailClosed("hew_reply_wait returned void".into()))?
            .into_pointer_value();

        // Null reply ⇒ this branch errored. Per §4.11.2 cancel the rest
        // (every not-yet-consumed channel: this one + branches i+1..n)
        // and trap (propagate).
        let null_bb = ctx.append_basic_block(parent_fn, &format!("join_reply_null_{i}"));
        let ok_bb = ctx.append_basic_block(parent_fn, &format!("join_reply_ok_{i}"));
        let is_null = fn_ctx
            .builder
            .build_is_null(reply_ptr, &format!("join_reply_is_null_{i}"))
            .llvm_ctx("join reply null cmp")?;
        fn_ctx
            .builder
            .build_conditional_branch(is_null, null_bb, ok_bb)
            .llvm_ctx("join reply null branch")?;

        // Cancel-rest + trap branch.
        fn_ctx.builder.position_at_end(null_bb);
        // Free the failing channel's caller-side ref (its reply was null).
        fn_ctx
            .builder
            .build_call(
                channel_free,
                &[win_ch.into()],
                &format!("join_err_free_self_{i}"),
            )
            .llvm_ctx("join error self free")?;
        // Cancel + free every still-pending sibling channel.
        for j in (i + 1)..n {
            let rest_slot = slot_ptr(j)?;
            let rest_ch = fn_ctx
                .builder
                .build_load(ptr_ty, rest_slot, &format!("join_err_rest_load_{i}_{j}"))
                .llvm_ctx("join error rest load")?
                .into_pointer_value();
            fn_ctx
                .builder
                .build_call(
                    channel_cancel,
                    &[rest_ch.into()],
                    &format!("join_err_rest_cancel_{i}_{j}"),
                )
                .llvm_ctx("join error rest cancel")?;
            fn_ctx
                .builder
                .build_call(
                    channel_free,
                    &[rest_ch.into()],
                    &format!("join_err_rest_free_{i}_{j}"),
                )
                .llvm_ctx("join error rest free")?;
        }
        let trap_intrinsic = Intrinsic::find("llvm.trap").ok_or_else(|| {
            CodegenError::Llvm("llvm.trap intrinsic not found in LLVM build".into())
        })?;
        let trap_fn = trap_intrinsic
            .get_declaration(fn_ctx.llvm_mod, &[])
            .ok_or_else(|| CodegenError::Llvm("llvm.trap declaration failed".into()))?;
        fn_ctx
            .builder
            .build_call(trap_fn, &[], &format!("join_reply_null_trap_{i}"))
            .llvm_ctx("join reply null trap")?;
        fn_ctx
            .builder
            .build_unreachable()
            .llvm_ctx("join reply null unreachable")?;

        // Ok branch: materialise the reply into result tuple element `i`.
        fn_ctx.builder.position_at_end(ok_bb);
        let (elem_ptr, elem_ty) = if let Some(struct_ty) = result_struct_ty {
            let elem_ty = struct_ty.get_field_type_at_index(i as u32).ok_or_else(|| {
                CodegenError::FailClosed(format!(
                    "join{{}} result tuple has no field at index {i} (branch/element mismatch)"
                ))
            })?;
            let field_ptr = fn_ctx
                .builder
                .build_struct_gep(
                    struct_ty,
                    result_ptr,
                    i as u32,
                    &format!("join_elem_{i}_gep"),
                )
                .llvm_ctx("join tuple elem gep")?;
            (field_ptr, elem_ty)
        } else {
            (result_ptr, result_ty)
        };
        let reply_val = fn_ctx
            .builder
            .build_load(elem_ty, reply_ptr, &format!("join_reply_value_{i}"))
            .llvm_ctx("join reply load")?;
        fn_ctx
            .builder
            .build_store(elem_ptr, reply_val)
            .llvm_ctx("join reply store")?;
        // Free the heap reply payload and the caller-side channel ref.
        fn_ctx
            .builder
            .build_call(
                libc_free,
                &[reply_ptr.into()],
                &format!("join_reply_free_{i}"),
            )
            .llvm_ctx("join reply free")?;
        fn_ctx
            .builder
            .build_call(channel_free, &[win_ch.into()], &format!("join_ch_free_{i}"))
            .llvm_ctx("join channel free")?;
        let _ = branch;
    }

    // All replies landed and the tuple is bound — continue at `next`.
    let next_bb = *fn_ctx.blocks.get(&next).ok_or_else(|| {
        CodegenError::FailClosed(format!(
            "join{{}} next block {next} missing from FnCtx.blocks"
        ))
    })?;
    fn_ctx
        .builder
        .build_unconditional_branch(next_bb)
        .llvm_ctx("join next br")?;
    Ok(())
}

/// Emit a fail-closed trap for a `Terminator::Select` mid-setup
/// failure (an ask-issue returned non-zero, leaving partially-allocated
/// channels which the recovery path frees before reaching here). Uses
/// `hew_trap_with_code(HEW_TRAP_ACTOR_SEND_FAILED=206)` so the
/// supervisor sees the same diagnostic as `Terminator::Send` failures;
/// follows with `llvm.trap` + `unreachable` as the non-actor fallback
/// (mirrors the `Terminator::Send` send-fail trap shape).
fn emit_select_setup_failure_trap<'ctx>(fn_ctx: &FnCtx<'_, 'ctx>) -> CodegenResult<()> {
    // Delegate to the single-sourced emit_trap_with_code helper so the
    // hew_trap_with_code declaration, llvm.trap, and unreachable are
    // emitted in one place. The trap code is single-sourced from the runtime.
    emit_trap_with_code(
        fn_ctx,
        HEW_TRAP_ACTOR_SEND_FAILED as u64,
        "select_setup_fail_trap",
    )
}

/// Emit a fail-closed trap for the unreachable "no winner" arm of the
/// select winner-dispatch switch. Reachable only if the runtime
/// contract is violated (e.g. `hew_select_first` returned -1 even
/// though we passed `-1` as the timeout and provided non-empty
/// channels).
fn emit_select_no_winner_trap<'ctx>(fn_ctx: &FnCtx<'_, 'ctx>) -> CodegenResult<()> {
    let trap_intrinsic = Intrinsic::find("llvm.trap")
        .ok_or_else(|| CodegenError::Llvm("llvm.trap intrinsic not found in LLVM build".into()))?;
    let trap_fn = trap_intrinsic
        .get_declaration(fn_ctx.llvm_mod, &[])
        .ok_or_else(|| CodegenError::Llvm("llvm.trap declaration failed".into()))?;
    fn_ctx
        .builder
        .build_call(trap_fn, &[], "select_no_winner_trap")
        .llvm_ctx("select no winner trap")?;
    fn_ctx
        .builder
        .build_unreachable()
        .llvm_ctx("select no winner unreachable")?;
    Ok(())
}

fn emit_cancel_trap_or_return(fn_ctx: &FnCtx<'_, '_>) -> CodegenResult<()> {
    // In a coroutine the function's LLVM return type is the `coro.begin` handle
    // (`ptr`), NOT `fn_ctx.return_ty` (which carries the LOGICAL Hew return type
    // so the body's value lowering still works). A cancel exit here must return
    // the handle — abandoning the coroutine — so the executor reclaims the frame
    // via `coro.destroy`. Returning the logical value would `ret i64` from a
    // `ptr`-returning function (an LLVM verify failure).
    if let Some(coro) = fn_ctx.coro {
        fn_ctx
            .builder
            .build_return(Some(&coro.handle))
            .llvm_ctx("coro cancel return handle")?;
        return Ok(());
    }
    // Lambda-actor body's LLVM ABI return is `i32` (the runtime status code),
    // independent of the USER reply type that sizes `return_slot`. A cancel
    // exit here must `ret i32 0` regardless of `fn_ctx.return_ty` (which holds
    // the logical user reply width). Mirrors the coroutine handling above.
    if fn_ctx.lambda_actor_shape.is_some() {
        let ret = fn_ctx.ctx.i32_type().const_zero();
        fn_ctx
            .builder
            .build_return(Some(&ret))
            .llvm_ctx("lambda body cancel return")?;
        return Ok(());
    }
    match fn_ctx.return_ty {
        BasicTypeEnum::IntType(i) => {
            let ret = i.const_zero();
            fn_ctx
                .builder
                .build_return(Some(&ret))
                .llvm_ctx("cancel return")?;
        }
        BasicTypeEnum::PointerType(p) => {
            let ret = p.const_null();
            fn_ctx
                .builder
                .build_return(Some(&ret))
                .llvm_ctx("cancel return")?;
        }
        BasicTypeEnum::FloatType(f) => {
            let ret = f.const_float(0.0);
            fn_ctx
                .builder
                .build_return(Some(&ret))
                .llvm_ctx("cancel return")?;
        }
        BasicTypeEnum::StructType(_) | BasicTypeEnum::ArrayType(_) => {
            let ret_val = fn_ctx
                .builder
                .build_load(fn_ctx.return_ty, fn_ctx.return_slot, "cancel_composite_ret")
                .llvm_ctx("cancel composite ret load")?;
            fn_ctx
                .builder
                .build_return(Some(&ret_val))
                .llvm_ctx("cancel composite ret")?;
        }
        other => {
            return Err(CodegenError::FailClosed(format!(
                "cancel exit cannot synthesize return for {other:?}"
            )));
        }
    }
    Ok(())
}

fn emit_cancel_drops(
    fn_ctx: &FnCtx<'_, '_>,
    block_id: u32,
    drop_plans: &[(ExitPath, hew_mir::DropPlan)],
) -> CodegenResult<()> {
    if let Some((_, plan)) = drop_plans
        .iter()
        .find(|(exit, _)| matches!(exit, ExitPath::Cancel { block } if *block == block_id))
    {
        for drop in &plan.drops {
            emit_one_elab_drop(fn_ctx, drop)?;
        }
    }
    Ok(())
}

fn emit_cooperate_check<'ctx>(
    fn_ctx: &FnCtx<'_, 'ctx>,
    block_id: u32,
    drop_plans: &[(ExitPath, hew_mir::DropPlan)],
) -> CodegenResult<()> {
    let signal = fn_ctx.call_runtime_int(
        "hew_actor_cooperate",
        &[],
        "hew_actor_cooperate",
        "hew_actor_cooperate call",
    )?;
    let cancel_code = fn_ctx.ctx.i32_type().const_int(2, false);
    let is_cancel = fn_ctx
        .builder
        .build_int_compare(
            inkwell::IntPredicate::EQ,
            signal,
            cancel_code,
            "hew_cooperate_is_cancel",
        )
        .llvm_ctx("cooperate cancel compare")?;

    let parent = fn_ctx
        .builder
        .get_insert_block()
        .and_then(|bb| bb.get_parent())
        .ok_or_else(|| CodegenError::Llvm("cooperate check outside function".into()))?;
    let cancel_bb = fn_ctx.ctx.append_basic_block(parent, "cancel_exit");
    let continue_bb = fn_ctx.ctx.append_basic_block(parent, "after_cooperate");
    fn_ctx
        .builder
        .build_conditional_branch(is_cancel, cancel_bb, continue_bb)
        .llvm_ctx("cooperate cancel branch")?;

    fn_ctx.builder.position_at_end(cancel_bb);
    emit_cancel_drops(fn_ctx, block_id, drop_plans)?;
    emit_cancel_trap_or_return(fn_ctx)?;

    fn_ctx.builder.position_at_end(continue_bb);
    Ok(())
}

fn cooperate_site_matches(site: &CooperateSite, block_id: u32, kind: CooperateKind) -> bool {
    site.bb_id == block_id && site.kind == kind
}

/// Lower an auto-injected mutex bracket — `Instr::AutoLockAcquire` /
/// `Instr::AutoLockRelease`. `lock` is a `Place` whose backing slot
/// holds the `*mut HewAutoMutex` handle produced by an earlier
/// `hew_auto_mutex_alloc` call (closure-env constructor or generator-
/// state field initialiser).
///
/// `acquire = true`  → `call hew_auto_mutex_lock(loaded_handle)`.
/// `acquire = false` → `call hew_auto_mutex_unlock(loaded_handle)`.
///
/// The handle is loaded from `lock`'s backing pointer — codegen does
/// not address the lock cell directly because the same handle may be
/// re-read at every cross-suspend access in the same bracket loop.
/// Both runtime symbols take a single `*mut HewAutoMutex` and return
/// void; nothing is written back to `lock`.
fn lower_auto_mutex_bracket<'ctx>(
    fn_ctx: &FnCtx<'_, 'ctx>,
    lock: Place,
    acquire: bool,
) -> CodegenResult<()> {
    let symbol = if acquire {
        "hew_auto_mutex_lock"
    } else {
        "hew_auto_mutex_unlock"
    };
    let runtime_fn = intern_runtime_decl(
        fn_ctx.ctx,
        fn_ctx.llvm_mod,
        &mut fn_ctx.runtime_decls.borrow_mut(),
        symbol,
    )?;
    let (lock_ptr, lock_ty) = place_pointer(fn_ctx, lock)?;
    // The lock slot stores a pointer; we expect a pointer-typed
    // alloca. Anything else is a producer contract violation —
    // fail-closed surfacing the mismatch at codegen rather than
    // miscompiling.
    let handle_ty = match lock_ty {
        BasicTypeEnum::PointerType(p) => p,
        other => {
            return Err(CodegenError::FailClosed(format!(
                "{symbol}: lock slot must be pointer-typed; got {other:?}"
            )));
        }
    };
    let handle = fn_ctx
        .builder
        .build_load(handle_ty, lock_ptr, "auto_lock_handle")
        .llvm_ctx_with(|| format!("{symbol} load"))?
        .into_pointer_value();
    fn_ctx
        .builder
        .build_call(runtime_fn, &[handle.into()], symbol)
        .llvm_ctx_with(|| format!("{symbol} call"))?;
    Ok(())
}

/// Whether a function lowers as an `llvm.coro` switched-resume coroutine ramp
/// (its LLVM return type is the `coro.begin` handle `ptr`, and it gets the coro
/// prologue + shared cleanup/suspend-return epilogue).
///
/// A function is a coroutine when EITHER it carries a suspend-family terminator
/// (the await family + a generator `Yield`) OR it is a generator body
/// (`__hew_gen_body_*`). The generator-body name check is load-bearing for a
/// NO-YIELD generator (`gen { 1 }` → `Generator<Never, R>`): it carries no
/// `Yield`, so the terminator scan alone would treat it as an ordinary function
/// returning its logical type — but its construction site (`MakeGenerator`)
/// drives it as a coro ramp expecting the handle. Marking every gen body a
/// coroutine makes a no-yield generator a ramp that runs straight to its final
/// suspend (the consumer's first `next()` then observes `None`), keeping the
/// representation uniform.
fn is_coroutine_function(func: &RawMirFunction) -> bool {
    func.name.starts_with("__hew_gen_body_")
        || func.blocks.iter().any(|b| {
            matches!(
                b.terminator,
                // The ten pure-{resume,cleanup} carriers all collapse to the bare
                // `Suspend`; `SuspendingScopeDeadline` / `SuspendingSelect` keep
                // their distinct terminators. Any of them makes the function a
                // presplit coroutine.
                Terminator::Yield { .. }
                    | Terminator::Suspend { .. }
                    | Terminator::SuspendingScopeDeadline { .. }
                    | Terminator::SuspendingSelect { .. }
            )
        })
}

// ---------------------------------------------------------------------------
// Per-function declaration + body lowering
// ---------------------------------------------------------------------------

fn declare_function<'ctx>(
    ctx: &'ctx Context,
    llvm_mod: &LlvmModule<'ctx>,
    func: &RawMirFunction,
    record_layouts: &RecordLayoutMap<'ctx>,
    enum_layouts: &[EnumLayout],
    emit_wasm_entry_alias: bool,
) -> CodegenResult<FnSymbol<'ctx>> {
    let linkage = if func.name == "main" {
        Some(Linkage::External)
    } else {
        Some(Linkage::Internal)
    };
    // `indirect enum` parameters and return values are heap-pointer-sized;
    // resolve_ty returns the struct type (struct-layout-first invariant for
    // collision safety), so override here for indirect enum names.
    let resolve_value_ty = |ty: &ResolvedTy| -> CodegenResult<BasicTypeEnum<'ctx>> {
        let raw = resolve_ty(ctx, ty, record_layouts)?;
        if let ResolvedTy::Named { name, .. } = ty {
            if crate::layout::is_indirect_enum(name, enum_layouts) {
                return Ok(ctx.ptr_type(AddressSpace::default()).into());
            }
        }
        Ok(raw)
    };
    // A suspendable function (its MIR carries a suspend carrier) is lowered as a
    // coroutine RAMP whose LLVM return type is the `coro.begin` handle (`ptr`),
    // NOT its logical Hew return type. The logical return value is deposited by
    // the body itself on its `Terminator::Return` coroutine arm
    // (`hew_get_reply_channel` + `hew_reply`) to the handler's caller — there is
    // no trailing out-pointer parameter; the trampoline reads no logical value
    // back (it only drives resume/poll and observes Ready). The `returns_unit`
    // flag below is derived from the LOGICAL return type so the body's return
    // lowering still knows whether there is a value to deposit.
    let is_coroutine = is_coroutine_function(func);
    let return_ty_llvm = if is_coroutine {
        ctx.ptr_type(AddressSpace::default()).into()
    } else if matches!(func.call_conv, FunctionCallConv::LambdaActorBody(_)) {
        // A lambda-actor body always returns the runtime ABI status `i32`
        // (`HewLambdaActorBody`'s C signature); the user reply value is
        // serialised through the `reply_out` / `reply_len_out` slots by
        // the Return epilogue. The MIR `return_ty` carries the USER reply
        // type (Unit for Tell, i64 for Ask) so the body's `ReturnSlot`
        // alloca sizes correctly for the reply move; the LLVM ABI return
        // is fixed to i32 here.
        ctx.i32_type().into()
    } else {
        resolve_value_ty(&func.return_ty)?
    };
    // Accept integer, float, pointer, and struct return types. Integer covers
    // the original Cluster 1 spine; pointer covers `String` (a
    // `*mut c_char` / opaque `ptr` in LLVM IR) which is lowerable via
    // `Instr::StringLit`. Float covers f32/f64 values returned by-value
    // through the standard LLVM ABI; locals, args, arithmetic, comparisons,
    // and call-site stores already carry `FloatType` as normal LLVM values.
    // Struct returns are needed by synthesised
    // machine `__step(self, event) -> <Name>` functions, which return
    // the tagged-union machine struct by value (Slice 5). LLVM emits
    // these as natural-ABI struct returns; the caller-side store-back
    // is wired by the `m.step(ev)` slice. Unit still uses its canonical
    // zero-sized stand-in return, and arrays/vectors remain outside this
    // accepted subset.
    // LESSONS: `boundary-fail-closed`.
    if !matches!(
        return_ty_llvm,
        BasicTypeEnum::IntType(_)
            | BasicTypeEnum::FloatType(_)
            | BasicTypeEnum::PointerType(_)
            | BasicTypeEnum::StructType(_)
    ) {
        return Err(CodegenError::Unsupported(
            "only integer-, float-, pointer-, and struct-returning functions are lowerable; \
             array/vector return types are out of the current spine subset",
        ));
    }
    // Resolve parameter types from `func.params`. Each parameter type must
    // be representable as a `BasicMetadataTypeEnum` (integers and pointers
    // are both legal LLVM value-param types for the current spine subset).
    // The parameter-prologue in `lower_function` stores each LLVM function
    // argument into the corresponding `locals[i]` alloca slot.
    let ctx_ptr_ty = ctx.ptr_type(AddressSpace::default());
    let mut param_tys: Vec<BasicMetadataTypeEnum> = Vec::with_capacity(
        func.params.len() + usize::from(func.call_conv.carries_execution_context()),
    );
    if func.call_conv.carries_execution_context() {
        param_tys.push(ctx_ptr_ty.into());
    }
    for param_ty in &func.params {
        let llvm_ty = resolve_value_ty(param_ty)?;
        param_tys.push(metadata_type_from_basic(llvm_ty));
    }
    // P5-RX sub-stage 1: receive handlers gain a trailing `borrow_mode: i32`
    // so the dispatch trampoline can thread the copy-vs-borrow receipt
    // discriminant through to the handler ABI. DORMANT — the handler body
    // ignores it this sub-stage (the prologue in `lower_function` stores only
    // `func.params`, so the trailing arg has no local slot).
    //
    // Scoped strictly to receive handlers (`<Actor>__recv__<handler>`): the
    // `ActorHandler` calling convention is also worn by `__init` / `__on_start`
    // / `__on_stop__N` / supervisor-bootstrap functions, which are invoked by
    // their OWN runtime trampolines with the unchanged ABI. The dispatch
    // trampoline (the sole caller of `__recv__` symbols — proven C4) is the
    // only emitter updated to pass this arg, so only `__recv__` signatures may
    // grow it.
    if func.call_conv == FunctionCallConv::ActorHandler && func.name.contains("__recv__") {
        param_tys.push(ctx.i32_type().into());
    }
    // W6.010 value routing needs NO extra parameter: a suspendable handler's
    // coroutine body deposits its reply directly via `hew_get_reply_channel` +
    // `hew_reply` at its final return (the body completes wherever the resume
    // lands — including the scheduler's `resume_park` after the trampoline frame
    // has unwound, so a trampoline-supplied out-slot would be dangling). The
    // ramp's only ABI change vs an ordinary handler is the `ptr` return type
    // (the coro handle), set above.
    let fn_ty = match return_ty_llvm {
        BasicTypeEnum::IntType(i) => i.fn_type(&param_tys, false),
        // Other shapes are pre-filtered above; keep the arms exhaustive so
        // the LLVM API surface stays explicit if a future cluster widens the
        // accepted set.
        BasicTypeEnum::FloatType(f) => f.fn_type(&param_tys, false),
        BasicTypeEnum::StructType(s) => s.fn_type(&param_tys, false),
        BasicTypeEnum::PointerType(p) => p.fn_type(&param_tys, false),
        BasicTypeEnum::ArrayType(a) => a.fn_type(&param_tys, false),
        BasicTypeEnum::VectorType(v) => v.fn_type(&param_tys, false),
        BasicTypeEnum::ScalableVectorType(v) => v.fn_type(&param_tys, false),
    };
    let symbol_name = if emit_wasm_entry_alias && func.name == "main" {
        "__original_main"
    } else {
        &func.name
    };
    let llvm_fn = llvm_mod.add_function(symbol_name, fn_ty, linkage);
    Ok(FnSymbol::Real {
        value: llvm_fn,
        return_ty: return_ty_llvm,
        returns_unit: matches!(func.return_ty, ResolvedTy::Unit),
    })
}

fn emit_wasm_main_export_wrapper<'ctx>(
    ctx: &'ctx Context,
    llvm_mod: &LlvmModule<'ctx>,
    fn_symbols: &FnSymbolMap<'ctx>,
) -> CodegenResult<()> {
    let Some(symbol) = fn_symbols.get("main").copied() else {
        return Ok(());
    };
    let (original, _return_ty, _returns_unit) =
        symbol.real("main", "emit_wasm_main_export_wrapper")?;
    let fn_ty = original.get_type();
    let params = fn_ty.get_param_types();
    if !params.is_empty() {
        return Err(CodegenError::FailClosed(format!(
            "WASM entry wrapper expected parameterless main, got {} parameters",
            params.len()
        )));
    }

    let wrapper = llvm_mod.add_function("main", fn_ty, Some(Linkage::External));
    let entry = ctx.append_basic_block(wrapper, "entry");
    let builder = ctx.create_builder();
    builder.position_at_end(entry);
    let call = builder
        .build_call(original, &[], "__original_main_call")
        .llvm_ctx("WASM main wrapper call")?;
    if fn_ty.get_return_type().is_some() {
        let ret = call.try_as_basic_value().basic().ok_or_else(|| {
            CodegenError::FailClosed("WASM main wrapper call returned void".into())
        })?;
        builder
            .build_return(Some(&ret))
            .llvm_ctx("WASM main wrapper return")?;
    } else {
        builder
            .build_return(None)
            .llvm_ctx("WASM main wrapper return void")?;
    }

    Ok(())
}

fn function_needs_closure_call_fallback_context(func: &RawMirFunction) -> bool {
    !func.call_conv.carries_execution_context()
        && func.blocks.iter().any(|block| {
            block
                .instructions
                .iter()
                .any(|instr| matches!(instr, Instr::CallClosure { .. }))
        })
}

fn build_zeroed_closure_call_fallback_context<'ctx>(
    ctx: &'ctx Context,
    builder: &Builder<'ctx>,
) -> CodegenResult<PointerValue<'ctx>> {
    let word_array_ty = ctx.i64_type().array_type(HEW_CTX_SIZE / 8);
    let slot = builder
        .build_alloca(word_array_ty, "closure_call_fallback_ctx")
        .llvm_ctx("alloca closure_call_fallback_ctx")?;
    builder
        .build_store(slot, word_array_ty.const_zero())
        .llvm_ctx("zero closure_call_fallback_ctx")?;
    Ok(slot)
}

fn validate_context_markers_for_codegen(func: &RawMirFunction) -> Vec<hew_mir::MirCheck> {
    if func.call_conv == FunctionCallConv::ClosureInvoke {
        // Closure invoke shims receive the caller-selected execution context as
        // an ABI parameter; they may observe it, but they must not masquerade
        // as scheduler-installed context boundaries.
        return func
            .blocks
            .iter()
            .flat_map(|block| {
                block.instructions.iter().filter(|&instr| matches!(instr, Instr::EnterContext | Instr::ExitContext)).map(|_| hew_mir::MirCheck::ContextBoundaryViolation {
                            function: func.name.clone(),
                            block: block.id,
                            kind: "closure-context-boundary-marker",
                            reason: "ClosureInvoke shims receive a context parameter; EnterContext/ExitContext are only legal on scheduler-installed context boundaries".to_string(),
                        })
            })
            .collect();
    }
    validate_context_markers(func)
}

/// Does the module reach a distributed-node authority (`Node::*` builtin)?
///
/// The de-globalized node state (`CURRENT_NODE`/`KNOWN_NODES`/`REPLY_TABLE`,
/// owned by `RuntimeInner::node`) is touched the moment a program calls
/// `Node::set_transport`/`start`/`connect`/`register`/`lookup`/`shutdown`.
/// Those builtins lower to `Terminator::Call` with a `Node::`-prefixed callee.
/// A program can touch the node authority WITHOUT declaring any actor (e.g. a
/// bare `Node::start` smoke), so node presence is an independent reason to
/// install the runtime at program entry — actor/supervisor presence does not
/// imply it. Scans every function body's terminators for a `Node::` callee.
fn module_uses_node_authority(raw_mir: &[RawMirFunction]) -> bool {
    raw_mir.iter().any(|func| {
        func.blocks.iter().any(|block| {
            matches!(
                &block.terminator,
                Terminator::Call { callee, .. } if callee.starts_with("Node::")
            )
        })
    })
}

/// Does the module reach the user-metrics registry authority?
///
/// The de-globalized metrics registry is owned by `RuntimeInner::metrics`.
/// Registration and mutation remain fail-closed in the runtime, so a metrics-only
/// program must install the runtime at `main` entry just like node/actor programs
/// do. Scans every function body's runtime-call instructions for the C-ABI symbols that
/// `std::metrics` lowers to.
fn module_uses_metric_authority(raw_mir: &[RawMirFunction]) -> bool {
    raw_mir.iter().any(|func| {
        func.blocks.iter().any(|block| {
            block.instructions.iter().any(|instr| {
                matches!(
                    instr,
                    Instr::CallRuntimeAbi(call) if call.symbol().starts_with("hew_metric_")
                )
            })
        })
    })
}

/// Lower one function from `raw_mir`, consuming `elaborated_mir.drop_plans`
/// to emit LIFO close calls before every exit terminator.
///
/// `elab` is the `ElaboratedMirFunction` whose `name` matches `func.name`.
/// When `pipeline.elaborated_mir` has no matching entry (e.g. in hand-built
/// test pipelines that predate elaboration), `elab` may be `None`; in that
/// case `emit_elab_drops` receives an empty slice and emits nothing — the
/// inline `Instr::Drop` path in `lower_instruction` still fires for any
/// `Instr::Drop` entries baked into `raw_mir.blocks`.
///
/// `checked` carries the cooperate-site side table computed by the MIR
/// dataflow pass. Empty/missing checked MIR means no cooperate injection
/// for legacy hand-built codegen tests; full lowered pipelines always carry
/// a matching checked function.
///
/// `module_uses_runtime` is true when the module declares an actor, declares a
/// supervisor, or reaches a runtime-owned authority (Node, metrics). When true,
/// the native `main` entry installs the default `RuntimeInner` (via
/// `hew_sched_init`) in its prologue, BEFORE any user code runs. This
/// guarantees a runtime authority (node setup, the live-actor registry, the
/// shutdown phase, user metrics) is never touched before the runtime is
/// installed — the de-globalized `rt_current()` fails closed
/// (`hew-runtime/src/runtime.rs`) rather than lazily fabricating one, so a
/// program that calls `Node::start`, `metrics.counter(..)`, or `pid.tell(..)`
/// before its first `spawn` site (which also calls `hew_sched_init`) would
/// otherwise trap.
/// `hew_sched_init` is idempotent (a second call CAS-fails to a no-op), so the
/// spawn-site and supervisor-bootstrap calls remain harmless.
/// Stage 2 (gdb `-g`): set the builder's current debug location from a
/// per-instruction / per-terminator source span (`(start_byte, end_byte)`),
/// scoped to the function's `DISubprogram`.
///
/// Fail-closed no-op when the function carries no subprogram (it is not a
/// plain, in-file, non-suspend `fn`), when there is no span for this position
/// (the previous, nearest-enclosing location persists — legal at -O0, never a
/// fabricated line), or when the span's start maps outside the compiled file
/// (a monomorphised stdlib body carries an offset into the stdlib source, not
/// the user's). Reuses the Stage-1 byte→line index as the single line
/// authority.
fn set_debug_location_for_span<'ctx>(
    ctx: &'ctx Context,
    builder: &Builder<'ctx>,
    debug: Option<&ModuleDebugCtx<'_, 'ctx>>,
    subprogram: Option<inkwell::debug_info::DISubprogram<'ctx>>,
    span: Option<&(u32, u32)>,
    lexical_scopes: Option<&LexicalScopes<'ctx>>,
) {
    let (Some(dctx), Some(subprogram), Some(&(start, _end))) = (debug, subprogram, span) else {
        return;
    };
    if !dctx.line_index.contains(start as usize) {
        return;
    }
    let line = dctx.line_index.line(start as usize);
    let column = dctx.line_index.column(start as usize);
    // Scope the location to the innermost lexical block whose source extent
    // contains this instruction's start byte — so an instruction inside a
    // shadowing `{ }` reports the inner block as its current scope, and the
    // debugger resolves a shadowed name to the inner binding. No containing
    // block (or no lexical table) → the flat subprogram scope, unchanged.
    let scope = lexical_scopes
        .and_then(|ls| ls.scope_for_byte(start))
        .unwrap_or_else(|| subprogram.as_debug_info_scope());
    let loc = dctx
        .di_builder
        .create_debug_location(ctx, line, column, scope, None);
    builder.set_current_debug_location(loc);
}

// DWARF `DW_ATE_*` base-type encodings (DWARF5 §7.8). inkwell takes these as a
// raw `LLVMDWARFTypeEncoding` (a `u32`); the constants are stable across LLVM
// versions.
const DW_ATE_BOOLEAN: u32 = 0x02;
const DW_ATE_FLOAT: u32 = 0x04;
const DW_ATE_SIGNED: u32 = 0x05;
const DW_ATE_UNSIGNED: u32 = 0x07;
const DW_ATE_UNSIGNED_CHAR: u32 = 0x08;

/// Scalar `(dwarf_name, size_in_bits, encoding)` for a `ResolvedTy`, or `None`
/// when the type is not a scalar base type. Pointer-width types use the
/// `target_data` pointer size so the DIE matches the alloca.
fn scalar_di_basic(ty: &ResolvedTy, target_data: &TargetData) -> Option<(&'static str, u64, u32)> {
    let ptr_bits = u64::from(target_data.get_pointer_byte_size(None)) * 8;
    Some(match ty {
        ResolvedTy::I8 => ("i8", 8, DW_ATE_SIGNED),
        ResolvedTy::U8 => ("u8", 8, DW_ATE_UNSIGNED),
        ResolvedTy::I16 => ("i16", 16, DW_ATE_SIGNED),
        ResolvedTy::U16 => ("u16", 16, DW_ATE_UNSIGNED),
        ResolvedTy::I32 => ("i32", 32, DW_ATE_SIGNED),
        ResolvedTy::U32 => ("u32", 32, DW_ATE_UNSIGNED),
        ResolvedTy::I64 => ("i64", 64, DW_ATE_SIGNED),
        ResolvedTy::U64 => ("u64", 64, DW_ATE_UNSIGNED),
        ResolvedTy::Isize => ("isize", ptr_bits, DW_ATE_SIGNED),
        ResolvedTy::Usize => ("usize", ptr_bits, DW_ATE_UNSIGNED),
        ResolvedTy::Bool => ("bool", 8, DW_ATE_BOOLEAN),
        // Hew `char` is a Unicode scalar value lowered to i32.
        ResolvedTy::Char => ("char", 32, DW_ATE_UNSIGNED_CHAR),
        ResolvedTy::F32 => ("f32", 32, DW_ATE_FLOAT),
        ResolvedTy::F64 => ("f64", 64, DW_ATE_FLOAT),
        // Duration is i64 nanoseconds at the ABI.
        ResolvedTy::Duration => ("Duration", 64, DW_ATE_SIGNED),
        _ => return None,
    })
}

/// Resolve a `ResolvedTy` to a DWARF type DIE, mirroring the `resolve_ty`
/// LLVM-type authority. Memoized on `dctx.di_type_cache` to dedup
/// monomorphizations and break recursive-type cycles (a record inserts a
/// placeholder before resolving its members). Returns `None` — emitting NO DIE,
/// fail-closed — when the type cannot be faithfully resolved (an unknown
/// `Named` in neither layout map, a `Never`, a not-yet-supported composite)
/// rather than fabricating a placeholder type. The caller then skips the
/// variable DIE for that slot.
#[expect(
    clippy::too_many_arguments,
    reason = "debug-type resolution mirrors resolve_ty's explicit borrows plus the layout maps"
)]
fn resolve_di_type<'ctx>(
    ctx: &'ctx Context,
    dctx: &ModuleDebugCtx<'_, 'ctx>,
    target_data: &TargetData,
    ty: &ResolvedTy,
    record_layouts: &RecordLayoutMap<'ctx>,
    enum_layouts: &[EnumLayout],
    record_field_resolved_tys: &HashMap<String, Vec<ResolvedTy>>,
    record_field_names: &HashMap<String, Vec<String>>,
) -> Option<inkwell::debug_info::DIType<'ctx>> {
    use inkwell::debug_info::DIType;

    // Scalars: emit a `DW_TAG_base_type`. Keyed by the scalar name (every
    // `i64` shares one DIE).
    if let Some((name, size_bits, encoding)) = scalar_di_basic(ty, target_data) {
        let key = format!("scalar:{name}");
        if let Some(t) = dctx.di_type_cache.borrow().get(&key).copied() {
            return Some(t);
        }
        let basic = dctx
            .di_builder
            .create_basic_type(name, size_bits, encoding, DIFlags::PUBLIC)
            .expect("DWARF base type for a scalar is infallible")
            .as_type();
        dctx.di_type_cache.borrow_mut().insert(key, basic);
        return Some(basic);
    }

    // `string`, `CancellationToken`, and other opaque handles lower to a bare
    // `ptr`; represent them as a typeless pointer DIE so gdb shows the address.
    let pointer_di = |pointee: Option<DIType<'ctx>>, name: &str| -> DIType<'ctx> {
        let ptr_bits = u64::from(target_data.get_pointer_byte_size(None)) * 8;
        let pointee = pointee.unwrap_or_else(|| {
            // A void-ish pointee: an i8 base type stands in for "unknown".
            dctx.di_builder
                .create_basic_type("u8", 8, DW_ATE_UNSIGNED, DIFlags::PUBLIC)
                .expect("u8 base type")
                .as_type()
        });
        dctx.di_builder
            .create_pointer_type(name, pointee, ptr_bits, 0, AddressSpace::default())
            .as_type()
    };

    if matches!(ty, ResolvedTy::String) {
        let key = "ptr:string".to_string();
        if let Some(t) = dctx.di_type_cache.borrow().get(&key).copied() {
            return Some(t);
        }
        let di = pointer_di(None, "string");
        dctx.di_type_cache.borrow_mut().insert(key, di);
        return Some(di);
    }

    if let ResolvedTy::Named { name, args, .. } = ty {
        let key = if args.is_empty() {
            name.clone()
        } else {
            mangle_with_shortened_args(name, args)
        };

        // An enum (in the enum-layout map) — emit the degraded tagged-union DIE.
        if let Some(enum_layout) = enum_layouts
            .iter()
            .find(|e| e.name == key || short_name(&e.name) == short_name(name))
        {
            return resolve_enum_di_type(
                ctx,
                dctx,
                target_data,
                enum_layout,
                record_layouts,
                enum_layouts,
                record_field_resolved_tys,
                record_field_names,
            );
        }

        // A record (in the LLVM struct-layout map) — emit a struct DIE.
        let llvm_struct = record_layouts
            .get(key.as_str())
            .or_else(|| record_layouts.get(short_name(name)))
            .copied();
        if let Some(llvm_struct) = llvm_struct {
            // Recursion guard: insert a forward struct placeholder under the key
            // BEFORE resolving members, so a self-referential record terminates.
            let cache_key = format!("record:{key}");
            if let Some(t) = dctx.di_type_cache.borrow().get(&cache_key).copied() {
                return Some(t);
            }
            let size_bits = target_data.get_bit_size(&llvm_struct);
            let align_bits = target_data.get_abi_alignment(&llvm_struct) * 8;
            let placeholder = dctx
                .di_builder
                .create_struct_type(
                    dctx.compile_unit.as_debug_info_scope(),
                    short_name(name),
                    dctx.file,
                    0,
                    size_bits,
                    align_bits,
                    DIFlags::PUBLIC,
                    None,
                    &[],
                    0,
                    None,
                    short_name(name),
                )
                .as_type();
            dctx.di_type_cache
                .borrow_mut()
                .insert(cache_key.clone(), placeholder);

            // Resolve member types + offsets. Field names come from the MIR
            // record layout; missing names fall back to positional `field_N`.
            let field_tys = record_field_resolved_tys
                .get(key.as_str())
                .or_else(|| record_field_resolved_tys.get(short_name(name)));
            let field_names = record_field_names
                .get(key.as_str())
                .or_else(|| record_field_names.get(short_name(name)));
            if let Some(field_tys) = field_tys {
                let mut members: Vec<DIType<'ctx>> = Vec::with_capacity(field_tys.len());
                for (i, fty) in field_tys.iter().enumerate() {
                    let member_di = resolve_di_type(
                        ctx,
                        dctx,
                        target_data,
                        fty,
                        record_layouts,
                        enum_layouts,
                        record_field_resolved_tys,
                        record_field_names,
                    );
                    let Some(member_di) = member_di else {
                        // A field whose type can't be resolved fails the whole
                        // record closed — never emit a struct with a guessed
                        // member type.
                        return None;
                    };
                    let offset_bits = target_data
                        .offset_of_element(
                            &llvm_struct,
                            u32::try_from(i).expect("struct field count fits in u32"),
                        )
                        .map(|b| b * 8)
                        .unwrap_or(0);
                    let member_size = member_di_size_bits(member_di, target_data, fty);
                    let member_name = field_names
                        .and_then(|names| names.get(i))
                        .cloned()
                        .unwrap_or_else(|| format!("field_{i}"));
                    let member = dctx.di_builder.create_member_type(
                        dctx.compile_unit.as_debug_info_scope(),
                        &member_name,
                        dctx.file,
                        0,
                        member_size,
                        0,
                        offset_bits,
                        DIFlags::PUBLIC,
                        member_di,
                    );
                    members.push(member.as_type());
                }
                let full = dctx
                    .di_builder
                    .create_struct_type(
                        dctx.compile_unit.as_debug_info_scope(),
                        short_name(name),
                        dctx.file,
                        0,
                        size_bits,
                        align_bits,
                        DIFlags::PUBLIC,
                        None,
                        &members,
                        0,
                        None,
                        short_name(name),
                    )
                    .as_type();
                dctx.di_type_cache.borrow_mut().insert(cache_key, full);
                return Some(full);
            }
            // Struct with no resolvable field list — keep the placeholder.
            return Some(placeholder);
        }
    }

    // Unknown / unsupported type — emit no DIE (fail-closed).
    None
}

/// Size-in-bits of a member's DIType, for the `DW_AT_byte_size` of the member.
/// Computed from the field's LLVM type via `resolve_ty` where possible; the
/// member type already carries its own size, so this only needs the field's
/// own size for the `DW_TAG_member` wrapper (LLVM recomputes from the member
/// type, so a 0 here is acceptable, but a real value keeps the IR readable).
fn member_di_size_bits(
    _member_di: inkwell::debug_info::DIType<'_>,
    _target_data: &TargetData,
    _fty: &ResolvedTy,
) -> u64 {
    // The member's `DW_AT_byte_size` is derived by LLVM from the member type's
    // own size; passing 0 lets the member type's size dominate. Kept as a
    // helper seam so a future exact-size pass has an obvious home.
    0
}

/// Emit the degraded-but-faithful enum DIE (Risk E): a `DW_TAG_structure_type`
/// named after the enum with a `tag` member typed by a
/// `DW_TAG_enumeration_type` (variant names as enumerators, so gdb prints the
/// active variant name) and a `payload` member typed by a `DW_TAG_union_type`
/// of per-variant struct DIEs (so gdb can read a variant's payload fields). The
/// true auto-discriminated `DW_TAG_variant_part` is out of scope (inkwell lacks
/// `create_variant_part`); this is the faithful-as-inkwell-allows view.
#[expect(
    clippy::too_many_arguments,
    reason = "debug-type resolution threads the same explicit borrows as resolve_di_type"
)]
fn resolve_enum_di_type<'ctx>(
    ctx: &'ctx Context,
    dctx: &ModuleDebugCtx<'_, 'ctx>,
    target_data: &TargetData,
    enum_layout: &EnumLayout,
    record_layouts: &RecordLayoutMap<'ctx>,
    enum_layouts: &[EnumLayout],
    record_field_resolved_tys: &HashMap<String, Vec<ResolvedTy>>,
    record_field_names: &HashMap<String, Vec<String>>,
) -> Option<inkwell::debug_info::DIType<'ctx>> {
    use inkwell::debug_info::DIType;

    let enum_name = short_name(&enum_layout.name);
    // An indirect enum's local holds a `ptr` to the heap struct; represent it
    // as a pointer to the (degraded) enum struct DIE.
    let cache_key = format!("enum:{}", enum_layout.name);
    if let Some(t) = dctx.di_type_cache.borrow().get(&cache_key).copied() {
        let result = if enum_layout.is_indirect {
            let ptr_bits = u64::from(target_data.get_pointer_byte_size(None)) * 8;
            dctx.di_builder
                .create_pointer_type(enum_name, t, ptr_bits, 0, AddressSpace::default())
                .as_type()
        } else {
            t
        };
        return Some(result);
    }

    // The enum's outer LLVM struct `{ tag: iW, payload: [..] }` lives in the
    // record-layout map under the enum name.
    let outer_struct = record_layouts
        .get(enum_layout.name.as_str())
        .or_else(|| record_layouts.get(enum_name))
        .copied()?;
    let struct_size_bits = target_data.get_bit_size(&outer_struct);
    let struct_align_bits = target_data.get_abi_alignment(&outer_struct) * 8;

    // Tag: a `DW_TAG_enumeration_type` whose enumerators are the variant names.
    let enumerators: Vec<_> = enum_layout
        .variants
        .iter()
        .enumerate()
        .map(|(i, v)| {
            dctx.di_builder.create_enumerator(
                short_name(&v.name),
                i64::try_from(i).unwrap_or(i64::MAX),
                false,
            )
        })
        .collect();
    let tag_bits = u64::from(enum_layout.tag_width);
    let tag_underlying = dctx
        .di_builder
        .create_basic_type("u32", tag_bits.max(8), DW_ATE_UNSIGNED, DIFlags::PUBLIC)
        .expect("DWARF base type for the enum tag is infallible")
        .as_type();
    let tag_di = dctx
        .di_builder
        .create_enumeration_type(
            dctx.compile_unit.as_debug_info_scope(),
            &format!("{enum_name}::Tag"),
            dctx.file,
            0,
            tag_bits.max(8),
            0,
            &enumerators,
            tag_underlying,
        )
        .as_type();

    // Recursion guard (Risk C): a recursive enum (`indirect enum List { Cons {
    // tail: List }; Nil }`) would re-enter this function while resolving the
    // `tail: List` payload field, with no cache entry yet → infinite recursion
    // → stack overflow. Insert a placeholder struct DIE (tag member only) under
    // the cache key BEFORE the payload loop, so the recursive field resolves to
    // a pointer-to-placeholder and terminates. The full struct (with the
    // payload union) overwrites the placeholder at the end; recursive references
    // legitimately point at the tag-only placeholder, which gdb resolves by
    // name — the standard forward-declared-composite pattern.
    let tag_offset_for_placeholder = target_data
        .offset_of_element(&outer_struct, 0)
        .map(|b| b * 8)
        .unwrap_or(0);
    let placeholder_tag_member = dctx
        .di_builder
        .create_member_type(
            dctx.compile_unit.as_debug_info_scope(),
            "tag",
            dctx.file,
            0,
            tag_bits.max(8),
            0,
            tag_offset_for_placeholder,
            DIFlags::PUBLIC,
            tag_di,
        )
        .as_type();
    let placeholder = dctx
        .di_builder
        .create_struct_type(
            dctx.compile_unit.as_debug_info_scope(),
            enum_name,
            dctx.file,
            0,
            struct_size_bits,
            struct_align_bits,
            DIFlags::PUBLIC,
            None,
            &[placeholder_tag_member],
            0,
            None,
            enum_name,
        )
        .as_type();
    dctx.di_type_cache
        .borrow_mut()
        .insert(cache_key.clone(), placeholder);

    // Payload: a `DW_TAG_union_type` of per-variant struct DIEs. A variant with
    // no payload contributes nothing; a variant whose payload can't be resolved
    // is skipped (the variant name still prints via the tag).
    let mut payload_variants: Vec<DIType<'ctx>> = Vec::new();
    for variant in &enum_layout.variants {
        if variant.field_tys.is_empty() {
            continue;
        }
        let mut members: Vec<DIType<'ctx>> = Vec::with_capacity(variant.field_tys.len());
        let mut ok = true;
        // The variant's own LLVM struct, for member offsets.
        let variant_struct = ctx.struct_type(
            &variant
                .field_tys
                .iter()
                .filter_map(|fty| resolve_ty(ctx, fty, record_layouts).ok())
                .collect::<Vec<_>>(),
            false,
        );
        for (i, fty) in variant.field_tys.iter().enumerate() {
            let Some(member_di) = resolve_di_type(
                ctx,
                dctx,
                target_data,
                fty,
                record_layouts,
                enum_layouts,
                record_field_resolved_tys,
                record_field_names,
            ) else {
                ok = false;
                break;
            };
            let field_idx = u32::try_from(i).unwrap_or(u32::MAX);
            let offset_bits = if field_idx < variant_struct.count_fields() {
                target_data
                    .offset_of_element(&variant_struct, field_idx)
                    .map(|b| b * 8)
                    .unwrap_or(0)
            } else {
                0
            };
            let member_name = variant
                .field_names
                .get(i)
                .cloned()
                .unwrap_or_else(|| format!("field_{i}"));
            let member = dctx.di_builder.create_member_type(
                dctx.compile_unit.as_debug_info_scope(),
                &member_name,
                dctx.file,
                0,
                0,
                0,
                offset_bits,
                DIFlags::PUBLIC,
                member_di,
            );
            members.push(member.as_type());
        }
        if !ok {
            continue;
        }
        let variant_size_bits = target_data.get_bit_size(&variant_struct);
        let variant_struct_di = dctx
            .di_builder
            .create_struct_type(
                dctx.compile_unit.as_debug_info_scope(),
                short_name(&variant.name),
                dctx.file,
                0,
                variant_size_bits,
                0,
                DIFlags::PUBLIC,
                None,
                &members,
                0,
                None,
                short_name(&variant.name),
            )
            .as_type();
        // A `DW_TAG_union_type`'s children must be `DW_TAG_member`s — LLVM's
        // DWARF emitter drops any union element that is a bare composite type
        // (the empty-union bug the live-debugger check caught). Wrap the variant
        // struct in a member named after the variant, at union offset 0 (every
        // union member overlays the same payload bytes), so gdb can read
        // `status.payload.Packet.code`.
        let variant_member = dctx
            .di_builder
            .create_member_type(
                dctx.compile_unit.as_debug_info_scope(),
                short_name(&variant.name),
                dctx.file,
                0,
                variant_size_bits,
                0,
                0,
                DIFlags::PUBLIC,
                variant_struct_di,
            )
            .as_type();
        payload_variants.push(variant_member);
    }

    // The outer struct: member 0 = tag (the enumeration), member 1 = payload
    // (the union), with offsets from the LLVM `{ tag, payload }` struct.
    let tag_offset_bits = target_data
        .offset_of_element(&outer_struct, 0)
        .map(|b| b * 8)
        .unwrap_or(0);
    // Payload byte-offset within the enclosing enum struct (after the tag +
    // its alignment padding). The payload union's own size is the bytes from
    // this offset to the end of the enum — `struct_size - payload_offset` — NOT
    // `struct_size - tag_bits`, which ignored the tag→payload padding and made
    // the union one byte larger than the space it occupies (extending past the
    // object). Falls back to the tag-width subtraction only if the offset query
    // fails (a 1-element struct with no payload field, which carries no union).
    let payload_offset_bits = target_data
        .offset_of_element(&outer_struct, 1)
        .map(|b| b * 8)
        .unwrap_or(tag_bits.max(8));

    let payload_di = if payload_variants.is_empty() {
        None
    } else {
        let payload_bits = struct_size_bits.saturating_sub(payload_offset_bits);
        Some(
            dctx.di_builder
                .create_union_type(
                    dctx.compile_unit.as_debug_info_scope(),
                    &format!("{enum_name}::Payload"),
                    dctx.file,
                    0,
                    payload_bits,
                    0,
                    DIFlags::PUBLIC,
                    &payload_variants,
                    0,
                    &format!("{enum_name}::Payload"),
                )
                .as_type(),
        )
    };
    let tag_member = dctx
        .di_builder
        .create_member_type(
            dctx.compile_unit.as_debug_info_scope(),
            "tag",
            dctx.file,
            0,
            tag_bits.max(8),
            0,
            tag_offset_bits,
            DIFlags::PUBLIC,
            tag_di,
        )
        .as_type();
    let mut struct_members = vec![tag_member];
    if let Some(payload_di) = payload_di {
        // Reuse the payload offset computed for the union's byte-size above.
        let payload_member = dctx
            .di_builder
            .create_member_type(
                dctx.compile_unit.as_debug_info_scope(),
                "payload",
                dctx.file,
                0,
                0,
                0,
                payload_offset_bits,
                DIFlags::PUBLIC,
                payload_di,
            )
            .as_type();
        struct_members.push(payload_member);
    }
    let enum_struct = dctx
        .di_builder
        .create_struct_type(
            dctx.compile_unit.as_debug_info_scope(),
            enum_name,
            dctx.file,
            0,
            struct_size_bits,
            struct_align_bits,
            DIFlags::PUBLIC,
            None,
            &struct_members,
            0,
            None,
            enum_name,
        )
        .as_type();
    dctx.di_type_cache
        .borrow_mut()
        .insert(cache_key, enum_struct);

    if enum_layout.is_indirect {
        let ptr_bits = u64::from(target_data.get_pointer_byte_size(None)) * 8;
        Some(
            dctx.di_builder
                .create_pointer_type(enum_name, enum_struct, ptr_bits, 0, AddressSpace::default())
                .as_type(),
        )
    } else {
        Some(enum_struct)
    }
}

/// Insert an `llvm.dbg.declare` record at the end of `block`, binding `storage`
/// (an alloca) to the variable `var_info` with `debug_loc`.
///
/// WHY a raw FFI call and not `DebugInfoBuilder::insert_declare_at_end`: under
/// LLVM 19+ (we build against LLVM 22) the underlying
/// `LLVMDIBuilderInsertDeclareAtEnd` returns a `DbgRecord`, not an
/// `Instruction`; inkwell 0.9's safe wrapper unconditionally casts that to a
/// `LLVMValueRef` and constructs an `InstructionValue`, whose `is_instruction()`
/// assertion then panics — even though the dbg.declare WAS correctly inserted.
/// Calling the new-format record API directly (`…InsertDeclareRecordAtEnd`,
/// which inkwell itself wraps for this LLVM version) sidesteps the broken
/// return-value handling. We discard the returned `DbgRecord`. This is a bug
/// workaround for the vendored inkwell, NOT new ABI substrate.
fn dbg_declare_at_end<'ctx>(
    di_builder: &DebugInfoBuilder<'ctx>,
    storage: PointerValue<'ctx>,
    var_info: inkwell::debug_info::DILocalVariable<'ctx>,
    expr: inkwell::debug_info::DIExpression<'ctx>,
    debug_loc: inkwell::debug_info::DILocation<'ctx>,
    block: inkwell::basic_block::BasicBlock<'ctx>,
) {
    use inkwell::llvm_sys::debuginfo::LLVMDIBuilderInsertDeclareRecordAtEnd;
    use inkwell::values::AsValueRef;
    // SAFETY: every pointer comes from a live inkwell wrapper bound to the same
    // module/context; the call only inserts a dbg record and returns a handle we
    // ignore. The new-format record API is correct for LLVM 19+ (the format the
    // module is built in — inkwell selects it via the `llvm22-1` feature).
    unsafe {
        LLVMDIBuilderInsertDeclareRecordAtEnd(
            di_builder.as_mut_ptr(),
            storage.as_value_ref(),
            var_info.as_mut_ptr(),
            expr.as_mut_ptr(),
            debug_loc.as_mut_ptr(),
            block.as_mut_ptr(),
        );
    }
}

/// gdb `-g` lexical-block map for one function. Holds one `DILexicalBlock` per
/// HIR scope in the MIR `scope_table`, parented per the table and rooted at the
/// subprogram, plus a byte-range index for resolving an instruction span to its
/// innermost enclosing scope. Empty (`blocks` empty) for any function whose MIR
/// carries no `scope_table` — every variable and location then falls back to the
/// flat subprogram scope, exactly the pre-lexical behaviour.
struct LexicalScopes<'ctx> {
    /// Raw HIR scope id → its `DILexicalBlock`.
    blocks: HashMap<u32, inkwell::debug_info::DILexicalBlock<'ctx>>,
    /// `(start, end, scope_id)` for every scope, sorted by ascending extent
    /// width so the FIRST containing entry is the innermost (tightest) scope.
    ranges: Vec<(u32, u32, u32)>,
}

impl<'ctx> LexicalScopes<'ctx> {
    /// Build the lexical-block map from `func.scope_table`. Parents are created
    /// before children (the table is walked until every block whose parent is
    /// ready is built), so each `create_lexical_block` has its parent `DIScope`
    /// in hand. A scope whose parent id is absent from the table roots at the
    /// subprogram. Fail-safe: a malformed cyclic parent chain (impossible from a
    /// lexical HIR, but defended against) stops the build with whatever blocks
    /// resolved, leaving the rest to fall back to the subprogram scope.
    fn build(
        dctx: &ModuleDebugCtx<'_, 'ctx>,
        subprogram: inkwell::debug_info::DISubprogram<'ctx>,
        func: &RawMirFunction,
    ) -> Self {
        use inkwell::debug_info::AsDIScope;
        let mut blocks: HashMap<u32, inkwell::debug_info::DILexicalBlock<'ctx>> = HashMap::new();
        let mut ranges: Vec<(u32, u32, u32)> = Vec::new();
        // Fixed-point build: each pass creates every scope whose parent is the
        // subprogram (None) or an already-built block. Bounded by the table
        // length — a lexical tree resolves in depth-many passes.
        let mut remaining: Vec<&MirScope> = func.scope_table.iter().collect();
        loop {
            let mut progressed = false;
            let mut still: Vec<&MirScope> = Vec::new();
            for sc in remaining {
                let parent_scope = match sc.parent {
                    None => Some(subprogram.as_debug_info_scope()),
                    Some(pid) => blocks.get(&pid).map(|b| b.as_debug_info_scope()),
                };
                let Some(parent_scope) = parent_scope else {
                    // Parent not yet built (or genuinely absent — a parent id
                    // not in the table resolves to None above, so this branch
                    // is only "not yet built"); retry next pass.
                    still.push(sc);
                    continue;
                };
                let line = dctx.line_index.line(sc.start as usize);
                let column = dctx.line_index.column(sc.start as usize);
                let block =
                    dctx.di_builder
                        .create_lexical_block(parent_scope, dctx.file, line, column);
                blocks.insert(sc.id, block);
                ranges.push((sc.start, sc.end, sc.id));
                progressed = true;
            }
            if still.is_empty() || !progressed {
                break;
            }
            remaining = still;
        }
        // Innermost-first: a tighter (narrower) extent wins a containment test.
        ranges.sort_by_key(|&(s, e, _)| e.saturating_sub(s));
        Self { blocks, ranges }
    }

    /// The `DIScope` for the variable/instruction whose source byte is `byte`:
    /// the innermost scope whose `[start, end)` contains it, or `None` (→ caller
    /// falls back to the subprogram). `ranges` is sorted innermost-first.
    fn scope_for_byte(&self, byte: u32) -> Option<inkwell::debug_info::DIScope<'ctx>> {
        use inkwell::debug_info::AsDIScope;
        self.ranges
            .iter()
            .find(|&&(s, e, _)| byte >= s && byte < e)
            .and_then(|&(_, _, id)| self.blocks.get(&id))
            .map(|b| b.as_debug_info_scope())
    }

    /// The `DIScope` for a named local declared in raw HIR scope `scope_id`, or
    /// `None` when that scope has no lexical block (→ subprogram fallback).
    fn scope_for_id(&self, scope_id: u32) -> Option<inkwell::debug_info::DIScope<'ctx>> {
        use inkwell::debug_info::AsDIScope;
        self.blocks.get(&scope_id).map(|b| b.as_debug_info_scope())
    }
}

/// Emit `DW_TAG_formal_parameter` / `DW_TAG_variable` DIEs and their
/// `llvm.dbg.declare` records for every named local slot (Stages 2/3). Each
/// declare is inserted at the end of `prologue_bb` (which holds the alloca and
/// dominates the body) with a `!dbg` location scoped to its lexical block.
/// Fail-closed per slot: a slot with no source name (an anonymous temporary, a
/// synthesised function with an empty `local_names`) or an unresolvable type is
/// skipped — no DIE, never a fabricated name or type. Parameters occupy
/// `locals[0..params.len()]`; the rest are body autos.
#[expect(
    clippy::too_many_arguments,
    reason = "debug emission threads the same explicit borrows as the lowering body"
)]
fn emit_variable_dies<'ctx>(
    ctx: &'ctx Context,
    dctx: &ModuleDebugCtx<'_, 'ctx>,
    subprogram: inkwell::debug_info::DISubprogram<'ctx>,
    func: &RawMirFunction,
    fn_ctx: &FnCtx<'_, 'ctx>,
    record_field_resolved_tys: &HashMap<String, Vec<ResolvedTy>>,
    record_field_names: &HashMap<String, Vec<String>>,
    prologue_bb: inkwell::basic_block::BasicBlock<'ctx>,
    lexical_scopes: &LexicalScopes<'ctx>,
) {
    // The function-declaration line is the fallback scope/line for a slot that
    // carries no per-binding span (params, synthesised locals). If the function
    // has no in-file span the subprogram would not exist, so a fallback of 0 is
    // unreachable here in practice.
    let decl_line = match func.span {
        Some((start, _)) if dctx.line_index.contains(start as usize) => {
            dctx.line_index.line(start as usize)
        }
        _ => 0,
    };
    let param_count = func.params.len();
    let empty_expr = dctx.di_builder.create_expression(vec![]);

    for (idx, ty) in func.locals.iter().enumerate() {
        // Fail-closed: only named slots get a DIE. An empty `local_names`
        // (synthesised function) or a `None` entry (anonymous temporary)
        // means no DIE for this slot.
        let Some(Some(name)) = func.local_names.get(idx) else {
            continue;
        };
        // The slot's alloca. Absent only for a divergent/never slot the body
        // never materialised; skip it.
        let idx_u32 = match u32::try_from(idx) {
            Ok(v) => v,
            Err(_) => continue,
        };
        let Some((slot, _slot_ty)) = fn_ctx.locals.get(&idx_u32).copied() else {
            continue;
        };
        let Some(di_type) = resolve_di_type(
            ctx,
            dctx,
            fn_ctx.target_data,
            ty,
            fn_ctx.record_layouts,
            fn_ctx.enum_layouts,
            record_field_resolved_tys,
            record_field_names,
        ) else {
            // Unresolvable type → no DIE (fail-closed), never a guessed type.
            continue;
        };

        // Each local's own declaration line keeps two same-named shadowed
        // locals distinct (a `None` decl-byte → the function-decl line).
        let var_line = func
            .local_decl_bytes
            .get(idx)
            .copied()
            .flatten()
            .filter(|b| dctx.line_index.contains(*b as usize))
            .map_or(decl_line, |b| dctx.line_index.line(b as usize));
        // Scope each local to its lexical block. The shadowed inner `first` is
        // recorded under its own (inner) HIR scope, so it lands in a distinct
        // `DILexicalBlock` from the outer `first` — both DIEs survive and the
        // debugger resolves each at its own PC range. A slot with no recorded
        // scope (or a scope without a block) falls back to the subprogram.
        let var_scope = func
            .local_scopes
            .get(idx)
            .copied()
            .flatten()
            .and_then(|sid| lexical_scopes.scope_for_id(sid))
            .unwrap_or_else(|| subprogram.as_debug_info_scope());
        // The dbg.declare's location must sit in the variable's own scope (the
        // verifier requires the location scope to match/descend the variable's).
        let var_debug_loc = dctx
            .di_builder
            .create_debug_location(ctx, var_line, 0, var_scope, None);

        let di_var = if idx < param_count {
            // Parameter: 1-based arg number in declaration order. Params are
            // always function-wide — scope them to the subprogram, not a block.
            let arg_no = u32::try_from(idx + 1).unwrap_or(u32::MAX);
            dctx.di_builder.create_parameter_variable(
                subprogram.as_debug_info_scope(),
                name,
                arg_no,
                dctx.file,
                decl_line,
                di_type,
                /* always_preserve */ true,
                DIFlags::ZERO,
            )
        } else {
            dctx.di_builder.create_auto_variable(
                var_scope,
                name,
                dctx.file,
                var_line,
                di_type,
                /* always_preserve */ true,
                DIFlags::ZERO,
                /* align_in_bits */ 0,
            )
        };
        // A parameter's declare uses the subprogram-scoped location; a body
        // auto uses its lexical-block-scoped location.
        let declare_loc = if idx < param_count {
            dctx.di_builder.create_debug_location(
                ctx,
                decl_line,
                0,
                subprogram.as_debug_info_scope(),
                None,
            )
        } else {
            var_debug_loc
        };
        dbg_declare_at_end(
            dctx.di_builder,
            slot,
            di_var,
            empty_expr,
            declare_loc,
            prologue_bb,
        );
    }
}

/// Apply `optnone` + `noinline` to a `-g`-built function so its locals stay
/// faithfully inspectable. `optnone` requires `noinline` (LLVM verifier rule)
/// and tells instruction selection to leave the body unoptimized, which keeps
/// every alloca store eager — the property a debugger needs to read a local at
/// any breakpoint. Best-effort: if the LLVM build does not expose these enum
/// attributes (kind id 0), the function is left as-is rather than failing the
/// whole build — a missing optnone degrades debug fidelity, it does not produce
/// wrong code.
fn apply_optnone_for_debug<'ctx>(ctx: &'ctx Context, func: inkwell::values::FunctionValue<'ctx>) {
    use inkwell::attributes::{Attribute, AttributeLoc};
    for name in ["noinline", "optnone"] {
        let kind_id = Attribute::get_named_enum_kind_id(name);
        if kind_id != 0 {
            func.add_attribute(
                AttributeLoc::Function,
                ctx.create_enum_attribute(kind_id, 0),
            );
        }
    }
}

#[expect(
    clippy::too_many_arguments,
    reason = "module-lowering context is deliberately passed as explicit borrows"
)]
fn lower_function<'ctx>(
    ctx: &'ctx Context,
    llvm_mod: &LlvmModule<'ctx>,
    target_data: &TargetData,
    func: &RawMirFunction,
    fn_symbols: &FnSymbolMap<'ctx>,
    elab: Option<&ElaboratedMirFunction>,
    checked: Option<&CheckedMirFunction>,
    record_layouts: &RecordLayoutMap<'ctx>,
    actor_layouts: &[ActorLayout],
    machine_layouts: &MachineLayoutMap<'ctx>,
    enum_layouts: &[EnumLayout],
    record_field_resolved_tys: &HashMap<String, Vec<ResolvedTy>>,
    record_field_names: &HashMap<String, Vec<String>>,
    dyn_vtable_registry: &[DynVtableInstance],
    const_globals: &ConstGlobalMap<'ctx>,
    emit_wasm_entry_alias: bool,
    has_supervisors: bool,
    module_uses_runtime: bool,
    debug: Option<&ModuleDebugCtx<'_, 'ctx>>,
) -> CodegenResult<()> {
    let symbol = *fn_symbols.get(&func.name).ok_or_else(|| {
        CodegenError::FailClosed(format!(
            "function `{}` was not declared before body lowering",
            func.name
        ))
    })?;
    let (llvm_fn, return_ty_llvm, _returns_unit) = symbol.real(&func.name, "lower_function")?;
    // gdb `-g`: mark every debug-built non-coroutine function `optnone noinline`
    // so the backend keeps each local's stack slot eagerly written. Without it,
    // even at `-O0` LLVM's instruction selection coalesces a `store slot; load
    // slot` pair into a register and DEFERS the slot store past the load's use —
    // leaving a `dbg.declare` slot stale at a breakpoint set on the using line.
    // That is exactly what made a shadowed inner `let first = …; println(first)`
    // read the pre-store slot value at the `println` breakpoint. `optnone`
    // restores the faithful one-store-per-assignment shape real `-O0` frontends
    // (clang/rustc) rely on for trustworthy locals. Skipped for coroutines: a
    // `presplitcoroutine` MUST run `CoroSplit`, which `optnone` would block — and
    // suspend-carrying bodies are excluded from `-g` debug info anyway.
    if debug.is_some() && !is_coroutine_function(func) {
        apply_optnone_for_debug(ctx, llvm_fn);
    }
    // W5.005 / F1b (Decision 4 Option A, D343): a `#[intrinsic("mem.*")]`
    // floor function carries a typed catalog id threaded from HIR. Its MIR
    // `blocks` are a bodyless placeholder — synthesize the real trampoline
    // body here and return, bypassing the normal block-lowering path.
    // Fail-closed: an id codegen does not recognise is a hard error, never a
    // silent empty-body no-op (the historic fail-OPEN bug).
    if let Some(intrinsic_id) = &func.intrinsic_id {
        let intrinsic =
            crate::arith::FloorIntrinsic::from_catalog_id(intrinsic_id).ok_or_else(|| {
                CodegenError::FailClosed(format!(
                    "function `{}` carries unknown floor intrinsic id {intrinsic_id:?}; \
                 codegen has no lowering for it — extend `FloorIntrinsic` or leave \
                 the declaration fail-closed (it must never emit an empty body)",
                    func.name
                ))
            })?;
        return crate::arith::emit_floor_intrinsic_body(ctx, llvm_mod, llvm_fn, func, intrinsic);
    }
    let context_marker_findings = validate_context_markers_for_codegen(func);
    if !context_marker_findings.is_empty() {
        return Err(CodegenError::FailClosed(format!(
            "function `{}` has invalid execution-context markers: {context_marker_findings:?}",
            func.name
        )));
    }
    let builder = ctx.create_builder();

    let entry_block = func.blocks.first().ok_or_else(|| {
        CodegenError::FailClosed(format!("function `{}` has zero blocks", func.name))
    })?;

    // Stackless suspend lowering (R326/R327, W6.007). A function whose MIR
    // carries a `Terminator::Suspend` is lowered as a `presplitcoroutine`: the
    // coro prologue (`coro.id`/`coro.alloc`/`coro.begin`) wraps the whole body,
    // each `Suspend` terminator emits `coro.suspend` + its 3-way switch, and a
    // shared suspend-return / cleanup epilogue closes the frame. Detected from
    // the carrier the codegen boundary ACTUALLY reads (the block terminator),
    // not the `ElaboratedMirFunction.coroutine` descriptor the `RawMirFunction`
    // path never consults (R2 / the Lane-B silent-no-op failure class).
    // Multi-suspend is fully supported. A body may carry any number of
    // `coro.suspend` points (sequential awaits, awaits in a loop): each yields to
    // the executor via its switch's default edge into the single shared
    // suspend-return block, and CoroSplit's `.resume` outline dispatches on the
    // stored suspend index. The single fallthrough `coro.end` wired in the
    // epilogue below is what makes the second-and-later yield-back-to-executor
    // land on a real return instead of `unreachable` (the prior crash).
    // A generator body's `yield` is a `coro.suspend` on this same substrate (the
    // `Terminator::Yield` codegen arm calls `CoroContext::emit_suspend`), so a
    // gen body — whether it yields or is a no-yield `Generator<Never, R>` —
    // needs the coro prologue + shared cleanup/suspend-return epilogue. Reuses
    // the same coroutine predicate `declare_function` uses, so the prologue
    // emission and the `ptr`-handle return type agree.
    let has_suspend = is_coroutine_function(func);

    // DWARF subprogram + function-entry location for `hew build -g` (W0.060).
    // Emitted only for plain (non-suspend) `fn`s whose span falls within the
    // compiled source file. FAIL-CLOSED on two fronts: a function with no span
    // gets NO debug info (a location-free function is legal at -O0) rather than
    // a fabricated line 0; and a span that lies outside this file — e.g. a
    // monomorphised stdlib function pulled into the module carries a byte
    // offset into the *stdlib* source, not the user's file — is skipped rather
    // than mapped to a wrong line in `dbg.hew`. Suspend-carrying coroutine
    // bodies are skipped too — their `DISubprogram` must survive `CoroSplit`,
    // a later stage — so emitting one now would risk verifier/codegen breakage.
    //
    // `fn_subprogram` is captured for the body walk below: Stage 2 sets a
    // per-instruction `DILocation` scoped to this subprogram so gdb steps the
    // body line-by-line.
    let mut fn_subprogram: Option<inkwell::debug_info::DISubprogram<'ctx>> = None;
    let entry_debug_loc = match (debug, func.span) {
        (Some(dctx), Some((start, _end)))
            if !has_suspend && dctx.line_index.contains(start as usize) =>
        {
            let line = dctx.line_index.line(start as usize);
            let column = dctx.line_index.column(start as usize);
            // Stage 5: a real `DISubroutineType` — element 0 is the return type
            // (`None` for unit/never, so gdb shows `void`), followed by each
            // parameter's type. Unresolvable types fall back to `None` for that
            // slot rather than failing the whole subprogram (the subprogram +
            // its variable DIEs are still useful with a partial signature).
            let return_di = match &func.return_ty {
                ResolvedTy::Unit | ResolvedTy::Never => None,
                ret => resolve_di_type(
                    ctx,
                    dctx,
                    target_data,
                    ret,
                    record_layouts,
                    enum_layouts,
                    record_field_resolved_tys,
                    record_field_names,
                ),
            };
            let param_dis: Vec<inkwell::debug_info::DIType<'ctx>> = func
                .params
                .iter()
                .filter_map(|p| {
                    resolve_di_type(
                        ctx,
                        dctx,
                        target_data,
                        p,
                        record_layouts,
                        enum_layouts,
                        record_field_resolved_tys,
                        record_field_names,
                    )
                })
                .collect();
            let subroutine_ty = dctx.di_builder.create_subroutine_type(
                dctx.file,
                return_di,
                &param_dis,
                DIFlags::PUBLIC,
            );
            let subprogram = dctx.di_builder.create_function(
                dctx.compile_unit.as_debug_info_scope(),
                &func.name,
                Some(&func.name),
                dctx.file,
                line,
                subroutine_ty,
                /* is_local_to_unit */ false,
                /* is_definition */ true,
                /* scope_line */ line,
                DIFlags::PUBLIC,
                /* is_optimized */ false,
            );
            llvm_fn.set_subprogram(subprogram);
            fn_subprogram = Some(subprogram);
            let loc = dctx.di_builder.create_debug_location(
                ctx,
                line,
                column,
                subprogram.as_debug_info_scope(),
                None,
            );
            Some(loc)
        }
        _ => None,
    };

    // gdb `-g` lexical-block map: built once per function from the MIR
    // `scope_table` and the now-established subprogram. Scopes every variable
    // DIE and every instruction `DILocation` by source containment, so shadowed
    // locals resolve to the right binding at the right PC. Empty (no blocks) for
    // any function with no `scope_table` — flat subprogram scoping, unchanged.
    let lexical_scopes: Option<LexicalScopes<'ctx>> = match (debug, fn_subprogram) {
        (Some(dctx), Some(subprogram)) => Some(LexicalScopes::build(dctx, subprogram, func)),
        _ => None,
    };

    // The coroutine prologue (when present) must own the function ENTRY block so
    // `coro.id` is the first instruction. Emit it before the alloca prologue.
    let coro_state: Option<CoroState> = if has_suspend {
        // A coroutine ramp returns the `coro.begin` frame handle (a pointer) to
        // the executor — not a Hew value. `declare_function` declared the ramp's
        // LLVM return as `ptr` for any suspend-carrying function; this guard
        // confirms the declaration agrees (fail-closed, R2/the Lane-B class).
        if !matches!(return_ty_llvm, BasicTypeEnum::PointerType(_)) {
            return Err(CodegenError::FailClosed(format!(
                "function `{}` carries a suspend terminator but its declared LLVM \
                 return type is {return_ty_llvm:?}; a coroutine ramp must return \
                 the coro handle (ptr) — declare_function must override the return \
                 type for suspend-carrying functions",
                func.name
            )));
        }
        // W6.010 value routing: the LOGICAL return value is deposited by the
        // body itself (`Terminator::Return` coroutine arm: `hew_get_reply_channel`
        // + `hew_reply`). Resolve the logical return type so the body's
        // return-value slot is sized correctly and the deposit loads the right
        // type. A unit/never logical return deposits no reply.
        let logical_return_ty = if matches!(func.return_ty, ResolvedTy::Unit | ResolvedTy::Never) {
            None
        } else {
            Some(resolve_ty(ctx, &func.return_ty, record_layouts)?)
        };
        // `hew_cont_frame_alloc` takes `u64` (not `size_t`) on all targets —
        // the prologue always passes the i64 `coro.size` value directly.
        let cc = crate::coro::emit_coro_prologue(ctx, llvm_mod, &builder, llvm_fn)?;
        // Shared epilogue blocks every suspend switch routes to: the default
        // edge (return to executor) and the cleanup edge (coro.destroy).
        let suspend_return_block = ctx.append_basic_block(llvm_fn, "coro.suspend.return");
        let cleanup_block = ctx.append_basic_block(llvm_fn, "coro.cleanup");
        let has_explicit_final_suspend = func
            .blocks
            .iter()
            .any(|b| matches!(b.terminator, Terminator::Suspend { is_final: true, .. }));
        // A generator body carries `Terminator::Yield` (its non-final suspends)
        // and completes at its `Return` — it has no explicit final `Suspend`.
        // Its completion routes through the shared `final_suspend_block` like a
        // SuspendingAsk coroutine, but the block emits a VALUE-FREE final suspend
        // (the value channel is the out-pointer, not a reply channel).
        let is_generator = func
            .blocks
            .iter()
            .any(|b| matches!(b.terminator, Terminator::Yield { .. }));
        // A coroutine with no explicit final Suspend (a SuspendingAsk handler OR
        // a generator) completes at its `Return` terminator(s). Reserve ONE
        // shared final-suspend block that every `Return` branches to, so the
        // (reply deposit for await; value-free for generators) + the synthesized
        // `coro.suspend(is_final=true)` are emitted exactly once regardless of
        // how many return paths the body has — mirroring the shared
        // `cleanup_block` / `suspend_return_block` plumbing. The body of this
        // block is filled in the coroutine epilogue. A coroutine that ALREADY
        // carries an explicit final Suspend needs no such block: its `Return`
        // arm just `ret`s the handle.
        let final_suspend_block = if has_explicit_final_suspend {
            None
        } else {
            Some(ctx.append_basic_block(llvm_fn, "coro.final.suspend"))
        };
        Some(CoroState {
            handle: cc.handle,
            id_token: cc.id_token,
            cleanup_block,
            suspend_return_block,
            logical_return_ty,
            has_explicit_final_suspend,
            final_suspend_block,
            is_generator,
        })
    } else {
        None
    };

    // Keep the LLVM entry block predecessor-free even when MIR loops target
    // bb0. The prologue holds allocas, parameter stores, and the function-entry
    // cooperate call, then branches into the first MIR block.
    //
    // For an ordinary (non-suspend) function this alloca block IS the entry
    // block, so it keeps the historical `entry` label — non-suspend IR stays
    // byte-identical to baseline (the substrate's dormancy invariant). Only a
    // coroutine renames it to `alloca.prologue`: there `coro.id`/`coro.begin`
    // must own the real `entry` block, and this alloca block is appended after
    // `coro.begin` and reached from it.
    let prologue_bb = ctx.append_basic_block(
        llvm_fn,
        if has_suspend {
            "alloca.prologue"
        } else {
            "entry"
        },
    );

    // Build every MIR block up front so terminators can name forward targets.
    let mut blocks = HashMap::new();
    for block in &func.blocks {
        let bb = ctx.append_basic_block(llvm_fn, &format!("bb{}", block.id));
        blocks.insert(block.id, bb);
    }

    let entry_bb = *blocks.get(&entry_block.id).expect("entry block in map");
    // For a coroutine, `coro.begin` (where the builder is positioned) branches
    // into the alloca prologue. For an ordinary function the alloca prologue IS
    // the entry block; position the builder there directly.
    if coro_state.is_some() {
        builder
            .build_unconditional_branch(prologue_bb)
            .llvm_ctx("coro.begin -> alloca.prologue branch")?;
    }
    builder.position_at_end(prologue_bb);

    // Attach the function-entry source location so every instruction lowered
    // into the body inherits a `!dbg`. The verifier requires a debug location
    // on any call site inside a function that carries a `DISubprogram`; setting
    // it here (before the alloca prologue and body) covers them all. Stage 2
    // refines this single coarse line into a per-statement line table.
    if let Some(loc) = entry_debug_loc {
        builder.set_current_debug_location(loc);
    }

    // The body's return-value slot is sized to the LOGICAL return type. For an
    // ordinary function that IS `return_ty_llvm`. For a coroutine, `return_ty_llvm`
    // is the ramp's `ptr` handle — the body still writes its logical Hew value
    // (e.g. the awaited reply) into this slot; the `Terminator::Return` coroutine
    // arm loads it and deposits it via `hew_get_reply_channel` + `hew_reply` to
    // the handler's caller (W6.010) — not through any out-pointer parameter.
    //
    // A UNIT logical return has no reply to deposit (the coroutine `Return` arm
    // takes the `logical_return_ty == None` path and never reads this slot), but
    // the body still emits the same trailing `Move { dest: ReturnSlot, src: <unit> }`
    // epilogue a non-coroutine unit function does. `place_pointer(ReturnSlot)`
    // reports this slot's type, so it MUST be sized to the unit value type (`i8`)
    // for that move to type-check — reusing the ramp `ptr` here makes the unit
    // move fail closed with an `i8 → ptr` mismatch. (First exercised by a
    // unit-returning suspend handler — e.g. NEW-5's `await remote.ask(...)` /
    // a local `await peer.method()` in an actor handler — which is the first
    // unit coroutine to reach full codegen.) `Never` carries no return-value
    // move (it diverges), so the ramp `ptr` placeholder stays harmless there.
    let body_return_ty_llvm = match &coro_state {
        Some(coro) => match coro.logical_return_ty {
            Some(logical) => logical,
            None if matches!(func.return_ty, ResolvedTy::Unit) => {
                resolve_ty(ctx, &func.return_ty, record_layouts)?
            }
            None => return_ty_llvm,
        },
        None if matches!(func.call_conv, FunctionCallConv::LambdaActorBody(_)) => {
            // A lambda-actor body's `return_ty` is the USER reply type
            // (Unit for Tell, i64 for Ask). Size the body's return_slot
            // alloca to that logical width — the LLVM ABI return is
            // `i32` (the status code), serialised by the Return epilogue,
            // not the contents of this slot.
            resolve_ty(ctx, &func.return_ty, record_layouts)?
        }
        None => return_ty_llvm,
    };
    let return_slot = builder
        .build_alloca(body_return_ty_llvm, "return_slot")
        .llvm_ctx("alloca return_slot")?;

    let execution_context = if func.call_conv.carries_execution_context() {
        let param = llvm_fn.get_nth_param(0).ok_or_else(|| {
            CodegenError::FailClosed(format!(
                "context-bearing function `{}` has no leading execution-context LLVM parameter",
                func.name
            ))
        })?;
        Some(param.into_pointer_value())
    } else {
        None
    };
    let closure_call_fallback_context = if function_needs_closure_call_fallback_context(func) {
        Some(build_zeroed_closure_call_fallback_context(ctx, &builder)?)
    } else {
        None
    };

    let mut locals: HashMap<u32, (PointerValue, BasicTypeEnum)> = HashMap::new();
    let mut local_tys: HashMap<u32, ResolvedTy> = HashMap::new();
    for (idx, ty) in func.locals.iter().enumerate() {
        // Use `resolve_ty` (not bare `primitive_to_llvm`) so record-typed
        // locals materialise as struct allocas rather than tripping the
        // D10-violation arm. Record-typed locals get an alloca sized to
        // the full struct; codegen for `RecordInit` writes into this slot
        // in place via per-field GEP+store.
        //
        // Exception: `indirect enum` locals hold a *pointer* to a
        // heap-allocated struct, not the struct inline. `resolve_ty` returns
        // the struct type because it prioritises the layout map over the
        // opaque set (collision-safety invariant for user records vs stdlib
        // opaque handles). We override the alloca type to `ptr` here so the
        // slot is pointer-sized and the `hew_alloc` prologue below can store
        // the heap pointer without type-mismatch.
        let llvm_ty = {
            // Never-typed locals are produced for diverging expressions
            // (e.g. the result slot of `panic(...)`). The diverging path
            // never returns so no instruction ever reads or writes this
            // local. Allocate an i8 stand-in so the slot exists without
            // calling `resolve_ty` which fails on `Never`.
            if matches!(ty, ResolvedTy::Never) {
                ctx.i8_type().into()
            } else {
                let raw_ty = resolve_ty(ctx, ty, record_layouts)?;
                if let ResolvedTy::Named { name, .. } = ty {
                    if crate::layout::is_indirect_enum(name, enum_layouts) {
                        ctx.ptr_type(inkwell::AddressSpace::default()).into()
                    } else {
                        raw_ty
                    }
                } else {
                    raw_ty
                }
            }
        };
        let idx_u32 = u32::try_from(idx).map_err(|_| {
            CodegenError::FailClosed("function exceeds u32::MAX locals — impossible".into())
        })?;
        let slot = builder
            .build_alloca(llvm_ty, &format!("local_{idx}"))
            .llvm_ctx_with(|| format!("alloca local {idx}"))?;
        locals.insert(idx_u32, (slot, llvm_ty));
        local_tys.insert(idx_u32, ty.clone());
    }

    // Indirect-enum heap-allocation prologue.
    //
    // For `indirect enum` types (spec §3.7.4), every variable holds a
    // pointer to a heap-allocated tagged-union struct rather than an
    // inline struct value.  `resolve_ty` maps such types to `ptr` alloca
    // slots (via `opaque_handle_names`).  Non-parameter locals whose type
    // is an indirect enum therefore start with an uninitialised `ptr` slot.
    //
    // To avoid a use-before-alloc crash on the first tag/variant write, we
    // eagerly allocate heap storage for each such local at function entry.
    // Parameters are excluded — their ptr values come from the caller.
    //
    // WHY eager (not lazy): MIR's `MachineVariantCtor` emits a sequence
    //   of `Move { dest: MachineTag, .. }` and `Move { dest: MachineVariant,
    //   .. }` instructions that write through `resolve_machine_base_ptr`.
    //   Inserting an alloc inside that emit path would require detecting
    //   "first write", which has no clean codegen-level marker.  An up-front
    //   alloc at function entry is simple and dominates every use.
    //
    // WHY not leak: indirect-enum drops emit `hew_dealloc` (added via
    //   DropKind::IndirectEnum).  Until the drop elaborator wires that,
    //   the heap allocation leaks — an acceptable interim gap (the value
    //   type is correct; memory safety is preserved; the only cost is the
    //   leak, which ASAN/valgrind will flag).
    //
    // WHEN-OBSOLETE: when drop elaboration for `indirect enum` locals is
    //   wired end-to-end (DropKind::IndirectEnum + codegen arm), this
    //   comment should note that drops now free the allocation.
    let param_count = func.params.len();
    let mut prologue_decls: RuntimeDeclMap<'ctx> = RuntimeDeclMap::new();
    for (idx, ty) in func.locals.iter().enumerate() {
        // Only non-parameter locals need heap pre-allocation.
        if idx < param_count {
            continue;
        }
        let ty_name = if let ResolvedTy::Named { name, .. } = ty {
            name.as_str()
        } else {
            continue;
        };
        if !crate::layout::is_indirect_enum(ty_name, enum_layouts) {
            continue;
        }
        // Locate the outer struct type for the indirect enum.
        let outer_struct = match record_layouts.get(ty_name) {
            Some(st) => *st,
            None => {
                // JUSTIFIED: layout registration must mirror every indirect enum local;
                // failing closed prevents an uninitialised pointer local from reaching codegen.
                return Err(CodegenError::FailClosed(format!(
                    "indirect enum local `{ty_name}` has no registered layout"
                )));
            }
        };
        let idx_u32 = u32::try_from(idx).expect("local index fits u32");
        let (slot, _) = *locals.get(&idx_u32).expect("local slot allocated above");
        // Compute ABI size and alignment for the heap allocation.
        //
        // WHY anonymous struct: `TargetData::get_abi_size` on a named LLVM
        // struct type returns 0 when the `TargetData` is constructed as a
        // standalone layout string (the `host_target_data()` path, used by
        // test harnesses where `target_machine == None`) rather than from a
        // `TargetMachine` linked to a module context. Named structs are
        // resolved through the LLVMContext; a layout-string-only `TargetData`
        // cannot walk the context's type table. Primitive types and anonymous
        // structs (which inline their field list) are sized correctly.
        //
        // In the `hew run` path the `TargetMachine`-linked `TargetData` is
        // used (`build_module`'s `target_data` argument), where named structs
        // size correctly (named == anon, measured). This anonymous-struct
        // indirection is therefore DEFENSIVE for the `target_machine == None`
        // harness paths, not load-bearing in the shipped run path.
        //
        // Fix: mirror the named struct's field list into a fresh anonymous
        // struct (`packed = false`, same fields) and call `get_abi_size` on
        // that. The ABI layout is identical: `{ tag_int, payload_array }` has
        // the same field offsets and total size whether named or anonymous.
        //
        // WHEN-OBSOLETE: if the codegen pipeline is restructured so that all
        // `TargetData` instances come from a `TargetMachine` (rather than
        // `host_target_data()`), this anonymous-struct indirection can be
        // removed and replaced with a direct `get_abi_size(&outer_struct)`.
        let anon_outer = ctx.struct_type(&outer_struct.get_field_types(), false);
        let size_bytes = target_data.get_abi_size(&anon_outer);
        let align_bytes = target_data.get_abi_alignment(&anon_outer);
        if size_bytes == 0 {
            return Err(CodegenError::FailClosed(format!(
                "indirect enum `{ty_name}`: cannot compute ABI size for heap allocation — \
                 anonymous struct has 0 bytes (variant layout or target-data mismatch)"
            )));
        }
        let size_val = ctx.i64_type().const_int(size_bytes, false);
        let align_val = ctx.i64_type().const_int(u64::from(align_bytes), false);
        // Declare and call `hew_alloc(size: i64, align: i64) -> ptr`.
        let alloc_fn = intern_runtime_decl(ctx, llvm_mod, &mut prologue_decls, "hew_alloc")?;
        let heap_ptr = builder
            .build_call(
                alloc_fn,
                &[size_val.into(), align_val.into()],
                "indirect_enum_alloc",
            )
            .llvm_ctx_with(|| format!("hew_alloc for indirect enum local {idx}"))?
            .try_as_basic_value()
            .basic()
            .ok_or_else(|| {
                CodegenError::FailClosed(format!(
                    "hew_alloc for indirect enum local {idx} returned void — expected ptr"
                ))
            })?
            .into_pointer_value();
        builder
            .build_store(slot, heap_ptr)
            .llvm_ctx_with(|| format!("store indirect-enum heap ptr into local_{idx}"))?;
    }

    // Parameter prologue: store each LLVM function argument into the
    // corresponding `locals[i]` alloca slot. Parameters occupy
    // `locals[0..func.params.len()]` by the invariant established in
    // `RawMirFunction` (see `lower_params` in hew-mir/src/lower.rs).
    // This runs after all allocas so the store is always in the entry
    // block and dominates every use in successor blocks.
    for (param_idx, _param_ty) in func.params.iter().enumerate() {
        let param_idx_u32 = u32::try_from(param_idx).map_err(|_| {
            CodegenError::FailClosed("function exceeds u32::MAX params — impossible".into())
        })?;
        let llvm_param_idx = param_idx + usize::from(func.call_conv.carries_execution_context());
        let llvm_param = llvm_fn
            .get_nth_param(llvm_param_idx as u32)
            .ok_or_else(|| {
                CodegenError::FailClosed(format!(
                    "function `{}` has no LLVM param at index {llvm_param_idx}; \
                     declare_function and lower_function param counts disagree",
                    func.name
                ))
            })?;
        let (slot, _slot_ty) = *locals.get(&param_idx_u32).ok_or_else(|| {
            CodegenError::FailClosed(format!(
                "function `{}` has no local slot for param index {param_idx}",
                func.name
            ))
        })?;
        builder
            .build_store(slot, llvm_param)
            .llvm_ctx_with(|| format!("param store {param_idx}"))?;
    }

    // Lambda-actor body user-parameter deserialise prologue.
    //
    // The runtime ABI delivers user message bytes as a `*const u8` /
    // `usize` pair (`Local(1)` = msg pointer alloca, `Local(2)` =
    // msg_len alloca). After the standard 5-slot ABI parameter
    // prologue (which writes the runtime arguments into Locals 0..=4),
    // copy `msg_len` bytes from `*Local(1)` into each user-param
    // alloca listed in `func.lambda_actor_user_param_locals`. The MVP
    // single-vertebra wire format places the (sole) user param at
    // byte offset 0; multi-param packing is a follow-on slice.
    //
    // WHY at body entry: the user-param locals are the slots HIR
    // `BindingRef`s resolve to via `binding_locals`; they must be
    // initialised before any body block can read them. WHY a memcpy
    // (not a typed load + store): the wire format is opaque bytes
    // by construction (the caller's `hew_lambda_actor_send` /
    // `hew_lambda_actor_ask` spills the message Place into a raw
    // byte buffer); a memcpy preserves whatever ABI representation
    // the sender used, including the 8-byte string handle pointer.
    if matches!(func.call_conv, FunctionCallConv::LambdaActorBody(_))
        && !func.lambda_actor_user_param_locals.is_empty()
    {
        // Load the msg pointer (the runtime delivers it as the
        // second ABI param; Local(1)'s alloca holds the ptr value).
        let (msg_ptr_slot, _) = *locals.get(&1u32).ok_or_else(|| {
            CodegenError::FailClosed(format!(
                "lambda-actor body `{}` missing Local(1) (msg ptr) slot",
                func.name
            ))
        })?;
        let msg_ptr_val = builder
            .build_load(
                ctx.ptr_type(AddressSpace::default()),
                msg_ptr_slot,
                "lambda_body_msg_ptr_load",
            )
            .llvm_ctx("lambda body msg ptr load")?
            .into_pointer_value();
        if func.lambda_actor_user_param_locals.len() > 1 {
            // Multi-param packed-record wire: the sender packed the N args
            // into an anonymous non-packed record whose field types are the
            // user params' types in declaration order. Rebuild the identical
            // literal struct here and copy each param from its natural field
            // offset, each at exactly `sizeof(field)` bytes — a base-pointer
            // copy per param would read every param from offset 0. LLVM
            // literal and named structs with one body share one layout, so
            // both wire ends agree by construction.
            let mut field_tys: Vec<BasicTypeEnum> =
                Vec::with_capacity(func.lambda_actor_user_param_locals.len());
            let mut slots: Vec<PointerValue> =
                Vec::with_capacity(func.lambda_actor_user_param_locals.len());
            for user_local_id in &func.lambda_actor_user_param_locals {
                let (user_slot, user_ty) = *locals.get(user_local_id).ok_or_else(|| {
                    CodegenError::FailClosed(format!(
                        "lambda-actor body `{}` missing user-param Local({user_local_id}) slot",
                        func.name
                    ))
                })?;
                field_tys.push(user_ty);
                slots.push(user_slot);
            }
            let packed_st = ctx.struct_type(&field_tys, false);
            for (idx, (user_slot, field_ty)) in slots.iter().zip(field_tys.iter()).enumerate() {
                let field_idx = u32::try_from(idx).map_err(|_| {
                    CodegenError::FailClosed(format!(
                        "lambda-actor body `{}` param count exceeds u32::MAX — \
                         impossible in Hew",
                        func.name
                    ))
                })?;
                let field_ptr = builder
                    .build_struct_gep(
                        packed_st,
                        msg_ptr_val,
                        field_idx,
                        &format!("lambda_body_msg_field_{idx}_ptr"),
                    )
                    .llvm_ctx("lambda body packed msg field gep")?;
                let (field_size, _align) = abi_size_align(*field_ty, Some(target_data))?;
                builder
                    .build_memcpy(
                        *user_slot,
                        1,
                        field_ptr,
                        1,
                        ctx.i64_type().const_int(field_size, false),
                    )
                    .map_err(|e| {
                        CodegenError::FailClosed(format!(
                            "lambda-actor body `{}` packed param {idx} memcpy failed: {e:?}",
                            func.name
                        ))
                    })?;
            }
        } else {
            // Single user param: copy EXACTLY `sizeof(user_ty)` bytes from
            // the wire at offset 0 into the param's alloca.
            //
            // Scalar params ride the 8-byte zero-padded single-vertebra slot
            // (`spill_msg_arg_as_ptr` zero-pads the high bytes; we read back
            // only the meaningful prefix). Struct-typed params (a tuple or
            // record message) arrive as `sizeof(struct)` bytes sent through
            // the aggregate `(ptr, sizeof)` path — the copy width equals the
            // bytes the sender transmitted, so the bounded-copy invariant
            // holds on both wires.
            //
            // CRITICAL: do NOT hardcode the copy width to 8. The user
            // param's alloca is sized to its own ABI byte width (1 for
            // `bool`, 4 for `i32`, 8 for `i64`/`ptr`/`f64`); a memcpy of
            // 8 bytes into a 1-byte alloca is a stack OVER-WRITE that
            // corrupts adjacent stack objects (the security review's HIGH
            // finding). A scalar wider than 8 bytes cannot ride the
            // zero-padded slot and stays fail-closed.
            for user_local_id in &func.lambda_actor_user_param_locals {
                let (user_slot, user_ty) = *locals.get(user_local_id).ok_or_else(|| {
                    CodegenError::FailClosed(format!(
                        "lambda-actor body `{}` missing user-param Local({user_local_id}) slot",
                        func.name
                    ))
                })?;
                let (user_size, _user_align) = abi_size_align(user_ty, Some(target_data))?;
                if user_size > 8 && !matches!(user_ty, BasicTypeEnum::StructType(_)) {
                    return Err(CodegenError::FailClosed(format!(
                        "lambda-actor body `{}` user-param Local({user_local_id}) has \
                         ABI byte size {user_size} > 8 and is not an aggregate — the \
                         scalar single-vertebra wire format is 8 bytes",
                        func.name
                    )));
                }
                builder
                    .build_memcpy(
                        user_slot,
                        1,
                        msg_ptr_val,
                        1,
                        ctx.i64_type().const_int(user_size, false),
                    )
                    .map_err(|e| {
                        CodegenError::FailClosed(format!(
                            "lambda-actor body `{}` user-param Local({user_local_id}) memcpy failed: {e:?}",
                            func.name
                        ))
                    })?;
            }
        }
    }

    let actor_state_ty = if func.call_conv == FunctionCallConv::ActorHandler {
        actor_layout_key_from_handler_symbol(&func.name)
            .and_then(|actor_key| record_layouts.get(&actor_key).copied())
    } else {
        None
    };
    // Per-field clone kinds for the same actor, resolved from the layout
    // registry so `lower_actor_state_field_store` can key its old-value
    // release on the MIR-level field classification (the single authority
    // the state clone/drop synthesis also consumes).
    let actor_state_field_kinds = if func.call_conv == FunctionCallConv::ActorHandler {
        actor_layout_key_from_handler_symbol(&func.name).and_then(|actor_key| {
            actor_layouts
                .iter()
                .find(|a| a.name == actor_key)
                .and_then(|a| a.state_field_clone_kinds.as_deref())
        })
    } else {
        None
    };

    // P5-RX Stage 2a (A625): for a receive handler, grab the trailing runtime
    // `borrow_mode` i32 LLVM parameter (threaded by Stage 1's dispatch
    // trampoline) and compute the borrow-taint set so the escape sinks and
    // drops of a borrowed String payload can be runtime-gated. `declare_function`
    // appends this param ONLY for `<Actor>__recv__<handler>` functions, at LLVM
    // index `params.len() + 1` (ctx occupies index 0, params occupy 1..=n).
    // Both stay inert (`None` / empty) for every other function.
    let is_recv_handler =
        func.call_conv == FunctionCallConv::ActorHandler && func.name.contains("__recv__");
    let borrow_mode = if is_recv_handler {
        let bm_idx = u32::try_from(func.params.len() + 1).map_err(|_| {
            CodegenError::FailClosed("receive handler exceeds u32::MAX params — impossible".into())
        })?;
        let param = llvm_fn.get_nth_param(bm_idx).ok_or_else(|| {
            CodegenError::FailClosed(format!(
                "receive handler `{}` has no trailing borrow_mode LLVM param at index {bm_idx}; \
                 declare_function and lower_function disagree on the receive ABI",
                func.name
            ))
        })?;
        Some(param.into_int_value())
    } else {
        None
    };
    let borrow_tainted = compute_borrow_taint(func);
    // P5-RX Stage 2a (A625): does any borrowed-String view escape through a
    // vector this stage does not retain (call/composite/ask/...)? If so we emit
    // a runtime `borrow_mode != 0` entry trap below (fail-closed without
    // breaking copy-mode compilation). Computed before the FnCtx move.
    let borrow_escape_trap =
        borrow_mode.is_some() && has_unhandled_borrow_escape(func, &borrow_tainted);

    // Emit the implicit actor-drain epilogue only for the native program entry
    // point of an actor-using program WITHOUT supervisors.
    //
    // Supervisor programs are excluded because:
    //   - They are designed as long-running services; their supervisor actors
    //     keep the scheduler perpetually active, so `drain_is_idle()` never
    //     returns true until the full 5-second timeout, after which
    //     `hew_supervisor_stop` blocks in `wait_for_supervisor_self_actor_quiescent`.
    //     Together these cause `hew_shutdown_wait` to hang indefinitely.
    //   - Supervisor programs do not have the fire-and-forget message-loss
    //     problem: their actor refs are obtained via `sup.child` (a handle
    //     lookup from a live supervisor, not a fire-and-forget bare ref that
    //     could escape scope).
    //   - Supervisor shutdown is correctly triggered by SIGTERM/SIGINT via the
    //     installed signal handlers, or explicitly by calling `supervisor_stop`.
    //
    // WASM is excluded because the host manages the cooperative scheduler's
    // lifecycle and `hew_shutdown_initiate` would attempt to spawn a thread.
    //
    // Non-actor programs are excluded because the scheduler is never
    // initialised there; emitting a drain would spin an orchestrator thread
    // for ~20 ms on every program exit for no benefit.
    //
    // The WASM rename path (`emit_wasm_entry_alias = true`) doubles as the
    // "is WASM target" signal: `main` becomes `__original_main` on WASM
    // targets before body lowering.
    let emit_drain_epilogue = func.name == "main"
        && !actor_layouts.is_empty()
        && !has_supervisors
        && !emit_wasm_entry_alias;

    // Lambda-actor drain epilogue: gated on `main` (native target) and
    // unconditional w.r.t. lambda-actor usage. Each lambda actor runs on
    // its own dedicated OS thread outside the work-stealing scheduler, so
    // `hew_shutdown_wait` (which drains scheduler workers) doesn't cover
    // them — without this drain a fire-and-forget `let log = actor |s| {
    // … }; log("hi")` races process termination and silently drops the
    // body's `println`. `hew_lambda_drain_all` returns immediately when
    // no lambda actors were spawned, so the unconditional gate (on every
    // native `main`) is cheap. Wasm32 lambda-actor support is HIR-gated
    // off — the scan in `uses_wasm_excluded_symbol` rejects modules that
    // would emit `Terminator::MakeLambdaActor` for a wasm target.
    let emit_lambda_drain_epilogue = func.name == "main" && !emit_wasm_entry_alias;

    // The wasm32 analogue: a standalone `hew run --target wasm32-wasi` actor
    // program has no scheduler driver or runtime-owned atexit hook, so `main`
    // must drain and clean up the cooperative runtime itself via
    // `hew_wasm_runtime_exit()`. Same gate as the native epilogue but for the
    // wasm target (`emit_wasm_entry_alias`). Supervisors remain HIR-gated off
    // wasm32 (#1475), so `!has_supervisors` is always true for wasm32 programs;
    // it is kept for symmetry with the native drain condition.
    let emit_wasm_runtime_exit = func.name == "main"
        && !actor_layouts.is_empty()
        && !has_supervisors
        && emit_wasm_entry_alias;

    // Install the default `RuntimeInner` at the native `main` entry for any
    // runtime-using program. The de-globalized runtime (#1228 M1) makes
    // `rt_current()` fail closed when no runtime is installed: a program that
    // touches a runtime authority — `Node::start`, `pid.tell(..)` via
    // `hew_actor_send_by_id`, the implicit drain epilogue — BEFORE its first
    // `spawn` site (the other place that calls `hew_sched_init`) would trap.
    // Installing once in the prologue removes that ordering hazard. The runtime
    // is freed at exit by `hew_runtime_cleanup` exactly as before.
    //
    // `hew_sched_init` is idempotent (a second call CAS-fails to a harmless
    // no-op), so the spawn-site and supervisor-bootstrap calls still run and
    // still cost nothing extra. WASM is excluded (the host owns the cooperative
    // scheduler's lifecycle). Pure-computation programs (no actors, no
    // supervisors, no node) never reach `module_uses_runtime`, so they pay
    // nothing.
    let install_runtime_at_entry =
        func.name == "main" && !emit_wasm_entry_alias && module_uses_runtime;

    let fn_ctx = FnCtx {
        ctx,
        llvm_mod,
        emit_drain_epilogue,
        emit_wasm_runtime_exit,
        emit_lambda_drain_epilogue,
        target_data,
        builder,
        return_slot,
        return_ty: body_return_ty_llvm,
        return_resolved_ty: func.return_ty.clone(),
        execution_context,
        closure_call_fallback_context,
        execution_context_is_actor_handler: func.call_conv == FunctionCallConv::ActorHandler,
        actor_state_ty,
        actor_state_field_kinds,
        locals,
        local_tys,
        blocks: blocks.clone(),
        runtime_decls: RefCell::new(HashMap::new()),
        record_layouts,
        fn_symbols,
        actor_layouts,
        machine_layouts,
        enum_layouts,
        record_field_resolved_tys,
        dyn_vtable_registry,
        const_globals,
        borrow_mode,
        borrow_tainted,
        coro: coro_state,
        lambda_actor_shape: match func.call_conv {
            FunctionCallConv::LambdaActorBody(shape) => Some(shape),
            _ => None,
        },
    };

    // Fail-closed boundary: reject composite returns whose heap-owning payload
    // has no tag-aware drop coverage. W5.020 added the move-out + caller-side
    // in-place drop spine for **enum composites** (`Result<T, string>` /
    // `Option<string>` / user enums with an owned-payload variant): the MIR
    // elaborator move-checks the active payload's single owner across the
    // return boundary and emits a `DropKind::EnumInPlace` caller-side drop, so
    // those returns now lower correctly and are admitted here.
    //
    // A SINGLE heap-owning leaf return (`bytes`) is also admitted: it lowers to
    // a `BytesTriple` struct, so it reaches this `StructType` arm, but it is one
    // `CowValue` leaf — the struct-by-value return path copies it flat into the
    // caller's slot with no interior owner needing a per-field drop. The leaf
    // has no scope-exit drop on either side (`cow_value_leaf_drop_symbol` is
    // `None` for `bytes`), so it leaks-as-before rather than double-freeing, the
    // same posture as every other `bytes`/aggregate `CowValue` leaf today. This
    // restores parity with `string`, which lowers to a flat `ptr` and is already
    // admitted because it never reaches the `StructType` arm. (`std::fs` import
    // was blocked solely because `fs.read_bytes -> bytes` was force-codegen'd.)
    //
    // W5.021 — heap-owning TUPLE and RECORD composite returns are now admitted:
    // the MIR elaborator move-checks each owned member's single owner across the
    // return boundary and emits a per-element `DropKind::TupleInPlace` /
    // per-field `DropKind::RecordInPlace` caller-side drop, so the caller's
    // binding (or destructure-temp element bindings) frees each member exactly
    // once. The admit predicates key on the same `ty_contains_heap_owning`
    // authority the MIR side uses, so the two can never disagree on which
    // returns own heap (`dedup-semantic-boundary`).
    //
    // Every OTHER heap-owning composite return — arrays carrying owned heap, a
    // generic record instantiation, and (caught earlier by the checker)
    // recursive value types — still lacks that ownership wiring and stays
    // fail-closed rather than silently leaking or double-freeing. Bitcopy-only
    // payloads (i64, f64, bool, …) carry no ownership and are unaffected.
    // LESSONS: boundary-fail-closed, migration-completeness.
    if matches!(return_ty_llvm, BasicTypeEnum::StructType(_))
        && ty_contains_heap_owning(&func.return_ty, fn_ctx.enum_layouts)
        && !crate::layout::is_heap_owning_enum_composite_return(
            &func.return_ty,
            fn_ctx.enum_layouts,
        )
        && !is_single_heap_owning_leaf_return(&func.return_ty)
        && !crate::layout::is_heap_owning_tuple_composite_return(
            &func.return_ty,
            fn_ctx.enum_layouts,
        )
        && !is_heap_owning_record_composite_return(
            &func.return_ty,
            fn_ctx.record_layouts,
            fn_ctx.enum_layouts,
        )
    {
        return Err(CodegenError::FailClosed(format!(
            "composite return of heap-owning payload `{}` requires tag-aware \
             drop, which is implemented for enum composites \
             (`Result`/`Option`/user enums), tuples, and monomorphic records \
             carrying owned heap in v0.5; for an array of owned values or a \
             generic record instantiation, restructure to return a supported \
             composite or avoid returning owned values directly",
            func.return_ty,
        )));
    }

    // Extract drop_plans from the matched elaborated function, or use an
    // empty slice when no elaborated function is available (hand-built test
    // pipelines that inline Instr::Drop instead of using drop_plans).
    let empty_plans: Vec<(ExitPath, hew_mir::DropPlan)> = Vec::new();
    let drop_plans: &[(ExitPath, hew_mir::DropPlan)] = elab
        .map(|e| e.drop_plans.as_slice())
        .unwrap_or(empty_plans.as_slice());
    let cooperate_sites: &[CooperateSite] =
        checked.map(|c| c.cooperate_sites.as_slice()).unwrap_or(&[]);
    if let Some(site) = cooperate_sites
        .iter()
        .find(|site| site.kind == CooperateKind::FunctionEntry && site.bb_id != entry_block.id)
    {
        return Err(CodegenError::FailClosed(format!(
            "function `{}` has FunctionEntry cooperate site on bb{}, expected bb{}",
            func.name, site.bb_id, entry_block.id
        )));
    }
    if let Some(site) = cooperate_sites
        .iter()
        .find(|site| site.kind == CooperateKind::LoopBackEdge && !blocks.contains_key(&site.bb_id))
    {
        return Err(CodegenError::FailClosed(format!(
            "function `{}` has LoopBackEdge cooperate site on missing bb{}",
            func.name, site.bb_id
        )));
    }

    if cooperate_sites
        .iter()
        .any(|site| cooperate_site_matches(site, entry_block.id, CooperateKind::FunctionEntry))
    {
        emit_cooperate_check(&fn_ctx, entry_block.id, drop_plans)?;
    }
    // P5-RX Stage 2a (A625): runtime fail-closed entry trap. When a borrowed
    // `String` receive view escapes through a vector this stage does not yet
    // retain (call-return laundering, composite construction, ask/select/spawn
    // payloads — see `has_unhandled_borrow_escape`), a LIVE borrow receipt
    // (`borrow_mode != 0`) would create a second owner and double-free against
    // `hew_msg_envelope_release`. Trap before any user code runs rather than
    // emit that fail-open double-free. Copy-mode receipts (`borrow_mode == 0`,
    // the only mode any scheduler drives today) fall straight through to the
    // unchanged body, so this never regresses current compilation/execution; it
    // only arms the guard for the future Stage-2b send flip. Coarse by design
    // (the whole handler traps if ANY unhandled escape exists) — false-closing a
    // dormant path is safe; fail-open is not. LESSONS: boundary-fail-closed.
    if let (true, Some(borrow_mode)) = (borrow_escape_trap, fn_ctx.borrow_mode) {
        let cont_bb = ctx.append_basic_block(llvm_fn, "borrow_escape_ok");
        let trap_bb = ctx.append_basic_block(llvm_fn, "borrow_escape_trap");
        let zero = borrow_mode.get_type().const_zero();
        let is_live = fn_ctx
            .builder
            .build_int_compare(IntPredicate::NE, borrow_mode, zero, "borrow_escape_is_live")
            .llvm_ctx("borrow-escape trap cmp")?;
        fn_ctx
            .builder
            .build_conditional_branch(is_live, trap_bb, cont_bb)
            .llvm_ctx("borrow-escape trap branch")?;
        fn_ctx.builder.position_at_end(trap_bb);
        let panic_fn = llvm_mod.get_function("hew_panic").unwrap_or_else(|| {
            let panic_ty = ctx.void_type().fn_type(&[], false);
            llvm_mod.add_function("hew_panic", panic_ty, Some(Linkage::External))
        });
        fn_ctx
            .builder
            .build_call(panic_fn, &[], "borrow_escape_panic")
            .llvm_ctx("borrow-escape trap hew_panic call")?;
        fn_ctx
            .builder
            .build_unreachable()
            .llvm_ctx("borrow-escape trap unreachable")?;
        fn_ctx.builder.position_at_end(cont_bb);
    }
    // Runtime install at native `main` entry (#1228 M1). Emitted in the
    // prologue — after any borrow-escape trap, before control reaches the
    // first user block — so the default `RuntimeInner` is installed before any
    // runtime authority (node setup, the live-actor registry, the shutdown
    // phase) is touched. `hew_sched_init` is idempotent, so later spawn-site /
    // supervisor-bootstrap calls are harmless no-ops. LESSONS:
    // boundary-fail-closed, lifecycle-symmetry.
    if install_runtime_at_entry {
        let sched_init = intern_runtime_decl(
            fn_ctx.ctx,
            fn_ctx.llvm_mod,
            &mut fn_ctx.runtime_decls.borrow_mut(),
            "hew_sched_init",
        )?;
        fn_ctx
            .builder
            .build_call(sched_init, &[], "hew_sched_init_entry_call")
            .llvm_ctx("hew_sched_init call in main prologue")?;
    }
    // gdb `-g` variable + parameter DIEs (Stages 2/3/4). Emitted into the
    // prologue block (which holds the allocas + param stores and dominates the
    // body) before the closing branch, so each `llvm.dbg.declare` references an
    // in-scope alloca. Fail-closed inside the helper: no subprogram / no name /
    // unresolvable type → no DIE for that slot.
    if let (Some(dctx), Some(subprogram), Some(ls)) =
        (debug, fn_subprogram, lexical_scopes.as_ref())
    {
        emit_variable_dies(
            ctx,
            dctx,
            subprogram,
            func,
            &fn_ctx,
            record_field_resolved_tys,
            record_field_names,
            prologue_bb,
            ls,
        );
    }
    fn_ctx
        .builder
        .build_unconditional_branch(entry_bb)
        .llvm_ctx("prologue br")?;

    for block in &func.blocks {
        let bb = *blocks.get(&block.id).expect("block in map");
        fn_ctx.builder.position_at_end(bb);
        for (instr_idx, instr) in block.instructions.iter().enumerate() {
            // Stage 2 (gdb `-g`): refine the current debug location to this
            // instruction's originating statement line so the body steps
            // line-by-line. Fail-closed inside the helper: no subprogram / no
            // side-table span / out-of-file span leaves the nearest-enclosing
            // location in place rather than fabricating a line. The
            // function-entry location seeded before this loop keeps every call
            // site `!dbg`-tagged for the verifier.
            set_debug_location_for_span(
                ctx,
                &fn_ctx.builder,
                debug,
                fn_subprogram,
                func.instr_spans
                    .get(&(block.id, u32::try_from(instr_idx).unwrap_or(u32::MAX))),
                lexical_scopes.as_ref(),
            );
            lower_instruction(&fn_ctx, instr, block.id, drop_plans)?;
        }
        if cooperate_sites
            .iter()
            .any(|site| cooperate_site_matches(site, block.id, CooperateKind::LoopBackEdge))
        {
            emit_cooperate_check(&fn_ctx, block.id, drop_plans)?;
        }
        // Emit LIFO drops from the elaborated drop plan BEFORE the
        // terminator so the alloca null-stores precede the ret/br.
        // LESSONS: cleanup-all-exits (P0), lifecycle-symmetry (P0).
        emit_elab_drops(&fn_ctx, block.id, drop_plans)?;
        // Stage 2 (gdb `-g`): a call / branch / return lowers to a TERMINATOR,
        // not an `Instr`, so a call-statement (`println(r)`) would otherwise
        // inherit the previous instruction's line. The terminator span is keyed
        // one slot past the last instruction (`block.instructions.len()`), kept
        // aligned through any post-seal splices by `shift_instr_spans_on_insert`.
        set_debug_location_for_span(
            ctx,
            &fn_ctx.builder,
            debug,
            fn_subprogram,
            func.instr_spans.get(&(
                block.id,
                u32::try_from(block.instructions.len()).unwrap_or(u32::MAX),
            )),
            lexical_scopes.as_ref(),
        );
        lower_terminator(
            &fn_ctx,
            fn_symbols,
            &block.terminator,
            block.id,
            &func.await_deadline_ns,
            &func.suspend_kinds,
        )?;
    }

    // Coroutine epilogue (R326/R327). Fill the two shared blocks every
    // `coro.suspend` switch routes to, wired so there is EXACTLY ONE fallthrough
    // `coro.end` reached by both edges (the multi-suspend correctness fix):
    //   - suspend_return: the DEFAULT switch edge (control returns to the
    //     executor — the suspend that frees the worker) AND the join target of
    //     the cleanup path. Carries the single fallthrough `coro.end` + `ret`.
    //   - cleanup: the case-1 switch edge (a `coro.destroy` is abandoning the
    //     frame). Runs `coro.free` → `hew_cont_frame_free`, then BRANCHES INTO
    //     suspend_return (it no longer owns its own `coro.end`/`ret`).
    // A single fallthrough `coro.end` is mandatory: LLVM permits only one, and
    // CoroSplit uses it to mark where the `.resume`/`.destroy` outlines return to
    // the executor. When the suspend-return block lacked a `coro.end`, CoroSplit
    // emitted `unreachable` for it inside the `.resume` outline. With one suspend
    // that block is dead (the default yield edge inside `.resume` is never taken),
    // but with two-plus suspends the later yield-back-to-executor routes through
    // it → ran off into `unreachable` → SIGSEGV on the second await. The single
    // shared `coro.end` is the documented switched-resume shape.
    // CoroSplit reads these to build the `.resume`/`.destroy`/`.cleanup`
    // outlines; the runtime's `hew_cont_*` verbs drive the resulting frame.
    if let Some(coro) = fn_ctx.coro {
        // Reconstruct the CoroContext (a bundle of borrows + the handle/token)
        // to reuse the canonical `coro.rs` epilogue helpers.
        let cc = crate::coro::CoroContext {
            ctx,
            llvm_mod,
            builder: &fn_ctx.builder,
            function: llvm_fn,
            handle: coro.handle,
            id_token: coro.id_token,
        };
        // Shared final-suspend block (SuspendingAsk-driven coroutine): EVERY
        // `Terminator::Return` branches here instead of inlining its own reply
        // deposit + final suspend. Emitting it once is what keeps a multi-return
        // handler to a SINGLE `coro.suspend(is_final=true)` — CoroSplit rejects
        // "Only one suspend point can be marked as final" when each `Return`
        // inlines its own. The reply value has already been stored into
        // `return_slot` by whichever `Return` predecessor branched here (a memory
        // alloca, so the load reads the correct path's value with no phi). This
        // is the body-side W6.010 value deposit, moved out of the per-`Return`
        // arm so it runs exactly once at the convergence point.
        if let Some(final_suspend_block) = coro.final_suspend_block {
            fn_ctx.builder.position_at_end(final_suspend_block);
            // A GENERATOR deposits no reply on completion — its value channel is
            // the out-pointer, surfaced per-yield, not a reply channel. Its
            // `Return` (body run off the end) just flips `coro.done` via this
            // value-free final suspend so the consumer's next `GeneratorNext`
            // observes `None`. Skip the await-family `hew_get_reply_channel` /
            // `hew_reply` deposit entirely.
            if let Some(logical_ty) = coro.logical_return_ty.filter(|_| !coro.is_generator) {
                let loaded = fn_ctx
                    .builder
                    .build_load(logical_ty, fn_ctx.return_slot, "coro_ret_val")
                    .llvm_ctx("coro return load")?;
                let ret_slot = fn_ctx
                    .builder
                    .build_alloca(logical_ty, "coro_reply_slot")
                    .llvm_ctx("coro reply alloca")?;
                fn_ctx
                    .builder
                    .build_store(ret_slot, loaded)
                    .llvm_ctx("coro reply store")?;
                let reply_channel = intern_runtime_decl(
                    fn_ctx.ctx,
                    fn_ctx.llvm_mod,
                    &mut fn_ctx.runtime_decls.borrow_mut(),
                    "hew_get_reply_channel",
                )?;
                let reply = intern_runtime_decl(
                    fn_ctx.ctx,
                    fn_ctx.llvm_mod,
                    &mut fn_ctx.runtime_decls.borrow_mut(),
                    "hew_reply",
                )?;
                let ch = fn_ctx
                    .builder
                    .build_call(reply_channel, &[], "coro_get_reply_channel_call")
                    .llvm_ctx("coro get reply channel call")?
                    .try_as_basic_value()
                    .basic()
                    .ok_or_else(|| {
                        CodegenError::FailClosed("hew_get_reply_channel returned void".into())
                    })?
                    .into_pointer_value();
                let size = logical_ty.size_of().ok_or_else(|| {
                    CodegenError::FailClosed(format!(
                        "coroutine reply type has no static size: {logical_ty:?}"
                    ))
                })?;
                // Reconcile LLVM size_of (always i64) to the target-correct
                // `usize`/`size_t` width (`hew_reply` third param). i32 on wasm32.
                let coro_reply_size_ty = runtime_size_ty(fn_ctx.ctx, fn_ctx.llvm_mod);
                let size = reconcile_int_width_signed(
                    &fn_ctx,
                    size.into(),
                    coro_reply_size_ty.into(),
                    "coro reply size",
                )?;
                fn_ctx
                    .builder
                    .build_call(
                        reply,
                        &[ch.into(), ret_slot.into(), size.into()],
                        "coro_reply_call",
                    )
                    .llvm_ctx("coro hew_reply call")?;
            }
            cc.emit_suspend(
                coro.cleanup_block,
                coro.cleanup_block,
                coro.suspend_return_block,
                true,
                "coro.final",
            )?;
        }
        // cleanup: free the frame, then join suspend_return. The frame-free
        // helper wants a `free` block (the dyn-free arm); allocate it and route
        // cleanup -> free-check -> suspend_return.
        let coro_free_block = ctx.append_basic_block(llvm_fn, "coro.dyn.free");
        fn_ctx.builder.position_at_end(coro.cleanup_block);
        crate::coro::emit_coro_frame_free(&cc, coro_free_block, coro.suspend_return_block)?;

        // suspend_return: the single fallthrough `coro.end(hdl, false, none)`
        // then `ret ptr <handle>` — hands the frame to the executor on a yield
        // and completes the ramp on teardown. Both edges (the suspend switches'
        // default edge and the cleanup join) terminate here.
        fn_ctx.builder.position_at_end(coro.suspend_return_block);
        crate::coro::emit_coro_end_ret(&cc)?;
    }

    Ok(())
}

fn actor_name_from_handler_symbol(symbol: &str) -> Option<&str> {
    symbol
        .split_once("__recv__")
        .map(|(actor_name, _)| actor_name)
        .or_else(|| symbol.strip_suffix("__init"))
        .or_else(|| symbol.strip_suffix("__on_start"))
        // Indexed stop-hook symbols: `<Actor>__on_stop__<N>`.
        // Strip the numeric suffix first, then the `__on_stop` infix.
        .or_else(|| {
            let after_on_stop = symbol.split_once("__on_stop__")?;
            // Verify the suffix is a decimal index (no empty or non-numeric).
            // JUSTIFIED: malformed indexed stop-hook suffixes are not handler symbols.
            after_on_stop.1.parse::<usize>().ok()?;
            Some(after_on_stop.0)
        })
}

/// Map an actor handler symbol back to the actor's REGISTRY key (the dotted
/// qualified identity that `ActorLayout.name` and the state-record layout
/// use).
///
/// Handler symbols carry the `$`-mangled base (`bank$Account__recv__deposit`,
/// from MIR's `actor_symbol_base` / `mangle_dotted_name`). The base is either
/// a bare root-actor name or `{module_short}${name}` with single-segment
/// components — Hew identifiers cannot contain `$`, and generic-instantiation
/// mangles (`Result$$i32$…`) never reach actor handler symbols — so replacing
/// `$` with `.` is the exact inverse of `mangle_dotted_name` here.
fn actor_layout_key_from_handler_symbol(symbol: &str) -> Option<String> {
    actor_name_from_handler_symbol(symbol).map(|base| base.replace('$', "."))
}

// ---------------------------------------------------------------------------
// Module-level orchestration
// ---------------------------------------------------------------------------

/// Build the LLVM module for a lowered pipeline.
///
/// `checked_mir` is all-or-nothing — if non-empty, every `raw_mir` function
/// MUST have a matching entry. Fails closed at codegen time if violated.
///
/// Test-only thin wrapper over [`build_module_for_target`] with no target
/// machine and no debug info; production emits through
/// `emit_textual` / `emit_object_in_process`.
#[cfg(test)]
fn build_module<'ctx>(
    ctx: &'ctx Context,
    pipeline: &IrPipeline,
    name: &str,
) -> CodegenResult<LlvmModule<'ctx>> {
    build_module_for_target(ctx, pipeline, name, None, None)
}

fn build_module_for_target<'ctx>(
    ctx: &'ctx Context,
    pipeline: &IrPipeline,
    name: &str,
    target_machine: Option<&TargetMachine>,
    debug: Option<DebugInput<'_>>,
) -> CodegenResult<LlvmModule<'ctx>> {
    let llvm_mod = ctx.create_module(name);
    let emit_wasm_entry_alias = target_machine.is_some_and(|machine| {
        machine
            .get_triple()
            .as_str()
            .to_string_lossy()
            .starts_with("wasm32")
    });
    let target_data = if let Some(machine) = target_machine {
        let triple = machine.get_triple();
        llvm_mod.set_triple(&triple);
        let data = machine.get_target_data();
        let layout = data.get_data_layout();
        llvm_mod.set_data_layout(&layout);
        data
    } else {
        // No target machine (the in-process IR build / `hew check`): still
        // declare the host triple on the module so target-keyed lowering — the
        // aggregate ABI classifier, `runtime_size_ty` — reads the correct
        // target rather than an empty triple. `host_target_data()` IS the host's
        // layout, so the host triple is the matching authority.
        llvm_mod.set_triple(&TargetTriple::create(&native_emission_triple()));
        host_target_data()
    };

    // DWARF compile unit + file for `hew build -g` (W0.060). Created once per
    // module; the `DebugInfoBuilder` is finalized just before `verify()` below
    // (inkwell requires `finalize()` before any code generation, verification
    // included). Without a threaded `DebugInput` (`hew build` with no `-g`)
    // this stays `None` and the module carries zero debug metadata — the
    // legacy behaviour, byte-for-byte.
    let line_index = debug.map(|d| LineIndex::new(d.source_text));
    let module_debug: Option<(DebugInfoBuilder<'ctx>, DICompileUnit<'ctx>, DIFile<'ctx>)> =
        if let Some(d) = debug {
            let file_name = d
                .source_path
                .file_name()
                .map(|s| s.to_string_lossy().into_owned())
                .unwrap_or_else(|| format!("{name}.hew"));
            let directory = d
                .source_path
                .parent()
                .filter(|p| !p.as_os_str().is_empty())
                .map(|p| p.to_string_lossy().into_owned())
                .unwrap_or_else(|| ".".to_string());
            let (di_builder, compile_unit) = llvm_mod.create_debug_info_builder(
                /* allow_unresolved */ true,
                DWARFSourceLanguage::C,
                &file_name,
                &directory,
                concat!("hew ", env!("CARGO_PKG_VERSION")),
                /* is_optimized */ false,
                /* compiler flags */ "",
                /* runtime_ver */ 0,
                /* split_name */ "",
                DWARFEmissionKind::Full,
                /* dwo_id */ 0,
                /* split_debug_inlining */ false,
                /* debug_info_for_profiling */ false,
                /* sysroot */ "",
                /* sdk */ "",
            );
            // The LLVM verifier requires the module's "Debug Info Version" flag
            // to equal the current `DEBUG_METADATA_VERSION` (3, stable since
            // LLVM 3.x and unchanged on LLVM 22); a missing/mismatched value
            // makes the verifier silently strip all debug info.
            let debug_metadata_version = ctx.i32_type().const_int(3, false);
            llvm_mod.add_basic_value_flag(
                "Debug Info Version",
                inkwell::module::FlagBehavior::Warning,
                debug_metadata_version,
            );
            let file = compile_unit.get_file();
            Some((di_builder, compile_unit, file))
        } else {
            None
        };
    let fn_debug_ctx: Option<ModuleDebugCtx<'_, 'ctx>> = match (&module_debug, &line_index) {
        (Some((di_builder, compile_unit, file)), Some(line_index)) => Some(ModuleDebugCtx {
            di_builder,
            compile_unit: *compile_unit,
            file: *file,
            line_index,
            di_type_cache: RefCell::new(HashMap::new()),
        }),
        _ => None,
    };
    // Predeclare opaque LLVM named structs for every record / enum / machine
    // outer + `<Name>Event` companion BEFORE any body-fill pass. Record
    // fields can reference enum or machine type names (e.g. `record
    // CrashNotification { kind: CrashKind }` where `CrashKind` is an
    // enum); without the predeclare-all-then-fill-all ordering, the record
    // body-fill would call `resolve_ty` against a map containing only
    // record opaques and trip the D10 fail-closed sentinel on `kind`.
    let mut record_layouts = crate::layout::predeclare_named_layouts(
        ctx,
        &pipeline.record_layouts,
        &pipeline.enum_layouts,
        &pipeline.machine_layouts,
        &pipeline.opaque_handle_names,
    )?;
    crate::layout::fill_record_layout_bodies(ctx, &pipeline.record_layouts, &record_layouts)?;
    // Build a quick lookup from record name → field ResolvedTys, shared by
    // every per-function lowering context. The synthesis path consults this
    // when walking a struct hash thunk so a `bool` field (i8 storage, low
    // bit semantically defined) gets masked with `and i8, 1` before the
    // FNV-1a mix step, while a general `i8`/`u8` field is hashed full-width.
    let record_field_resolved_tys: HashMap<String, Vec<ResolvedTy>> = pipeline
        .record_layouts
        .iter()
        .map(|r| (r.name.clone(), r.field_tys.clone()))
        .collect();
    // Parallel field-name map for `-g` `DW_TAG_member` DIEs (Stage 4b). Keyed
    // identically to `record_field_resolved_tys`; codegen's `resolve_di_type`
    // looks names up by the same record key and falls back to positional
    // `field_N` when a layout carries no names.
    let record_field_names: HashMap<String, Vec<String>> = pipeline
        .record_layouts
        .iter()
        .map(|r| (r.name.clone(), r.field_names.clone()))
        .collect();
    let mut machine_layouts: MachineLayoutMap<'ctx> = HashMap::new();
    // Register user-defined enum layouts before machines so machine payloads
    // can name enum types declared in imported stdlib modules.
    // Enum-typed locals use the same `Place::MachineTag` / `Place::MachineVariant`
    // addressing as machine-typed locals; the map lookup in
    // `machine_layout_for_local` is keyed by type name and does not
    // distinguish surface form. Outer structs were predeclared above; this
    // call sets each body on the existing opaque via `build_tagged_union_layout`.
    //
    // MACHINE-REFERENCING enums are deferred to a second registration pass
    // AFTER the machines: an enum-instantiation payload can embed a machine
    // value (`Option<Conn>` — the binding every machine-element channel
    // recv produces), and `build_tagged_union_layout` sizes the payload via
    // `get_abi_size` on the variant structs. Sizing while the machine's
    // named struct is still OPAQUE yields 0, the payload array under-sizes,
    // and the recv decode writes past the alloca (observed as a clobbered
    // receiver handle and a lost wake). Machines may reference plain enums
    // in their state payloads (pass 1), and the deferred enums may
    // reference machines (pass 3) — the split keeps both directions sized
    // against bodied members.
    let machine_short_names: HashSet<&str> = pipeline
        .machine_layouts
        .iter()
        .map(|m| short_name(&m.name))
        .collect();
    let (machine_free_enums, machine_ref_enums): (
        Vec<hew_mir::EnumLayout>,
        Vec<hew_mir::EnumLayout>,
    ) = pipeline.enum_layouts.iter().cloned().partition(|layout| {
        !layout.variants.iter().any(|v| {
            v.field_tys
                .iter()
                .any(|t| resolved_ty_references_machine(t, &machine_short_names))
        })
    });
    crate::layout::register_enum_layouts(
        ctx,
        &machine_free_enums,
        &mut record_layouts,
        &mut machine_layouts,
        Some(&target_data),
    )?;
    // Slice 5: register machine tagged-union types alongside records.
    // Outer structs + `<Name>Event` companions were predeclared above; this
    // call sets each body on the existing opaque. The richer per-variant
    // metadata (inner structs, tag int type) lives in `machine_layouts`.
    let machine_layout_map = crate::layout::register_machine_layouts(
        ctx,
        &llvm_mod,
        &pipeline.machine_layouts,
        &mut record_layouts,
        &pipeline.enum_layouts,
        Some(&target_data),
    )?;
    machine_layouts.extend(machine_layout_map);
    // Second enum pass: the machine-referencing instantiations, sized now
    // that every machine body is set.
    crate::layout::register_enum_layouts(
        ctx,
        &machine_ref_enums,
        &mut record_layouts,
        &mut machine_layouts,
        Some(&target_data),
    )?;
    let const_globals = emit_const_globals(ctx, &llvm_mod, &pipeline.user_consts, &record_layouts)?;
    // Emit the per-type text-codec descriptor globals BEFORE body lowering: the
    // `to_json`/`from_json` lowering (`lower_wire_text_codec_instr`) references
    // them by name at each call site, so they must exist when bodies are lowered.
    // (The CBOR thunks themselves are only declared during body lowering and
    // defined afterward, but a global-string constant cannot be forward-declared
    // the same way.)
    emit_all_wire_text_descriptor_globals(
        ctx,
        &llvm_mod,
        pipeline,
        &pipeline.record_layouts,
        &pipeline.enum_layouts,
    )?;
    let mut fn_symbols: FnSymbolMap<'ctx> = HashMap::new();
    predeclare_stdlib_catalog(ctx, &llvm_mod, &mut fn_symbols, &record_layouts)?;
    predeclare_extern_decls(
        ctx,
        &llvm_mod,
        &mut fn_symbols,
        &pipeline.extern_decls,
        &record_layouts,
    )?;
    for func in &pipeline.raw_mir {
        let sym = declare_function(
            ctx,
            &llvm_mod,
            func,
            &record_layouts,
            &pipeline.enum_layouts,
            emit_wasm_entry_alias,
        )?;
        fn_symbols.insert(func.name.clone(), sym);
    }
    if emit_wasm_entry_alias {
        emit_wasm_main_export_wrapper(ctx, &llvm_mod, &fn_symbols)?;
    }
    // W3.030 Stage 2 V13: verify every `ElabDrop { drop_fn: Some(_) }`
    // resolves to one of the two `DropDispatch` arms (runtime symbol or
    // registered user function) BEFORE any body lowering begins. A third
    // path — drop_fn that resolves to neither — fails closed here rather
    // than as a dangling reference at link time.
    verify_drop_dispatch_resolves(pipeline, &fn_symbols)?;
    for actor in &pipeline.actor_layouts {
        // NEW-3a (R326/R327): per-handler suspendable predicate, derived from
        // the SAME carrier the per-function coroutine emission keys off — the
        // handler's MIR block terminators carrying `Terminator::Suspend`
        // (`lower_function` `has_suspend`, see the coroutine prologue arm). The
        // handler MIR blocks are not on `ActorHandlerLayout`; they live in
        // `pipeline.raw_mir`, in scope here. Deriving the predicate from the
        // identical data + match arm makes the trampoline's ramp-vs-direct
        // decision agree with the ramp emission BY CONSTRUCTION — there is no
        // second source of truth to drift (R2 / the Lane-B silent-no-op class).
        // A handler whose symbol has no matching raw MIR function fails closed
        // inside the trampoline rather than silently defaulting to direct-call.
        let handler_suspendable: Vec<Option<bool>> = actor
            .handlers
            .iter()
            .map(|h| {
                pipeline
                    .raw_mir
                    .iter()
                    .find(|f| f.name == h.symbol)
                    .map(|f| {
                        f.blocks.iter().any(|b| {
                            matches!(
                                b.terminator,
                                // The ten pure carriers collapse to bare `Suspend`;
                                // ScopeDeadline / Select stay distinct.
                                Terminator::Suspend { .. }
                                    | Terminator::SuspendingScopeDeadline { .. }
                                    | Terminator::SuspendingSelect { .. }
                            )
                        })
                    })
            })
            .collect();
        crate::thunks::emit_actor_dispatch_trampoline(
            ctx,
            &llvm_mod,
            actor,
            &handler_suspendable,
            &fn_symbols,
            &record_layouts,
        )?;
        if !actor.on_stop_symbols.is_empty() {
            crate::thunks::emit_actor_terminate_trampoline(ctx, &llvm_mod, actor, &fn_symbols)?;
        }
    }
    // W2.002 Stage 3: synthesise `__hew_state_clone_<Actor>` /
    // `__hew_state_drop_<Actor>` + companion `__hew_record_*_inplace_<R>`
    // BODIES for every classified actor in `pipeline.actor_layouts`.
    // Must run BEFORE supervisor bootstrap emission so the
    // `get_function`-or-declare lookup at Stage 2's supervisor-child
    // registration sites (and at every direct-spawn emission site)
    // resolves to the synthesised `define`, not a Stage 2 extern-stub
    // that would only surface at link time.
    // W5.020 — collect the enum-layout keys that any elaborated function drops
    // via `DropKind::EnumInPlace`, so the synthesis pass below emits their
    // `__hew_enum_drop_inplace_<Enum>` body even when no actor/record reaches
    // them. The key is resolved from each drop's `ElabDrop::ty` through the
    // same registration scheme `register_enum_layouts` uses.
    let mut enum_inplace_drop_seeds =
        collect_enum_inplace_drop_seeds(&pipeline.elaborated_mir, &pipeline.enum_layouts);
    // W5.016 — seed every owned-Vec element record/enum so its
    // `__hew_record/enum_{clone,drop}_inplace_<key>` body is emitted (the owned
    // Vec descriptor is the only referent; without this seed the thunk pointers
    // dangle at link). Enum seeds merge into the EnumInPlace seed list; record
    // seeds go through the dedicated `extra_record_seeds` channel.
    // Machines are enums at the value-classification layer: the seed scan
    // and the clone/drop synthesis below resolve machine names against the
    // enum view, so the machine projections join the list once here.
    // `machine_layout_map` registers every machine's tagged-union layout
    // under the same name, so the emitted
    // `__hew_enum_{clone,drop}_inplace_<Machine>` bodies walk the real
    // machine layout. The pipeline's own `enum_layouts` (registration,
    // xnode codecs) stays untouched.
    let synthesis_enum_layouts: Vec<hew_mir::EnumLayout> = pipeline
        .enum_layouts
        .iter()
        .cloned()
        .chain(hew_mir::machine_enum_views(&pipeline.machine_layouts))
        .collect();
    let (mut vec_owned_record_seeds, vec_owned_enum_seeds) = collect_vec_owned_element_seeds(
        &pipeline.raw_mir,
        &pipeline.record_layouts,
        &synthesis_enum_layouts,
    );
    for enum_seed in vec_owned_enum_seeds {
        if !enum_inplace_drop_seeds.contains(&enum_seed) {
            enum_inplace_drop_seeds.push(enum_seed);
        }
    }
    // Value-class capstone — seed every record dropped via
    // `DropKind::RecordInPlace` (owned aggregate record by value) into the
    // record-seed channel so its `__hew_record_{clone,drop}_inplace_<R>` body
    // is synthesized. Reuses the same channel as the owned-Vec element record
    // seeds; `collect_reachable_clone_targets` dedups by record key.
    for record_seed in
        collect_record_inplace_drop_seeds(&pipeline.elaborated_mir, &pipeline.record_layouts)
    {
        if !vec_owned_record_seeds.contains(&record_seed) {
            vec_owned_record_seeds.push(record_seed);
        }
    }
    // cross-node codec path — seed every record- or enum-typed actor handler
    // message/reply so `emit_state_clone_drop_synthesis` emits the
    // `__hew_record_drop_inplace_*` / `__hew_enum_drop_inplace_*` body before
    // `emit_actor_codec_module_init` declares it via
    // `get_or_declare_{record,enum}_drop_inplace` in the fail-path drop walk
    // (`emit_de_drop_owned`).  Without this seed, LLVM verify rejects the module
    // ("Global is external, but doesn't have external or weak linkage") for any
    // record or enum used as a handler type but not reachable from an actor
    // state field.
    let wire_codec_value_types = collect_wire_codec_value_types(pipeline);
    let (xnode_codec_record_seeds, xnode_codec_enum_seeds) = collect_xnode_codec_drop_seeds(
        &pipeline.actor_layouts,
        &wire_codec_value_types,
        &pipeline.record_layouts,
        &pipeline.enum_layouts,
    );
    for xnode_enum_seed in xnode_codec_enum_seeds {
        if !enum_inplace_drop_seeds.contains(&xnode_enum_seed) {
            enum_inplace_drop_seeds.push(xnode_enum_seed);
        }
    }
    for xnode_rec_seed in xnode_codec_record_seeds {
        if !vec_owned_record_seeds.contains(&xnode_rec_seed) {
            vec_owned_record_seeds.push(xnode_rec_seed);
        }
    }
    // D2 — seed every record/enum that appears as a `dyn Trait` CONCRETE so
    // `emit_state_clone_drop_synthesis` (immediately below) emits its
    // `__hew_{record,enum}_drop_inplace_<key>` body BEFORE
    // `emit_dyn_trait_drop_in_place_fns` (further down) emits the vtable
    // slot-0 `drop_in_place` thunk that dispatches to it. A concrete used
    // only behind `dyn` (never in an actor/record state field) is reachable
    // through no other seed, so without this its structural-drop helper
    // would be declared-but-undefined and LLVM verify would reject the
    // module. Enum-aware classification routes enum concretes to the enum
    // channel (D2 Mode B); record concretes to the record channel (Mode A).
    let (dyn_concrete_record_seeds, dyn_concrete_enum_seeds) = collect_dyn_concrete_drop_seeds(
        &pipeline.dyn_vtable_registry,
        &pipeline.record_layouts,
        &synthesis_enum_layouts,
    );
    for seed in dyn_concrete_enum_seeds {
        if !enum_inplace_drop_seeds.contains(&seed) {
            enum_inplace_drop_seeds.push(seed);
        }
    }
    for seed in dyn_concrete_record_seeds {
        if !vec_owned_record_seeds.contains(&seed) {
            vec_owned_record_seeds.push(seed);
        }
    }
    // User-authored `.clone()` calls on record types: seed their thunk pairs
    // so every record cloned by user code gets a synthesised
    // `__hew_record_clone_inplace_<R>` / `__hew_record_drop_inplace_<R>` body,
    // regardless of actor-state or Vec<R> reachability.
    for seed in &pipeline.user_clone_record_seeds {
        if !vec_owned_record_seeds.contains(seed) {
            vec_owned_record_seeds.push(seed.clone());
        }
    }
    // Generic record-clone instantiations: `clone Pair<i64, i64>` lowers to a
    // `RecordCloneInplace` keyed by the monomorphised layout (`Pair$$i64$i64`),
    // which the bare-name `user_clone_record_seeds` above does not cover and
    // which the `RecordInPlace` drop twin only covers when the record has a
    // non-trivial drop. Seed the clone site directly so the per-mono clone/drop
    // thunk pair is synthesised together (clone/drop always emitted as a unit per key).
    for seed in collect_record_clone_inplace_seeds(&pipeline.raw_mir, &pipeline.record_layouts) {
        if !vec_owned_record_seeds.contains(&seed) {
            vec_owned_record_seeds.push(seed);
        }
    }
    // Generic/top-level enum-clone instantiations: `clone Maybe<i64>` lowers to
    // an `EnumCloneInplace` keyed by the monomorphised tagged-union layout
    // (`Maybe$$i64`). An all-`BitCopy`-payload enum is cloned but never earns an
    // `EnumInPlace` drop, so the drop-side `collect_enum_inplace_drop_seeds`
    // above does not cover it. Seed the clone site directly so the per-key
    // clone/drop thunk PAIR is synthesised together (the enum twin of the
    // record clone-site seed loop directly above).
    for seed in collect_enum_clone_inplace_seeds(&pipeline.raw_mir, &pipeline.enum_layouts) {
        if !enum_inplace_drop_seeds.contains(&seed) {
            enum_inplace_drop_seeds.push(seed);
        }
    }
    emit_state_clone_drop_synthesis(
        ctx,
        &llvm_mod,
        &pipeline.actor_layouts,
        &pipeline.record_layouts,
        &record_layouts,
        &synthesis_enum_layouts,
        &pipeline.opaque_handle_names,
        &machine_layouts,
        Some(&target_data),
        &enum_inplace_drop_seeds,
        &vec_owned_record_seeds,
    )?;
    // Supervisor bootstraps replace the MIR-side synthesised body wholesale
    // with the canonical `hew_supervisor_new` → `add_child_spec` × N →
    // `start` call sequence (S-D.3). The set of bootstrap symbols is
    // collected so the body-lowering loop below skips them — the MIR-side
    // body exists only to carry the declaration signature.
    let supervisor_bootstrap_symbols: std::collections::HashSet<String> = pipeline
        .supervisor_layouts
        .iter()
        .map(|s| s.bootstrap_symbol.clone())
        .collect();
    // Whether the module reaches any runtime authority — an actor, a
    // supervisor, or a runtime-owned builtin/FFI surface. Drives the native
    // `main`-entry runtime install (#1228 M1): when true, `main` calls
    // `hew_sched_init` in its prologue so the de-globalized `RuntimeInner` is
    // installed before any authority is touched (node setup before the first
    // spawn, a remote `pid.tell` with no spawn site at all, metrics registry
    // registration/mutation, the implicit drain epilogue).
    let module_uses_runtime = !pipeline.actor_layouts.is_empty()
        || !pipeline.supervisor_layouts.is_empty()
        || module_uses_node_authority(&pipeline.raw_mir)
        || module_uses_metric_authority(&pipeline.raw_mir);
    for sup in &pipeline.supervisor_layouts {
        emit_supervisor_bootstrap_body(
            ctx,
            &llvm_mod,
            sup,
            &fn_symbols,
            &pipeline.actor_layouts,
            &record_layouts,
        )?;
    }
    for func in &pipeline.raw_mir {
        if supervisor_bootstrap_symbols.contains(&func.name) {
            // Body already emitted by `emit_supervisor_bootstrap_body`. Skip
            // the normal MIR lowering — the MIR-side synthesised body is a
            // stub kept only to carry the bootstrap function's signature
            // through `declare_function`.
            continue;
        }
        // Match by name: elaborated_mir is parallel to raw_mir when the
        // full pipeline runs. Hand-built test pipelines may leave
        // elaborated_mir empty; `find` returns `None` in that case and
        // `lower_function` falls back to the inline Instr::Drop path.
        let elab = pipeline.elaborated_mir.iter().find(|e| e.name == func.name);
        let checked = if pipeline.checked_mir.is_empty() {
            None
        } else {
            Some(
                pipeline
                    .checked_mir
                    .iter()
                    .find(|c| c.name == func.name)
                    .ok_or_else(|| {
                        CodegenError::FailClosed(format!(
                            "function `{}` has no matching checked MIR for cooperate-site lowering",
                            func.name
                        ))
                    })?,
            )
        };
        lower_function(
            ctx,
            &llvm_mod,
            &target_data,
            func,
            &fn_symbols,
            elab,
            checked,
            &record_layouts,
            &pipeline.actor_layouts,
            &machine_layouts,
            &pipeline.enum_layouts,
            &record_field_resolved_tys,
            &record_field_names,
            &pipeline.dyn_vtable_registry,
            &const_globals,
            emit_wasm_entry_alias,
            !pipeline.supervisor_layouts.is_empty(),
            module_uses_runtime,
            fn_debug_ctx.as_ref(),
        )?;
    }
    // Emit regex module-init infrastructure if the module uses any regex literals.
    // This must come AFTER all function bodies are lowered (the init function
    // references globals declared here) and BEFORE llvm_mod.verify() so the
    // verifier can check the emitted IR.
    let mut module_init_ctors: Vec<FunctionValue<'ctx>> = Vec::new();
    if !pipeline.regex_literals.is_empty() {
        if let Some(f) = emit_regex_module_init(ctx, &llvm_mod, &pipeline.regex_literals)? {
            module_init_ctors.push(f);
        }
    }
    // Emit the cross-node payload codec thunks + registration constructor so a
    // Serializable actor message survives a process hop. The cross-node codec is
    // the same CBOR body codec the `.encode()`/`.decode()` path uses, so a wire
    // type rides one shared thunk pair on both paths. Runs after layouts are
    // registered. No-op when there are no actor handlers.
    if let Some(f) = emit_actor_codec_module_init(
        ctx,
        &llvm_mod,
        &pipeline.actor_layouts,
        &pipeline.wire_layouts,
        &record_layouts,
        &machine_layouts,
        &pipeline.record_layouts,
        &pipeline.enum_layouts,
    )? {
        module_init_ctors.push(f);
    }
    // Emit serialize/deserialize thunk bodies for wire types referenced by a
    // direct `.encode()` / `.decode()` call. Idempotent with the actor-message
    // codec emission above — a type used in both shares one thunk pair.
    emit_wire_codec_call_thunks(
        ctx,
        &llvm_mod,
        pipeline,
        &record_layouts,
        &machine_layouts,
        &pipeline.record_layouts,
        &pipeline.enum_layouts,
    )?;
    // Materialise the single @llvm.global_ctors from all collected module inits.
    emit_global_ctors(ctx, &llvm_mod, &module_init_ctors)?;
    // Synthesize one erased method thunk per `(vtable_id, method_index)`
    // pair in `pipeline.dyn_vtable_registry`. The thunk has signature
    // `fn(ptr_erased_self, <receiver-skipped params>) -> ret`; its body
    // forwards every argument verbatim to the concrete impl method
    // named by `method_table[method_index].1`. Opaque pointers make the
    // erased-vs-typed self forward a bit-identical pass-through, so no
    // explicit bitcast is emitted. The function pointer the future
    // vtable static (and the dispatch arm) references is exactly this
    // thunk, never the bare impl method, because the indirect-call
    // type at a `CallTraitMethod` site is *erased* in slot 0 — the
    // impl declares slot 0 typed, the thunk re-types it.
    //
    // Thunks are emitted even when no caller exists yet (the vtable
    // static initialiser and the indirect-dispatch arm at
    // `CallTraitMethod` remain fail-closed until their own substrate
    // lands). `Linkage::Private` keeps the symbols internal to the
    // compilation unit with no ABI promise; the trait/concrete/id-
    // mangled names keep `nm`-style observation legible for tests
    // without crossing the dispatch fail-closed gate.
    emit_dyn_trait_thunks(
        ctx,
        &llvm_mod,
        &pipeline.dyn_vtable_registry,
        &fn_symbols,
        &record_layouts,
    )?;
    // Synthesise one `void (*)(ptr)` slot-0 `drop_in_place` function per
    // `vtable_id` in `pipeline.dyn_vtable_registry`. The function runs the
    // concrete value's STRUCTURAL drop only — it dispatches to the
    // per-type `__hew_{record,enum}_drop_inplace_<key>` helper (the
    // runtime-erased counterpart to `DropKind::{Record,Enum}InPlace`),
    // dropping owned-heap fields WITHOUT freeing storage. Storage release
    // is the drop SITE's job: `hew_dyn_box_free` for `HeapBoxed`, nothing
    // for `FrameOwned` (see `lower_dyn_trait_vtable_drop`). This split is
    // the runtime ABI contract (`hew-runtime/src/trait_object.rs::HewVtable`
    // — "run the value's drop code WITHOUT freeing storage").
    //
    // The dispatched-to helper bodies are emitted by
    // `emit_state_clone_drop_synthesis` above; the dyn-concrete seed pass
    // (`collect_dyn_concrete_drop_seeds`) guarantees a body exists for every
    // record/enum concrete reachable only through `dyn`. `BitCopy`
    // concretes (primitives, all-bitcopy records via the synthesised
    // no-op record helper) emit an empty body. The function is emitted with
    // `Private` LLVM linkage and named via
    // `hew_mir::mangle_dyn_drop_in_place_symbol`
    // (`__hew_dyn_drop_in_place__{trait}__{concrete}__{vtable_id}`, routed
    // through `hew_mir::sanitize_for_symbol`); the trait/concrete/id
    // mangling keeps `nm`-style observation legible for tests while the
    // `Private` linkage gives no ABI promise. The in-module caller is the
    // vtable static initialiser emitted by
    // `emit_dyn_trait_vtable_definitions` immediately below, and — at
    // runtime — the slot-0 dispatch in `lower_dyn_trait_vtable_drop`.
    emit_dyn_trait_drop_in_place_fns(
        ctx,
        &llvm_mod,
        &pipeline.dyn_vtable_registry,
        &pipeline.record_layouts,
        &synthesis_enum_layouts,
    )?;
    // Finalise the `%hew.dyn.vtable.N` opaque struct and the
    // `@__hew_vtable__{trait}__{concrete}__{vtable_id} = private constant`
    // global that `Instr::CoerceToDynTrait` sites declared earlier.
    // The body is the 3-slot prefix triple — `{ ptr (drop_in_place),
    // <usize> (size_of), <usize> (align_of) }` — followed by N
    // erased-self method-thunk pointer slots in registry declaration
    // order. The prefix triple mirrors `HewVtable` in
    // `hew-runtime/src/trait_object.rs:108-130` and matches the
    // checker's slot convention (`DynMethodCall::slot = 3 +
    // method_decl_order`). All three symbol families are guaranteed
    // present by the two emission passes immediately above (drop fns
    // and thunks); the size/align values are sourced from the LLVM
    // ABI layout of `inst.concrete_type` against the host target
    // data, the same authority the drop-SITE `hew_dyn_box_free(ptr,
    // size, align)` call uses (`lower_dyn_trait_vtable_drop`, the
    // HeapBoxed arm) so the dealloc layout cannot drift from the
    // vtable's published layout. The vtable global keeps its `Linkage::Private`
    // (internal to the compilation unit, no ABI promise) and the
    // name produced by `hew_mir::mangle_dyn_vtable_symbol` (routed
    // through `hew_mir::sanitize_for_symbol` for a trait/concrete/id
    // triple that keeps `nm`-style observation legible). The same
    // named struct handle the declaration site produced is reused —
    // the opaque body is filled by `set_body` and the global's
    // initializer by `set_initializer`, so every prior fat-pointer
    // construction remains ABI-stable.
    emit_dyn_trait_vtable_definitions(
        ctx,
        &llvm_mod,
        &pipeline.dyn_vtable_registry,
        &record_layouts,
    )?;
    if emit_wasm_entry_alias {
        emit_wasm_coro_runtime_overrides(ctx, &llvm_mod, &target_data)?;
    }
    // Finalize all deferred debug-info metadata BEFORE verification: inkwell's
    // `DebugInfoBuilder::finalize` resolves forward references and the verifier
    // rejects (or silently drops) incomplete debug metadata otherwise.
    if let Some((di_builder, _, _)) = &module_debug {
        di_builder.finalize();
    }
    llvm_mod
        .verify()
        .map_err(|e| CodegenError::LlvmVerify(e.to_string()))?;
    Ok(llvm_mod)
}

/// Define wasm-local generator teardown that must lower in the same LLVM module
/// as the coroutine frame it destroys.
///
/// Native calls the runtime's Rust `hew_gen_coro_destroy`, which in turn mirrors
/// switched-resume's `{ resume_fn, destroy_fn, ... }` frame prefix. On wasm32 the
/// correct function-table lowering is target-specific; reimplementing the
/// destroy-call half of that ABI in a separately compiled Rust runtime is the
/// trap-prone path that fenced generators. This definition keeps the C ABI name
/// (`hew_gen_coro_destroy`) but lowers the frame teardown through LLVM's own
/// `llvm.coro.destroy` intrinsic inside the final program module. CoroSplit/coro-
/// cleanup then produces the target-correct wasm table call while preserving the
/// native single-owner drop contract:
///
/// - `hew_gen_coro_destroy(companion)` destroys the frame, frees the heap env,
///   typed-drops an unconsumed pending `out_value`, and frees the companion.
fn emit_wasm_coro_runtime_overrides<'ctx>(
    ctx: &'ctx Context,
    llvm_mod: &LlvmModule<'ctx>,
    target_data: &TargetData,
) -> CodegenResult<()> {
    let ptr_ty = ctx.ptr_type(AddressSpace::default());
    let i8_ty = ctx.i8_type();
    let void_ty = ctx.void_type();

    let Some(destroy_fn) = llvm_mod.get_function("hew_gen_coro_destroy") else {
        return Ok(());
    };
    if destroy_fn.count_basic_blocks() > 0 {
        return Ok(());
    }

    let builder = ctx.create_builder();
    let entry = ctx.append_basic_block(destroy_fn, "entry");
    let do_destroy = ctx.append_basic_block(destroy_fn, "do_destroy");
    let pending_check = ctx.append_basic_block(destroy_fn, "pending_check");
    let thunk_call = ctx.append_basic_block(destroy_fn, "out_drop_call");
    let free_companion = ctx.append_basic_block(destroy_fn, "free_companion");
    let done = ctx.append_basic_block(destroy_fn, "done");

    builder.position_at_end(entry);
    let companion = destroy_fn
        .get_nth_param(0)
        .ok_or_else(|| {
            CodegenError::FailClosed("hew_gen_coro_destroy missing companion param".into())
        })?
        .into_pointer_value();
    let is_null = builder
        .build_is_null(companion, "gen_destroy_null")
        .llvm_ctx("wasm gen destroy null check")?;
    builder
        .build_conditional_branch(is_null, done, do_destroy)
        .llvm_ctx("wasm gen destroy null branch")?;

    builder.position_at_end(do_destroy);
    let handle = builder
        .build_load(ptr_ty, companion, "gen_destroy_handle")
        .llvm_ctx("wasm gen destroy handle load")?
        .into_pointer_value();
    let handle_is_null = builder
        .build_is_null(handle, "gen_destroy_handle_null")
        .llvm_ctx("wasm gen destroy handle null check")?;
    let destroy_frame = ctx.append_basic_block(destroy_fn, "destroy_frame");
    let after_frame = ctx.append_basic_block(destroy_fn, "after_frame");
    builder
        .build_conditional_branch(handle_is_null, after_frame, destroy_frame)
        .llvm_ctx("wasm gen destroy handle branch")?;

    builder.position_at_end(destroy_frame);
    let coro_destroy = Intrinsic::find("llvm.coro.destroy")
        .ok_or_else(|| CodegenError::FailClosed("llvm.coro.destroy intrinsic missing".into()))?
        .get_declaration(llvm_mod, &[])
        .ok_or_else(|| CodegenError::FailClosed("llvm.coro.destroy declaration failed".into()))?;
    builder
        .build_call(coro_destroy, &[handle.into()], "wasm_coro_destroy")
        .llvm_ctx("wasm llvm.coro.destroy call")?;
    builder
        .build_unconditional_branch(after_frame)
        .llvm_ctx("wasm gen destroy after frame branch")?;

    builder.position_at_end(after_frame);
    let ptr_width = u64::from(target_data.get_pointer_byte_size(None));
    let i64_ty = ctx.i64_type();
    let env_slot = unsafe {
        builder.build_in_bounds_gep(
            i8_ty,
            companion,
            &[i64_ty.const_int(ptr_width, false)],
            "gen_destroy_env_slot",
        )
    }
    .llvm_ctx("wasm gen destroy env slot gep")?;
    let env = builder
        .build_load(ptr_ty, env_slot, "gen_destroy_env")
        .llvm_ctx("wasm gen destroy env load")?
        .into_pointer_value();
    let frame_free = llvm_mod
        .get_function("hew_cont_frame_free")
        .unwrap_or_else(|| {
            llvm_mod.add_function(
                "hew_cont_frame_free",
                void_ty.fn_type(&[ptr_ty.into()], false),
                Some(Linkage::External),
            )
        });
    builder
        .build_call(frame_free, &[env.into()], "gen_destroy_env_free")
        .llvm_ctx("wasm gen destroy env free")?;
    builder
        .build_unconditional_branch(pending_check)
        .llvm_ctx("wasm gen destroy pending branch")?;

    builder.position_at_end(pending_check);
    let pending_offset = ptr_width
        .checked_mul(3)
        .and_then(|base| base.checked_add(1))
        .ok_or_else(|| {
            CodegenError::FailClosed("generator companion pending offset overflow".into())
        })?;
    let pending_slot = unsafe {
        builder.build_in_bounds_gep(
            i8_ty,
            companion,
            &[i64_ty.const_int(pending_offset, false)],
            "gen_destroy_pending_slot",
        )
    }
    .llvm_ctx("wasm gen destroy pending slot gep")?;
    let pending = builder
        .build_load(i8_ty, pending_slot, "gen_destroy_pending")
        .llvm_ctx("wasm gen destroy pending load")?
        .into_int_value();
    let pending_live = builder
        .build_int_compare(
            IntPredicate::NE,
            pending,
            i8_ty.const_zero(),
            "gen_destroy_pending_live",
        )
        .llvm_ctx("wasm gen destroy pending cmp")?;
    builder
        .build_conditional_branch(pending_live, thunk_call, free_companion)
        .llvm_ctx("wasm gen destroy pending conditional")?;

    builder.position_at_end(thunk_call);
    let thunk_slot = unsafe {
        builder.build_in_bounds_gep(
            i8_ty,
            companion,
            &[i64_ty.const_int(ptr_width * 2, false)],
            "gen_destroy_thunk_slot",
        )
    }
    .llvm_ctx("wasm gen destroy thunk slot gep")?;
    let thunk = builder
        .build_load(ptr_ty, thunk_slot, "gen_destroy_thunk")
        .llvm_ctx("wasm gen destroy thunk load")?
        .into_pointer_value();
    let thunk_is_null = builder
        .build_is_null(thunk, "gen_destroy_thunk_null")
        .llvm_ctx("wasm gen destroy thunk null check")?;
    let thunk_invoke = ctx.append_basic_block(destroy_fn, "out_drop_invoke");
    builder
        .build_conditional_branch(thunk_is_null, free_companion, thunk_invoke)
        .llvm_ctx("wasm gen destroy thunk branch")?;

    builder.position_at_end(thunk_invoke);
    let thunk_ty = void_ty.fn_type(&[ptr_ty.into()], false);
    builder
        .build_indirect_call(thunk_ty, thunk, &[companion.into()], "gen_destroy_out_drop")
        .llvm_ctx("wasm gen destroy out-drop thunk call")?;
    builder
        .build_unconditional_branch(free_companion)
        .llvm_ctx("wasm gen destroy thunk -> free")?;

    builder.position_at_end(free_companion);
    builder
        .build_call(
            frame_free,
            &[companion.into()],
            "gen_destroy_companion_free",
        )
        .llvm_ctx("wasm gen destroy companion free")?;
    builder
        .build_unconditional_branch(done)
        .llvm_ctx("wasm gen destroy done branch")?;

    builder.position_at_end(done);
    builder
        .build_return(None)
        .llvm_ctx("wasm gen destroy return")?;
    Ok(())
}

/// Synthesise one erased-self method thunk per `(vtable_id,
/// method_index)` pair in `registry`.
///
/// Each thunk's LLVM signature is `fn(ptr, <P1>, <P2>, ...) -> <R>`
/// where `<Pi>` and `<R>` come from
/// `DynVtableInstance::vtable_entries[method_index].signature` — that
/// signature is checker-substituted and receiver-skipped (the checker
/// recorded it for the originating coercion site and pinned the
/// receiver-skipped invariant at the MIR producer boundary), so
/// `params[0]` is the first *real* argument and not a `Self`.
///
/// The thunk body forwards every argument to the concrete impl method
/// named by `method_table[method_index].1` (looked up in `fn_symbols`)
/// and returns the impl's return value verbatim. Slot 0 — the erased
/// fat-pointer data word — is forwarded to the impl's typed `self`
/// slot directly: in LLVM's opaque-pointer world the value type is
/// the same and no bitcast is needed.
///
/// Fails closed when:
/// - `method_table` and `vtable_entries` have mismatched lengths or
///   inconsistent method names (the registry is the only producer and
///   pins these parallel),
/// - the impl method named by `impl_fn_key` was not declared in the
///   module (checker authority guarantees every vtable entry resolves
///   to a declared impl),
/// - the impl's LLVM parameter count differs from `1 +
///   signature.params.len()` (an `ActorHandler`-style impl with a
///   leading execution-context arg is not forwardable by a
///   single-receiver thunk; any later substrate that needs dyn
///   dispatch across an async/actor seam must lift this constraint),
/// - any boundary state (`Ty::Var`, `Ty::Error`, unmaterialized
///   literal, unresolved assoc projection) leaked into the signature.
///
/// The function only emits the thunks; the vtable static initialiser
/// that references them and the indirect-dispatch arm at
/// `CallTraitMethod` are independent substrate slices. `Linkage::Private`
/// keeps the symbols internal to the compilation unit with no ABI
/// promise; the trait/concrete/id-mangled names keep `nm`-style
/// observation legible for tests without crossing the dispatch
/// fail-closed gate.
fn emit_dyn_trait_thunks<'ctx>(
    ctx: &'ctx Context,
    llvm_mod: &LlvmModule<'ctx>,
    registry: &[hew_mir::DynVtableInstance],
    fn_symbols: &FnSymbolMap<'ctx>,
    record_layouts: &RecordLayoutMap<'ctx>,
) -> CodegenResult<()> {
    if registry.is_empty() {
        return Ok(());
    }
    let ptr_ty = ctx.ptr_type(AddressSpace::default());
    for inst in registry {
        if inst.method_table.len() != inst.vtable_entries.len() {
            return Err(CodegenError::FailClosed(format!(
                "dyn vtable `{}` has mismatched method_table/vtable_entries lengths \
                 ({} vs {}) — the registry construction is the only producer and \
                 MUST keep these parallel",
                inst.symbol,
                inst.method_table.len(),
                inst.vtable_entries.len()
            )));
        }
        for (method_index, entry) in inst.vtable_entries.iter().enumerate() {
            let (method_name, impl_fn_key) = &inst.method_table[method_index];
            if &entry.method_name != method_name {
                return Err(CodegenError::FailClosed(format!(
                    "dyn vtable `{}` method_table[{method_index}].0 = `{method_name}` \
                     diverges from vtable_entries[{method_index}].method_name = `{}` — \
                     the registry construction is the only producer",
                    inst.symbol, entry.method_name
                )));
            }
            let impl_fn = fn_symbols.get(impl_fn_key).ok_or_else(|| {
                CodegenError::FailClosed(format!(
                    "dyn trait thunk for vtable `{}` slot {method_index} \
                     (`{}::{method_name}`) references impl fn `{impl_fn_key}` \
                     that was not declared in the module; checker authority \
                     guarantees every vtable entry resolves to a declared impl",
                    inst.symbol, entry.trait_name
                ))
            })?;
            let (impl_fn_value, _impl_ret_ty, _impl_unit) =
                impl_fn.real(impl_fn_key, "dyn trait thunk emission")?;

            // Lower the receiver-skipped signature into LLVM types.
            let return_resolved =
                ResolvedTy::from_ty(&entry.signature.return_type).map_err(|e| {
                    CodegenError::FailClosed(format!(
                        "dyn trait thunk for vtable `{}` slot {method_index} \
                         (`{}::{method_name}`): return type leaked checker-internal \
                         state past the boundary: {e}",
                        inst.symbol, entry.trait_name
                    ))
                })?;
            let return_basic = resolve_ty(ctx, &return_resolved, record_layouts)?;

            // Thunk param 0 is the erased self pointer; subsequent
            // params are the receiver-skipped trait method args.
            let mut param_basics: Vec<BasicTypeEnum<'ctx>> =
                Vec::with_capacity(entry.signature.params.len() + 1);
            param_basics.push(ptr_ty.into());
            for (i, p) in entry.signature.params.iter().enumerate() {
                let resolved = ResolvedTy::from_ty(p).map_err(|e| {
                    CodegenError::FailClosed(format!(
                        "dyn trait thunk for vtable `{}` slot {method_index} \
                         (`{}::{method_name}`): param {i} leaked checker-internal \
                         state past the boundary: {e}",
                        inst.symbol, entry.trait_name
                    ))
                })?;
                param_basics.push(resolve_ty(ctx, &resolved, record_layouts)?);
            }

            // The impl method receives a typed `self` at LLVM slot 0;
            // the thunk's erased `ptr` at slot 0 is bit-identical
            // under opaque pointers, so the forward is a direct call
            // with no bitcast. Verifying the parameter count matches
            // (1 erased self + N receiver-skipped args) fails closed
            // on a call-conv shift (e.g. an impl that ever needs a
            // leading execution-context pointer) instead of producing
            // a miscompiled indirect call.
            let expected_params = param_basics.len();
            let impl_params = impl_fn_value.count_params() as usize;
            if impl_params != expected_params {
                return Err(CodegenError::FailClosed(format!(
                    "dyn trait thunk for vtable `{}` slot {method_index} \
                     (`{}::{method_name}`): impl fn `{impl_fn_key}` has \
                     {impl_params} LLVM parameter(s) but the thunk expects \
                     {expected_params} (1 erased self + {} receiver-skipped \
                     arg(s)); a call conv that prepends extra ABI words is not \
                     forwardable by a single-receiver thunk",
                    inst.symbol,
                    entry.trait_name,
                    entry.signature.params.len()
                )));
            }

            let param_meta: Vec<BasicMetadataTypeEnum<'ctx>> = param_basics
                .iter()
                .copied()
                .map(metadata_type_from_basic)
                .collect();
            let fn_ty = match return_basic {
                BasicTypeEnum::IntType(t) => t.fn_type(&param_meta, false),
                BasicTypeEnum::FloatType(t) => t.fn_type(&param_meta, false),
                BasicTypeEnum::PointerType(t) => t.fn_type(&param_meta, false),
                BasicTypeEnum::StructType(t) => t.fn_type(&param_meta, false),
                BasicTypeEnum::ArrayType(t) => t.fn_type(&param_meta, false),
                BasicTypeEnum::VectorType(t) => t.fn_type(&param_meta, false),
                BasicTypeEnum::ScalableVectorType(t) => t.fn_type(&param_meta, false),
            };

            let method_index_u32 = u32::try_from(method_index).unwrap_or_else(|_| {
                unreachable!(
                    "trait method index exceeded u32::MAX — DynVtableInstance \
                     construction would have rejected the program first"
                )
            });
            let thunk_symbol = hew_mir::mangle_dyn_thunk_symbol(
                inst.vtable_id,
                method_index_u32,
                &inst.trait_name,
                &inst.concrete_type,
            );

            // `Linkage::Private`. The thunk is referenced only by the
            // in-module vtable static (which is itself `Private`);
            // there is no cross-compilation-unit ABI promise.
            let thunk_fn = llvm_mod.add_function(&thunk_symbol, fn_ty, Some(Linkage::Private));
            let builder = ctx.create_builder();
            let entry_bb = ctx.append_basic_block(thunk_fn, "entry");
            builder.position_at_end(entry_bb);

            // The impl's concrete first-param type. Param 0 of the impl may be
            // a non-pointer (e.g. `i64`, `bool`, `i8` for struct/record) when
            // the concrete type is a Hew primitive or a struct passed by value.
            // The thunk's param 0 is always `ptr` (the fat-pointer data word,
            // which is the alloca address of the concrete value on the caller's
            // frame). When the impl's param 0 is also `ptr` (e.g. String),
            // forward directly. Otherwise load the concrete value through the
            // data pointer before forwarding. Under LLVM's opaque-pointer model
            // `ptr` ≡ `ptr` but `ptr` ≠ `i64`, so the load is required.
            let impl_first_param_is_ptr = {
                let impl_param_meta_tys = impl_fn_value.get_type().get_param_types();
                impl_param_meta_tys
                    .first()
                    .map(|t| matches!(t, BasicMetadataTypeEnum::PointerType(_)))
                    .unwrap_or(false)
            };

            let mut call_args: Vec<BasicMetadataValueEnum<'ctx>> =
                Vec::with_capacity(expected_params);
            for i in 0..expected_params {
                let idx = u32::try_from(i).unwrap_or_else(|_| {
                    unreachable!(
                        "thunk parameter index `{i}` exceeded u32::MAX — \
                         entry.signature.params length bounded by checker"
                    )
                });
                let p = thunk_fn.get_nth_param(idx).ok_or_else(|| {
                    CodegenError::FailClosed(format!(
                        "dyn trait thunk `{thunk_symbol}`: parameter {i} missing \
                         from synthesised LLVM function"
                    ))
                })?;
                // Receiver parameter (i == 0): the thunk always carries a
                // `ptr` data word. When the impl's param 0 is also a pointer
                // type, forward directly. When it is a value type (e.g. `i64`,
                // `bool`, struct), load the concrete value through the pointer.
                // CoerceToDynTrait stores the concrete value into the frame
                // slot and places the alloca address in the fat-pointer data
                // word, so `ptr %0 → load <ty>` always yields the original
                // value without copies.
                let arg = if i == 0 && !impl_first_param_is_ptr {
                    // Impl's receiver is a non-pointer value type. Load through
                    // the data pointer. The concrete LLVM type is the resolved
                    // form of `inst.concrete_type` — the same type the impl fn
                    // was compiled to accept at its first parameter position.
                    let concrete_ty = resolve_ty(ctx, &inst.concrete_type, record_layouts)?;
                    let data_ptr = p.into_pointer_value();
                    builder
                        .build_load(concrete_ty, data_ptr, "dyn_recv_load")
                        .llvm_ctx_with(|| {
                            format!(
                                "dyn trait thunk `{thunk_symbol}`: load concrete \
                                 receiver for `{impl_fn_key}`"
                            )
                        })?
                } else {
                    p
                };
                call_args.push(metadata_value_from_basic(arg));
            }

            let call_site = builder
                .build_call(impl_fn_value, &call_args, "dyn_thunk_call")
                .llvm_ctx_with(|| {
                    format!(
                        "dyn trait thunk `{thunk_symbol}`: forward call to \
                         `{impl_fn_key}`"
                    )
                })?;

            // Propagate the impl's return value verbatim. Unit-returning
            // impls lower as `i8` per `primitive_to_llvm`; void-returning
            // impls do not arise in the current spine but the path is
            // covered so future runtime-style impls do not fall through
            // a silent miscompile.
            match call_site.try_as_basic_value().basic() {
                Some(rv) => {
                    builder
                        .build_return(Some(&rv))
                        .llvm_ctx_with(|| format!("dyn trait thunk `{thunk_symbol}`: return"))?;
                }
                None => {
                    builder.build_return(None).llvm_ctx_with(|| {
                        format!("dyn trait thunk `{thunk_symbol}`: void return")
                    })?;
                }
            }
        }
    }
    Ok(())
}

/// Synthesise one `void (*)(ptr)` slot-0 `drop_in_place` function per
/// `vtable_id` in `registry`. The `ptr` argument is the fat pointer's
/// DATA word (the concrete value's storage). The function runs the
/// concrete value's STRUCTURAL drop ONLY — it does NOT free storage:
///
/// - `BitCopy` concrete (primitive, or an all-`BitCopy` record reached
///   through the synthesised no-op record helper) — empty body; nothing
///   owns heap, nothing to drop.
/// - `UserRecord { name }` — call `__hew_record_drop_inplace_<name>(ptr)`,
///   the per-type structural drop that releases the record's owned-heap
///   fields (String / Vec / nested heap-bearing records / …). The body is
///   synthesised by `emit_state_clone_drop_synthesis`; the dyn-concrete
///   seed pass (`collect_dyn_concrete_drop_seeds`) guarantees it exists.
/// - `Enum { name }` — call `__hew_enum_drop_inplace_<name>(ptr)`, the
///   tag-dispatching structural drop for the active variant's payload.
///
/// Storage release is deliberately NOT this function's job: the runtime
/// ABI (`hew-runtime/src/trait_object.rs::HewVtable::drop_in_place`) pins
/// slot 0 to "run the value's drop code WITHOUT freeing storage", leaving
/// the heap-box free to the caller. The drop SITE
/// (`lower_dyn_trait_vtable_drop`) calls `hew_dyn_box_free` after this fn
/// returns for `HeapBoxed` storage, and nothing for `FrameOwned` (a stack
/// alloca). Putting the free here would either over-free a `FrameOwned`
/// stack address or hard-wire a `HeapBoxed` assumption into a slot the ABI
/// says is storage-agnostic.
///
/// The function is emitted at `Linkage::Private`: internal to the
/// compilation unit, no ABI promise. The trait/concrete/id-mangled symbol
/// name produced by [`hew_mir::mangle_dyn_drop_in_place_symbol`] keeps
/// `nm`-style observation legible for tests without exposing the symbol to
/// the linker. The vtable static initialiser (emitted in this module)
/// installs it in slot 0; the runtime caller is the slot-0 dispatch in
/// `lower_dyn_trait_vtable_drop`.
///
/// One function per `vtable_id` (not per method): the vtable's concrete
/// type determines the drop ritual, not the trait or any individual
/// method. Test coverage:
/// `hew-codegen-rs/tests/dyn_trait_drop_in_place_emission.rs`.
///
/// Fails closed when:
/// - `inst.concrete_type` cannot be classified (boundary state like
///   `Ty::Var` / `Ty::Error` leaked past the checker, or a `RecordLayout`
///   / `EnumLayout` for a Named arm is missing — the classifier itself
///   emits the diagnostic),
/// - the classification is a BARE owned-heap concrete (`String` / `Bytes`
///   / `Vec` / `HashMap` / `HashSet` / `IoHandle` / closure-pair coerced
///   DIRECTLY to `dyn`, not wrapped in a record/enum) — the slot-0 path
///   dispatches structural drop only through the per-type record/enum
///   helpers, so a bare heap concrete needs its own runtime release wired
///   here; refusing rather than emitting a body that would leak it,
/// - the resolved record/enum structural-drop helper has no body after
///   synthesis (the dyn-concrete seed pass failed to register it — a
///   substrate-ordering bug, caught before emitting a call to an undefined
///   symbol).
fn emit_dyn_trait_drop_in_place_fns<'ctx>(
    ctx: &'ctx Context,
    llvm_mod: &LlvmModule<'ctx>,
    registry: &[hew_mir::DynVtableInstance],
    pipeline_records: &[RecordLayout],
    enum_layouts: &[EnumLayout],
) -> CodegenResult<()> {
    if registry.is_empty() {
        return Ok(());
    }
    let ptr_ty = ctx.ptr_type(AddressSpace::default());
    let void_ty = ctx.void_type();

    for inst in registry {
        let symbol = hew_mir::mangle_dyn_drop_in_place_symbol(
            inst.vtable_id,
            &inst.trait_name,
            &inst.concrete_type,
        );

        // Classify the concrete type ENUM-AWARE. `classify_state_field`
        // alone (no enum layouts) fails closed for every enum concrete
        // (D2 Mode B); threading `enum_layouts` lets an enum concrete
        // resolve to `Enum { name }` and ride the structural drop path.
        // The returned `name` is the registry key
        // `get_or_declare_{record,enum}_drop_inplace` mangle into the
        // helper symbol, so classification + dispatch can never drift.
        let mut visited: std::collections::HashSet<String> = std::collections::HashSet::new();
        let kind = hew_mir::classify_state_field_with_enum_layouts(
            &inst.concrete_type,
            pipeline_records,
            enum_layouts,
            &mut visited,
        )
        .map_err(|e| {
            CodegenError::FailClosed(format!(
                "dyn drop_in_place for vtable `{}`: concrete type `{:?}` is \
                 not classifiable: {e}",
                inst.symbol, inst.concrete_type
            ))
        })?;

        // Resolve the per-type structural-drop helper (if any) and verify
        // its body exists BEFORE creating the slot-0 fn, so a missing body
        // fails closed here rather than emitting a call to an undefined
        // symbol. `None` = `BitCopy` concrete (empty slot-0 body).
        let structural_helper: Option<FunctionValue<'ctx>> = match &kind {
            StateFieldCloneKind::BitCopy { .. } => None,
            StateFieldCloneKind::UserRecord { name } => {
                let helper = get_or_declare_record_drop_inplace(ctx, llvm_mod, name);
                if helper.count_basic_blocks() == 0 {
                    return Err(CodegenError::FailClosed(format!(
                        "dyn drop_in_place for vtable `{}` (concrete record \
                         `{name}`): resolved `__hew_record_drop_inplace_{name}` \
                         but it has no body after synthesis. The dyn-concrete \
                         drop seed (`collect_dyn_concrete_drop_seeds`) must \
                         register `{name}` before `emit_state_clone_drop_synthesis` \
                         runs (LESSONS: boundary-fail-closed).",
                        inst.symbol
                    )));
                }
                Some(helper)
            }
            StateFieldCloneKind::Enum { name } => {
                let helper = get_or_declare_enum_drop_inplace(ctx, llvm_mod, name);
                if helper.count_basic_blocks() == 0 {
                    return Err(CodegenError::FailClosed(format!(
                        "dyn drop_in_place for vtable `{}` (concrete enum \
                         `{name}`): resolved `__hew_enum_drop_inplace_{name}` \
                         but it has no body after synthesis. The dyn-concrete \
                         drop seed (`collect_dyn_concrete_drop_seeds`) must \
                         register `{name}` before `emit_state_clone_drop_synthesis` \
                         runs (LESSONS: boundary-fail-closed).",
                        inst.symbol
                    )));
                }
                Some(helper)
            }
            other => {
                return Err(CodegenError::FailClosed(format!(
                    "dyn drop_in_place for vtable `{}` (concrete `{:?}`): \
                     classification {other:?} is a bare owned-heap concrete \
                     (String / Bytes / Vec / HashMap / HashSet / IoHandle / \
                     closure-pair coerced directly to `dyn`). The vtable slot-0 \
                     drop path dispatches structural drop only through the \
                     per-type record/enum drop-in-place helpers; a bare heap \
                     concrete needs its own runtime release wired here — \
                     refusing to emit a body that would leak it (LESSONS: \
                     boundary-fail-closed).",
                    inst.symbol, inst.concrete_type
                )));
            }
        };

        let fn_ty = void_ty.fn_type(&[ptr_ty.into()], false);
        // `Private` linkage — internal-to-module, no ABI promise.
        // Same collision rationale as the vtable global and the thunks.
        let fn_val = llvm_mod.add_function(&symbol, fn_ty, Some(Linkage::Private));
        let entry_bb = ctx.append_basic_block(fn_val, "entry");
        let builder = ctx.create_builder();
        builder.position_at_end(entry_bb);

        let erased = fn_val.get_nth_param(0).ok_or_else(|| {
            CodegenError::FailClosed(format!(
                "dyn drop_in_place `{symbol}`: synthesised function missing \
                 the erased-self parameter"
            ))
        })?;
        let erased_ptr = erased.into_pointer_value();

        // Slot-0 body = structural drop ONLY (no `hew_dyn_box_free`). The
        // per-type helper (`fn(*mut)`) null-checks internally, so calling
        // it on the data word is safe for any non-dangling pointer.
        if let Some(helper) = structural_helper {
            builder
                .build_call(helper, &[erased_ptr.into()], "dyn_structural_drop")
                .llvm_ctx_with(|| {
                    format!("dyn drop_in_place `{symbol}`: structural drop-inplace call")
                })?;
        }
        builder
            .build_return(None)
            .llvm_ctx_with(|| format!("dyn drop_in_place `{symbol}`: void return"))?;
    }
    Ok(())
}

/// Promote each `%hew.dyn.vtable.N` opaque named struct +
/// `@__hew_vtable__{trait}__{concrete}__{vtable_id}` private-constant
/// declaration into a fully-defined constant whose body is
/// `{ ptr, <usize>, <usize>, ptr × method_count }` (a 3-slot prefix
/// triple followed by N method-thunk pointer slots) and whose
/// initializer is
/// `{ drop_in_place_fn_ptr, size_of<Concrete>, align_of<Concrete>,
///   thunk_0_fn_ptr, ..., thunk_(N-1)_fn_ptr }`.
///
/// **Layout (matches `hew-runtime/src/trait_object.rs::HewVtable` and
/// §1.5 of the design notes (vtable struct prefix entry)).**
/// - Slot 0: pointer to the `drop_in_place` fn named by
///   [`hew_mir::mangle_dyn_drop_in_place_symbol`] and synthesised by
///   `emit_dyn_trait_drop_in_place_fns` (must run first).
/// - Slot 1: `size_of::<ConcreteType>()` as a ptr-sized integer
///   (`<usize>`), sourced from the LLVM ABI layout of `inst.concrete_type`
///   via `abi_size_align` against the host target data.
/// - Slot 2: `align_of::<ConcreteType>()` as a ptr-sized integer
///   (`<usize>`), sourced the same way.
/// - Slots 3..(3+N): pointers to the method thunks named by
///   [`hew_mir::mangle_dyn_thunk_symbol`] and synthesised by
///   `emit_dyn_trait_thunks` (must run first), one per
///   `inst.vtable_entries[method_index]`, in declaration order.
///
/// **Why the size/align prefix.** The runtime ABI (`HewVtable` in
/// `hew-runtime/src/trait_object.rs:108-130`) commits to the prefix
/// triple so the future heap-boxed storage class can free the box
/// without re-deriving the concrete layout, and so any future
/// reflection / printer path can recover the value's footprint
/// from the vtable alone. The checker's slot convention
/// (`hew-types/src/check/types.rs`: `DynMethodCall::slot =
/// 3 + method_decl_order`) bakes the prefix in. Emitting only one
/// drop slot would mis-index every dispatch and have the runtime
/// drop path read a function pointer where it expects a `usize`.
///
/// **Drop-fn routing.** Slot 0 carries the per-vtable
/// `__hew_dyn_drop_in_place_*` function, which runs the concrete's
/// STRUCTURAL drop only — owned-heap field drops via
/// `__hew_{record,enum}_drop_inplace_*` — and frees NO storage. Storage
/// release is the drop SITE's job (`lower_dyn_trait_vtable_drop`), routed
/// by storage class: `TraitObjectStorage::FrameOwned` dispatches slot 0
/// and frees nothing (the data word is a frame alloca, so a
/// `hew_dyn_box_free` here would over-free a stack address);
/// `TraitObjectStorage::HeapBoxed` dispatches slot 0 and THEN calls
/// `hew_dyn_box_free` with the prefix slot 1/2 `(size, align)`. This split
/// is the runtime ABI contract (`hew-runtime/src/trait_object.rs:112-123`
/// — `drop_in_place` "must run drop code WITHOUT freeing the storage;
/// storage release is the caller's responsibility"; the HeapBoxed
/// return-position path at `:220-223`). The single drop fn-pointer slot
/// (no storage-class flag) keeps the ABI surface narrow.
///
/// **Idempotence with the forward declaration.**
/// `get_or_declare_dyn_vtable_global` produces the opaque struct
/// `%hew.dyn.vtable.N` and the `Private`-linkage global named
/// `__hew_vtable__{trait}__{concrete}__{vtable_id}` (see
/// [`hew_mir::mangle_dyn_vtable_symbol`]) at every
/// `Instr::CoerceToDynTrait` site. This pass looks up the SAME named
/// struct and the SAME global and finalises them in place via
/// `StructType::set_body` + `GlobalValue::set_initializer`. References
/// emitted at coercion sites remain bit-identical: only the body of the
/// struct and the body of the global are filled in.
///
/// **Linkage.** The vtable global, the
/// per-vtable `drop_in_place` fn, and the per-(vtable, method) thunks
/// are all emitted with `Linkage::Private`. The symbols are referenced
/// only from within the same compilation unit (vtable global → drop
/// fn + thunks; coercion sites → vtable global) and carry no ABI
/// promise. The trait/concrete/id-mangled names keep `nm`-style
/// observation legible.
///
/// **Fail-closed paths.** Returns an error when:
/// - the registry references a `drop_in_place` or `thunk` symbol that
///   the prior two emission passes did not synthesise (invariant
///   violation — `emit_dyn_trait_drop_in_place_fns` and
///   `emit_dyn_trait_thunks` are the only producers and run before
///   this pass on the same registry slice),
/// - the named struct backing `mangle_dyn_vtable_symbol(vtable_id)`
///   was already set to a non-opaque body (only this pass may finalise
///   the body),
/// - the global already has an initializer attached (only this pass
///   may attach the initializer).
fn emit_dyn_trait_vtable_definitions<'ctx>(
    ctx: &'ctx Context,
    llvm_mod: &LlvmModule<'ctx>,
    registry: &[hew_mir::DynVtableInstance],
    record_layouts: &RecordLayoutMap<'ctx>,
) -> CodegenResult<()> {
    if registry.is_empty() {
        return Ok(());
    }
    let ptr_ty = ctx.ptr_type(AddressSpace::default());
    // Ptr-sized integer for the `size_of` / `align_of` prefix slots.
    // Sourced from the host target data (the same `host_target_data`
    // that `emit_dyn_trait_drop_in_place_fns` uses) so a wasm32 build
    // would naturally produce `i32` slots and a native build produces
    // `i64`. The runtime ABI in `hew-runtime/src/trait_object.rs`
    // declares `size_of`/`align_of` as Rust `usize`, which lowers to
    // exactly this width on every Hew target.
    let host_td = host_target_data();
    let usize_ty = ctx.ptr_sized_int_type(&host_td, None);
    for inst in registry {
        // Ensure the forward declaration exists for vtables whose
        // coercion site, in some edge cases (registry pre-populated
        // by `build_dyn_vtable_registry` for a coercion site that
        // exists in the MIR but whose codegen arm short-circuits
        // before calling `get_or_declare_dyn_vtable_global`), might
        // not have been triggered. Calling the helper here is
        // idempotent — it returns the existing global when one is
        // present and creates the opaque declaration otherwise. This
        // keeps the definition pass self-contained against the
        // registry.
        let _vtable_ptr = get_or_declare_dyn_vtable_global(ctx, llvm_mod, inst);

        let drop_symbol = hew_mir::mangle_dyn_drop_in_place_symbol(
            inst.vtable_id,
            &inst.trait_name,
            &inst.concrete_type,
        );
        let drop_fn = llvm_mod.get_function(&drop_symbol).ok_or_else(|| {
            CodegenError::FailClosed(format!(
                "dyn vtable definition for `{}`: drop-in-place fn `{drop_symbol}` \
                 was not synthesised by `emit_dyn_trait_drop_in_place_fns`; the \
                 two emission passes share the same registry slice and the \
                 drop-in-place pass MUST run before vtable definition emission",
                inst.symbol
            ))
        })?;

        // Compute the concrete type's ABI size/align for the prefix
        // triple (slots 1/2). Sourcing both from the LLVM ABI layout of
        // the same `ResolvedTy` keeps the vtable prefix on the same
        // authority as the `hew_dyn_box_alloc` that produced a `HeapBoxed`
        // value and the drop-SITE `hew_dyn_box_free` that releases it
        // (`lower_dyn_trait_vtable_drop`'s HeapBoxed arm — NOT the slot-0
        // drop-in-place fn, which frees no storage). Drift between the
        // alloc and the free would surface as either an under-free (live
        // byte leak) or an over-free (dealloc with the wrong layout).
        let concrete_llvm = resolve_ty(ctx, &inst.concrete_type, record_layouts)?;
        let (concrete_size, concrete_align) = abi_size_align(concrete_llvm, Some(&host_td))?;

        let n_methods = inst.vtable_entries.len();
        // Layout: 3-slot prefix (drop, size, align) + N method thunks.
        let mut slot_tys: Vec<BasicTypeEnum<'ctx>> = Vec::with_capacity(3 + n_methods);
        let mut slot_vals: Vec<BasicValueEnum<'ctx>> = Vec::with_capacity(3 + n_methods);
        // Slot 0: drop_in_place fn pointer.
        slot_tys.push(ptr_ty.into());
        slot_vals.push(drop_fn.as_global_value().as_pointer_value().into());
        // Slot 1: size_of<ConcreteType> as usize.
        slot_tys.push(usize_ty.into());
        slot_vals.push(usize_ty.const_int(concrete_size, false).into());
        // Slot 2: align_of<ConcreteType> as usize.
        slot_tys.push(usize_ty.into());
        slot_vals.push(usize_ty.const_int(u64::from(concrete_align), false).into());

        for method_index in 0..n_methods {
            let method_index_u32 = u32::try_from(method_index).unwrap_or_else(|_| {
                unreachable!(
                    "dyn vtable method index exceeded u32::MAX — \
                     `DynVtableInstance` construction would have rejected the \
                     program first"
                )
            });
            let thunk_symbol = hew_mir::mangle_dyn_thunk_symbol(
                inst.vtable_id,
                method_index_u32,
                &inst.trait_name,
                &inst.concrete_type,
            );
            let thunk_fn = llvm_mod.get_function(&thunk_symbol).ok_or_else(|| {
                CodegenError::FailClosed(format!(
                    "dyn vtable definition for `{}`: method thunk `{thunk_symbol}` \
                     (slot {slot}, method `{}`) was not synthesised by \
                     `emit_dyn_trait_thunks`; the two emission passes share the \
                     same registry slice and the thunk pass MUST run before \
                     vtable definition",
                    inst.symbol,
                    inst.vtable_entries[method_index].method_name,
                    slot = 3 + method_index,
                ))
            })?;
            slot_tys.push(ptr_ty.into());
            slot_vals.push(thunk_fn.as_global_value().as_pointer_value().into());
        }

        // Look up the SAME opaque struct the forward declaration used.
        // `get_or_declare_dyn_vtable_global` interns this struct by name
        // so this lookup is guaranteed to return Some.
        let struct_name = format!("hew.dyn.vtable.{}", inst.vtable_id);
        let vtable_struct = ctx.get_struct_type(&struct_name).ok_or_else(|| {
            CodegenError::FailClosed(format!(
                "dyn vtable definition for `{}`: named struct `%{struct_name}` is \
                 not registered with the LLVM context; \
                 `get_or_declare_dyn_vtable_global` is the only declaration \
                 site and was called immediately above",
                inst.symbol
            ))
        })?;

        // Finalise the body exactly once. If the struct is already
        // non-opaque a prior pass mutated it under us — invariant
        // violation rather than user error.
        if vtable_struct.is_opaque() {
            vtable_struct.set_body(&slot_tys, false);
        } else {
            return Err(CodegenError::FailClosed(format!(
                "dyn vtable definition for `{}`: named struct `%{struct_name}` \
                 is no longer opaque — only `emit_dyn_trait_vtable_definitions` \
                 may set the body",
                inst.symbol
            )));
        }

        // Look up the SAME global the forward declaration created.
        let global = llvm_mod.get_global(&inst.symbol).ok_or_else(|| {
            CodegenError::FailClosed(format!(
                "dyn vtable definition: global `@{symbol}` is missing from the \
                 LLVM module; `get_or_declare_dyn_vtable_global` is the only \
                 declaration site and was called immediately above",
                symbol = inst.symbol
            ))
        })?;

        if global.get_initializer().is_some() {
            return Err(CodegenError::FailClosed(format!(
                "dyn vtable definition for `@{}`: global already has an \
                 initializer — only `emit_dyn_trait_vtable_definitions` \
                 may attach it",
                inst.symbol
            )));
        }

        let init = vtable_struct.const_named_struct(&slot_vals);
        global.set_initializer(&init);
    }
    Ok(())
}

// ===========================================================================
// Cross-node payload serialization thunks (gap #31)
// ===========================================================================
//
// For every actor-message type that can cross a process boundary, codegen emits
// a `__hew_cbor_serialize_<key>` / `__hew_cbor_deserialize_<key>` C-ABI thunk
// pair. The thunk WALKS the value's layout in IR (the single source of truth for
// field order and offsets) and calls the runtime codec primitives
// (`hew-runtime/src/cbor_serial.rs`) to build / read the wire bytes. The
// byte-format authority lives in the runtime; the layout-walk authority lives
// here. A module-init constructor registers each pair by its `msg_type`
// discriminant so the receive path can find the decoder.
//
// Accepted subset == the `Serializable` floor the checker already enforces:
// scalars, `string`, `bytes`, records (positional fields), enums (a tag + the
// active variant's positional fields). Any other shape fails closed at codegen.

/// Stable, symbol-safe key for a serializable message type, used as the
/// `__hew_cbor_serialize_<key>` / `__hew_cbor_deserialize_<key>` suffix. Reuses
/// the canonical structural `ResolvedTy` encoder so two distinct shapes never
/// collide on one thunk.
fn xnode_codec_key(ty: &ResolvedTy) -> String {
    hew_hir::mangle_resolved_ty(ty)
}

/// Declare a runtime codec primitive by name with the given LLVM signature.
fn declare_codec_prim<'ctx>(
    ctx: &'ctx Context,
    llvm_mod: &LlvmModule<'ctx>,
    name: &str,
    fn_ty: inkwell::types::FunctionType<'ctx>,
) -> FunctionValue<'ctx> {
    let _ = ctx;
    llvm_mod
        .get_function(name)
        .unwrap_or_else(|| llvm_mod.add_function(name, fn_ty, Some(Linkage::External)))
}

/// Resolve a `Named { name, args }` to the layout-map registration key:
/// the plain (short) name for a monomorphic type, the `mangle`d name for a
/// generic instantiation. Mirrors `user_record_layout_key` / `lookup_enum_layout`.
fn xnode_registry_key(
    name: &str,
    args: &[ResolvedTy],
    records: &[RecordLayout],
    enums: &[EnumLayout],
) -> String {
    let short = name.rsplit_once('.').map_or(name, |(_, s)| s);
    if args.is_empty() {
        // Prefer an exact registered name; else the short form.
        if records.iter().any(|r| r.name == name) || enums.iter().any(|e| e.name == name) {
            return name.to_string();
        }
        short.to_string()
    } else {
        // Shorten the spine for the full-outer-name candidate too: registration
        // keys on bare args, so a qualified payload must be normalised here or
        // the `full` probe never matches and only the short form would.
        let full = mangle_with_shortened_args(name, args);
        if records.iter().any(|r| r.name == full) || enums.iter().any(|e| e.name == full) {
            return full;
        }
        mangle_with_shortened_args(short, args)
    }
}

/// Emit inline drop calls for any heap-owning fields written by the decode walk
/// into `dst`.  Used on the decode-failure path (Fix 3b): the destination struct
/// was zero-initialised before the walk, so every field the walk did NOT reach is
/// still null/zero and the null-safe drop helpers (`hew_string_drop`,
/// `hew_bytes_drop`) short-circuit safely.
///
/// WHY here and not in a shared runtime helper: the field layout is statically
/// known from the type, so a static walk is cheaper than a runtime descriptor
/// lookup and avoids adding a new FFI surface for what is a narrow failure path.
/// WHEN-OBSOLETE: if Hew gains a general GC or type-descriptor RTTI, delegate
/// there instead.
/// WHAT: only String and Bytes carry inline heap pointers that the decode walk
/// allocates; scalars/unit/bool/int/float are value types — no drop needed.
/// Named records and enums delegate to the existing
/// `__hew_record_drop_inplace_*` / `__hew_enum_drop_inplace_*` helpers (which
/// are also null-field-safe because Hew drop helpers guard against null).
#[allow(clippy::too_many_arguments)]
fn emit_de_drop_owned<'ctx>(
    ctx: &'ctx Context,
    llvm_mod: &LlvmModule<'ctx>,
    builder: &inkwell::builder::Builder<'ctx>,
    ty: &ResolvedTy,
    dst: PointerValue<'ctx>,
    record_layouts: &RecordLayoutMap<'ctx>,
    _machine_layouts: &MachineLayoutMap<'ctx>,
    pipeline_records: &[RecordLayout],
    enum_layouts: &[EnumLayout],
) -> CodegenResult<()> {
    let ptr_ty = ctx.ptr_type(AddressSpace::default());
    match ty {
        // Scalars: no heap allocation in the decode walk — nothing to drop.
        ResolvedTy::Bool
        | ResolvedTy::I8
        | ResolvedTy::U8
        | ResolvedTy::I16
        | ResolvedTy::U16
        | ResolvedTy::I32
        | ResolvedTy::U32
        | ResolvedTy::Char
        | ResolvedTy::I64
        | ResolvedTy::U64
        | ResolvedTy::Isize
        | ResolvedTy::Usize
        | ResolvedTy::Duration
        | ResolvedTy::F32
        | ResolvedTy::F64
        | ResolvedTy::Unit
        | ResolvedTy::Never => Ok(()),

        // String: `hew_cbor_de_string` stores a malloc'd C string pointer.
        // `hew_string_drop(null)` is a no-op (guards with `cabi_guard!`), so
        // calling it unconditionally on a zero-inited (i.e. null) field is safe.
        ResolvedTy::String => {
            let drop_str = declare_codec_prim(
                ctx,
                llvm_mod,
                "hew_string_drop",
                ctx.void_type().fn_type(&[ptr_ty.into()], false),
            );
            // Load the *mut c_char pointer stored at `dst`.
            let s = builder
                .build_load(ptr_ty, dst, "de_drop_str_load")
                .llvm_ctx("de drop string load")?
                .into_pointer_value();
            builder
                .build_call(drop_str, &[s.into()], "de_drop_str")
                .llvm_ctx("de drop string call")?;
            Ok(())
        }

        // Bytes: stored as a `{ ptr, i32, i32 }` triple where the first word is
        // the data pointer (null when zero-inited or on decode failure before the
        // field is written).  `hew_bytes_drop(null)` returns immediately.
        ResolvedTy::Bytes => {
            let drop_bytes = declare_codec_prim(
                ctx,
                llvm_mod,
                "hew_bytes_drop",
                ctx.void_type().fn_type(&[ptr_ty.into()], false),
            );
            // GEP to the first field (data ptr) of the triple.
            let triple_ty = ctx.struct_type(
                &[ptr_ty.into(), ctx.i32_type().into(), ctx.i32_type().into()],
                false,
            );
            let data_ptr_slot = builder
                .build_struct_gep(triple_ty, dst, 0, "de_drop_bytes_slot")
                .llvm_ctx("de drop bytes gep")?;
            let data_ptr = builder
                .build_load(ptr_ty, data_ptr_slot, "de_drop_bytes_load")
                .llvm_ctx("de drop bytes load")?
                .into_pointer_value();
            builder
                .build_call(drop_bytes, &[data_ptr.into()], "de_drop_bytes")
                .llvm_ctx("de drop bytes call")?;
            Ok(())
        }

        // Named record: delegate to the codegen-emitted per-type in-place drop
        // helper (`__hew_record_drop_inplace_<name>`).  That helper walks the
        // struct's owned fields and drops them; null fields are safe.
        ResolvedTy::Named { name, args, .. } => {
            let key = xnode_registry_key(name, args, pipeline_records, enum_layouts);
            if let Some(_el) = enum_layouts.iter().find(|e| e.name == key) {
                // Enum: delegate to the per-enum in-place drop helper.
                let drop_fn = get_or_declare_enum_drop_inplace(ctx, llvm_mod, &key);
                builder
                    .build_call(drop_fn, &[dst.into()], "de_drop_enum")
                    .llvm_ctx("de drop enum call")?;
            } else if record_layouts.contains_key(&key) {
                // Record: delegate to the per-record in-place drop helper.
                let drop_fn = get_or_declare_record_drop_inplace(ctx, llvm_mod, &key);
                builder
                    .build_call(drop_fn, &[dst.into()], "de_drop_record")
                    .llvm_ctx("de drop record call")?;
            }
            // If neither layout is found (e.g. a type not yet registered), the
            // decode walk would have already failed with a codegen error before
            // reaching this path — no drop needed.
            Ok(())
        }

        // JUSTIFIED: unsupported compound/runtime-only types should have failed in
        // `emit_de_value_cbor` or at the Serializable boundary before cleanup emission.
        // If one reaches cleanup, fail closed instead of silently skipping fields
        // that may own heap allocations in a future lowering.
        other => Err(CodegenError::FailClosed(format!(
            "cross-node decode cleanup: unsupported value type {other:?} \
             (outside the Serializable cleanup floor)"
        ))),
    }
}

// ── CBOR wire-body codec ─────────────────────────────────────────────────────
//
// The wire `.encode()` / `.decode()` path lowers to a `__hew_cbor_serialize_*`
// / `__hew_cbor_deserialize_*` thunk pair whose bodies are emitted here. The
// ABI is identical to the bespoke serialize/deserialize thunks above, so the
// existing `lower_wire_codec_instr` call shape is reused verbatim; only the
// runtime primitives differ. A wire struct encodes as a CBOR map keyed by each
// field's `@N` wire tag (the compatibility authority); the decoder selects
// fields by the same key, tolerates absent/extra keys per forward-compat, and
// fails closed on any type mismatch or truncation. The map framing is the one
// structural difference from the flat positional walk above.

/// The CBOR map key for field `field_name` (declaration index `field_idx`) of
/// record `record_key`. A `#[wire]` struct keys by its `@N` tag (the
/// compatibility authority recorded in the wire layout table); a record with no
/// wire layout (e.g. a hand-built fixture) falls back to a 1-based positional
/// key. The encoder and decoder both call this with the same inputs, so the two
/// directions always agree regardless of which branch is taken.
fn cbor_field_key(
    wire_layouts: &WireLayoutTable,
    record_key: &str,
    field_name: &str,
    field_idx: usize,
) -> u64 {
    let probe = |name: &str| -> Option<u64> {
        wire_layouts
            .get(name)
            .and_then(|entry| entry.fields.iter().find(|f| f.name == field_name))
            .map(|f| u64::from(f.tag))
    };
    if let Some(tag) = probe(record_key) {
        return tag;
    }
    // Records are usually keyed by the short name; try it if the key was qualified.
    let short = record_key.rsplit_once('.').map_or(record_key, |(_, s)| s);
    if short != record_key {
        if let Some(tag) = probe(short) {
            return tag;
        }
    }
    field_idx as u64 + 1
}

/// Declare-or-fetch the CBOR serialize thunk:
/// `ptr __hew_cbor_serialize_<key>(ptr value, ptr out_len)`. Same ABI as the
/// bespoke serialize thunk so `lower_wire_codec_instr` calls it identically.
fn get_or_declare_cbor_serialize_thunk<'ctx>(
    ctx: &'ctx Context,
    llvm_mod: &LlvmModule<'ctx>,
    key: &str,
) -> FunctionValue<'ctx> {
    let sym = format!("__hew_cbor_serialize_{key}");
    if let Some(fv) = llvm_mod.get_function(&sym) {
        return fv;
    }
    let ptr_ty = ctx.ptr_type(AddressSpace::default());
    llvm_mod.add_function(
        &sym,
        ptr_ty.fn_type(&[ptr_ty.into(), ptr_ty.into()], false),
        Some(Linkage::Internal),
    )
}

/// Declare-or-fetch the CBOR deserialize thunk:
/// `ptr __hew_cbor_deserialize_<key>(ptr data, usize len, ptr out_struct_size)`.
/// Returns a `libc::malloc`'d reconstructed value (or null on decode failure),
/// matching the bespoke deserialize thunk ABI.
fn get_or_declare_cbor_deserialize_thunk<'ctx>(
    ctx: &'ctx Context,
    llvm_mod: &LlvmModule<'ctx>,
    key: &str,
) -> FunctionValue<'ctx> {
    let sym = format!("__hew_cbor_deserialize_{key}");
    if let Some(fv) = llvm_mod.get_function(&sym) {
        return fv;
    }
    let ptr_ty = ctx.ptr_type(AddressSpace::default());
    let size_ty = runtime_size_ty(ctx, llvm_mod);
    llvm_mod.add_function(
        &sym,
        ptr_ty.fn_type(&[ptr_ty.into(), size_ty.into(), ptr_ty.into()], false),
        Some(Linkage::Internal),
    )
}

/// Emit the per-field ENCODE walk for a value of type `ty` rooted at
/// `value_ptr`, emitting CBOR items onto the runtime `CborSerBuf` handle `buf`.
/// The caller has already emitted the map key for this value (if it sits inside
/// a struct map); this routine emits exactly one CBOR item. Recurses into nested
/// records as nested maps. Fails closed on any shape outside the supported
/// wire-body floor.
#[allow(clippy::too_many_arguments)]
fn emit_ser_value_cbor<'ctx>(
    ctx: &'ctx Context,
    llvm_mod: &LlvmModule<'ctx>,
    builder: &inkwell::builder::Builder<'ctx>,
    func: FunctionValue<'ctx>,
    ty: &ResolvedTy,
    value_ptr: PointerValue<'ctx>,
    buf: PointerValue<'ctx>,
    wire_layouts: &WireLayoutTable,
    record_layouts: &RecordLayoutMap<'ctx>,
    machine_layouts: &MachineLayoutMap<'ctx>,
    pipeline_records: &[RecordLayout],
    enum_layouts: &[EnumLayout],
) -> CodegenResult<()> {
    let ptr_ty = ctx.ptr_type(AddressSpace::default());
    let void_ty = ctx.void_type();
    let i64_ty = ctx.i64_type();
    match ty {
        ResolvedTy::Bool
        | ResolvedTy::I8
        | ResolvedTy::U8
        | ResolvedTy::I16
        | ResolvedTy::U16
        | ResolvedTy::I32
        | ResolvedTy::U32
        | ResolvedTy::Char
        | ResolvedTy::I64
        | ResolvedTy::U64
        | ResolvedTy::Isize
        | ResolvedTy::Usize
        | ResolvedTy::Duration => {
            let llvm_ty = resolve_ty(ctx, ty, record_layouts)?;
            let int_ty = llvm_ty.into_int_type();
            let raw = builder
                .build_load(int_ty, value_ptr, "cbor_ser_scalar")
                .llvm_ctx("cbor ser scalar load")?
                .into_int_value();
            if matches!(ty, ResolvedTy::Bool) {
                let i8_ty = ctx.i8_type();
                let as_i8 = if int_ty.get_bit_width() == 8 {
                    raw
                } else {
                    builder
                        .build_int_truncate(raw, i8_ty, "cbor_ser_bool_trunc")
                        .llvm_ctx("cbor ser bool trunc")?
                };
                let prim = declare_codec_prim(
                    ctx,
                    llvm_mod,
                    "hew_cbor_ser_bool",
                    void_ty.fn_type(&[ptr_ty.into(), i8_ty.into()], false),
                );
                builder
                    .build_call(prim, &[buf.into(), as_i8.into()], "cbor_ser_bool")
                    .llvm_ctx("cbor ser bool")?;
            } else {
                let unsigned = matches!(
                    ty,
                    ResolvedTy::U8
                        | ResolvedTy::U16
                        | ResolvedTy::U32
                        | ResolvedTy::U64
                        | ResolvedTy::Usize
                        | ResolvedTy::Char
                );
                let widened = if int_ty.get_bit_width() == 64 {
                    raw
                } else if unsigned {
                    builder
                        .build_int_z_extend(raw, i64_ty, "cbor_ser_zext")
                        .llvm_ctx("cbor ser zext")?
                } else {
                    builder
                        .build_int_s_extend(raw, i64_ty, "cbor_ser_sext")
                        .llvm_ctx("cbor ser sext")?
                };
                let prim_name = if unsigned {
                    "hew_cbor_ser_u64"
                } else {
                    "hew_cbor_ser_i64"
                };
                let prim = declare_codec_prim(
                    ctx,
                    llvm_mod,
                    prim_name,
                    void_ty.fn_type(&[ptr_ty.into(), i64_ty.into()], false),
                );
                builder
                    .build_call(prim, &[buf.into(), widened.into()], "cbor_ser_int")
                    .llvm_ctx("cbor ser int")?;
            }
            Ok(())
        }
        ResolvedTy::F32 | ResolvedTy::F64 => {
            let llvm_ty = resolve_ty(ctx, ty, record_layouts)?;
            let f = builder
                .build_load(llvm_ty, value_ptr, "cbor_ser_float")
                .llvm_ctx("cbor ser float load")?
                .into_float_value();
            let f64v = if matches!(ty, ResolvedTy::F64) {
                f
            } else {
                builder
                    .build_float_ext(f, ctx.f64_type(), "cbor_ser_fext")
                    .llvm_ctx("cbor ser fext")?
            };
            let prim = declare_codec_prim(
                ctx,
                llvm_mod,
                "hew_cbor_ser_f64",
                void_ty.fn_type(&[ptr_ty.into(), ctx.f64_type().into()], false),
            );
            builder
                .build_call(prim, &[buf.into(), f64v.into()], "cbor_ser_f64")
                .llvm_ctx("cbor ser f64")?;
            Ok(())
        }
        ResolvedTy::String => {
            let s = builder
                .build_load(ptr_ty, value_ptr, "cbor_ser_string_ptr")
                .llvm_ctx("cbor ser string load")?
                .into_pointer_value();
            let prim = declare_codec_prim(
                ctx,
                llvm_mod,
                "hew_cbor_ser_string",
                void_ty.fn_type(&[ptr_ty.into(), ptr_ty.into()], false),
            );
            builder
                .build_call(prim, &[buf.into(), s.into()], "cbor_ser_string")
                .llvm_ctx("cbor ser string")?;
            Ok(())
        }
        ResolvedTy::Bytes => {
            let i32_ty = ctx.i32_type();
            let triple_ty = ctx.struct_type(&[ptr_ty.into(), i32_ty.into(), i32_ty.into()], false);
            let data_ptr = builder
                .build_struct_gep(triple_ty, value_ptr, 0, "cbor_ser_bytes_ptr")
                .llvm_ctx("cbor ser bytes ptr gep")?;
            let data = builder
                .build_load(ptr_ty, data_ptr, "cbor_ser_bytes_data")
                .llvm_ctx("cbor ser bytes data load")?
                .into_pointer_value();
            let off_ptr = builder
                .build_struct_gep(triple_ty, value_ptr, 1, "cbor_ser_bytes_off")
                .llvm_ctx("cbor ser bytes off gep")?;
            let off = builder
                .build_load(i32_ty, off_ptr, "cbor_ser_bytes_offv")
                .llvm_ctx("cbor ser bytes off load")?
                .into_int_value();
            let len_ptr = builder
                .build_struct_gep(triple_ty, value_ptr, 2, "cbor_ser_bytes_len")
                .llvm_ctx("cbor ser bytes len gep")?;
            let len = builder
                .build_load(i32_ty, len_ptr, "cbor_ser_bytes_lenv")
                .llvm_ctx("cbor ser bytes len load")?
                .into_int_value();
            let prim = declare_codec_prim(
                ctx,
                llvm_mod,
                "hew_cbor_ser_bytes",
                void_ty.fn_type(
                    &[ptr_ty.into(), ptr_ty.into(), i32_ty.into(), i32_ty.into()],
                    false,
                ),
            );
            builder
                .build_call(
                    prim,
                    &[buf.into(), data.into(), off.into(), len.into()],
                    "cbor_ser_bytes",
                )
                .llvm_ctx("cbor ser bytes")?;
            Ok(())
        }
        ResolvedTy::Named {
            name,
            args,
            builtin,
            ..
        } => match builtin {
            Some(BuiltinType::Vec) => {
                let elem = args.first().ok_or_else(|| {
                    CodegenError::FailClosed("wire CBOR serialize: Vec<T> missing element".into())
                })?;
                emit_ser_vec_cbor(
                    ctx,
                    llvm_mod,
                    builder,
                    func,
                    elem,
                    value_ptr,
                    buf,
                    wire_layouts,
                    record_layouts,
                    machine_layouts,
                    pipeline_records,
                    enum_layouts,
                )
            }
            Some(BuiltinType::Option) => emit_ser_option_cbor(
                ctx,
                llvm_mod,
                builder,
                func,
                name,
                args,
                value_ptr,
                buf,
                wire_layouts,
                record_layouts,
                machine_layouts,
                pipeline_records,
                enum_layouts,
            ),
            _ => emit_ser_named_cbor(
                ctx,
                llvm_mod,
                builder,
                func,
                name,
                args,
                value_ptr,
                buf,
                wire_layouts,
                record_layouts,
                machine_layouts,
                pipeline_records,
                enum_layouts,
            ),
        },
        other => Err(CodegenError::FailClosed(format!(
            "wire CBOR serialize: unsupported value type {other:?} \
             (outside the supported wire-body floor)"
        ))),
    }
}

/// Emit the CBOR encode walk for a `Named` type. A registered record encodes as
/// a CBOR map keyed by each field's wire tag; a registered enum encodes under
/// the map-of-one shape (`emit_ser_enum_cbor`).
#[allow(clippy::too_many_arguments)]
fn emit_ser_named_cbor<'ctx>(
    ctx: &'ctx Context,
    llvm_mod: &LlvmModule<'ctx>,
    builder: &inkwell::builder::Builder<'ctx>,
    func: FunctionValue<'ctx>,
    name: &str,
    args: &[ResolvedTy],
    value_ptr: PointerValue<'ctx>,
    buf: PointerValue<'ctx>,
    wire_layouts: &WireLayoutTable,
    record_layouts: &RecordLayoutMap<'ctx>,
    machine_layouts: &MachineLayoutMap<'ctx>,
    pipeline_records: &[RecordLayout],
    enum_layouts: &[EnumLayout],
) -> CodegenResult<()> {
    let key = xnode_registry_key(name, args, pipeline_records, enum_layouts);
    // Enum: encode under the map-of-one shape.
    if let (Some(layout), Some(el)) = (
        machine_layouts.get(&key),
        enum_layouts.iter().find(|e| e.name == key),
    ) {
        return emit_ser_enum_cbor(
            ctx,
            llvm_mod,
            builder,
            func,
            &key,
            layout,
            el,
            value_ptr,
            buf,
            wire_layouts,
            record_layouts,
            machine_layouts,
            pipeline_records,
            enum_layouts,
        );
    }
    let ptr_ty = ctx.ptr_type(AddressSpace::default());
    let void_ty = ctx.void_type();
    let i64_ty = ctx.i64_type();
    if let (Some(struct_ty), Some(rl)) = (
        record_layouts.get(&key).copied(),
        pipeline_records.iter().find(|r| r.name == key),
    ) {
        let begin = declare_codec_prim(
            ctx,
            llvm_mod,
            "hew_cbor_ser_begin_map",
            void_ty.fn_type(&[ptr_ty.into()], false),
        );
        builder
            .build_call(begin, &[buf.into()], "cbor_ser_begin_map")
            .llvm_ctx("cbor ser begin_map")?;
        let key_prim = declare_codec_prim(
            ctx,
            llvm_mod,
            "hew_cbor_ser_key_u64",
            void_ty.fn_type(&[ptr_ty.into(), i64_ty.into()], false),
        );
        for (idx, fty) in rl.field_tys.iter().enumerate() {
            let field_name = rl.field_names.get(idx).map_or("", String::as_str);
            let tag = cbor_field_key(wire_layouts, &key, field_name, idx);
            let tag_const = i64_ty.const_int(tag, false);
            builder
                .build_call(
                    key_prim,
                    &[buf.into(), tag_const.into()],
                    &format!("cbor_ser_key_{idx}"),
                )
                .llvm_ctx("cbor ser key")?;
            let field_ptr = builder
                .build_struct_gep(
                    struct_ty,
                    value_ptr,
                    idx as u32,
                    &format!("cbor_ser_field_{idx}"),
                )
                .llvm_ctx("cbor ser field gep")?;
            emit_ser_value_cbor(
                ctx,
                llvm_mod,
                builder,
                func,
                fty,
                field_ptr,
                buf,
                wire_layouts,
                record_layouts,
                machine_layouts,
                pipeline_records,
                enum_layouts,
            )?;
        }
        let end = declare_codec_prim(
            ctx,
            llvm_mod,
            "hew_cbor_ser_end_map",
            void_ty.fn_type(&[ptr_ty.into()], false),
        );
        builder
            .build_call(end, &[buf.into()], "cbor_ser_end_map")
            .llvm_ctx("cbor ser end_map")?;
        return Ok(());
    }
    Err(CodegenError::FailClosed(format!(
        "wire CBOR serialize: named type `{name}` (key `{key}`) is not a \
         registered record layout"
    )))
}

/// Emit the CBOR DECODE walk for a value of type `ty`, reading from the runtime
/// `CborDeReader` handle `reader` and storing the reconstructed value into
/// `dst`. The caller has already selected this value's map key (if any). Fails
/// closed on any shape outside the supported wire-body floor.
#[allow(clippy::too_many_arguments)]
fn emit_de_value_cbor<'ctx>(
    ctx: &'ctx Context,
    llvm_mod: &LlvmModule<'ctx>,
    builder: &inkwell::builder::Builder<'ctx>,
    func: FunctionValue<'ctx>,
    ty: &ResolvedTy,
    dst: PointerValue<'ctx>,
    reader: PointerValue<'ctx>,
    wire_layouts: &WireLayoutTable,
    record_layouts: &RecordLayoutMap<'ctx>,
    machine_layouts: &MachineLayoutMap<'ctx>,
    pipeline_records: &[RecordLayout],
    enum_layouts: &[EnumLayout],
) -> CodegenResult<()> {
    let ptr_ty = ctx.ptr_type(AddressSpace::default());
    let i64_ty = ctx.i64_type();
    match ty {
        ResolvedTy::Bool
        | ResolvedTy::I8
        | ResolvedTy::U8
        | ResolvedTy::I16
        | ResolvedTy::U16
        | ResolvedTy::I32
        | ResolvedTy::U32
        | ResolvedTy::Char
        | ResolvedTy::I64
        | ResolvedTy::U64
        | ResolvedTy::Isize
        | ResolvedTy::Usize
        | ResolvedTy::Duration => {
            let llvm_ty = resolve_ty(ctx, ty, record_layouts)?;
            let int_ty = llvm_ty.into_int_type();
            if matches!(ty, ResolvedTy::Bool) {
                let i8_ty = ctx.i8_type();
                let prim = declare_codec_prim(
                    ctx,
                    llvm_mod,
                    "hew_cbor_de_bool",
                    i8_ty.fn_type(&[ptr_ty.into()], false),
                );
                let v = builder
                    .build_call(prim, &[reader.into()], "cbor_de_bool")
                    .llvm_ctx("cbor de bool")?
                    .try_as_basic_value()
                    .basic()
                    .ok_or_else(|| CodegenError::FailClosed("hew_cbor_de_bool void".into()))?
                    .into_int_value();
                let stored = if int_ty.get_bit_width() == 8 {
                    v
                } else {
                    builder
                        .build_int_z_extend(v, int_ty, "cbor_de_bool_zext")
                        .llvm_ctx("cbor de bool zext")?
                };
                builder
                    .build_store(dst, stored)
                    .llvm_ctx("cbor de bool store")?;
            } else if matches!(ty, ResolvedTy::Char) {
                // `char` reads through a dedicated primitive that validates the
                // decoded scalar is a Unicode scalar value (rejecting surrogates
                // and values above U+10FFFF) and fails closed otherwise. It
                // returns the codepoint widened to i64; truncate to the i32
                // `char` store (lossless — a scalar value is below 2^21).
                let prim = declare_codec_prim(
                    ctx,
                    llvm_mod,
                    "hew_cbor_de_char",
                    i64_ty.fn_type(&[ptr_ty.into()], false),
                );
                let wide = builder
                    .build_call(prim, &[reader.into()], "cbor_de_char")
                    .llvm_ctx("cbor de char")?
                    .try_as_basic_value()
                    .basic()
                    .ok_or_else(|| CodegenError::FailClosed("hew_cbor_de_char void".into()))?
                    .into_int_value();
                let narrow = builder
                    .build_int_truncate(wide, int_ty, "cbor_de_char_trunc")
                    .llvm_ctx("cbor de char trunc")?;
                builder
                    .build_store(dst, narrow)
                    .llvm_ctx("cbor de char store")?;
            } else {
                // Every fixed-width integer reads through the range-checked
                // primitive: a CBOR integer outside the target type's bounds
                // (over-max, under-min, or negative for an unsigned target) is
                // rejected as a decode failure instead of being truncated to a
                // fabricated value (CLAUDE.md §2). The reader returns the in-range
                // value's exact low-64 bit pattern, so the narrowing truncation
                // below is lossless.
                let unsigned = matches!(
                    ty,
                    ResolvedTy::U8
                        | ResolvedTy::U16
                        | ResolvedTy::U32
                        | ResolvedTy::U64
                        | ResolvedTy::Usize
                );
                let i32_ty = ctx.i32_type();
                let width = int_ty.get_bit_width();
                let prim = declare_codec_prim(
                    ctx,
                    llvm_mod,
                    "hew_cbor_de_int_checked",
                    i64_ty.fn_type(&[ptr_ty.into(), i32_ty.into(), i32_ty.into()], false),
                );
                let bits_arg = i32_ty.const_int(u64::from(width), false);
                let signed_arg = i32_ty.const_int(u64::from(!unsigned), false);
                let wide = builder
                    .build_call(
                        prim,
                        &[reader.into(), bits_arg.into(), signed_arg.into()],
                        "cbor_de_int",
                    )
                    .llvm_ctx("cbor de int")?
                    .try_as_basic_value()
                    .basic()
                    .ok_or_else(|| CodegenError::FailClosed("hew_cbor_de_int_checked void".into()))?
                    .into_int_value();
                let narrow = if width == 64 {
                    wide
                } else {
                    builder
                        .build_int_truncate(wide, int_ty, "cbor_de_int_trunc")
                        .llvm_ctx("cbor de int trunc")?
                };
                builder
                    .build_store(dst, narrow)
                    .llvm_ctx("cbor de int store")?;
            }
            Ok(())
        }
        ResolvedTy::F32 | ResolvedTy::F64 => {
            let prim = declare_codec_prim(
                ctx,
                llvm_mod,
                "hew_cbor_de_f64",
                ctx.f64_type().fn_type(&[ptr_ty.into()], false),
            );
            let f = builder
                .build_call(prim, &[reader.into()], "cbor_de_f64")
                .llvm_ctx("cbor de f64")?
                .try_as_basic_value()
                .basic()
                .ok_or_else(|| CodegenError::FailClosed("hew_cbor_de_f64 void".into()))?
                .into_float_value();
            let stored = if matches!(ty, ResolvedTy::F64) {
                f
            } else {
                builder
                    .build_float_trunc(f, ctx.f32_type(), "cbor_de_ftrunc")
                    .llvm_ctx("cbor de ftrunc")?
            };
            builder
                .build_store(dst, stored)
                .llvm_ctx("cbor de float store")?;
            Ok(())
        }
        ResolvedTy::String => {
            let prim = declare_codec_prim(
                ctx,
                llvm_mod,
                "hew_cbor_de_string",
                ptr_ty.fn_type(&[ptr_ty.into()], false),
            );
            let s = builder
                .build_call(prim, &[reader.into()], "cbor_de_string")
                .llvm_ctx("cbor de string")?
                .try_as_basic_value()
                .basic()
                .ok_or_else(|| CodegenError::FailClosed("hew_cbor_de_string void".into()))?
                .into_pointer_value();
            builder
                .build_store(dst, s)
                .llvm_ctx("cbor de string store")?;
            Ok(())
        }
        ResolvedTy::Bytes => {
            let i32_ty = ctx.i32_type();
            let len_slot = builder
                .build_alloca(i32_ty, "cbor_de_bytes_len")
                .llvm_ctx("cbor de bytes len alloca")?;
            let read_prim = declare_codec_prim(
                ctx,
                llvm_mod,
                "hew_cbor_de_bytes",
                ptr_ty.fn_type(&[ptr_ty.into(), ptr_ty.into()], false),
            );
            let raw = builder
                .build_call(
                    read_prim,
                    &[reader.into(), len_slot.into()],
                    "cbor_de_bytes",
                )
                .llvm_ctx("cbor de bytes")?
                .try_as_basic_value()
                .basic()
                .ok_or_else(|| CodegenError::FailClosed("hew_cbor_de_bytes void".into()))?
                .into_pointer_value();
            let len = builder
                .build_load(i32_ty, len_slot, "cbor_de_bytes_lenv")
                .llvm_ctx("cbor de bytes len load")?
                .into_int_value();
            let new_prim = declare_codec_prim(
                ctx,
                llvm_mod,
                "hew_bytes_from_static_raw",
                ctx.void_type()
                    .fn_type(&[ptr_ty.into(), i32_ty.into(), ptr_ty.into()], false),
            );
            builder
                .build_call(
                    new_prim,
                    &[raw.into(), len.into(), dst.into()],
                    "cbor_de_bytes_new_raw",
                )
                .llvm_ctx("cbor de bytes_from_static_raw")?;
            let free_prim = declare_codec_prim(
                ctx,
                llvm_mod,
                "hew_ser_free_bytes",
                ctx.void_type().fn_type(&[ptr_ty.into()], false),
            );
            builder
                .build_call(free_prim, &[raw.into()], "cbor_de_bytes_free_raw")
                .llvm_ctx("cbor de bytes free raw")?;
            Ok(())
        }
        ResolvedTy::Named {
            name,
            args,
            builtin,
            ..
        } => match builtin {
            Some(BuiltinType::Vec) => {
                let elem = args.first().ok_or_else(|| {
                    CodegenError::FailClosed("wire CBOR deserialize: Vec<T> missing element".into())
                })?;
                emit_de_vec_cbor(
                    ctx,
                    llvm_mod,
                    builder,
                    func,
                    elem,
                    dst,
                    reader,
                    wire_layouts,
                    record_layouts,
                    machine_layouts,
                    pipeline_records,
                    enum_layouts,
                )
            }
            Some(BuiltinType::Option) => emit_de_option_cbor(
                ctx,
                llvm_mod,
                builder,
                func,
                name,
                args,
                dst,
                reader,
                wire_layouts,
                record_layouts,
                machine_layouts,
                pipeline_records,
                enum_layouts,
            ),
            _ => emit_de_named_cbor(
                ctx,
                llvm_mod,
                builder,
                func,
                name,
                args,
                dst,
                reader,
                wire_layouts,
                record_layouts,
                machine_layouts,
                pipeline_records,
                enum_layouts,
            ),
        },
        other => Err(CodegenError::FailClosed(format!(
            "wire CBOR deserialize: unsupported value type {other:?} \
             (outside the supported wire-body floor)"
        ))),
    }
}

/// Emit the CBOR decode walk for a `Named` type into `dst`. A registered record
/// enters a CBOR map, selects each field by its wire tag, decodes it, then exits
/// the map (tolerating extra keys); a registered enum decodes the
/// map-of-one shape (`emit_de_enum_cbor`).
#[allow(clippy::too_many_arguments)]
fn emit_de_named_cbor<'ctx>(
    ctx: &'ctx Context,
    llvm_mod: &LlvmModule<'ctx>,
    builder: &inkwell::builder::Builder<'ctx>,
    func: FunctionValue<'ctx>,
    name: &str,
    args: &[ResolvedTy],
    dst: PointerValue<'ctx>,
    reader: PointerValue<'ctx>,
    wire_layouts: &WireLayoutTable,
    record_layouts: &RecordLayoutMap<'ctx>,
    machine_layouts: &MachineLayoutMap<'ctx>,
    pipeline_records: &[RecordLayout],
    enum_layouts: &[EnumLayout],
) -> CodegenResult<()> {
    let key = xnode_registry_key(name, args, pipeline_records, enum_layouts);
    // Enum: decode the map-of-one shape.
    if let (Some(layout), Some(el)) = (
        machine_layouts.get(&key),
        enum_layouts.iter().find(|e| e.name == key),
    ) {
        return emit_de_enum_cbor(
            ctx,
            llvm_mod,
            builder,
            func,
            &key,
            layout,
            el,
            dst,
            reader,
            wire_layouts,
            record_layouts,
            machine_layouts,
            pipeline_records,
            enum_layouts,
        );
    }
    let ptr_ty = ctx.ptr_type(AddressSpace::default());
    let void_ty = ctx.void_type();
    let i64_ty = ctx.i64_type();
    if let (Some(struct_ty), Some(rl)) = (
        record_layouts.get(&key).copied(),
        pipeline_records.iter().find(|r| r.name == key),
    ) {
        let enter = declare_codec_prim(
            ctx,
            llvm_mod,
            "hew_cbor_de_enter_map",
            void_ty.fn_type(&[ptr_ty.into()], false),
        );
        builder
            .build_call(enter, &[reader.into()], "cbor_de_enter_map")
            .llvm_ctx("cbor de enter_map")?;
        let select = declare_codec_prim(
            ctx,
            llvm_mod,
            "hew_cbor_de_select_key",
            void_ty.fn_type(&[ptr_ty.into(), i64_ty.into()], false),
        );
        for (idx, fty) in rl.field_tys.iter().enumerate() {
            let field_name = rl.field_names.get(idx).map_or("", String::as_str);
            let tag = cbor_field_key(wire_layouts, &key, field_name, idx);
            let tag_const = i64_ty.const_int(tag, false);
            builder
                .build_call(
                    select,
                    &[reader.into(), tag_const.into()],
                    &format!("cbor_de_select_{idx}"),
                )
                .llvm_ctx("cbor de select_key")?;
            let field_ptr = builder
                .build_struct_gep(struct_ty, dst, idx as u32, &format!("cbor_de_field_{idx}"))
                .llvm_ctx("cbor de field gep")?;
            emit_de_value_cbor(
                ctx,
                llvm_mod,
                builder,
                func,
                fty,
                field_ptr,
                reader,
                wire_layouts,
                record_layouts,
                machine_layouts,
                pipeline_records,
                enum_layouts,
            )?;
        }
        let exit = declare_codec_prim(
            ctx,
            llvm_mod,
            "hew_cbor_de_exit_map",
            void_ty.fn_type(&[ptr_ty.into()], false),
        );
        builder
            .build_call(exit, &[reader.into()], "cbor_de_exit_map")
            .llvm_ctx("cbor de exit_map")?;
        return Ok(());
    }
    Err(CodegenError::FailClosed(format!(
        "wire CBOR deserialize: named type `{name}` (key `{key}`) is not a \
         registered record layout"
    )))
}

/// Wire tag for an enum variant: the schema-stable tag from the enum's wire
/// layout (matched by variant name), falling back to the positional index when
/// no explicit layout entry exists. Mirrors `cbor_field_key` for record fields:
/// the wire tag — not the in-memory discriminant — is the cross-version
/// compatibility authority, so the map key / unit integer is driven from it.
fn cbor_variant_tag(
    wire_layouts: &WireLayoutTable,
    enum_key: &str,
    variant_name: &str,
    variant_idx: usize,
) -> u64 {
    let probe = |name: &str| -> Option<u64> {
        wire_layouts
            .get(name)
            .and_then(|entry| entry.variants.iter().find(|(n, _)| n == variant_name))
            .map(|(_, tag)| u64::from(*tag))
    };
    if let Some(tag) = probe(enum_key) {
        return tag;
    }
    let short = enum_key.rsplit_once('.').map_or(enum_key, |(_, s)| s);
    if short != enum_key {
        if let Some(tag) = probe(short) {
            return tag;
        }
    }
    variant_idx as u64
}

/// Resolve a wire struct field's JSON/YAML key name. An explicit `json_name` /
/// `yaml_name` override wins; otherwise the source field name is folded through
/// the type-level `json_case` / `yaml_case` policy (if any); otherwise the source
/// name is used verbatim. The DECODE side reads the same descriptor, so the key
/// the encoder writes is exactly the key the decoder looks for.
fn wire_text_field_name(
    field: &hew_types::WireFieldLayout,
    case: Option<hew_parser::ast::NamingCase>,
    format: WireTextFormat,
) -> String {
    let explicit = match format {
        WireTextFormat::Json => field.json_name.as_deref(),
        WireTextFormat::Yaml => field.yaml_name.as_deref(),
    };
    if let Some(name) = explicit {
        return name.to_string();
    }
    match case {
        Some(c) => apply_naming_case(&field.name, c),
        None => field.name.clone(),
    }
}

/// Apply a [`hew_parser::ast::NamingCase`] to a snake_case-or-mixed source
/// identifier, producing the cased key string. Words are split on `_` and on
/// lower→upper boundaries so both `user_id` and `userId` normalise consistently.
fn apply_naming_case(name: &str, case: hew_parser::ast::NamingCase) -> String {
    use hew_parser::ast::NamingCase;
    let words = split_identifier_words(name);
    if words.is_empty() {
        return name.to_string();
    }
    match case {
        NamingCase::SnakeCase => words.join("_"),
        NamingCase::ScreamingSnake => words
            .iter()
            .map(|w| w.to_uppercase())
            .collect::<Vec<_>>()
            .join("_"),
        NamingCase::KebabCase => words.join("-"),
        NamingCase::CamelCase => {
            let mut out = String::new();
            for (i, w) in words.iter().enumerate() {
                if i == 0 {
                    out.push_str(w);
                } else {
                    out.push_str(&capitalize(w));
                }
            }
            out
        }
        NamingCase::PascalCase => words.iter().map(|w| capitalize(w)).collect(),
    }
}

/// Split a source identifier into lowercase words on `_`/`-` separators and on
/// lower→upper case boundaries.
fn split_identifier_words(name: &str) -> Vec<String> {
    let mut words = Vec::new();
    let mut current = String::new();
    let mut prev_lower = false;
    for ch in name.chars() {
        if ch == '_' || ch == '-' {
            if !current.is_empty() {
                words.push(std::mem::take(&mut current));
            }
            prev_lower = false;
            continue;
        }
        if ch.is_uppercase() && prev_lower && !current.is_empty() {
            words.push(std::mem::take(&mut current));
        }
        for lc in ch.to_lowercase() {
            current.push(lc);
        }
        prev_lower = ch.is_lowercase() || ch.is_ascii_digit();
    }
    if !current.is_empty() {
        words.push(current);
    }
    words
}

/// Capitalize the first character of a lowercase word.
fn capitalize(word: &str) -> String {
    let mut chars = word.chars();
    match chars.next() {
        Some(first) => first.to_uppercase().collect::<String>() + chars.as_str(),
        None => String::new(),
    }
}

/// Build the per-type text-codec DESCRIPTOR: a compact JSON schema string that
/// maps each wire tag (`@N`) to its JSON/YAML key name, recursively for nested
/// wire structs/enums, vectors, and options. The runtime `wire_text` bridge
/// parses this to drive the CBOR↔text transcode. The schema mirrors EXACTLY the
/// shapes the binary CBOR codec walk produces (struct = tag-keyed map, enum =
/// integer tag / map-of-one), so the two stay in lockstep.
///
/// `format` selects the JSON or YAML key naming (the override + case policy may
/// differ between the two). A type outside the supported wire-body floor emits an
/// `{"k":"opaque"}` node, which the bridge fails closed on — never a fabricated
/// transcode.
fn build_text_descriptor(
    ty: &ResolvedTy,
    format: WireTextFormat,
    wire_layouts: &WireLayoutTable,
    pipeline_records: &[RecordLayout],
    enum_layouts: &[EnumLayout],
) -> String {
    let mut visiting: std::collections::HashSet<String> = std::collections::HashSet::new();
    build_text_descriptor_node(
        ty,
        format,
        wire_layouts,
        pipeline_records,
        enum_layouts,
        &mut visiting,
    )
}

/// Recursive descriptor-node builder. `visiting` breaks layout cycles (a
/// recursive record/enum) by emitting `opaque` on a back-edge — the wire-body
/// floor does not include recursive text types, so this fails closed rather than
/// looping forever.
fn build_text_descriptor_node(
    ty: &ResolvedTy,
    format: WireTextFormat,
    wire_layouts: &WireLayoutTable,
    pipeline_records: &[RecordLayout],
    enum_layouts: &[EnumLayout],
    visiting: &mut std::collections::HashSet<String>,
) -> String {
    match ty {
        ResolvedTy::I8
        | ResolvedTy::I16
        | ResolvedTy::I32
        | ResolvedTy::I64
        | ResolvedTy::Isize
        | ResolvedTy::Duration => r#"{"k":"i64"}"#.to_string(),
        ResolvedTy::U8
        | ResolvedTy::U16
        | ResolvedTy::U32
        | ResolvedTy::U64
        | ResolvedTy::Usize
        | ResolvedTy::Char => r#"{"k":"u64"}"#.to_string(),
        ResolvedTy::F32 | ResolvedTy::F64 => r#"{"k":"f64"}"#.to_string(),
        ResolvedTy::Bool => r#"{"k":"bool"}"#.to_string(),
        ResolvedTy::String => r#"{"k":"str"}"#.to_string(),
        ResolvedTy::Bytes => r#"{"k":"bytes"}"#.to_string(),
        ResolvedTy::Named {
            name,
            args,
            builtin,
            ..
        } => match builtin {
            Some(BuiltinType::Vec) => {
                let elem = args.first().map_or_else(
                    || r#"{"k":"opaque"}"#.to_string(),
                    |e| {
                        build_text_descriptor_node(
                            e,
                            format,
                            wire_layouts,
                            pipeline_records,
                            enum_layouts,
                            visiting,
                        )
                    },
                );
                format!(r#"{{"k":"vec","e":{elem}}}"#)
            }
            Some(BuiltinType::Option) => {
                let elem = args.first().map_or_else(
                    || r#"{"k":"opaque"}"#.to_string(),
                    |e| {
                        build_text_descriptor_node(
                            e,
                            format,
                            wire_layouts,
                            pipeline_records,
                            enum_layouts,
                            visiting,
                        )
                    },
                );
                format!(r#"{{"k":"opt","e":{elem}}}"#)
            }
            _ => build_text_descriptor_named(
                name,
                args,
                format,
                wire_layouts,
                pipeline_records,
                enum_layouts,
                visiting,
            ),
        },
        _ => r#"{"k":"opaque"}"#.to_string(),
    }
}

/// Build the descriptor for a `Named` record or enum: a struct node (tag-keyed
/// field list) or an enum node (variant list), mirroring the CBOR codec's
/// record/enum resolution (`xnode_registry_key` + `cbor_field_key` /
/// `cbor_variant_tag`).
fn build_text_descriptor_named(
    name: &str,
    args: &[ResolvedTy],
    format: WireTextFormat,
    wire_layouts: &WireLayoutTable,
    pipeline_records: &[RecordLayout],
    enum_layouts: &[EnumLayout],
    visiting: &mut std::collections::HashSet<String>,
) -> String {
    let key = xnode_registry_key(name, args, pipeline_records, enum_layouts);
    if !visiting.insert(key.clone()) {
        // Recursive back-edge: a recursive text type is outside the floor.
        return r#"{"k":"opaque"}"#.to_string();
    }
    let case = wire_layouts.get(&key).and_then(|e| match format {
        WireTextFormat::Json => e.json_case,
        WireTextFormat::Yaml => e.yaml_case,
    });
    let result = if let Some(el) = enum_layouts.iter().find(|e| e.name == key) {
        // Enum: list each variant's tag, source name, and payload descriptors.
        let variants: Vec<String> = el
            .variants
            .iter()
            .enumerate()
            .map(|(idx, variant)| {
                let tag = cbor_variant_tag(wire_layouts, &key, &variant.name, idx);
                let payload: Vec<String> = variant
                    .field_tys
                    .iter()
                    .map(|fty| {
                        build_text_descriptor_node(
                            fty,
                            format,
                            wire_layouts,
                            pipeline_records,
                            enum_layouts,
                            visiting,
                        )
                    })
                    .collect();
                format!(
                    r#"{{"t":{tag},"n":{name},"p":[{payload}]}}"#,
                    name = json_string_literal(&variant.name),
                    payload = payload.join(",")
                )
            })
            .collect();
        format!(r#"{{"k":"enum","v":[{}]}}"#, variants.join(","))
    } else if let Some(rl) = pipeline_records.iter().find(|r| r.name == key) {
        // Struct: list each field's tag, JSON/YAML key name, and field descriptor.
        let fields: Vec<String> = rl
            .field_tys
            .iter()
            .enumerate()
            .map(|(idx, fty)| {
                let field_name = rl.field_names.get(idx).map_or("", String::as_str);
                let tag = cbor_field_key(wire_layouts, &key, field_name, idx);
                // Resolve the text key name from the wire layout (override + case).
                let text_name = wire_layouts
                    .get(&key)
                    .and_then(|e| e.fields.iter().find(|f| f.name == field_name))
                    .map_or_else(
                        || field_name.to_string(),
                        |f| wire_text_field_name(f, case, format),
                    );
                let desc = build_text_descriptor_node(
                    fty,
                    format,
                    wire_layouts,
                    pipeline_records,
                    enum_layouts,
                    visiting,
                );
                format!(
                    r#"{{"t":{tag},"n":{name},"d":{desc}}}"#,
                    name = json_string_literal(&text_name)
                )
            })
            .collect();
        format!(r#"{{"k":"struct","f":[{}]}}"#, fields.join(","))
    } else {
        // Not a registered record or enum: outside the text floor.
        r#"{"k":"opaque"}"#.to_string()
    };
    visiting.remove(&key);
    result
}

/// Serialize a string as a JSON string literal (quoted, with the JSON escapes the
/// descriptor parser expects). Used for field/variant key names embedded in the
/// descriptor schema.
fn json_string_literal(s: &str) -> String {
    let mut out = String::with_capacity(s.len() + 2);
    out.push('"');
    for ch in s.chars() {
        match ch {
            '"' => out.push_str("\\\""),
            '\\' => out.push_str("\\\\"),
            '\n' => out.push_str("\\n"),
            '\r' => out.push_str("\\r"),
            '\t' => out.push_str("\\t"),
            c if (c as u32) < 0x20 => out.push_str(&format!("\\u{:04x}", c as u32)),
            c => out.push(c),
        }
    }
    out.push('"');
    out
}

/// Standalone heap-ownership probe for a CBOR Vec element type, using only the
/// pipeline record/enum layouts the thunk emitter has on hand (no `FnCtx`).
/// Returns true when `ty` is — or transitively contains — a heap-owning leaf
/// (string / bytes / collection / boxed handle): a value a plain BitCopy Vec
/// slot could not own without leaking. A `visiting` set breaks layout cycles
/// (recursive records/enums) by treating a back-edge as non-owning — the
/// cycle's owning leaves, if any, are already seen on the first visit.
fn cbor_ty_owns_heap(
    ty: &ResolvedTy,
    pipeline_records: &[RecordLayout],
    enum_layouts: &[EnumLayout],
    visiting: &mut std::collections::HashSet<String>,
) -> bool {
    match ty {
        ResolvedTy::String | ResolvedTy::Bytes => true,
        ResolvedTy::Named {
            builtin: Some(b),
            args,
            ..
        } => match b {
            // An `Option` is inline (tag + payload); it owns heap iff its
            // payload does.
            BuiltinType::Option => args
                .first()
                .is_some_and(|a| cbor_ty_owns_heap(a, pipeline_records, enum_layouts, visiting)),
            // Every other builtin admitted as a field is a heap handle.
            _ => true,
        },
        ResolvedTy::Named { name, args, .. } => {
            let key = xnode_registry_key(name, args, pipeline_records, enum_layouts);
            if !visiting.insert(key.clone()) {
                return false;
            }
            if let Some(rl) = pipeline_records.iter().find(|r| r.name == key) {
                return rl
                    .field_tys
                    .iter()
                    .any(|f| cbor_ty_owns_heap(f, pipeline_records, enum_layouts, visiting));
            }
            if let Some(el) = enum_layouts.iter().find(|e| e.name == key) {
                return el.variants.iter().any(|v| {
                    v.field_tys
                        .iter()
                        .any(|f| cbor_ty_owns_heap(f, pipeline_records, enum_layouts, visiting))
                });
            }
            false
        }
        _ => false,
    }
}

/// Backing-store kind a decoded CBOR array needs for its element type.
#[derive(Clone, Copy, PartialEq, Eq)]
enum CborVecElemKind {
    /// BitCopy element (scalar / heap-free record / heap-free enum): a plain
    /// `hew_vec_new_with_elem_size` buffer filled by byte-copy
    /// `hew_vec_push_generic`. `hew_vec_free` frees the buffer; no per-element
    /// heap to release.
    Plain,
    /// `string` element: a `hew_vec_new_str` vec filled by copy-in
    /// `hew_vec_push_str`. `hew_vec_free` releases every element string.
    Str,
    /// Owned-compound element (bytes / heap-owning record / nested collection):
    /// the standalone emitter cannot synthesise the owned clone/drop descriptor
    /// the backing vec would need, so the codec fails closed (a failable
    /// sub-shape, not a silent partial).
    Defer,
}

/// Classify a CBOR Vec element type into the backing-store kind its decode
/// needs. Encode is uniform across `Plain`/`Str` (both read through
/// `hew_vec_get_generic`); only decode branches on the kind.
fn cbor_vec_elem_kind(
    elem: &ResolvedTy,
    pipeline_records: &[RecordLayout],
    enum_layouts: &[EnumLayout],
) -> CborVecElemKind {
    match elem {
        ResolvedTy::Bool
        | ResolvedTy::I8
        | ResolvedTy::U8
        | ResolvedTy::I16
        | ResolvedTy::U16
        | ResolvedTy::I32
        | ResolvedTy::U32
        | ResolvedTy::I64
        | ResolvedTy::U64
        | ResolvedTy::Isize
        | ResolvedTy::Usize
        | ResolvedTy::Char
        | ResolvedTy::Duration
        | ResolvedTy::F32
        | ResolvedTy::F64 => CborVecElemKind::Plain,
        ResolvedTy::String => CborVecElemKind::Str,
        ResolvedTy::Named { .. } => {
            let mut visiting = std::collections::HashSet::new();
            if cbor_ty_owns_heap(elem, pipeline_records, enum_layouts, &mut visiting) {
                CborVecElemKind::Defer
            } else {
                CborVecElemKind::Plain
            }
        }
        _ => CborVecElemKind::Defer,
    }
}

/// Encode a `Vec<T>` field as a CBOR array. Encode is uniform across element
/// kinds: `hew_vec_get_generic` returns the element slot for both BitCopy and
/// `string` vecs (neither is layout-aware), and `emit_ser_value_cbor` loads it
/// (the `String` arm dereferences the slot). Owned-compound elements fail
/// closed, symmetric with `emit_de_vec_cbor` (which cannot reconstruct them).
#[allow(clippy::too_many_arguments)]
fn emit_ser_vec_cbor<'ctx>(
    ctx: &'ctx Context,
    llvm_mod: &LlvmModule<'ctx>,
    builder: &inkwell::builder::Builder<'ctx>,
    func: FunctionValue<'ctx>,
    elem_ty: &ResolvedTy,
    value_ptr: PointerValue<'ctx>,
    buf: PointerValue<'ctx>,
    wire_layouts: &WireLayoutTable,
    record_layouts: &RecordLayoutMap<'ctx>,
    machine_layouts: &MachineLayoutMap<'ctx>,
    pipeline_records: &[RecordLayout],
    enum_layouts: &[EnumLayout],
) -> CodegenResult<()> {
    if cbor_vec_elem_kind(elem_ty, pipeline_records, enum_layouts) == CborVecElemKind::Defer {
        return Err(CodegenError::FailClosed(format!(
            "wire CBOR serialize: Vec<{elem_ty:?}> has an owned-compound element \
             (bytes / heap-owning record / nested collection) outside the \
             supported wire-body floor"
        )));
    }
    let ptr_ty = ctx.ptr_type(AddressSpace::default());
    let void_ty = ctx.void_type();
    let i64_ty = ctx.i64_type();

    let vec_ptr = builder
        .build_load(ptr_ty, value_ptr, "cbor_ser_vec_ptr")
        .llvm_ctx("cbor ser vec load")?
        .into_pointer_value();
    let len_fn = declare_codec_prim(
        ctx,
        llvm_mod,
        "hew_vec_len",
        i64_ty.fn_type(&[ptr_ty.into()], false),
    );
    let len = builder
        .build_call(len_fn, &[vec_ptr.into()], "cbor_ser_vec_len")
        .llvm_ctx("cbor ser vec len")?
        .try_as_basic_value()
        .basic()
        .ok_or_else(|| CodegenError::FailClosed("hew_vec_len void".into()))?
        .into_int_value();

    let begin = declare_codec_prim(
        ctx,
        llvm_mod,
        "hew_cbor_ser_begin_array",
        void_ty.fn_type(&[ptr_ty.into()], false),
    );
    builder
        .build_call(begin, &[buf.into()], "cbor_ser_vec_begin")
        .llvm_ctx("cbor ser vec begin")?;

    // for (i = 0; i < len; i += 1) { encode element i }
    let idx_slot = builder
        .build_alloca(i64_ty, "cbor_ser_vec_i")
        .llvm_ctx("cbor ser vec i alloca")?;
    builder
        .build_store(idx_slot, i64_ty.const_zero())
        .llvm_ctx("cbor ser vec i init")?;
    let head_bb = ctx.append_basic_block(func, "cbor_ser_vec_head");
    let body_bb = ctx.append_basic_block(func, "cbor_ser_vec_body");
    let done_bb = ctx.append_basic_block(func, "cbor_ser_vec_done");
    builder
        .build_unconditional_branch(head_bb)
        .llvm_ctx("cbor ser vec entry br")?;

    builder.position_at_end(head_bb);
    let i_cur = builder
        .build_load(i64_ty, idx_slot, "cbor_ser_vec_i_cur")
        .llvm_ctx("cbor ser vec i load")?
        .into_int_value();
    let in_range = builder
        .build_int_compare(IntPredicate::SLT, i_cur, len, "cbor_ser_vec_cmp")
        .llvm_ctx("cbor ser vec cmp")?;
    builder
        .build_conditional_branch(in_range, body_bb, done_bb)
        .llvm_ctx("cbor ser vec head br")?;

    builder.position_at_end(body_bb);
    let get_gen = declare_codec_prim(
        ctx,
        llvm_mod,
        "hew_vec_get_generic",
        ptr_ty.fn_type(&[ptr_ty.into(), i64_ty.into()], false),
    );
    let elem_ptr = builder
        .build_call(get_gen, &[vec_ptr.into(), i_cur.into()], "cbor_ser_vec_get")
        .llvm_ctx("cbor ser vec get_generic")?
        .try_as_basic_value()
        .basic()
        .ok_or_else(|| CodegenError::FailClosed("hew_vec_get_generic void".into()))?
        .into_pointer_value();
    emit_ser_value_cbor(
        ctx,
        llvm_mod,
        builder,
        func,
        elem_ty,
        elem_ptr,
        buf,
        wire_layouts,
        record_layouts,
        machine_layouts,
        pipeline_records,
        enum_layouts,
    )?;
    let i_next = builder
        .build_int_add(i_cur, i64_ty.const_int(1, false), "cbor_ser_vec_inc")
        .llvm_ctx("cbor ser vec inc")?;
    builder
        .build_store(idx_slot, i_next)
        .llvm_ctx("cbor ser vec i store")?;
    builder
        .build_unconditional_branch(head_bb)
        .llvm_ctx("cbor ser vec body br")?;

    builder.position_at_end(done_bb);
    let end = declare_codec_prim(
        ctx,
        llvm_mod,
        "hew_cbor_ser_end_array",
        void_ty.fn_type(&[ptr_ty.into()], false),
    );
    builder
        .build_call(end, &[buf.into()], "cbor_ser_vec_end")
        .llvm_ctx("cbor ser vec end")?;
    Ok(())
}

/// Decode a CBOR array into a `Vec<T>`. Constructs the backing vec matching the
/// element's ownership kind (so `hew_vec_free` releases element heap correctly),
/// then drains the array, decoding each element. Owned-compound elements fail
/// closed. On a malformed tail the partially built vec is owned by `dst` and
/// released by the enclosing type's drop helper (`hew_vec_free` is null-safe and
/// frees a string-kind vec's element strings).
#[allow(clippy::too_many_arguments)]
fn emit_de_vec_cbor<'ctx>(
    ctx: &'ctx Context,
    llvm_mod: &LlvmModule<'ctx>,
    builder: &inkwell::builder::Builder<'ctx>,
    func: FunctionValue<'ctx>,
    elem_ty: &ResolvedTy,
    dst: PointerValue<'ctx>,
    reader: PointerValue<'ctx>,
    wire_layouts: &WireLayoutTable,
    record_layouts: &RecordLayoutMap<'ctx>,
    machine_layouts: &MachineLayoutMap<'ctx>,
    pipeline_records: &[RecordLayout],
    enum_layouts: &[EnumLayout],
) -> CodegenResult<()> {
    let kind = cbor_vec_elem_kind(elem_ty, pipeline_records, enum_layouts);
    if kind == CborVecElemKind::Defer {
        return Err(CodegenError::FailClosed(format!(
            "wire CBOR deserialize: Vec<{elem_ty:?}> has an owned-compound element \
             (bytes / heap-owning record / nested collection) outside the \
             supported wire-body floor"
        )));
    }
    let ptr_ty = ctx.ptr_type(AddressSpace::default());
    let void_ty = ctx.void_type();
    let i64_ty = ctx.i64_type();
    let i32_ty = ctx.i32_type();

    // Construct the backing vec matching the element ownership kind.
    let vec_ptr = match kind {
        CborVecElemKind::Str => {
            let new_str =
                declare_codec_prim(ctx, llvm_mod, "hew_vec_new_str", ptr_ty.fn_type(&[], false));
            builder
                .build_call(new_str, &[], "cbor_de_vec_new_str")
                .llvm_ctx("cbor de vec new_str")?
                .try_as_basic_value()
                .basic()
                .ok_or_else(|| CodegenError::FailClosed("hew_vec_new_str void".into()))?
                .into_pointer_value()
        }
        CborVecElemKind::Plain => {
            let elem_llvm = resolve_ty(ctx, elem_ty, record_layouts)?;
            let elem_size = elem_llvm
                .size_of()
                .ok_or_else(|| CodegenError::FailClosed("Vec element has no size".into()))?;
            let new_gen = declare_codec_prim(
                ctx,
                llvm_mod,
                "hew_vec_new_with_elem_size",
                ptr_ty.fn_type(&[i64_ty.into()], false),
            );
            builder
                .build_call(new_gen, &[elem_size.into()], "cbor_de_vec_new")
                .llvm_ctx("cbor de vec new_with_elem_size")?
                .try_as_basic_value()
                .basic()
                .ok_or_else(|| CodegenError::FailClosed("hew_vec_new_with_elem_size void".into()))?
                .into_pointer_value()
        }
        CborVecElemKind::Defer => unreachable!("Defer handled above"),
    };
    builder
        .build_store(dst, vec_ptr)
        .llvm_ctx("cbor de vec store handle")?;

    let enter = declare_codec_prim(
        ctx,
        llvm_mod,
        "hew_cbor_de_enter_array",
        void_ty.fn_type(&[ptr_ty.into()], false),
    );
    builder
        .build_call(enter, &[reader.into()], "cbor_de_vec_enter")
        .llvm_ctx("cbor de vec enter")?;

    // while (array_next) { decode element; push }
    let head_bb = ctx.append_basic_block(func, "cbor_de_vec_head");
    let body_bb = ctx.append_basic_block(func, "cbor_de_vec_body");
    let done_bb = ctx.append_basic_block(func, "cbor_de_vec_done");
    builder
        .build_unconditional_branch(head_bb)
        .llvm_ctx("cbor de vec entry br")?;

    builder.position_at_end(head_bb);
    let next_fn = declare_codec_prim(
        ctx,
        llvm_mod,
        "hew_cbor_de_array_next",
        i32_ty.fn_type(&[ptr_ty.into()], false),
    );
    let has = builder
        .build_call(next_fn, &[reader.into()], "cbor_de_vec_next")
        .llvm_ctx("cbor de vec next")?
        .try_as_basic_value()
        .basic()
        .ok_or_else(|| CodegenError::FailClosed("hew_cbor_de_array_next void".into()))?
        .into_int_value();
    let cont = builder
        .build_int_compare(
            IntPredicate::NE,
            has,
            i32_ty.const_zero(),
            "cbor_de_vec_has",
        )
        .llvm_ctx("cbor de vec has cmp")?;
    builder
        .build_conditional_branch(cont, body_bb, done_bb)
        .llvm_ctx("cbor de vec head br")?;

    builder.position_at_end(body_bb);
    match kind {
        CborVecElemKind::Str => {
            let de_string = declare_codec_prim(
                ctx,
                llvm_mod,
                "hew_cbor_de_string",
                ptr_ty.fn_type(&[ptr_ty.into()], false),
            );
            let s = builder
                .build_call(de_string, &[reader.into()], "cbor_de_vec_string")
                .llvm_ctx("cbor de vec string")?
                .try_as_basic_value()
                .basic()
                .ok_or_else(|| CodegenError::FailClosed("hew_cbor_de_string void".into()))?
                .into_pointer_value();
            let push_str = declare_codec_prim(
                ctx,
                llvm_mod,
                "hew_vec_push_str",
                void_ty.fn_type(&[ptr_ty.into(), ptr_ty.into()], false),
            );
            builder
                .build_call(
                    push_str,
                    &[vec_ptr.into(), s.into()],
                    "cbor_de_vec_push_str",
                )
                .llvm_ctx("cbor de vec push_str")?;
            // push_str copies the string in; release our decode temp.
            let drop_str = declare_codec_prim(
                ctx,
                llvm_mod,
                "hew_string_drop",
                void_ty.fn_type(&[ptr_ty.into()], false),
            );
            builder
                .build_call(drop_str, &[s.into()], "cbor_de_vec_drop_str")
                .llvm_ctx("cbor de vec drop_str")?;
        }
        CborVecElemKind::Plain => {
            let elem_llvm = resolve_ty(ctx, elem_ty, record_layouts)?;
            let temp = builder
                .build_alloca(elem_llvm, "cbor_de_vec_elem")
                .llvm_ctx("cbor de vec elem alloca")?;
            // Zero the slot so a fail-closed partial element is a defined,
            // heap-free BitCopy value (a Plain element owns no heap to leak).
            builder
                .build_store(temp, elem_llvm.const_zero())
                .llvm_ctx("cbor de vec elem zero")?;
            emit_de_value_cbor(
                ctx,
                llvm_mod,
                builder,
                func,
                elem_ty,
                temp,
                reader,
                wire_layouts,
                record_layouts,
                machine_layouts,
                pipeline_records,
                enum_layouts,
            )?;
            let push_gen = declare_codec_prim(
                ctx,
                llvm_mod,
                "hew_vec_push_generic",
                void_ty.fn_type(&[ptr_ty.into(), ptr_ty.into()], false),
            );
            builder
                .build_call(push_gen, &[vec_ptr.into(), temp.into()], "cbor_de_vec_push")
                .llvm_ctx("cbor de vec push_generic")?;
        }
        CborVecElemKind::Defer => unreachable!("Defer handled above"),
    }
    builder
        .build_unconditional_branch(head_bb)
        .llvm_ctx("cbor de vec body br")?;

    builder.position_at_end(done_bb);
    let exit = declare_codec_prim(
        ctx,
        llvm_mod,
        "hew_cbor_de_exit_array",
        void_ty.fn_type(&[ptr_ty.into()], false),
    );
    builder
        .build_call(exit, &[reader.into()], "cbor_de_vec_exit")
        .llvm_ctx("cbor de vec exit")?;
    Ok(())
}

/// Encode an `Option<T>` field under the null encoding: `None` emits CBOR
/// null; `Some(v)` emits the bare value `v`. Nested `Option<Option<_>>` is
/// ambiguous under this encoding (a `Some(None)` and an outer `None` both reduce
/// to null), so it fails closed.
#[allow(clippy::too_many_arguments)]
fn emit_ser_option_cbor<'ctx>(
    ctx: &'ctx Context,
    llvm_mod: &LlvmModule<'ctx>,
    builder: &inkwell::builder::Builder<'ctx>,
    func: FunctionValue<'ctx>,
    name: &str,
    args: &[ResolvedTy],
    value_ptr: PointerValue<'ctx>,
    buf: PointerValue<'ctx>,
    wire_layouts: &WireLayoutTable,
    record_layouts: &RecordLayoutMap<'ctx>,
    machine_layouts: &MachineLayoutMap<'ctx>,
    pipeline_records: &[RecordLayout],
    enum_layouts: &[EnumLayout],
) -> CodegenResult<()> {
    let ptr_ty = ctx.ptr_type(AddressSpace::default());
    let void_ty = ctx.void_type();
    let key = xnode_registry_key(name, args, pipeline_records, enum_layouts);
    let (Some(layout), Some(el)) = (
        machine_layouts.get(&key),
        enum_layouts.iter().find(|e| e.name == key),
    ) else {
        return Err(CodegenError::FailClosed(format!(
            "wire CBOR serialize: Option `{name}` (key `{key}`) has no enum layout"
        )));
    };
    let some_idx = el
        .variants
        .iter()
        .position(|v| !v.field_tys.is_empty())
        .ok_or_else(|| {
            CodegenError::FailClosed(format!("wire CBOR serialize: Option `{key}` has no Some"))
        })?;
    let payload_ty = &el.variants[some_idx].field_tys[0];
    if matches!(
        payload_ty,
        ResolvedTy::Named {
            builtin: Some(BuiltinType::Option),
            ..
        }
    ) {
        return Err(CodegenError::FailClosed(
            "wire CBOR serialize: Option<Option<_>> is ambiguous under the null \
             encoding — not supported"
                .into(),
        ));
    }

    let base = if el.is_indirect {
        builder
            .build_load(ptr_ty, value_ptr, "cbor_ser_opt_indirect")
            .llvm_ctx("cbor ser option indirect load")?
            .into_pointer_value()
    } else {
        value_ptr
    };
    let tag_ptr = builder
        .build_struct_gep(layout.outer_struct, base, 0, "cbor_ser_opt_tag_ptr")
        .llvm_ctx("cbor ser option tag gep")?;
    let tag = builder
        .build_load(layout.tag_int_ty, tag_ptr, "cbor_ser_opt_tag")
        .llvm_ctx("cbor ser option tag load")?
        .into_int_value();
    let some_const = layout.tag_int_ty.const_int(some_idx as u64, false);
    let is_some = builder
        .build_int_compare(IntPredicate::EQ, tag, some_const, "cbor_ser_opt_is_some")
        .llvm_ctx("cbor ser option is_some")?;

    let some_bb = ctx.append_basic_block(func, "cbor_ser_opt_some");
    let none_bb = ctx.append_basic_block(func, "cbor_ser_opt_none");
    let cont_bb = ctx.append_basic_block(func, "cbor_ser_opt_cont");
    builder
        .build_conditional_branch(is_some, some_bb, none_bb)
        .llvm_ctx("cbor ser option branch")?;

    builder.position_at_end(some_bb);
    let payload_ptr = builder
        .build_struct_gep(layout.outer_struct, base, 1, "cbor_ser_opt_payload")
        .llvm_ctx("cbor ser option payload gep")?;
    let field0_ptr = builder
        .build_struct_gep(
            layout.variant_struct_tys[some_idx],
            payload_ptr,
            0,
            "cbor_ser_opt_field0",
        )
        .llvm_ctx("cbor ser option field gep")?;
    emit_ser_value_cbor(
        ctx,
        llvm_mod,
        builder,
        func,
        payload_ty,
        field0_ptr,
        buf,
        wire_layouts,
        record_layouts,
        machine_layouts,
        pipeline_records,
        enum_layouts,
    )?;
    builder
        .build_unconditional_branch(cont_bb)
        .llvm_ctx("cbor ser option some br")?;

    builder.position_at_end(none_bb);
    let null_prim = declare_codec_prim(
        ctx,
        llvm_mod,
        "hew_cbor_ser_null",
        void_ty.fn_type(&[ptr_ty.into()], false),
    );
    builder
        .build_call(null_prim, &[buf.into()], "cbor_ser_opt_null")
        .llvm_ctx("cbor ser option null")?;
    builder
        .build_unconditional_branch(cont_bb)
        .llvm_ctx("cbor ser option none br")?;

    builder.position_at_end(cont_bb);
    Ok(())
}

/// Decode an `Option<T>` field under the null encoding: CBOR null
/// reconstructs `None`; any other value reconstructs `Some(decode(value))`.
/// Nested `Option<Option<_>>` fails closed (ambiguous under null).
#[allow(clippy::too_many_arguments)]
fn emit_de_option_cbor<'ctx>(
    ctx: &'ctx Context,
    llvm_mod: &LlvmModule<'ctx>,
    builder: &inkwell::builder::Builder<'ctx>,
    func: FunctionValue<'ctx>,
    name: &str,
    args: &[ResolvedTy],
    dst: PointerValue<'ctx>,
    reader: PointerValue<'ctx>,
    wire_layouts: &WireLayoutTable,
    record_layouts: &RecordLayoutMap<'ctx>,
    machine_layouts: &MachineLayoutMap<'ctx>,
    pipeline_records: &[RecordLayout],
    enum_layouts: &[EnumLayout],
) -> CodegenResult<()> {
    let ptr_ty = ctx.ptr_type(AddressSpace::default());
    let void_ty = ctx.void_type();
    let i32_ty = ctx.i32_type();
    let i64_ty = ctx.i64_type();
    let key = xnode_registry_key(name, args, pipeline_records, enum_layouts);
    let (Some(layout), Some(el)) = (
        machine_layouts.get(&key),
        enum_layouts.iter().find(|e| e.name == key),
    ) else {
        return Err(CodegenError::FailClosed(format!(
            "wire CBOR deserialize: Option `{name}` (key `{key}`) has no enum layout"
        )));
    };
    let some_idx = el
        .variants
        .iter()
        .position(|v| !v.field_tys.is_empty())
        .ok_or_else(|| {
            CodegenError::FailClosed(format!("wire CBOR deserialize: Option `{key}` has no Some"))
        })?;
    let none_idx = el
        .variants
        .iter()
        .position(|v| v.field_tys.is_empty())
        .ok_or_else(|| {
            CodegenError::FailClosed(format!("wire CBOR deserialize: Option `{key}` has no None"))
        })?;
    let payload_ty = &el.variants[some_idx].field_tys[0];
    if matches!(
        payload_ty,
        ResolvedTy::Named {
            builtin: Some(BuiltinType::Option),
            ..
        }
    ) {
        return Err(CodegenError::FailClosed(
            "wire CBOR deserialize: Option<Option<_>> is ambiguous under the null \
             encoding — not supported"
                .into(),
        ));
    }

    // For an indirect Option, allocate the heap tagged-union and store the ptr.
    let base = if el.is_indirect {
        let size = layout
            .outer_struct
            .size_of()
            .ok_or_else(|| CodegenError::FailClosed("indirect Option has no size".into()))?;
        let align = i64_ty.const_int(8, false);
        let alloc_prim = declare_codec_prim(
            ctx,
            llvm_mod,
            "hew_alloc",
            ptr_ty.fn_type(&[i64_ty.into(), i64_ty.into()], false),
        );
        let heap = builder
            .build_call(
                alloc_prim,
                &[size.into(), align.into()],
                "cbor_de_opt_alloc",
            )
            .llvm_ctx("cbor de option alloc")?
            .try_as_basic_value()
            .basic()
            .ok_or_else(|| CodegenError::FailClosed("hew_alloc void".into()))?
            .into_pointer_value();
        builder
            .build_store(dst, heap)
            .llvm_ctx("cbor de option indirect store")?;
        heap
    } else {
        dst
    };

    let is_null_fn = declare_codec_prim(
        ctx,
        llvm_mod,
        "hew_cbor_de_is_null",
        i32_ty.fn_type(&[ptr_ty.into()], false),
    );
    let is_null = builder
        .build_call(is_null_fn, &[reader.into()], "cbor_de_opt_is_null")
        .llvm_ctx("cbor de option is_null")?
        .try_as_basic_value()
        .basic()
        .ok_or_else(|| CodegenError::FailClosed("hew_cbor_de_is_null void".into()))?
        .into_int_value();
    let is_null_b = builder
        .build_int_compare(
            IntPredicate::NE,
            is_null,
            i32_ty.const_zero(),
            "cbor_de_opt_nullc",
        )
        .llvm_ctx("cbor de option null cmp")?;

    let none_bb = ctx.append_basic_block(func, "cbor_de_opt_none");
    let some_bb = ctx.append_basic_block(func, "cbor_de_opt_some");
    let cont_bb = ctx.append_basic_block(func, "cbor_de_opt_cont");
    builder
        .build_conditional_branch(is_null_b, none_bb, some_bb)
        .llvm_ctx("cbor de option branch")?;

    builder.position_at_end(none_bb);
    let skip_fn = declare_codec_prim(
        ctx,
        llvm_mod,
        "hew_cbor_de_skip",
        void_ty.fn_type(&[ptr_ty.into()], false),
    );
    builder
        .build_call(skip_fn, &[reader.into()], "cbor_de_opt_skip")
        .llvm_ctx("cbor de option skip")?;
    let none_tag = layout.tag_int_ty.const_int(none_idx as u64, false);
    let tag_ptr_none = builder
        .build_struct_gep(layout.outer_struct, base, 0, "cbor_de_opt_none_tag")
        .llvm_ctx("cbor de option none tag gep")?;
    builder
        .build_store(tag_ptr_none, none_tag)
        .llvm_ctx("cbor de option none tag store")?;
    builder
        .build_unconditional_branch(cont_bb)
        .llvm_ctx("cbor de option none br")?;

    builder.position_at_end(some_bb);
    let some_tag = layout.tag_int_ty.const_int(some_idx as u64, false);
    let tag_ptr_some = builder
        .build_struct_gep(layout.outer_struct, base, 0, "cbor_de_opt_some_tag")
        .llvm_ctx("cbor de option some tag gep")?;
    builder
        .build_store(tag_ptr_some, some_tag)
        .llvm_ctx("cbor de option some tag store")?;
    let payload_ptr = builder
        .build_struct_gep(layout.outer_struct, base, 1, "cbor_de_opt_payload")
        .llvm_ctx("cbor de option payload gep")?;
    let field0_ptr = builder
        .build_struct_gep(
            layout.variant_struct_tys[some_idx],
            payload_ptr,
            0,
            "cbor_de_opt_field0",
        )
        .llvm_ctx("cbor de option field gep")?;
    emit_de_value_cbor(
        ctx,
        llvm_mod,
        builder,
        func,
        payload_ty,
        field0_ptr,
        reader,
        wire_layouts,
        record_layouts,
        machine_layouts,
        pipeline_records,
        enum_layouts,
    )?;
    builder
        .build_unconditional_branch(cont_bb)
        .llvm_ctx("cbor de option some br")?;

    builder.position_at_end(cont_bb);
    Ok(())
}

/// Encode a wire enum under the "map-of-one" shape: a unit variant emits
/// its bare integer tag; a payload variant emits a single-entry map
/// `{tag: [field0, field1, ...]}`. The tag is the schema-stable wire tag
/// (`cbor_variant_tag`). An out-of-range in-memory discriminant traps
/// (exhaustiveness fallthrough), matching the bespoke codec.
#[allow(clippy::too_many_arguments)]
fn emit_ser_enum_cbor<'ctx>(
    ctx: &'ctx Context,
    llvm_mod: &LlvmModule<'ctx>,
    builder: &inkwell::builder::Builder<'ctx>,
    func: FunctionValue<'ctx>,
    key: &str,
    layout: &MachineCodegenLayout<'ctx>,
    el: &EnumLayout,
    value_ptr: PointerValue<'ctx>,
    buf: PointerValue<'ctx>,
    wire_layouts: &WireLayoutTable,
    record_layouts: &RecordLayoutMap<'ctx>,
    machine_layouts: &MachineLayoutMap<'ctx>,
    pipeline_records: &[RecordLayout],
    enum_layouts: &[EnumLayout],
) -> CodegenResult<()> {
    let ptr_ty = ctx.ptr_type(AddressSpace::default());
    let void_ty = ctx.void_type();
    let i64_ty = ctx.i64_type();

    let base = if el.is_indirect {
        builder
            .build_load(ptr_ty, value_ptr, "cbor_ser_enum_indirect")
            .llvm_ctx("cbor ser enum indirect load")?
            .into_pointer_value()
    } else {
        value_ptr
    };
    let tag_ptr = builder
        .build_struct_gep(layout.outer_struct, base, 0, "cbor_ser_enum_tag_ptr")
        .llvm_ctx("cbor ser enum tag gep")?;
    let tag = builder
        .build_load(layout.tag_int_ty, tag_ptr, "cbor_ser_enum_tag")
        .llvm_ctx("cbor ser enum tag load")?
        .into_int_value();

    let cont_bb = ctx.append_basic_block(func, "cbor_ser_enum_cont");
    let trap_bb = ctx.append_basic_block(func, "cbor_ser_enum_oob");
    let mut cases = Vec::with_capacity(layout.variant_struct_tys.len());
    let mut variant_bbs = Vec::with_capacity(layout.variant_struct_tys.len());
    for idx in 0..layout.variant_struct_tys.len() {
        let bb = ctx.append_basic_block(func, &format!("cbor_ser_enum_v{idx}"));
        cases.push((layout.tag_int_ty.const_int(idx as u64, false), bb));
        variant_bbs.push(bb);
    }
    builder
        .build_switch(tag, trap_bb, &cases)
        .llvm_ctx("cbor ser enum switch")?;

    builder.position_at_end(trap_bb);
    emit_trap_with_code_raw(
        ctx,
        llvm_mod,
        builder,
        HEW_TRAP_EXHAUSTIVENESS_FALLTHROUGH as u64,
        "cbor_ser_enum_oob",
    )?;

    let ser_u64 = declare_codec_prim(
        ctx,
        llvm_mod,
        "hew_cbor_ser_u64",
        void_ty.fn_type(&[ptr_ty.into(), i64_ty.into()], false),
    );
    let begin_map = declare_codec_prim(
        ctx,
        llvm_mod,
        "hew_cbor_ser_begin_map",
        void_ty.fn_type(&[ptr_ty.into()], false),
    );
    let key_u64 = declare_codec_prim(
        ctx,
        llvm_mod,
        "hew_cbor_ser_key_u64",
        void_ty.fn_type(&[ptr_ty.into(), i64_ty.into()], false),
    );
    let begin_arr = declare_codec_prim(
        ctx,
        llvm_mod,
        "hew_cbor_ser_begin_array",
        void_ty.fn_type(&[ptr_ty.into()], false),
    );
    let end_arr = declare_codec_prim(
        ctx,
        llvm_mod,
        "hew_cbor_ser_end_array",
        void_ty.fn_type(&[ptr_ty.into()], false),
    );
    let end_map = declare_codec_prim(
        ctx,
        llvm_mod,
        "hew_cbor_ser_end_map",
        void_ty.fn_type(&[ptr_ty.into()], false),
    );

    for (idx, variant_struct) in layout.variant_struct_tys.iter().enumerate() {
        builder.position_at_end(variant_bbs[idx]);
        let variant = &el.variants[idx];
        let wire_tag = cbor_variant_tag(wire_layouts, key, &variant.name, idx);
        let tag_const = i64_ty.const_int(wire_tag, false);
        if variant.field_tys.is_empty() {
            builder
                .build_call(
                    ser_u64,
                    &[buf.into(), tag_const.into()],
                    "cbor_ser_enum_unit",
                )
                .llvm_ctx("cbor ser enum unit tag")?;
        } else {
            builder
                .build_call(begin_map, &[buf.into()], "cbor_ser_enum_begin_map")
                .llvm_ctx("cbor ser enum begin_map")?;
            builder
                .build_call(
                    key_u64,
                    &[buf.into(), tag_const.into()],
                    "cbor_ser_enum_key",
                )
                .llvm_ctx("cbor ser enum key")?;
            builder
                .build_call(begin_arr, &[buf.into()], "cbor_ser_enum_begin_arr")
                .llvm_ctx("cbor ser enum begin_array")?;
            let payload_ptr = builder
                .build_struct_gep(
                    layout.outer_struct,
                    base,
                    1,
                    &format!("cbor_ser_enum_payload_{idx}"),
                )
                .llvm_ctx("cbor ser enum payload gep")?;
            for (fidx, fty) in variant.field_tys.iter().enumerate() {
                let field_ptr = builder
                    .build_struct_gep(
                        *variant_struct,
                        payload_ptr,
                        fidx as u32,
                        &format!("cbor_ser_enum_v{idx}_f{fidx}"),
                    )
                    .llvm_ctx("cbor ser enum field gep")?;
                emit_ser_value_cbor(
                    ctx,
                    llvm_mod,
                    builder,
                    func,
                    fty,
                    field_ptr,
                    buf,
                    wire_layouts,
                    record_layouts,
                    machine_layouts,
                    pipeline_records,
                    enum_layouts,
                )?;
            }
            builder
                .build_call(end_arr, &[buf.into()], "cbor_ser_enum_end_arr")
                .llvm_ctx("cbor ser enum end_array")?;
            builder
                .build_call(end_map, &[buf.into()], "cbor_ser_enum_end_map")
                .llvm_ctx("cbor ser enum end_map")?;
        }
        builder
            .build_unconditional_branch(cont_bb)
            .llvm_ctx("cbor ser enum variant br")?;
    }
    builder.position_at_end(cont_bb);
    Ok(())
}

/// Decode a wire enum under the "map-of-one" shape. `hew_cbor_de_enum_begin` returns
/// the wire tag and stages the payload array (empty for a unit variant); a
/// switch on the wire tag selects the variant, stores the in-memory
/// discriminant, and drains the payload array into the variant's fields.
/// `hew_cbor_de_enum_end` closes the frame on every non-trap path. An unknown
/// wire tag traps (exhaustiveness fallthrough), matching the bespoke codec.
#[allow(clippy::too_many_arguments)]
fn emit_de_enum_cbor<'ctx>(
    ctx: &'ctx Context,
    llvm_mod: &LlvmModule<'ctx>,
    builder: &inkwell::builder::Builder<'ctx>,
    func: FunctionValue<'ctx>,
    key: &str,
    layout: &MachineCodegenLayout<'ctx>,
    el: &EnumLayout,
    dst: PointerValue<'ctx>,
    reader: PointerValue<'ctx>,
    wire_layouts: &WireLayoutTable,
    record_layouts: &RecordLayoutMap<'ctx>,
    machine_layouts: &MachineLayoutMap<'ctx>,
    pipeline_records: &[RecordLayout],
    enum_layouts: &[EnumLayout],
) -> CodegenResult<()> {
    let ptr_ty = ctx.ptr_type(AddressSpace::default());
    let void_ty = ctx.void_type();
    let i64_ty = ctx.i64_type();
    let i32_ty = ctx.i32_type();

    let base = if el.is_indirect {
        let size = layout
            .outer_struct
            .size_of()
            .ok_or_else(|| CodegenError::FailClosed("indirect enum has no size".into()))?;
        let align = i64_ty.const_int(8, false);
        let alloc_prim = declare_codec_prim(
            ctx,
            llvm_mod,
            "hew_alloc",
            ptr_ty.fn_type(&[i64_ty.into(), i64_ty.into()], false),
        );
        let heap = builder
            .build_call(
                alloc_prim,
                &[size.into(), align.into()],
                "cbor_de_enum_alloc",
            )
            .llvm_ctx("cbor de enum alloc")?
            .try_as_basic_value()
            .basic()
            .ok_or_else(|| CodegenError::FailClosed("hew_alloc void".into()))?
            .into_pointer_value();
        builder
            .build_store(dst, heap)
            .llvm_ctx("cbor de enum indirect store")?;
        heap
    } else {
        dst
    };

    let enum_begin = declare_codec_prim(
        ctx,
        llvm_mod,
        "hew_cbor_de_enum_begin",
        i64_ty.fn_type(&[ptr_ty.into()], false),
    );
    let wire_tag = builder
        .build_call(enum_begin, &[reader.into()], "cbor_de_enum_begin")
        .llvm_ctx("cbor de enum begin")?
        .try_as_basic_value()
        .basic()
        .ok_or_else(|| CodegenError::FailClosed("hew_cbor_de_enum_begin void".into()))?
        .into_int_value();

    let cont_bb = ctx.append_basic_block(func, "cbor_de_enum_cont");
    let trap_bb = ctx.append_basic_block(func, "cbor_de_enum_oob");
    let mut cases = Vec::with_capacity(layout.variant_struct_tys.len());
    let mut variant_bbs = Vec::with_capacity(layout.variant_struct_tys.len());
    for idx in 0..layout.variant_struct_tys.len() {
        let bb = ctx.append_basic_block(func, &format!("cbor_de_enum_v{idx}"));
        let wt = cbor_variant_tag(wire_layouts, key, &el.variants[idx].name, idx);
        cases.push((i64_ty.const_int(wt, false), bb));
        variant_bbs.push(bb);
    }
    builder
        .build_switch(wire_tag, trap_bb, &cases)
        .llvm_ctx("cbor de enum switch")?;

    builder.position_at_end(trap_bb);
    // Unknown wire tag — no declared variant matches. Fail closed WITHOUT an
    // inline native trap: an inline trap here would unwind (via the actor
    // crash-recovery `siglongjmp` seam) PAST the deserialize thunk's
    // `hew_cbor_de_free(reader)` + `free(dst)` cleanup, leaking the parsed CBOR
    // tree and the partial value shell per malformed message. Instead latch the
    // reader failure and rejoin the normal control flow (the `cont_bb`
    // `enum_end` balances the payload frame `enum_begin` pushed). The thunk's
    // post-walk `failed` check then drops the partial value, frees the shell +
    // reader, and returns null — the call site traps — exactly the
    // free-before-trap discipline every other malformed shape already follows.
    //
    // Zero `base` first so the fail path's in-place drop sees a well-defined
    // variant-0 value with null payload. A direct enum's `base` is the thunk's
    // already-zeroed `dst`, but an indirect (recursive) enum's `base` is a fresh
    // `hew_alloc` block whose tag/payload are otherwise uninitialised — dropping
    // a garbage tag/payload would be undefined behaviour.
    let oob_size = layout
        .outer_struct
        .size_of()
        .ok_or_else(|| CodegenError::FailClosed("cbor de enum oob: value has no size".into()))?;
    let oob_memset_size_ty = runtime_size_ty(ctx, llvm_mod);
    let oob_memset = declare_codec_prim(
        ctx,
        llvm_mod,
        "memset",
        ptr_ty.fn_type(
            &[ptr_ty.into(), i32_ty.into(), oob_memset_size_ty.into()],
            false,
        ),
    );
    let oob_memset_size = if oob_memset_size_ty == i64_ty {
        oob_size
    } else {
        builder
            .build_int_truncate(oob_size, oob_memset_size_ty, "cbor_de_enum_oob_size_trunc")
            .llvm_ctx("cbor de enum oob size trunc")?
    };
    builder
        .build_call(
            oob_memset,
            &[
                base.into(),
                i32_ty.const_zero().into(),
                oob_memset_size.into(),
            ],
            "cbor_de_enum_oob_zero",
        )
        .llvm_ctx("cbor de enum oob zero")?;
    let de_fail = declare_codec_prim(
        ctx,
        llvm_mod,
        "hew_cbor_de_fail",
        void_ty.fn_type(&[ptr_ty.into()], false),
    );
    builder
        .build_call(de_fail, &[reader.into()], "cbor_de_enum_oob_fail")
        .llvm_ctx("cbor de enum oob fail")?;
    builder
        .build_unconditional_branch(cont_bb)
        .llvm_ctx("cbor de enum oob br")?;

    let array_next = declare_codec_prim(
        ctx,
        llvm_mod,
        "hew_cbor_de_array_next",
        i32_ty.fn_type(&[ptr_ty.into()], false),
    );
    for (idx, variant_struct) in layout.variant_struct_tys.iter().enumerate() {
        builder.position_at_end(variant_bbs[idx]);
        // Store the in-memory discriminant = variant index.
        let tag_mem = layout.tag_int_ty.const_int(idx as u64, false);
        let tag_ptr = builder
            .build_struct_gep(layout.outer_struct, base, 0, "cbor_de_enum_tag_ptr")
            .llvm_ctx("cbor de enum tag gep")?;
        builder
            .build_store(tag_ptr, tag_mem)
            .llvm_ctx("cbor de enum tag store")?;
        let variant = &el.variants[idx];
        if !variant.field_tys.is_empty() {
            let payload_ptr = builder
                .build_struct_gep(
                    layout.outer_struct,
                    base,
                    1,
                    &format!("cbor_de_enum_payload_{idx}"),
                )
                .llvm_ctx("cbor de enum payload gep")?;
            for (fidx, fty) in variant.field_tys.iter().enumerate() {
                // Stage the next payload element; a missing field leaves nothing
                // staged and the field read fails closed.
                builder
                    .build_call(array_next, &[reader.into()], "cbor_de_enum_next")
                    .llvm_ctx("cbor de enum array_next")?;
                let field_ptr = builder
                    .build_struct_gep(
                        *variant_struct,
                        payload_ptr,
                        fidx as u32,
                        &format!("cbor_de_enum_v{idx}_f{fidx}"),
                    )
                    .llvm_ctx("cbor de enum field gep")?;
                emit_de_value_cbor(
                    ctx,
                    llvm_mod,
                    builder,
                    func,
                    fty,
                    field_ptr,
                    reader,
                    wire_layouts,
                    record_layouts,
                    machine_layouts,
                    pipeline_records,
                    enum_layouts,
                )?;
            }
        }
        builder
            .build_unconditional_branch(cont_bb)
            .llvm_ctx("cbor de enum variant br")?;
    }
    builder.position_at_end(cont_bb);
    let enum_end = declare_codec_prim(
        ctx,
        llvm_mod,
        "hew_cbor_de_enum_end",
        void_ty.fn_type(&[ptr_ty.into()], false),
    );
    builder
        .build_call(enum_end, &[reader.into()], "cbor_de_enum_end")
        .llvm_ctx("cbor de enum end")?;
    Ok(())
}

/// Emit the full CBOR serialize + deserialize thunk bodies for `ty` (idempotent:
/// a second call for the same key no-ops). This is the sole wire body codec:
/// the `out_struct_size` write, the target-width `malloc`/`memset` zero-init,
/// and the fail-closed `emit_de_drop_owned` cleanup all route through the
/// `hew_cbor_*` runtime primitives.
#[allow(clippy::too_many_arguments, clippy::too_many_lines)]
fn emit_cbor_codec_thunks<'ctx>(
    ctx: &'ctx Context,
    llvm_mod: &LlvmModule<'ctx>,
    ty: &ResolvedTy,
    wire_layouts: &WireLayoutTable,
    record_layouts: &RecordLayoutMap<'ctx>,
    machine_layouts: &MachineLayoutMap<'ctx>,
    pipeline_records: &[RecordLayout],
    enum_layouts: &[EnumLayout],
) -> CodegenResult<(String, String)> {
    let key = xnode_codec_key(ty);
    let ser_sym = format!("__hew_cbor_serialize_{key}");
    let de_sym = format!("__hew_cbor_deserialize_{key}");
    let ser_fn = get_or_declare_cbor_serialize_thunk(ctx, llvm_mod, &key);
    let de_fn = get_or_declare_cbor_deserialize_thunk(ctx, llvm_mod, &key);
    if ser_fn.count_basic_blocks() > 0 {
        return Ok((ser_sym, de_sym)); // already emitted
    }

    let ptr_ty = ctx.ptr_type(AddressSpace::default());
    let i64_ty = ctx.i64_type();

    // ── serialize(value, out_len) -> bytes: build a CborSerBuf, walk, finish. ──
    {
        let builder = ctx.create_builder();
        let entry = ctx.append_basic_block(ser_fn, "entry");
        builder.position_at_end(entry);
        let value_ptr = ser_fn
            .get_nth_param(0)
            .ok_or_else(|| {
                CodegenError::FailClosed("cbor serialize thunk missing value param".into())
            })?
            .into_pointer_value();
        let out_len = ser_fn
            .get_nth_param(1)
            .ok_or_else(|| {
                CodegenError::FailClosed("cbor serialize thunk missing out_len param".into())
            })?
            .into_pointer_value();
        let buf_new = declare_codec_prim(
            ctx,
            llvm_mod,
            "hew_cbor_ser_new",
            ptr_ty.fn_type(&[], false),
        );
        let buf = builder
            .build_call(buf_new, &[], "cbor_ser_buf")
            .llvm_ctx("cbor_ser_new")?
            .try_as_basic_value()
            .basic()
            .ok_or_else(|| CodegenError::FailClosed("hew_cbor_ser_new void".into()))?
            .into_pointer_value();
        emit_ser_value_cbor(
            ctx,
            llvm_mod,
            &builder,
            ser_fn,
            ty,
            value_ptr,
            buf,
            wire_layouts,
            record_layouts,
            machine_layouts,
            pipeline_records,
            enum_layouts,
        )?;
        let finish = declare_codec_prim(
            ctx,
            llvm_mod,
            "hew_cbor_ser_finish",
            ptr_ty.fn_type(&[ptr_ty.into(), ptr_ty.into()], false),
        );
        let bytes = builder
            .build_call(finish, &[buf.into(), out_len.into()], "cbor_ser_finish")
            .llvm_ctx("cbor_ser_finish")?
            .try_as_basic_value()
            .basic()
            .ok_or_else(|| CodegenError::FailClosed("hew_cbor_ser_finish void".into()))?
            .into_pointer_value();
        builder
            .build_return(Some(&bytes))
            .llvm_ctx("cbor ser return")?;
    }

    // ── deserialize: make a reader, alloc the value, walk, free reader. ──
    {
        let builder = ctx.create_builder();
        let entry = ctx.append_basic_block(de_fn, "entry");
        builder.position_at_end(entry);
        let data = de_fn
            .get_nth_param(0)
            .ok_or_else(|| CodegenError::FailClosed("cbor deserialize thunk missing data".into()))?
            .into_pointer_value();
        let len = de_fn
            .get_nth_param(1)
            .ok_or_else(|| CodegenError::FailClosed("cbor deserialize thunk missing len".into()))?
            .into_int_value();
        let out_struct_size = de_fn
            .get_nth_param(2)
            .ok_or_else(|| {
                CodegenError::FailClosed("cbor deserialize thunk missing out_struct_size".into())
            })?
            .into_pointer_value();
        let de_reader_size_ty = runtime_size_ty(ctx, llvm_mod);
        let reader_new = declare_codec_prim(
            ctx,
            llvm_mod,
            "hew_cbor_de_new",
            ptr_ty.fn_type(&[ptr_ty.into(), de_reader_size_ty.into()], false),
        );
        let reader = builder
            .build_call(reader_new, &[data.into(), len.into()], "cbor_de_reader")
            .llvm_ctx("cbor_de_new")?
            .try_as_basic_value()
            .basic()
            .ok_or_else(|| CodegenError::FailClosed("hew_cbor_de_new void".into()))?
            .into_pointer_value();

        let llvm_ty = resolve_ty(ctx, ty, record_layouts)?;
        let size = llvm_ty.size_of().ok_or_else(|| {
            CodegenError::FailClosed("cbor deserialize: value has no static size".into())
        })?;
        builder
            .build_store(out_struct_size, size)
            .llvm_ctx("cbor de store struct size")?;
        let malloc_fn = get_or_declare_libc_malloc(ctx, llvm_mod);
        let malloc_size_ty = runtime_size_ty(ctx, llvm_mod);
        let malloc_size = if malloc_size_ty == i64_ty {
            size
        } else {
            builder
                .build_int_truncate(size, malloc_size_ty, "cbor_de_size_trunc")
                .llvm_ctx("cbor de malloc size trunc")?
        };
        let dst = builder
            .build_call(malloc_fn, &[malloc_size.into()], "cbor_de_value")
            .llvm_ctx("cbor de value malloc")?
            .try_as_basic_value()
            .basic()
            .ok_or_else(|| CodegenError::FailClosed("malloc void".into()))?
            .into_pointer_value();

        // Fail closed on OOM — a null malloc must not reach memset / the walk.
        {
            let oom_bb = ctx.append_basic_block(de_fn, "cbor_de_oom");
            let alloc_ok_bb = ctx.append_basic_block(de_fn, "cbor_de_alloc_ok");
            let null_ptr = ptr_ty.const_null();
            let is_null = builder
                .build_int_compare(
                    IntPredicate::EQ,
                    builder
                        .build_ptr_to_int(dst, ctx.i64_type(), "cbor_dst_as_int")
                        .llvm_ctx("cbor dst ptr_to_int")?,
                    builder
                        .build_ptr_to_int(null_ptr, ctx.i64_type(), "cbor_null_as_int")
                        .llvm_ctx("cbor null ptr_to_int")?,
                    "cbor_dst_is_null",
                )
                .llvm_ctx("cbor de null check")?;
            builder
                .build_conditional_branch(is_null, oom_bb, alloc_ok_bb)
                .llvm_ctx("cbor de oom branch")?;
            builder.position_at_end(oom_bb);
            let reader_free_oom = declare_codec_prim(
                ctx,
                llvm_mod,
                "hew_cbor_de_free",
                ctx.void_type().fn_type(&[ptr_ty.into()], false),
            );
            builder
                .build_call(reader_free_oom, &[reader.into()], "cbor_de_reader_free_oom")
                .llvm_ctx("cbor de reader free oom")?;
            builder
                .build_return(Some(&ptr_ty.const_null()))
                .llvm_ctx("cbor de oom return")?;
            builder.position_at_end(alloc_ok_bb);
        }

        // Zero-init so partially-decoded values have well-defined slots.
        let memset_size_ty = runtime_size_ty(ctx, llvm_mod);
        let memset = declare_codec_prim(
            ctx,
            llvm_mod,
            "memset",
            ptr_ty.fn_type(
                &[ptr_ty.into(), ctx.i32_type().into(), memset_size_ty.into()],
                false,
            ),
        );
        let memset_size = if memset_size_ty == i64_ty {
            size
        } else {
            builder
                .build_int_truncate(size, memset_size_ty, "cbor_de_memset_size_trunc")
                .llvm_ctx("cbor de memset size trunc")?
        };
        builder
            .build_call(
                memset,
                &[
                    dst.into(),
                    ctx.i32_type().const_zero().into(),
                    memset_size.into(),
                ],
                "cbor_de_zero",
            )
            .llvm_ctx("cbor de zero-init")?;

        emit_de_value_cbor(
            ctx,
            llvm_mod,
            &builder,
            de_fn,
            ty,
            dst,
            reader,
            wire_layouts,
            record_layouts,
            machine_layouts,
            pipeline_records,
            enum_layouts,
        )?;

        // Fail closed: if the reader latched an error, drop the partial value's
        // owned fields, free the shell + the reader, and return null.
        let failed_prim = declare_codec_prim(
            ctx,
            llvm_mod,
            "hew_cbor_de_failed",
            ctx.i32_type().fn_type(&[ptr_ty.into()], false),
        );
        let failed = builder
            .build_call(failed_prim, &[reader.into()], "cbor_de_failed")
            .llvm_ctx("cbor de failed")?
            .try_as_basic_value()
            .basic()
            .ok_or_else(|| CodegenError::FailClosed("hew_cbor_de_failed void".into()))?
            .into_int_value();
        let reader_free = declare_codec_prim(
            ctx,
            llvm_mod,
            "hew_cbor_de_free",
            ctx.void_type().fn_type(&[ptr_ty.into()], false),
        );
        builder
            .build_call(reader_free, &[reader.into()], "cbor_de_reader_free")
            .llvm_ctx("cbor de reader free")?;

        let ok_bb = ctx.append_basic_block(de_fn, "cbor_de_ok");
        let fail_bb = ctx.append_basic_block(de_fn, "cbor_de_fail");
        let is_failed = builder
            .build_int_compare(
                IntPredicate::NE,
                failed,
                ctx.i32_type().const_zero(),
                "cbor_de_is_failed",
            )
            .llvm_ctx("cbor de is_failed cmp")?;
        builder
            .build_conditional_branch(is_failed, fail_bb, ok_bb)
            .llvm_ctx("cbor de fail branch")?;

        builder.position_at_end(fail_bb);
        // Drop any heap-owning fields already written before the failure; the
        // struct was zero-initialised, so unwritten fields are null and the
        // null-safe drop helpers short-circuit. Drop BEFORE free(dst) — the drop
        // helpers operate in-place — so free runs exactly once, no double-free.
        emit_de_drop_owned(
            ctx,
            llvm_mod,
            &builder,
            ty,
            dst,
            record_layouts,
            machine_layouts,
            pipeline_records,
            enum_layouts,
        )?;
        let free_fn = declare_codec_prim(
            ctx,
            llvm_mod,
            "free",
            ctx.void_type().fn_type(&[ptr_ty.into()], false),
        );
        builder
            .build_call(free_fn, &[dst.into()], "cbor_de_free_partial")
            .llvm_ctx("cbor de free partial")?;
        builder
            .build_return(Some(&ptr_ty.const_null()))
            .llvm_ctx("cbor de fail return")?;

        builder.position_at_end(ok_bb);
        builder
            .build_return(Some(&dst))
            .llvm_ctx("cbor de return")?;
    }

    Ok((ser_sym, de_sym))
}

/// module-init constructor functions (priority 65535 each, run before `main`).
///
/// LLVM permits only one `@llvm.global_ctors` symbol per module, so all module
/// inits (regex, cross-node codec) register their init fn into a shared list and
/// this helper materialises the single global. No-op for an empty list. inkwell
/// 0.9 cannot read back an existing const-array initialiser element-wise, so the
/// list-then-emit-once shape avoids ever needing to.
fn emit_global_ctors<'ctx>(
    ctx: &'ctx Context,
    llvm_mod: &LlvmModule<'ctx>,
    init_fns: &[FunctionValue<'ctx>],
) -> CodegenResult<()> {
    if init_fns.is_empty() {
        return Ok(());
    }
    let i32_ty = ctx.i32_type();
    let ptr_ty = ctx.ptr_type(AddressSpace::default());
    let entry_ty = ctx.struct_type(&[i32_ty.into(), ptr_ty.into(), ptr_ty.into()], false);
    let priority = i32_ty.const_int(65535, false);
    let assoc = ptr_ty.const_null();
    let entries: Vec<inkwell::values::StructValue<'ctx>> = init_fns
        .iter()
        .map(|f| {
            let fp = f.as_global_value().as_pointer_value();
            entry_ty.const_named_struct(&[priority.into(), fp.into(), assoc.into()])
        })
        .collect();
    let arr = entry_ty.const_array(&entries);
    let g = llvm_mod.add_global(
        entry_ty.array_type(entries.len() as u32),
        None,
        "llvm.global_ctors",
    );
    g.set_initializer(&arr);
    g.set_linkage(Linkage::Appending);
    Ok(())
}

/// Emit the serialize/deserialize thunk bodies for every wire type that a
/// direct `.encode()` / `.decode()` call references in the MIR.
///
/// Both the `.encode()` / `.decode()` path and the actor cross-node payload
/// codec (`emit_actor_codec_module_init`) emit the same CBOR thunks via
/// `emit_cbor_codec_thunks`, which is idempotent (it no-ops once a thunk body
/// is present). A wire type referenced by several `.encode()` / `.decode()`
/// sites — or used as both a direct-call type and an actor message — shares the
/// one CBOR thunk pair.
fn emit_wire_codec_call_thunks<'ctx>(
    ctx: &'ctx Context,
    llvm_mod: &LlvmModule<'ctx>,
    pipeline: &IrPipeline,
    record_layouts: &RecordLayoutMap<'ctx>,
    machine_layouts: &MachineLayoutMap<'ctx>,
    pipeline_records: &[RecordLayout],
    enum_layouts: &[EnumLayout],
) -> CodegenResult<()> {
    let mut seen: Vec<ResolvedTy> = Vec::new();
    for func in &pipeline.raw_mir {
        for block in &func.blocks {
            for instr in &block.instructions {
                if let Instr::WireCodec { value_ty, .. } = instr {
                    if !seen.contains(value_ty) {
                        seen.push(value_ty.clone());
                        emit_cbor_codec_thunks(
                            ctx,
                            llvm_mod,
                            value_ty,
                            &pipeline.wire_layouts,
                            record_layouts,
                            machine_layouts,
                            pipeline_records,
                            enum_layouts,
                        )?;
                    }
                }
            }
        }
    }
    Ok(())
}

/// Emit the JSON/YAML text-codec descriptor globals for every wire type that a
/// text-direction (`to_json`/`from_json`/`to_yaml`/`from_yaml`) call references.
/// Runs BEFORE function-body lowering so the descriptor globals exist when
/// `lower_wire_text_codec_instr` resolves them by name at each call site.
fn emit_all_wire_text_descriptor_globals<'ctx>(
    ctx: &'ctx Context,
    llvm_mod: &LlvmModule<'ctx>,
    pipeline: &IrPipeline,
    pipeline_records: &[RecordLayout],
    enum_layouts: &[EnumLayout],
) -> CodegenResult<()> {
    let mut text_seen: Vec<ResolvedTy> = Vec::new();
    for func in &pipeline.raw_mir {
        for block in &func.blocks {
            for instr in &block.instructions {
                if let Instr::WireCodec {
                    value_ty,
                    direction,
                    ..
                } = instr
                {
                    if direction.is_text() && !text_seen.contains(value_ty) {
                        text_seen.push(value_ty.clone());
                        emit_wire_text_descriptor_globals(
                            ctx,
                            llvm_mod,
                            value_ty,
                            &pipeline.wire_layouts,
                            pipeline_records,
                            enum_layouts,
                        )?;
                    }
                }
            }
        }
    }
    Ok(())
}

/// Emit the JSON and YAML descriptor string globals for a wire `value_ty`. The
/// globals are named `__hew_wire_desc_{json,yaml}_<key>` (deterministic, keyed by
/// `xnode_codec_key` like the CBOR thunks) so `lower_wire_text_codec_instr` can
/// look them up by name at each call site. Idempotent: `build_const_string_ptr`
/// no-ops if a global of that name already exists.
fn emit_wire_text_descriptor_globals<'ctx>(
    ctx: &'ctx Context,
    llvm_mod: &LlvmModule<'ctx>,
    value_ty: &ResolvedTy,
    wire_layouts: &WireLayoutTable,
    pipeline_records: &[RecordLayout],
    enum_layouts: &[EnumLayout],
) -> CodegenResult<()> {
    let key = xnode_codec_key(value_ty);
    let json_desc = build_text_descriptor(
        value_ty,
        WireTextFormat::Json,
        wire_layouts,
        pipeline_records,
        enum_layouts,
    );
    let yaml_desc = build_text_descriptor(
        value_ty,
        WireTextFormat::Yaml,
        wire_layouts,
        pipeline_records,
        enum_layouts,
    );
    build_const_string_ptr(
        ctx,
        llvm_mod,
        &json_desc,
        &wire_desc_global_name(&key, WireTextFormat::Json),
    )?;
    build_const_string_ptr(
        ctx,
        llvm_mod,
        &yaml_desc,
        &wire_desc_global_name(&key, WireTextFormat::Yaml),
    )?;
    Ok(())
}

/// The deterministic global-symbol name for a wire type's text descriptor.
fn wire_desc_global_name(key: &str, format: WireTextFormat) -> String {
    match format {
        WireTextFormat::Json => format!("__hew_wire_desc_json_{key}"),
        WireTextFormat::Yaml => format!("__hew_wire_desc_yaml_{key}"),
    }
}

/// Emit the cross-node codec module-init: for every actor receive handler,
/// synthesize the CBOR serialize/deserialize thunk pair for its message type
/// (and reply type) and emit a `hew_xnode_register_codec` call keyed by
/// `msg_type`, so the runtime receive path can decode inbound payloads and the
/// ask reply path can encode reply values. The thunks are the same CBOR body
/// codec the `.encode()`/`.decode()` path emits — a wire type used on both
/// paths shares one thunk pair. No-op when there are no actor handlers.
#[allow(clippy::too_many_arguments)]
fn emit_actor_codec_module_init<'ctx>(
    ctx: &'ctx Context,
    llvm_mod: &LlvmModule<'ctx>,
    actor_layouts: &[ActorLayout],
    wire_layouts: &WireLayoutTable,
    record_layouts: &RecordLayoutMap<'ctx>,
    machine_layouts: &MachineLayoutMap<'ctx>,
    pipeline_records: &[RecordLayout],
    enum_layouts: &[EnumLayout],
) -> CodegenResult<Option<FunctionValue<'ctx>>> {
    // Collect (dispatch global, msg_type, msg_ty, reply_ty) for every handler.
    // The codec registry is keyed by `(dispatch, msg_type)` — the owning actor
    // TYPE's dispatch function pointer plus the discriminant — so two distinct
    // actor types whose handler names SipHash-collide on the low 32 bits of
    // `msg_type` register SEPARATE codecs (no silent displacement / cross-node
    // type-confusion). Dedup is therefore by `(dispatch, msg_type)`, NOT
    // `msg_type` alone; a handler still appears once per actor type.
    let mut entries: Vec<(FunctionValue<'ctx>, i32, ResolvedTy, ResolvedTy)> = Vec::new();
    for actor in actor_layouts {
        // Resolve the actor TYPE's dispatch global, the same symbol the spawn
        // path stores into `HewActor.dispatch` and the runtime decode paths
        // resolve from `target_actor_id`. It is emitted by
        // `emit_actor_dispatch_trampoline` ahead of this pass; a missing symbol
        // is wrong-code territory — fail closed rather than seed an unkeyable
        // codec.
        let dispatch_name = format!("__hew_actor_dispatch_{}", mangle_dotted_name(&actor.name));
        let dispatch_fn = llvm_mod.get_function(&dispatch_name).ok_or_else(|| {
            CodegenError::FailClosed(format!(
                "xnode codec seeder: actor `{}` requires dispatch trampoline \
                 `{dispatch_name}` (the codec-registry key); it was not declared \
                 before the codec module-init pass",
                actor.name
            ))
        })?;
        for h in &actor.handlers {
            // Single-parameter handlers only. A multi-arg handler's wire
            // payload is the packed-args anonymous record; seeding a codec
            // keyed to its FIRST param type would register a serializer
            // that encodes one field of an N-field payload — a remote peer
            // dispatching that msg_type would then deliver short bytes to
            // a body that unpacks the full record (out-of-bounds read).
            // Leaving the msg_type unseeded keeps the receive direction on
            // the runtime's no-codec fail-closed drop path. The cross-node
            // payload serialization lane seeds packed-args shapes with
            // real structural codecs and lifts this skip.
            let [msg_ty] = h.param_tys.as_slice() else {
                continue;
            };
            // Channel handles (`Sender<T>`/`Receiver<T>`) and actor-identity
            // handles (`LocalPid`/`RemotePid`/`ActorRef`/`Actor`/`Pid`) are
            // process-local runtime resources: the local mailbox transfers the
            // retained handle pointer or packed pid by value (ownership moves;
            // the checker consumes the caller binding for resources), and the
            // checker's Serializable enforcement already refuses every one of
            // them at every RemotePid boundary with a named diagnostic. None
            // has a cross-node wire layout, so emitting a codec here would fail
            // the WHOLE compile for a purely local program. Skip the msg_type
            // instead — the cross-node receive direction stays on the runtime's
            // no-codec fail-closed drop path, exactly like the packed-args skip
            // above.
            if resolved_ty_contains_channel_handle(msg_ty)
                || resolved_ty_contains_channel_handle(&h.return_ty)
                || resolved_ty_contains_actor_handle(msg_ty)
                || resolved_ty_contains_actor_handle(&h.return_ty)
            {
                continue;
            }
            // Dedup by (dispatch, msg_type): the SAME actor type can list a
            // handler once; distinct actor types with a colliding msg_type each
            // seed their own codec under their own dispatch key.
            if entries
                .iter()
                .any(|(d, mt, _, _)| *d == dispatch_fn && *mt == h.msg_type)
            {
                continue;
            }
            entries.push((dispatch_fn, h.msg_type, msg_ty.clone(), h.return_ty.clone()));
        }
    }
    if entries.is_empty() {
        return Ok(None);
    }

    let void_ty = ctx.void_type();
    let ptr_ty = ctx.ptr_type(AddressSpace::default());
    let i32_ty = ctx.i32_type();

    // Emit CBOR thunk bodies for every distinct msg AND reply type first.
    // (Best-effort: a type outside the Serializable floor fails closed here,
    // surfacing the codegen error rather than shipping raw bytes.) These are the
    // same thunks the `.encode()`/`.decode()` path emits; `emit_cbor_codec_thunks`
    // is idempotent per key, so a type used on both paths is emitted once.
    for (_dispatch, _mt, msg_ty, reply_ty) in &entries {
        emit_cbor_codec_thunks(
            ctx,
            llvm_mod,
            msg_ty,
            wire_layouts,
            record_layouts,
            machine_layouts,
            pipeline_records,
            enum_layouts,
        )?;
        if !matches!(reply_ty, ResolvedTy::Unit | ResolvedTy::Never) {
            emit_cbor_codec_thunks(
                ctx,
                llvm_mod,
                reply_ty,
                wire_layouts,
                record_layouts,
                machine_layouts,
                pipeline_records,
                enum_layouts,
            )?;
        }
    }

    // Constructor: void hew_module_init_actor_codecs().
    let init_fn = llvm_mod.add_function(
        "hew_module_init_actor_codecs",
        void_ty.fn_type(&[], false),
        Some(Linkage::Private),
    );
    let builder = ctx.create_builder();
    let entry_bb = ctx.append_basic_block(init_fn, "entry");
    builder.position_at_end(entry_bb);

    // hew_xnode_register_codec(dispatch: ptr, msg_type: i32, ser: ptr, de: ptr).
    // The leading `dispatch` ptr is the codec-registry key (codegen-offset-mirror
    // -drift: this declare MUST match the runtime `#[no_mangle]` signature).
    let reg_fn = declare_codec_prim(
        ctx,
        llvm_mod,
        "hew_xnode_register_codec",
        void_ty.fn_type(
            &[ptr_ty.into(), i32_ty.into(), ptr_ty.into(), ptr_ty.into()],
            false,
        ),
    );
    // hew_xnode_register_reply_codec(dispatch: ptr, msg_type: i32, ser, de) — the
    // reply codec for the ask path, keyed by (dispatch, request msg_type).
    let reg_reply_fn = declare_codec_prim(
        ctx,
        llvm_mod,
        "hew_xnode_register_reply_codec",
        void_ty.fn_type(
            &[ptr_ty.into(), i32_ty.into(), ptr_ty.into(), ptr_ty.into()],
            false,
        ),
    );

    for (dispatch_fn, mt, msg_ty, reply_ty) in &entries {
        let dispatch_ptr = dispatch_fn.as_global_value().as_pointer_value();
        let mt_const = i32_ty.const_int(*mt as u64, true);
        let msg_key = xnode_codec_key(msg_ty);
        let ser = get_or_declare_cbor_serialize_thunk(ctx, llvm_mod, &msg_key);
        let de = get_or_declare_cbor_deserialize_thunk(ctx, llvm_mod, &msg_key);
        builder
            .build_call(
                reg_fn,
                &[
                    dispatch_ptr.into(),
                    mt_const.into(),
                    ser.as_global_value().as_pointer_value().into(),
                    de.as_global_value().as_pointer_value().into(),
                ],
                "xnode_register",
            )
            .llvm_ctx("hew_xnode_register_codec call")?;
        if !matches!(reply_ty, ResolvedTy::Unit | ResolvedTy::Never) {
            let reply_key = xnode_codec_key(reply_ty);
            let rser = get_or_declare_cbor_serialize_thunk(ctx, llvm_mod, &reply_key);
            let rde = get_or_declare_cbor_deserialize_thunk(ctx, llvm_mod, &reply_key);
            builder
                .build_call(
                    reg_reply_fn,
                    &[
                        dispatch_ptr.into(),
                        mt_const.into(),
                        rser.as_global_value().as_pointer_value().into(),
                        rde.as_global_value().as_pointer_value().into(),
                    ],
                    "xnode_register_reply",
                )
                .llvm_ctx("hew_xnode_register_reply_codec call")?;
        }
    }
    builder
        .build_return(None)
        .llvm_ctx("xnode codec init return")?;

    Ok(Some(init_fn))
}

/// Emit the module-level regex infrastructure when `pipeline.regex_literals` is non-empty.
///
/// Emits:
/// 1. `@hew_regex_handles : [N x ptr]` — global mutable array of `*mut HewRegex` handles,
///    initialised to null. The module-init constructor populates each slot.
/// 2. Per literal: `@hew_regex_pattern_<i> : [M x i8]` — private NUL-terminated i8 constant
///    holding the pattern bytes.
/// 3. `@hew_module_init_regex` — void() constructor that calls `hew_regex_compile` for each
///    pattern and stores the result into `@hew_regex_handles[i]`. Traps fail-closed if any
///    compile returns null (the type-checker guaranteed the pattern is valid; null means OOM
///    or an internal invariant was broken).
/// 4. `@llvm.global_ctors = appending [{ i32, ptr, ptr } { 65535, @hew_module_init_regex,
///    null }]` — ensures the constructor runs before `main`.
///
/// WHY `@llvm.global_ctors` not a call from `main`: every user-defined entrypoint (not just
/// `main`) runs after module init; a ctors entry is the substrate-correct mechanism.
/// WHEN-OBSOLETE: if Hew gains a module-level DSL for eager resource initialisation, this
/// synthesised constructor is the expected substrate for that feature.
/// WHAT: the `lower_call_runtime_abi` arms for `hew_regex_match` and `hew_regex_capture` load
/// from this global array by GEP (literal_id → slot index).
pub(crate) fn emit_regex_module_init<'ctx>(
    ctx: &'ctx Context,
    llvm_mod: &LlvmModule<'ctx>,
    literals: &[RegexLiteral],
) -> CodegenResult<Option<FunctionValue<'ctx>>> {
    if literals.is_empty() {
        return Ok(None);
    }
    let n = u32::try_from(literals.len()).map_err(|_| {
        CodegenError::FailClosed("regex literal count exceeds u32::MAX — impossible".into())
    })?;
    let ptr_ty = ctx.ptr_type(AddressSpace::default());
    let i8_ty = ctx.i8_type();
    let i64_ty = ctx.i64_type();

    // 1. Global handle array: [N x ptr] initialised to all-null.
    let handle_arr_ty = ptr_ty.array_type(n);
    let handles_global = llvm_mod.add_global(handle_arr_ty, None, "hew_regex_handles");
    let null_ptrs: Vec<inkwell::values::PointerValue<'ctx>> =
        (0..n).map(|_| ptr_ty.const_null()).collect();
    let null_arr_init = ptr_ty.const_array(&null_ptrs);
    handles_global.set_initializer(&null_arr_init);
    handles_global.set_linkage(Linkage::Private);

    // 2. Per-literal pattern constant: private unnamed_addr [M x i8].
    let mut pattern_ptrs: Vec<inkwell::values::PointerValue<'ctx>> =
        Vec::with_capacity(literals.len());
    for lit in literals {
        let bytes_with_nul: Vec<u8> = lit.pattern.bytes().chain(std::iter::once(0u8)).collect();
        let len = u32::try_from(bytes_with_nul.len()).map_err(|_| {
            CodegenError::FailClosed(format!(
                "regex pattern {lit_id} is too long for LLVM constant",
                lit_id = lit.literal_id
            ))
        })?;
        let arr_ty = i8_ty.array_type(len);
        let global_name = format!("hew_regex_pattern_{}", lit.literal_id);
        let pat_global = llvm_mod.add_global(arr_ty, None, &global_name);
        let bytes_as_i8: Vec<inkwell::values::IntValue<'ctx>> = bytes_with_nul
            .iter()
            .map(|b| i8_ty.const_int(u64::from(*b), false))
            .collect();
        let arr_init = i8_ty.const_array(&bytes_as_i8);
        pat_global.set_initializer(&arr_init);
        pat_global.set_linkage(Linkage::Private);
        pat_global.set_constant(true);
        pat_global.set_unnamed_addr(true);
        pattern_ptrs.push(pat_global.as_pointer_value());
    }

    // 3. Constructor function: `void hew_module_init_regex()`.
    let void_ty = ctx.void_type();
    let init_fn_ty = void_ty.fn_type(&[], false);
    let init_fn =
        llvm_mod.add_function("hew_module_init_regex", init_fn_ty, Some(Linkage::Private));
    let entry_bb = ctx.append_basic_block(init_fn, "entry");
    let builder = ctx.create_builder();
    builder.position_at_end(entry_bb);

    // Intern hew_regex_compile declaration.
    let compile_fn = {
        let compile_ty = ptr_ty.fn_type(&[ptr_ty.into()], false);
        llvm_mod
            .get_function("hew_regex_compile")
            .unwrap_or_else(|| {
                llvm_mod.add_function("hew_regex_compile", compile_ty, Some(Linkage::External))
            })
    };

    for (i, pat_ptr) in pattern_ptrs.iter().enumerate() {
        // Call hew_regex_compile(pattern).
        let call_result = builder
            .build_call(
                compile_fn,
                &[(*pat_ptr).into()],
                &format!("compile_regex_{i}"),
            )
            .llvm_ctx("hew_regex_compile call in module-init")?;
        let handle = call_result
            .try_as_basic_value()
            .basic()
            .ok_or_else(|| {
                CodegenError::FailClosed(
                    "hew_regex_compile returned void — signature mismatch".into(),
                )
            })?
            .into_pointer_value();

        // Fail-closed trap if null: pattern was validated by the checker; null is OOM or
        // a code invariant violation.
        // WHY trap not unreachable: LLVM may speculate past `unreachable` at -O2; a call to
        // `hew_trap_with_code` is opaque to the optimiser and always terminates. WHEN-OBSOLETE:
        // when LLVM's opaque-pointer + assume attributes land in hew-codegen-rs, the assume
        // could suppress the branch; for now the explicit call is the correct substrate.
        let null_check_bb = ctx.append_basic_block(init_fn, &format!("null_check_{i}"));
        let ok_bb = ctx.append_basic_block(init_fn, &format!("ok_{i}"));
        let is_null = builder
            .build_is_null(handle, &format!("is_null_{i}"))
            .llvm_ctx("is_null check in module-init")?;
        builder
            .build_conditional_branch(is_null, null_check_bb, ok_bb)
            .llvm_ctx("null-check branch in module-init")?;

        builder.position_at_end(null_check_bb);
        // Trap code 209 — module-init regex compile failure (internal invariant
        // violation; patterns are validated by the type-checker so this branch
        // is dead code in correctly-compiled programs). The code is now
        // single-sourced from the runtime (`HEW_TRAP_MODULE_INIT_REGEX_FAILED`),
        // which carries the matching `ExitReason::ModuleInitRegexFailed` decoder
        // arm — a renumber on either side is a build error.
        // WHY not 206: 206 is HEW_TRAP_ACTOR_SEND_FAILED; reusing it would
        // make diagnostics misleading.
        //
        // Use emit_trap_with_code_raw so the declaration is single-sourced
        // at fn(i32) matching the runtime's `hew_trap_with_code(code: i32)`
        // (supervisor.rs:364). The old inline declaration used fn(i32, i32)
        // which would produce an arity-mismatch IR if no prior declaration
        // of the correct shape existed in the module.
        emit_trap_with_code_raw(
            ctx,
            llvm_mod,
            &builder,
            HEW_TRAP_MODULE_INIT_REGEX_FAILED as u64,
            &format!("regex_init_null_trap_{i}"),
        )?;

        builder.position_at_end(ok_bb);
        // Store handle into @hew_regex_handles[i].
        let idx = i64_ty.const_int(u64::try_from(i).unwrap_or(u64::MAX), false);
        let slot_ptr = unsafe {
            builder
                .build_gep(
                    handle_arr_ty,
                    handles_global.as_pointer_value(),
                    &[i64_ty.const_zero(), idx],
                    &format!("regex_slot_{i}"),
                )
                .llvm_ctx_with(|| format!("GEP for regex handle slot {i}"))?
        };
        builder
            .build_store(slot_ptr, handle)
            .llvm_ctx_with(|| format!("store regex handle {i}"))?;
    }
    builder
        .build_return(None)
        .llvm_ctx("return in hew_module_init_regex")?;

    // The caller collects this init fn and emits the single @llvm.global_ctors
    // (priority 65535) alongside any other module-init constructor.
    Ok(Some(init_fn))
}

fn emit_textual(
    pipeline: &IrPipeline,
    name: &str,
    out: &Path,
    triple: &str,
    debug: Option<DebugInput<'_>>,
) -> CodegenResult<()> {
    // Build the diagnostic `.ll` against the SAME target machine the object
    // emission uses, so the textual IR reflects the requested target's ABI
    // (the aggregate classifier reads the module triple; a host-triple textual
    // build of a wasm32 target would emit host-classified aggregate calls in
    // the diagnostic, misrepresenting what the `.wasm` object actually emits).
    let machine = target_machine_for_triple(triple)?;
    let ctx = Context::create();
    let llvm_mod = build_module_for_target(&ctx, pipeline, name, Some(&machine), debug)?;
    llvm_mod
        .print_to_file(out)
        .llvm_ctx_with(|| format!("print_to_file {}", out.display()))?;
    Ok(())
}

/// Link a wasm relocatable object into a standalone wasm module.
///
/// Prefers `wasm-ld` on PATH (Homebrew/lld). Falls back to
/// `rust-lld -flavor wasm` (which ships with rustup). The probe established
/// this fallback order empirically; the Hew dev shell on macOS has both,
/// CI runners on Linux typically have at least `rust-lld` via rustup.
fn link_wasm_module(obj: &Path, out: &Path) -> CodegenResult<()> {
    let candidates: &[(&str, &[&str])] = &[("wasm-ld", &[]), ("rust-lld", &["-flavor", "wasm"])];
    let mut last_err: Option<String> = None;
    for (cmd, prefix_args) in candidates {
        let mut command = Command::new(cmd);
        command.args(*prefix_args);
        command
            .arg("--no-entry")
            .arg("--export=main")
            // `--import-undefined`: undefined runtime symbols (e.g.
            // `hew_trap_with_code` from `Terminator::Trap` lowering) become
            // wasm imports the host module provides. The native link path
            // resolves these against the hew-runtime static archive in
            // `hew-cli/src/link.rs`; the codegen-internal wasm link in this
            // helper does not pull in the runtime, so the symbols must be
            // host-imports instead of hard link errors. WASM-TODO(#1451):
            // a follow-up wires per-kind trap reporting into a real wasm
            // runtime stub.
            .arg("--import-undefined")
            .arg("-o")
            .arg(out)
            .arg(obj);
        let output = match command.output() {
            Ok(o) => o,
            Err(e) => {
                last_err = Some(format!("spawn {cmd}: {e}"));
                continue;
            }
        };
        if output.status.success() {
            return Ok(());
        }
        last_err = Some(format!(
            "{cmd} failed ({:?}): {}",
            output.status,
            String::from_utf8_lossy(&output.stderr)
        ));
    }
    Err(CodegenError::Link(format!(
        "wasm link failed for {}: {} (install `wasm-ld` via Homebrew/llvm or ensure `rust-lld` is on PATH via rustup)",
        obj.display(),
        last_err.unwrap_or_else(|| "no linker available".into())
    )))
}

